def _effective_monitor_notional_threshold(min_notional: Any, custom_min_notional: Any = 0.0) -> Dict[str, float]:
    normalized_min = _normalize_notional_threshold(min_notional)
    normalized_custom = _normalize_custom_notional_threshold(custom_min_notional)
    effective = max(float(normalized_min or 0.0), float(normalized_custom or 0.0), float(MONITOR_WHALE_BUCKETS[0]))
    return {
        "min_notional": float(normalized_min or 0.0),
        "custom_min_notional": float(normalized_custom or 0.0),
        "effective_min_notional": float(effective or 0.0),
    }


def _normalize_entry_thresholds(
    *,
    spot_confirm_min: Any = 62.0,
    spot_dispersion_max: Any = 0.22,
    spot_cost_max: Any = 16.0,
    perp_crowding_caution: Any = 62.0,
    perp_crowding_block: Any = 72.0,
    funding_caution: Any = 4.0,
    funding_block: Any = 5.5,
) -> Dict[str, float]:
    def _bounded(value: Any, default: float, minimum: float, maximum: float) -> float:
        try:
            normalized = float(value)
        except (TypeError, ValueError):
            normalized = float(default)
        return max(minimum, min(maximum, normalized))

    thresholds = {
        "spot_confirm_min": _bounded(spot_confirm_min, 62.0, 0.0, 100.0),
        "spot_dispersion_max": _bounded(spot_dispersion_max, 0.22, 0.01, 10.0),
        "spot_cost_max": _bounded(spot_cost_max, 16.0, 0.0, 500.0),
        "perp_crowding_caution": _bounded(perp_crowding_caution, 62.0, 0.0, 100.0),
        "perp_crowding_block": _bounded(perp_crowding_block, 72.0, 0.0, 100.0),
        "funding_caution": _bounded(funding_caution, 4.0, 0.0, 50.0),
        "funding_block": _bounded(funding_block, 5.5, 0.0, 50.0),
    }
    if thresholds["perp_crowding_block"] < thresholds["perp_crowding_caution"]:
        thresholds["perp_crowding_block"] = thresholds["perp_crowding_caution"]
    if thresholds["funding_block"] < thresholds["funding_caution"]:
        thresholds["funding_block"] = thresholds["funding_caution"]
    return thresholds


