def _row_funding_bps(row: Any) -> Optional[float]:
    if not hasattr(row, "get"):
        return None

    def _coerce_funding_bps(value: Any, key: str) -> Optional[float]:
        numeric_value = _payload_float(value)
        if numeric_value is None:
            return None
        lowered = str(key or "").strip().lower()
        if "bp" in lowered:
            return numeric_value
        if lowered in {"fundingrate", "funding_rate", "funding rate"}:
            return numeric_value * 10000.0
        if "funding" in lowered or "资金费率" in lowered:
            abs_value = abs(float(numeric_value))
            if abs_value < 0.001:
                return numeric_value * 10000.0
            if abs_value <= 0.05:
                return numeric_value * 100.0
        return numeric_value

    for key in (
        "funding_bps",
        "perp_funding_bps",
        "Funding(bp)",
        "Funding(bps)",
        "资金费率(bps)",
        "funding_rate",
        "fundingRate",
        "Funding Rate",
        "资金费率",
        "资金费率(%)",
    ):
        value = _coerce_funding_bps(row.get(key), key)
        if value is not None:
            return value
    return None


def _funding_rate_percent_from_bps(value: Any) -> Optional[float]:
    numeric_value = _payload_float(value)
    if numeric_value is None:
        return None
    return float(numeric_value) / 100.0


def _format_funding_rate_percent(value: Any, digits: int = 5, signed: bool = False) -> str:
    rate_percent = _funding_rate_percent_from_bps(value)
    if rate_percent is None:
        return "-"
    formatted = f"{rate_percent:+.{digits}f}" if signed else f"{rate_percent:.{digits}f}"
    formatted = formatted.rstrip("0").rstrip(".")
    return "0" if formatted in {"-0", "+0"} else formatted


