def _row_price_change_pct(row: Any, window: str = "24h") -> Optional[float]:
    if not hasattr(row, "get"):
        return None
    normalized_window = str(window or "24h").strip().lower()
    canonical_key = f"price_change_{normalized_window}_pct"
    legacy_candidates = {
        "5m": ("5m%",),
        "30m": ("30m%",),
        "1h": ("1h%",),
        "4h": ("4h%",),
        "24h": ("24h%",),
        "1d": ("24h%",),
    }.get(normalized_window, ())
    for key in (canonical_key, *legacy_candidates):
        value = _payload_float(row.get(key))
        if value is not None:
            return value
    return None


def _row_oi_change_pct(row: Any, window: str = "1h") -> Optional[float]:
    if not hasattr(row, "get"):
        return None
    normalized_window = str(window or "1h").strip().lower()
    canonical_key = f"oi_change_{normalized_window}_pct"
    legacy_key = f"OI {normalized_window}(%)"
    computed_legacy_key = _monitor_oi_window_column(normalized_window)
    for key in (canonical_key, legacy_key, computed_legacy_key):
        value = _payload_float(row.get(key))
        if value is not None:
            return value
    return None


def _row_window_volume_notional(row: Any, window: str) -> Optional[float]:
    if not hasattr(row, "get"):
        return None
    normalized_window = _normalize_time_window(window)
    for key in (f"{normalized_window}_volume_notional", f"{normalized_window}成交量"):
        value = _payload_float(row.get(key))
        if value is not None:
            return value
