def _row_window_large_metric(row: Any, window: str, metric: str = "total") -> Optional[float]:
    if not hasattr(row, "get"):
        return None
    normalized_window = _normalize_monitor_whale_window(window)
    metric_map = {
        "total": (f"{normalized_window}_large_notional", f"{normalized_window}大额成交额"),
        "buy": (f"{normalized_window}_large_buy_notional", f"{normalized_window}大额买入额"),
        "sell": (f"{normalized_window}_large_sell_notional", f"{normalized_window}大额卖出额"),
        "count": (f"{normalized_window}_large_count", f"{normalized_window}大额成交笔数"),
    }
    computed_columns = _monitor_whale_window_columns(normalized_window)
    computed_key_map = {
        "total": (computed_columns["total"],),
        "buy": (computed_columns["buy"],),
        "sell": (computed_columns["sell"],),
        "count": (computed_columns["count"],),
    }
    for key in (
        *metric_map.get(str(metric or "total").strip().lower(), metric_map["total"]),
        *computed_key_map.get(str(metric or "total").strip().lower(), ()),
    ):
        value = _payload_float(row.get(key))
        if value is not None:
            return value
    return None


def _numeric_series_sum_or_none(series: Any) -> Optional[float]:
    numeric = pd.to_numeric(series, errors="coerce")
    if isinstance(numeric, pd.Series):
        if numeric.dropna().empty:
            return None
        return float(numeric.fillna(0.0).sum())
    value = _payload_float(numeric)
    return value


def _normalize_hot_runtime_coins(value: Any) -> List[str]:
    if isinstance(value, (list, tuple, set)):
        candidates = value
    else:
        candidates = str(value or "").replace("|", ",").split(",")
    selected: List[str] = []
    for item in candidates:
        normalized = str(item or "").strip().upper()
        if normalized and normalized not in selected:
            selected.append(normalized)
    return selected or list(DEFAULT_HOT_RUNTIME_COINS)


def _normalize_custom_coins(value: Any, *, limit: int = 12) -> List[str]:
    if isinstance(value, (list, tuple, set)):
        candidates = value
    else:
        raw = str(value or "")
        for separator in ["|", ";", "\n", "\r", "\t", " ", "，", "/", "\\"]:
            raw = raw.replace(separator, ",")
        candidates = raw.split(",")
    selected: List[str] = []
    for item in candidates:
        normalized = str(item or "").strip().upper()
        if not normalized:
            continue
        compact = normalized.replace("-", "").replace("_", "")
        if not compact.isalnum():
            continue
        if normalized not in selected:
            selected.append(normalized)
        if len(selected) >= max(int(limit or 12), 1):
            break
    return selected


def _cache_signature_token(value: Any) -> str:
    normalized = _normalize_scalar(value)
    try:
        payload = json.dumps(normalized, ensure_ascii=True, sort_keys=True, separators=(",", ":"))
    except TypeError:
        payload = json.dumps(str(normalized), ensure_ascii=True, separators=(",", ":"))
    return hashlib.sha1(payload.encode("utf-8")).hexdigest()[:16]


