def _friendly_request_error(value: Any) -> str:
    text = str(value or "").strip()
    lowered = text.lower()
    if not text:
        return "-"
    if "out of maintenance" in lowered:
        return "爆仓 REST 回补端点维护中，已自动降级为 WS / 本地归档"
    return text


def _sanitize_request_health_rows(rows: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    cleaned: List[Dict[str, Any]] = []
    for row in rows or []:
        item = dict(row or {})
        item["display_error"] = _friendly_request_error(item.get("last_error") or item.get("error_kind"))
        cleaned.append(item)
    return cleaned


def _baseline_request_health_rows(exchange_keys: Any, market_scope: str) -> List[Dict[str, Any]]:
    normalized_exchange_keys = _normalize_exchange_keys(exchange_keys)
    normalized_market_scope = _normalize_market_scope(market_scope)
    rows: List[Dict[str, Any]] = []
    for exchange_key in normalized_exchange_keys:
        if normalized_market_scope != "spot":
            rows.append(
                {
                    "exchange_key": exchange_key,
                    "exchange_name": EXCHANGE_TITLE_MAP.get(exchange_key, exchange_key.title()),
                    "market": "perp",
                    "last_success_ms": None,
                    "last_attempt_ms": None,
                    "last_error_ms": None,
                    "last_error": None,
                    "last_status_code": None,
                    "error_kind": None,
                    "consecutive_failures": 0,
                    "cooldown_until_ms": None,
                    "cooldown_remaining_s": 0,
                    "status": "idle",
                    "display_error": "-",
                }
            )
        if normalized_market_scope != "perp" and exchange_key in SPOT_EXCHANGE_ORDER:
            rows.append(
                {
                    "exchange_key": exchange_key,
                    "exchange_name": EXCHANGE_TITLE_MAP.get(exchange_key, exchange_key.title()),
                    "market": "spot",
                    "last_success_ms": None,
                    "last_attempt_ms": None,
                    "last_error_ms": None,
                    "last_error": None,
                    "last_status_code": None,
                    "error_kind": None,
                    "consecutive_failures": 0,
                    "cooldown_until_ms": None,
                    "cooldown_remaining_s": 0,
                    "status": "idle",
                    "display_error": "-",
                }
            )
    return rows


def _request_backpressure(exchange_keys: List[str]) -> Dict[str, Any]:
    normalized_exchange_keys = _normalize_exchange_keys(exchange_keys)
    rows = [
        row
        for row in describe_exchange_request_health()
        if str(row.get("exchange_key") or "") in normalized_exchange_keys
    ]
    cooldown_rows = [row for row in rows if int(row.get("cooldown_remaining_s") or 0) > 0]
    return {
        "cooldown_count": len(cooldown_rows),
        "rate_limit_count": sum(1 for row in cooldown_rows if str(row.get("error_kind") or "").lower() == "rate_limit"),
        "max_cooldown_s": max([int(row.get("cooldown_remaining_s") or 0) for row in cooldown_rows], default=0),
        "rows": cooldown_rows,
    }


def _request_health_lookup() -> Dict[str, Dict[str, Any]]:
    rows = _sanitize_request_health_rows(describe_exchange_request_health())
    return {
        f"{_normalize_exchange_value(row.get('exchange_key') or row.get('exchange'))}:{_normalize_market_value(row.get('market'))}": dict(row)
        for row in rows
    }


def _exchange_market_request_health(
    exchange_key: Any,
    market: Any,
    *,
    health_lookup: Optional[Dict[str, Dict[str, Any]]] = None,
) -> Dict[str, Any]:
    normalized_exchange = _normalize_exchange_value(exchange_key)
    normalized_market = _normalize_market_value(market) or "perp"
    lookup = health_lookup or _request_health_lookup()
    row = dict(lookup.get(f"{normalized_exchange}:{normalized_market}") or {})
    if row:
        return row
    return {
        "exchange_key": normalized_exchange,
        "market": normalized_market,
        "status": "idle",
        "cooldown_remaining_s": 0,
        "error_kind": None,
        "last_status_code": None,
        "display_error": "-",
    }


def _exchange_market_rest_hard_degraded(
    exchange_key: Any,
    market: Any,
    *,
    health_lookup: Optional[Dict[str, Dict[str, Any]]] = None,
) -> bool:
    row = _exchange_market_request_health(exchange_key, market, health_lookup=health_lookup)
    status = str(row.get("status") or "").strip().lower()
    error_kind = str(row.get("error_kind") or "").strip().lower()
    status_code = int(row.get("last_status_code") or 0)
    cooldown_remaining_s = int(row.get("cooldown_remaining_s") or 0)
    return bool(
        cooldown_remaining_s > 0
        or status in {"cooldown", "backoff"}
        or error_kind in {"rate_limit", "forbidden", "legal"}
        or status_code in {403, 418, 429, 451}
    )


def _history_rows_for_exchange(frame: pd.DataFrame, exchange_key: Any) -> pd.DataFrame:
    normalized_exchange = _normalize_exchange_value(exchange_key)
    if frame is None or frame.empty or not normalized_exchange:
        return pd.DataFrame()
    working = _filter_frame_by_exchange_keys(frame, [normalized_exchange])
    if working is None or working.empty:
        return pd.DataFrame()
    ts_column = "\u65f6\u95f4" if "\u65f6\u95f4" in working.columns else "time" if "time" in working.columns else None
    if ts_column:
        working = working.assign(_ts_ms=_coerce_timestamp_series_ms(working[ts_column]))
        working = working.sort_values("_ts_ms").drop(columns="_ts_ms", errors="ignore")
    return working.reset_index(drop=True)


def _history_latest_row(frame: pd.DataFrame, exchange_key: Any) -> Dict[str, Any]:
    scoped = _history_rows_for_exchange(frame, exchange_key)
    if scoped.empty:
        return {}
    return dict(scoped.iloc[-1].to_dict())


def _history_change_pct(frame: pd.DataFrame, exchange_key: Any, value_column: str, window_minutes: int) -> Optional[float]:
    scoped = _history_rows_for_exchange(frame, exchange_key)
    if scoped.empty or value_column not in scoped.columns:
        return None
    working = scoped.assign(
        _ts_ms=_coerce_timestamp_series_ms(scoped["\u65f6\u95f4"] if "\u65f6\u95f4" in scoped.columns else pd.Series(dtype="object")),
        _value=pd.to_numeric(scoped[value_column], errors="coerce"),
    ).dropna(subset=["_ts_ms", "_value"])
    if len(working) < 2:
        return None
    latest = working.iloc[-1]
    latest_value = _payload_float(latest.get("_value"))
    latest_ts = _coerce_timestamp_ms(latest.get("_ts_ms"))
    if latest_value in (None, 0) or latest_ts is None:
        return None
    anchor_cutoff_ms = latest_ts - max(int(window_minutes), 1) * 60_000
    anchor_slice = working[working["_ts_ms"] <= float(anchor_cutoff_ms)]
    anchor_row = anchor_slice.iloc[-1] if not anchor_slice.empty else working.iloc[0]
    anchor_value = _payload_float(anchor_row.get("_value"))
    if anchor_value in (None, 0):
        return None
    return (float(latest_value) - float(anchor_value)) / float(anchor_value) * 100.0


def _history_range_pct(frame: pd.DataFrame, exchange_key: Any, value_column: str, window_minutes: int) -> Optional[float]:
    scoped = _history_rows_for_exchange(frame, exchange_key)
    if scoped.empty or value_column not in scoped.columns:
        return None
    working = scoped.assign(
        _ts_ms=_coerce_timestamp_series_ms(scoped["\u65f6\u95f4"] if "\u65f6\u95f4" in scoped.columns else pd.Series(dtype="object")),
        _value=pd.to_numeric(scoped[value_column], errors="coerce"),
    ).dropna(subset=["_ts_ms", "_value"])
    if working.empty:
        return None
    latest_ts = _coerce_timestamp_ms(working.iloc[-1].get("_ts_ms"))
    if latest_ts is None:
        return None
    window = working[working["_ts_ms"] >= float(latest_ts - max(int(window_minutes), 1) * 60_000)]
    if window.empty:
        window = working
    reference = _payload_float(window.iloc[0].get("_value"))
    if reference in (None, 0):
        return None
    max_value = pd.to_numeric(window["_value"], errors="coerce").max()
    min_value = pd.to_numeric(window["_value"], errors="coerce").min()
    if pd.isna(max_value) or pd.isna(min_value):
        return None
    return (float(max_value) - float(min_value)) / float(reference) * 100.0


def _history_trade_window_totals(
    frame: pd.DataFrame,
    *,
    now_ms: int,
    large_trade_threshold: float,
) -> Dict[str, Any]:
    if frame is None or frame.empty:
        return {}
    time_column = "\u65f6\u95f4" if "\u65f6\u95f4" in frame.columns else None
    if time_column is None or "\u540d\u4e49\u91d1\u989d" not in frame.columns:
        return {}
    working = frame.assign(
        _ts_ms=_coerce_timestamp_series_ms(frame[time_column]),
        _notional=pd.to_numeric(frame["\u540d\u4e49\u91d1\u989d"], errors="coerce").abs(),
        _side=frame.get("\u65b9\u5411", pd.Series("", index=frame.index)).astype(str).str.strip().str.lower(),
        _price=pd.to_numeric(frame.get("\u4ef7\u683c", pd.Series(dtype="float64")), errors="coerce"),
    ).dropna(subset=["_ts_ms", "_notional"])
    if working.empty:
        return {}
    trades: List[TradeEvent] = []
    for timestamp_ms, notional, side, price in working[["_ts_ms", "_notional", "_side", "_price"]].itertuples(
        index=False,
        name=None,
    ):
        trades.append(
            TradeEvent(
                exchange="",
                symbol="",
                side=str(side or ""),
                price=_payload_float(price),
                size=None,
                notional=_payload_float(notional),
                timestamp_ms=int(timestamp_ms or 0),
                source="history",
            )
        )
    return _compute_trade_window_totals(trades, now_ms=now_ms, large_trade_threshold=large_trade_threshold)


def _filter_signal_frame(frame: pd.DataFrame, *, min_notional: float, oi_threshold_pct: float) -> pd.DataFrame:
    if frame is None or frame.empty:
        return frame
    working = frame.copy()
    if "score" not in working.columns or "kind" not in working.columns:
        return working
    scores = pd.to_numeric(working["score"], errors="coerce").abs()
    kind_series = working["kind"].astype(str).str.lower()
    mask = pd.Series(True, index=working.index)
    if min_notional > 0:
        mask &= ~kind_series.isin(["large", "liquidation"]) | (scores >= float(min_notional))
    if oi_threshold_pct > 0:
        mask &= (kind_series != "oi") | (scores >= float(oi_threshold_pct))
    return working[mask].copy()


def _filter_event_frame(frame: pd.DataFrame, *, min_notional: float) -> pd.DataFrame:
    if frame is None or frame.empty or min_notional <= 0:
        return frame
    working = frame.copy()
    if "名义金额" not in working.columns:
        return working
    notionals = pd.to_numeric(working["名义金额"], errors="coerce").abs().fillna(0.0)
    return working[notionals >= float(min_notional)].copy()


def _filter_event_kind_frame(frame: pd.DataFrame, event_kind: str) -> pd.DataFrame:
    normalized_event_kind = _normalize_event_kind(event_kind)
    if frame is None or frame.empty or normalized_event_kind == "all":
        return frame
    working = frame.copy()
    type_series = (
        working.get("类型", pd.Series(dtype="object"))
        .astype(str)
        .str.strip()
        .str.lower()
    )
    return working[type_series == normalized_event_kind].copy()


def _filter_quality_frame(frame: pd.DataFrame, *, min_notional: float) -> pd.DataFrame:
    if frame is None or frame.empty or min_notional <= 0:
        return frame
    working = frame.copy()
    columns = [column for column in ("新增挂单额", "撤单额", "净变化") if column in working.columns]
    if not columns:
        return working
    magnitude = pd.Series(0.0, index=working.index)
    for column in columns:
        magnitude = magnitude.combine(
            pd.to_numeric(working[column], errors="coerce").abs().fillna(0.0),
            max,
        )
    return working[magnitude >= float(min_notional)].copy()


def _quality_row_to_event_record(row: Dict[str, Any]) -> Dict[str, Any]:
    added = abs(_payload_float(row.get("新增挂单额")) or 0.0)
    canceled = abs(_payload_float(row.get("撤单额")) or 0.0)
    near_added = abs(_payload_float(row.get("近价新增")) or 0.0)
    near_canceled = abs(_payload_float(row.get("近价撤单")) or 0.0)
    net = _payload_float(row.get("净变化")) or 0.0
    imbalance = _payload_float(row.get("盘口失衡(%)"))
    spoof_events = int(_payload_float(row.get("假挂单次数")) or 0)
    refill_events = int(_payload_float(row.get("补单次数")) or 0)
    best_bid = _payload_float(row.get("最优买价"))
    best_ask = _payload_float(row.get("最优卖价"))
    price = ((float(best_bid) + float(best_ask)) / 2.0) if best_bid is not None and best_ask is not None else (best_bid if best_bid is not None else best_ask)
    notional = max(added, canceled, near_added, near_canceled, abs(net))
    if imbalance is not None and abs(float(imbalance)) >= 1.0:
        side_label = "买盘失衡" if float(imbalance) > 0 else "卖盘失衡"
    elif net > 0:
        side_label = "净加单"
    elif net < 0:
        side_label = "净撤单"
    elif refill_events > 0:
        side_label = "补单"
    elif spoof_events > 0:
        side_label = "假挂单"
    else:
        side_label = "盘口质量"
    tags: List[str] = []
    if imbalance is not None:
        tags.append(f"失衡 {float(imbalance):.2f}%")
    if spoof_events > 0:
        tags.append(f"假挂单 {spoof_events}")
    if refill_events > 0:
        tags.append(f"补单 {refill_events}")
    source = "quality_history"
    if tags:
        source = f"{source} | {' / '.join(tags[:3])}"
    return {
        "时间": row.get("时间"),
        "币种": row.get("币种"),
        "交易所键": row.get("交易所键"),
        "交易所": row.get("交易所"),
        "市场": row.get("市场"),
        "类型": "orderbook_quality",
        "合约": row.get("合约"),
        "方向": side_label,
        "价格": price,
        "数量": None,
        "名义金额": notional,
        "来源": source,
    }


def _quality_frame_to_event_frame(frame: pd.DataFrame, *, limit: int = 3000) -> pd.DataFrame:
    columns = ["时间", "币种", "交易所键", "交易所", "市场", "类型", "合约", "方向", "价格", "数量", "名义金额", "来源"]
    if frame is None or frame.empty:
        return pd.DataFrame(columns=columns)
    frame_columns = list(frame.columns)
    records = [
        _quality_row_to_event_record({column: value for column, value in zip(frame_columns, row_values)})
        for row_values in frame.itertuples(index=False, name=None)
    ]
    if not records:
        return pd.DataFrame(columns=columns)
    event_frame = pd.DataFrame(records, columns=columns)
    if "时间" in event_frame.columns:
        event_frame = event_frame.sort_values("时间", ascending=False, na_position="last")
    return event_frame.head(max(int(limit or 0), 0)).reset_index(drop=True)


def _merge_event_and_quality_frames(event_frame: pd.DataFrame, quality_frame: pd.DataFrame, *, limit: int = 3000) -> pd.DataFrame:
    columns = ["时间", "币种", "交易所键", "交易所", "市场", "类型", "合约", "方向", "价格", "数量", "名义金额", "来源"]
    records: List[Dict[str, Any]] = []
    if isinstance(event_frame, pd.DataFrame) and not event_frame.empty:
        records.extend(event_frame.reindex(columns=columns).to_dict("records"))
    quality_event_frame = _quality_frame_to_event_frame(quality_frame, limit=limit)
    if not quality_event_frame.empty:
        records.extend(quality_event_frame.reindex(columns=columns).to_dict("records"))
    if not records:
        return pd.DataFrame(columns=columns)
    merged = pd.DataFrame(records, columns=columns)
    if "时间" in merged.columns:
        merged = merged.sort_values("时间", ascending=False, na_position="last")
    if {"时间", "交易所键", "市场", "类型", "合约", "方向", "名义金额"}.issubset(merged.columns):
        merged = merged.drop_duplicates(subset=["时间", "交易所键", "市场", "类型", "合约", "方向", "名义金额"], keep="first")
    return merged.head(max(int(limit or 0), 0)).reset_index(drop=True)


def _normalize_exchange_value(value: Any) -> str:
    raw = str(value or "").strip().lower()
    if not raw:
        return ""
    if raw in EXCHANGE_ORDER:
        return raw
    for exchange_key, exchange_title in EXCHANGE_TITLE_MAP.items():
        if raw == str(exchange_title or "").strip().lower():
            return exchange_key
    alias_map = {
        "binance": "binance",
        "bybit": "bybit",
        "okx": "okx",
        "hyperliquid": "hyperliquid",
    }
    return alias_map.get(raw, "")


def _normalize_market_value(value: Any) -> str:
    raw = str(value or "").strip().lower()
    if raw in {"spot", "\u73b0\u8d27"}:
        return "spot"
    if raw in {"perp", "futures", "contract", "\u5408\u7ea6", "\u6c38\u7eed", "\u671f\u8d27"}:
        return "perp"
    return raw


def _coerce_timestamp_ms(value: Any) -> Optional[int]:
    numeric = _payload_float(value)
    if numeric is not None and numeric > 0:
        return int(numeric)
    try:
        parsed = pd.to_datetime(value, errors="coerce")
    except Exception:
        return None
    if parsed is None or pd.isna(parsed):
        return None
    try:
        return int(parsed.timestamp() * 1000)
    except Exception:
        return None


def _coerce_timestamp_series_ms(series: pd.Series) -> pd.Series:
    numeric = pd.to_numeric(series, errors="coerce")
    if numeric.notna().any():
        max_abs = float(numeric.abs().max() or 0.0)
        if max_abs >= 1e17:
            return numeric / 1_000_000.0
        if max_abs >= 1e14:
            return numeric / 1_000.0
        if 0 < max_abs < 1e11:
            return numeric * 1000.0
        return numeric
    parsed = pd.to_datetime(series, errors="coerce")
    converted = pd.Series(float("nan"), index=series.index, dtype="float64")
    valid = parsed.notna()
    if valid.any():
        converted.loc[valid] = parsed.loc[valid].astype("int64") / 1_000_000.0
    return converted


def _filter_frame_by_exchange_keys(frame: pd.DataFrame, exchange_keys: List[str]) -> pd.DataFrame:
    normalized_exchange_keys = _normalize_exchange_keys(exchange_keys)
    if frame is None or frame.empty or not normalized_exchange_keys:
        return frame
    working = frame.copy()
    candidates = [column for column in ("exchange_key", "exchange", "\u4ea4\u6613\u6240\u952e", "\u4ea4\u6613\u6240") if column in working.columns]
    if not candidates:
        return working
    mask = pd.Series(False, index=working.index)
    for column in candidates:
        mask |= working[column].map(lambda value: _normalize_exchange_value(value) in normalized_exchange_keys)
    return working[mask].copy()


def _filter_frame_by_market_scope(frame: pd.DataFrame, market_scope: str) -> pd.DataFrame:
    normalized_market_scope = _normalize_market_scope(market_scope)
    if frame is None or frame.empty or normalized_market_scope == "merged":
        return frame
    working = frame.copy()
    candidates = [column for column in ("market", "\u5e02\u573a") if column in working.columns]
    if not candidates:
        return working
    mask = pd.Series(False, index=working.index)
    for column in candidates:
        mask |= working[column].map(lambda value: _normalize_market_value(value) == normalized_market_scope)
    return working[mask].copy()


def _filter_frame_since_ms(
    frame: pd.DataFrame,
    since_ms: Optional[int],
    *,
    candidate_columns: Optional[List[str]] = None,
) -> pd.DataFrame:
    if frame is None or frame.empty or since_ms in (None, 0):
        return frame
    working = frame.copy()
    candidates = [
        column
        for column in (candidate_columns or ["timestamp_ms", "time", "\u65f6\u95f4", "\u5f00\u59cb\u65f6\u95f4", "\u6700\u8fd1\u65f6\u95f4"])
        if column in working.columns
    ]
    if not candidates:
        return working
    mask = pd.Series(False, index=working.index)
    for column in candidates:
        mask |= _coerce_timestamp_series_ms(working[column]) >= float(since_ms)
    return working[mask].copy()


def _frame_max_timestamp_ms(frame: pd.DataFrame, *candidate_columns: str) -> Optional[int]:
    if frame is None or frame.empty:
        return None
    candidates = [column for column in candidate_columns if column in frame.columns]
    if not candidates:
        return None
    values: List[int] = []
    for column in candidates:
        series = _coerce_timestamp_series_ms(frame[column])
        if series.notna().any():
            values.append(int(series.max()))
    return max(values) if values else None


def _filter_records_by_exchange_keys(items: List[Dict[str, Any]], exchange_keys: List[str]) -> List[Dict[str, Any]]:
    normalized_exchange_keys = _normalize_exchange_keys(exchange_keys)
    if not items or not normalized_exchange_keys:
        return items
    filtered: List[Dict[str, Any]] = []
    for item in items:
        exchange_key = _normalize_exchange_value(
            item.get("exchange_key")
            or item.get("exchange")
            or item.get("\u4ea4\u6613\u6240\u952e")
            or item.get("\u4ea4\u6613\u6240")
        )
        if exchange_key in normalized_exchange_keys:
            filtered.append(item)
    return filtered


def _filter_records_by_market_scope(items: List[Dict[str, Any]], market_scope: str) -> List[Dict[str, Any]]:
    normalized_market_scope = _normalize_market_scope(market_scope)
    if not items or normalized_market_scope == "merged":
        return items
    filtered: List[Dict[str, Any]] = []
    for item in items:
        market = _normalize_market_value(item.get("market") or item.get("\u5e02\u573a"))
        if market == normalized_market_scope:
            filtered.append(item)
    return filtered


def _filter_records_since_ms(items: List[Dict[str, Any]], since_ms: Optional[int]) -> List[Dict[str, Any]]:
    if not items or since_ms in (None, 0):
        return items
    filtered: List[Dict[str, Any]] = []
    for item in items:
        timestamp_ms = None
        for key in ("timestamp_ms", "time", "\u65f6\u95f4", "\u5f00\u59cb\u65f6\u95f4", "\u6700\u8fd1\u65f6\u95f4"):
            if key in item:
                timestamp_ms = _coerce_timestamp_ms(item.get(key))
                if timestamp_ms is not None:
                    break
        if timestamp_ms is None or timestamp_ms >= int(since_ms):
            filtered.append(item)
    return filtered


def _extract_first_exchange_key(value: Any) -> str:
    raw = str(value or "").strip()
    if not raw:
        return ""
    direct = _normalize_exchange_value(raw)
    if direct:
        return direct
    normalized = raw.replace("/", " ").replace("|", " ").replace(",", " ").replace("、", " ")
    for part in normalized.split():
        exchange_key = _normalize_exchange_value(part)
        if exchange_key:
            return exchange_key
    return ""


def _normalize_coin_symbol(value: Any) -> str:
    raw = str(value or "").strip().upper()
    if not raw:
        return ""
    normalized = (
        raw.replace("/", "")
        .replace("-", "")
        .replace("_", "")
        .replace("USDT", "")
        .replace("USD", "")
        .replace("PERP", "")
        .strip()
    )
    compact = "".join(ch for ch in normalized if ch.isalnum())
    return compact


def _is_major_workbench_coin(value: Any) -> bool:
    return _normalize_coin_symbol(value) in set(DEFAULT_MAJOR_WORKBENCH_COINS)


def _attach_selection_column(
    frame: pd.DataFrame,
    *,
    coin: str,
    exchange_columns: Optional[List[str]] = None,
    fallback_exchange: str = "",
) -> pd.DataFrame:
    if frame is None or frame.empty:
        return frame
    if "__selection" in frame.columns:
        return frame
    candidates = [
        column
        for column in (exchange_columns or ["exchange_key", "exchange", "交易所键", "交易所", "主交易所键", "主交易所", "偏离交易所"])
        if column in frame.columns
    ]
    if not candidates and not fallback_exchange:
        return frame
    working = frame.copy()
    selections: List[Optional[Dict[str, Any]]] = []
    for row in working.to_dict("records"):
        row_coin = (
            _normalize_coin_symbol(row.get("coin"))
            or _normalize_coin_symbol(row.get("币种"))
            or _normalize_coin_symbol(row.get("交易对"))
            or _normalize_coin_symbol(coin)
        )
        exchange_key = ""
        for column in candidates:
            exchange_key = _extract_first_exchange_key(row.get(column))
            if exchange_key:
                break
        payload: Dict[str, Any] = {"coin": row_coin or str(coin or "").upper()}
        if exchange_key:
            payload["exchange"] = exchange_key
        elif fallback_exchange:
            payload["exchange"] = fallback_exchange
        selections.append(payload)
    working["__selection"] = selections
    return working


def _find_column_by_tokens(
    columns: List[Any],
    *,
    includes: List[str],
    excludes: Optional[List[str]] = None,
) -> str:
    exclude_tokens = [str(token) for token in (excludes or []) if str(token)]
    for column in columns or []:
        text = str(column or "")
        if not text:
            continue
        if any(token not in text for token in includes):
            continue
        if any(token in text for token in exclude_tokens):
            continue
        return text
    return ""


def _filter_persisted_events(events: List[Any]) -> List[Any]:
    filtered: List[Any] = []
    for event in events or []:
        category = str(getattr(event, "category", "") or "").strip().lower()
        notional = float(getattr(event, "notional", 0.0) or 0.0)
        if category == "orderbook_quality":
            continue
        if category == "trade":
            if abs(notional) < PERSISTED_EVENT_MIN_NOTIONAL:
                continue
        elif category in {"liquidation", "oi"}:
            if abs(notional) < PERSISTED_EVENT_MIN_NOTIONAL:
                continue
        elif abs(notional) > 0 and abs(notional) < PERSISTED_EVENT_MIN_NOTIONAL:
            notional = float(getattr(event, "notional", 0.0) or 0.0)
            continue
        filtered.append(event)
    return filtered


def _filter_persisted_quality_points(points: List[Any]) -> List[Any]:
    filtered: List[Any] = []
    for point in points or []:
        added_notional = float(getattr(point, "added_notional", 0.0) or 0.0)
        canceled_notional = float(getattr(point, "canceled_notional", 0.0) or 0.0)
        near_added = float(getattr(point, "near_added_notional", 0.0) or 0.0)
        near_canceled = float(getattr(point, "near_canceled_notional", 0.0) or 0.0)
        imbalance_pct = abs(float(getattr(point, "imbalance_pct", 0.0) or 0.0))
        spoof_events = int(getattr(point, "spoof_events", 0) or 0)
        refill_events = int(getattr(point, "refill_events", 0) or 0)
        max_notional = max(abs(added_notional), abs(canceled_notional), abs(near_added), abs(near_canceled))
        if max_notional >= PERSISTED_QUALITY_MIN_NOTIONAL:
            filtered.append(point)
            continue
        if spoof_events > 0 or refill_events > 0:
            filtered.append(point)
            continue
        if imbalance_pct >= PERSISTED_QUALITY_IMBALANCE_PCT:
            filtered.append(point)
            continue
    return filtered


def _safe_mean(values: List[float]) -> Optional[float]:
    filtered = [float(item) for item in values if item is not None]
    if not filtered:
        return None
    return sum(filtered) / len(filtered)


def _safe_median(values: List[float]) -> Optional[float]:
    filtered = [float(item) for item in values if item is not None]
    if not filtered:
        return None
    return float(statistics.median(filtered))


def _safe_numeric_series_mean(series: Any) -> Optional[float]:
    numeric = pd.to_numeric(series, errors="coerce").dropna()
    if numeric.empty:
        return None
    return float(numeric.sum() / len(numeric))


def _safe_numeric_series_median(series: Any) -> Optional[float]:
    numeric = pd.to_numeric(series, errors="coerce").dropna()
    if numeric.empty:
        return None
    return float(statistics.median(float(value) for value in numeric.tolist()))


def _normalize_scalar(value: Any) -> Any:
    if value is None:
        return None
    try:
        if pd.isna(value):
            return None
    except Exception:
        pass
    if isinstance(value, pd.Timestamp):
        return int(value.timestamp() * 1000)
    if isinstance(value, (pd.Series, pd.Index)):
        return [_normalize_scalar(item) for item in value.tolist()]
    if np is not None:
        if isinstance(value, np.ndarray):
            return [_normalize_scalar(item) for item in value.tolist()]
        if isinstance(value, np.generic):
            return _normalize_scalar(value.item())
    if isinstance(value, dict):
        return {str(key): _normalize_scalar(item) for key, item in value.items()}
    if isinstance(value, (list, tuple)):
        return [_normalize_scalar(item) for item in value]
    return value


def _serialize_plotly_figure(figure: Any) -> Any:
    if figure is None:
        return None
    return _standardize_payload_metrics(figure.to_plotly_json())


def _with_standard_metric_aliases(record: Dict[str, Any]) -> Dict[str, Any]:
    working = dict(record or {})
    reference_price = _payload_float(working.get("reference_price"))
    if reference_price is None:
        for key in ("market_reference_price", "spot_reference_price", "现货参考价", "合约最新价", "价格"):
            reference_price = _payload_float(working.get(key))
            if reference_price is not None:
                break
    if reference_price is not None:
        working.setdefault("reference_price", reference_price)
        working.setdefault("market_reference_price", reference_price)
    funding_bps = _row_funding_bps(working)
    if funding_bps is not None:
        working.setdefault("funding_bps", funding_bps)
        working.setdefault("perp_funding_bps", funding_bps)
        working.setdefault("Funding(bp)", funding_bps)
        working.setdefault("Funding(bps)", funding_bps)
    oi_notional = _row_oi_notional(working)
    if oi_notional is not None:
        working.setdefault("oi_notional_usdt", oi_notional)
        working.setdefault("perp_oi_notional", oi_notional)
        working.setdefault("open_interest_notional", oi_notional)
        working.setdefault("total_oi_notional", oi_notional)
        working.setdefault("OI总额", oi_notional)
        working.setdefault("OI金额", oi_notional)
    volume_24h_notional = _payload_float(working.get("volume_24h_notional"))
    if volume_24h_notional is None:
        for key in ("perp_volume_24h_notional", "spot_volume_24h_notional", "24h成交额", "24h现货成交额", "现货24h成交额", "合约24h成交额"):
            volume_24h_notional = _payload_float(working.get(key))
            if volume_24h_notional is not None:
                break
    if volume_24h_notional is not None:
        working.setdefault("volume_24h_notional", volume_24h_notional)
        working.setdefault("24h成交额", volume_24h_notional)
    for canonical_key, legacy_key in (
        ("price_change_5m_pct", "5m%"),
        ("price_change_30m_pct", "30m%"),
        ("price_change_1h_pct", "1h%"),
        ("price_change_4h_pct", "4h%"),
        ("price_change_24h_pct", "24h%"),
    ):
        canonical_value = _payload_float(working.get(canonical_key))
        legacy_value = _payload_float(working.get(legacy_key))
        if canonical_value is None and legacy_value is not None:
            working.setdefault(canonical_key, legacy_value)
        elif canonical_value is not None and legacy_value is None:
            working.setdefault(legacy_key, canonical_value)
    for window in ("5m", "30m", "1h", "4h", "1d"):
        oi_canonical_key = f"oi_change_{window}_pct"
        oi_legacy_key = f"OI {window}(%)"
        oi_canonical_value = _payload_float(working.get(oi_canonical_key))
        oi_legacy_value = _payload_float(working.get(oi_legacy_key))
        if oi_canonical_value is None and oi_legacy_value is not None:
            working.setdefault(oi_canonical_key, oi_legacy_value)
        elif oi_canonical_value is not None and oi_legacy_value is None:
            working.setdefault(oi_legacy_key, oi_canonical_value)
        volume_canonical_key = f"{window}_volume_notional"
        volume_legacy_key = f"{window}成交量"
        volume_canonical_value = _payload_float(working.get(volume_canonical_key))
        volume_legacy_value = _payload_float(working.get(volume_legacy_key))
        if volume_canonical_value is None and volume_legacy_value is not None:
            working.setdefault(volume_canonical_key, volume_legacy_value)
        elif volume_canonical_value is not None and volume_legacy_value is None:
            working.setdefault(volume_legacy_key, volume_canonical_value)
        for metric_name, legacy_key in (
            ("large_notional", f"{window}大额成交额"),
            ("large_buy_notional", f"{window}大额买入额"),
            ("large_sell_notional", f"{window}大额卖出额"),
            ("large_count", f"{window}大额成交笔数"),
        ):
            canonical_key = f"{window}_{metric_name}"
            canonical_value = _payload_float(working.get(canonical_key))
            legacy_value = _payload_float(working.get(legacy_key))
            if canonical_value is None and legacy_value is not None:
                working.setdefault(canonical_key, legacy_value)
            elif canonical_value is not None and legacy_value is None:
                working.setdefault(legacy_key, canonical_value)
    exchange_key = str(
        working.get("exchange_key")
        or working.get("交易所键")
        or working.get("主交易所键")
        or ""
    ).strip().lower()
    if exchange_key:
        working.setdefault("exchange_key", exchange_key)
        working.setdefault("交易所键", exchange_key)
        working.setdefault("主交易所键", exchange_key)
    exchange_name = str(
        working.get("exchange")
        or working.get("交易所")
        or working.get("主交易所")
        or ""
    ).strip()
    if exchange_name:
        working.setdefault("exchange", exchange_name)
        working.setdefault("交易所", exchange_name)
        working.setdefault("主交易所", exchange_name)
    signal = str(working.get("signal") or working.get("信号") or "").strip()
    if signal:
        working.setdefault("signal", signal)
        working.setdefault("信号", signal)
    sentiment_score = _payload_float(working.get("sentiment_score"))
    if sentiment_score is None:
        sentiment_score = _payload_float(working.get("情绪评分"))
    if sentiment_score is not None:
        working.setdefault("sentiment_score", sentiment_score)
        working.setdefault("情绪评分", sentiment_score)
    event_count = working.get("event_count")
    if event_count is None:
        event_count = working.get("事件数")
    if event_count is not None:
        normalized_event_count = _normalize_scalar(event_count)
        working.setdefault("event_count", normalized_event_count)
        working.setdefault("事件数", normalized_event_count)
    total_notional = _payload_float(working.get("total_notional"))
    if total_notional is None:
        total_notional = _payload_float(working.get("总名义金额"))
    if total_notional is not None:
        working.setdefault("total_notional", total_notional)
        working.setdefault("总名义金额", total_notional)
    long_notional = _payload_float(working.get("long_notional"))
    if long_notional is None:
        long_notional = _payload_float(working.get("多头爆仓额"))
    if long_notional is not None:
        working.setdefault("long_notional", long_notional)
        working.setdefault("多头爆仓额", long_notional)
    short_notional = _payload_float(working.get("short_notional"))
    if short_notional is None:
        short_notional = _payload_float(working.get("空头爆仓额"))
    if short_notional is not None:
        working.setdefault("short_notional", short_notional)
        working.setdefault("空头爆仓额", short_notional)
    for canonical_key, legacy_keys in (
        ("last_timestamp_ms", ("最近时间", "latest_timestamp_ms")),
        ("first_timestamp_ms", ("最早时间", "first_timestamp_ms")),
        ("archive_sample_count", ("本地归档样本",)),
        ("archive_path", ("归档目录",)),
    ):
        canonical_value = working.get(canonical_key)
        if canonical_value in (None, ""):
            for legacy_key in legacy_keys:
                legacy_value = working.get(legacy_key)
                if legacy_value not in (None, ""):
                    working.setdefault(canonical_key, _normalize_scalar(legacy_value))
                    break
        else:
            for legacy_key in legacy_keys:
                working.setdefault(legacy_key, _normalize_scalar(canonical_value))
    return working


def _standardize_payload_metrics(value: Any) -> Any:
    if isinstance(value, dict):
        normalized = {str(key): _standardize_payload_metrics(item) for key, item in value.items()}
        return _with_standard_metric_aliases(normalized)
    if isinstance(value, list):
        return [_standardize_payload_metrics(item) for item in value]
    if isinstance(value, tuple):
        return [_standardize_payload_metrics(item) for item in value]
    return _normalize_scalar(value)


def _frame_to_records(frame: pd.DataFrame, *, limit: Optional[int] = None) -> List[Dict[str, Any]]:
    if frame is None or frame.empty:
        return []
    selected = frame.head(limit) if limit is not None else frame
    selected = canonicalize_market_frame_columns(selected.copy())
    columns = [str(column) for column in selected.columns]
    rows: List[Dict[str, Any]] = []
    for row_values in selected.itertuples(index=False, name=None):
        normalized = {column: _normalize_scalar(value) for column, value in zip(columns, row_values)}
        rows.append(_with_standard_metric_aliases(normalized))
    return rows


def _load_ui_preferences_snapshot() -> Dict[str, Any]:
    try:
        loaded = json.loads(LOCAL_UI_PREFERENCES_PATH.read_text(encoding="utf-8"))
    except (FileNotFoundError, json.JSONDecodeError, OSError):
        return {}
    return loaded if isinstance(loaded, dict) else {}


def _save_ui_preferences_snapshot(updates: Dict[str, Any]) -> Dict[str, Any]:
    existing = _load_ui_preferences_snapshot()
    merged = dict(existing)
    for key, value in (updates or {}).items():
        if value is None:
            merged.pop(str(key), None)
        else:
            merged[str(key)] = value
    LOCAL_UI_PREFERENCES_PATH.write_text(json.dumps(merged, ensure_ascii=False, indent=2), encoding="utf-8")
    return merged


def _load_custom_alert_rules(preferences: Optional[Dict[str, Any]] = None) -> List[Dict[str, Any]]:
    source = preferences if isinstance(preferences, dict) else _load_ui_preferences_snapshot()
    raw_rules = source.get("custom_alert_rules", [])
    if isinstance(raw_rules, str):
        try:
            raw_rules = json.loads(raw_rules)
        except json.JSONDecodeError:
            raw_rules = []
    if not isinstance(raw_rules, list):
        return []
    rules: List[Dict[str, Any]] = []
    for index, item in enumerate(raw_rules, start=1):
        if not isinstance(item, dict):
            continue
        rule = dict(item)
        label = str(rule.get("label") or rule.get("name") or f"Custom Rule {index}").strip()
        if not label:
            continue
        rule["id"] = str(rule.get("id") or f"custom_rule_{index}").strip() or f"custom_rule_{index}"
        rule["label"] = label
        rule["enabled"] = bool(rule.get("enabled", True))
        rule["direction"] = normalize_request_choice(rule.get("direction"), allowed=("buy", "sell", "both"), default="both")
        rule["price_window"] = _normalize_time_window(rule.get("price_window") or "5m")
        rule["large_window"] = _normalize_monitor_whale_window(rule.get("large_window") or "5m")
        rule["oi_window"] = _normalize_monitor_oi_window(rule.get("oi_window") or "1h")
        rule["volume_ratio_window"] = _normalize_time_window(rule.get("volume_ratio_window") or "30m")
        for float_key in (
            "price_gte",
            "price_lte",
            "price_abs_gte",
            "large_notional_gte",
            "large_buy_notional_gte",
            "large_sell_notional_gte",
            "oi_gte",
            "oi_lte",
            "oi_abs_gte",
            "volume_ratio_gte",
        ):
            if float_key in rule:
                rule[float_key] = _payload_float(rule.get(float_key))
        tags = rule.get("tags", [])
        if isinstance(tags, str):
            tags = [token.strip() for token in tags.replace("|", ",").split(",") if token.strip()]
        rule["tags"] = [str(tag).strip() for tag in tags if str(tag).strip()]
        rules.append(rule)
    return rules


def _payload_float(value: Any) -> Optional[float]:
    try:
        if value is None or pd.isna(value):
            return None
    except Exception:
        if value is None:
            return None
    try:
        return float(value)
    except (TypeError, ValueError):
        return None


def _compute_trade_window_totals(
    trades: List[TradeEvent],
    *,
    now_ms: int,
    large_trade_threshold: float,
) -> Dict[str, Any]:
    metrics: Dict[str, Any] = {}
    serialized: List[Dict[str, Any]] = []
    for event in trades or []:
        timestamp_ms = int(getattr(event, "timestamp_ms", 0) or 0)
        if timestamp_ms <= 0:
            continue
        notional = float(abs(getattr(event, "notional", 0.0) or 0.0))
        side = str(getattr(event, "side", "") or "").strip().lower()
        serialized.append(
            {
                "timestamp_ms": timestamp_ms,
                "notional": notional,
                "side": side,
                "price": _payload_float(getattr(event, "price", None)),
            }
        )
    for window, minutes in MONITOR_WHALE_WINDOWS.items():
        since_ms = now_ms - int(minutes) * 60_000
        window_items = [item for item in serialized if int(item["timestamp_ms"]) >= since_ms]
        large_items = [item for item in window_items if float(item["notional"]) >= float(large_trade_threshold or 0.0)]
        buy_large = sum(float(item["notional"]) for item in large_items if item["side"] == "buy")
        sell_large = sum(float(item["notional"]) for item in large_items if item["side"] == "sell")
        total_large = buy_large + sell_large
        metrics[f"{window}_count"] = len(window_items)
        metrics[f"{window}_large_count"] = len(large_items)
        metrics[f"{window}_large_notional"] = total_large or None
        metrics[f"{window}_large_buy_notional"] = buy_large or None
        metrics[f"{window}_large_sell_notional"] = sell_large or None
        metrics[f"{window}_last_trade_at_ms"] = _best_updated_at_ms(*[item["timestamp_ms"] for item in window_items])
    metrics["latest_trade_at_ms"] = _best_updated_at_ms(*[item["timestamp_ms"] for item in serialized])
    return metrics


def _compute_candle_window_notional(candles: List[Any], steps: int) -> Optional[float]:
    if not candles:
        return None
    selected = list(candles)[-max(1, int(steps)) :]
    total = 0.0
    seen = False
    for candle in selected:
        close_price = _payload_float(getattr(candle, "close", None))
        volume = _payload_float(getattr(candle, "volume", None))
        if close_price is None or volume is None:
            continue
        total += float(close_price) * float(volume)
        seen = True
    return total if seen else None


def _build_monitor_row_tags(row: Dict[str, Any]) -> List[str]:
    tags: List[str] = []
    move_5m = _row_price_change_pct(row, "5m") or 0.0
    move_30m = _row_price_change_pct(row, "30m") or 0.0
    move_1h = _row_price_change_pct(row, "1h") or 0.0
    oi_1h = _row_oi_change_pct(row, "1h") or 0.0
    funding_bps = _row_funding_bps(row) or 0.0
    large_5m = _row_window_large_metric(row, "5m", "total") or 0.0
    buy_5m = _row_window_large_metric(row, "5m", "buy") or 0.0
    sell_5m = _row_window_large_metric(row, "5m", "sell") or 0.0
    volume_5m = _row_window_volume_notional(row, "5m") or 0.0
    volume_1h = _row_window_volume_notional(row, "1h") or 0.0
    if move_5m >= 3.0:
        tags.append("急拉")
    elif move_5m <= -3.0:
        tags.append("急跌")
    if abs(move_30m) >= 4.0 or abs(move_1h) >= 6.0:
        tags.append("持续单边")
    if large_5m >= 500_000 and buy_5m > sell_5m * 1.2:
        tags.append("大单扫货")
    elif large_5m >= 500_000 and sell_5m > buy_5m * 1.2:
        tags.append("大单砸盘")
    if volume_5m > 0 and volume_1h > 0:
        baseline = float(volume_1h) / 12.0
        if baseline > 0 and volume_5m >= baseline * 1.8:
            if move_5m >= 0.8:
                tags.append("放量上涨")
            elif move_5m <= -0.8:
                tags.append("放量下跌")
    if abs(oi_1h) >= 3.0:
        tags.append("OI放大")
    if abs(funding_bps) >= 12.0:
        tags.append("Funding极端")
    return tags


def _monitor_signal_label(tags: List[str], *, move_5m: float, oi_1h: float, funding_bps: float) -> str:
    if "急拉" in tags and "大单扫货" in tags:
        return "拉升联动"
    if "急跌" in tags and "大单砸盘" in tags:
        return "下杀联动"
    if "OI放大" in tags and abs(move_5m) >= 1.0:
        return "增仓推进"
    if "Funding极端" in tags:
        return "拥挤交易"
    if "放量上涨" in tags:
        return "放量上攻"
    if "放量下跌" in tags:
        return "放量回撤"
    if abs(move_5m) >= 3.0:
        return "价格异动"
    if abs(oi_1h) >= 3.0:
        return "OI异动"
    if abs(funding_bps) >= 12.0:
        return "Funding异动"
    return "观察"


def _monitor_trade_direction_label(side: Any) -> str:
    normalized = str(side or "").strip().lower()
    if normalized == "buy":
        return "主动买入"
    if normalized == "sell":
        return "主动卖出"
    return normalized or "-"


def _monitor_window_volume_ratio(row: Dict[str, Any], window: str) -> Optional[float]:
    minutes = TIME_WINDOW_OPTIONS.get(_normalize_time_window(window))
    if not minutes:
        return None
    volume_value = _row_window_volume_notional(row, window)
    volume_24h = _row_volume_24h_notional(row)
    if volume_value is None or volume_24h is None or volume_24h <= 0:
        return None
    baseline = float(volume_24h) * (float(minutes) / 1440.0)
    if baseline <= 0:
        return None
    return float(volume_value) / baseline


def _monitor_window_anomaly_label(row: Dict[str, Any], *, window: str) -> str:
    normalized_window = _normalize_time_window(window)
    move_value = _row_price_change_pct(row, normalized_window) or 0.0
    large_value = _row_window_large_metric(row, normalized_window, "total") or 0.0
    buy_value = _row_window_large_metric(row, normalized_window, "buy") or 0.0
    sell_value = _row_window_large_metric(row, normalized_window, "sell") or 0.0
    trade_count = int(_row_window_large_metric(row, normalized_window, "count") or 0)
    volume_ratio = _monitor_window_volume_ratio(row, normalized_window) or 0.0
    if large_value >= 500_000.0 and buy_value > sell_value * 1.2:
        return "大单扫货"
    if large_value >= 500_000.0 and sell_value > buy_value * 1.2:
        return "大单砸盘"
    if trade_count >= 3 and large_value >= 500_000.0:
        return "连续放量"
    if move_value >= 3.0:
        return "急拉"
    if move_value <= -3.0:
        return "急跌"
    if volume_ratio >= 1.8 and move_value >= 0.8:
        return "放量上涨"
    if volume_ratio >= 1.8 and move_value <= -0.8:
        return "放量下跌"
    tags = [item.strip() for item in str(row.get("异动标签") or "").split("/") if item.strip() and item.strip() != "-"]
    return tags[0] if tags else "观察"


def _monitor_oi_price_divergence_label(row: Dict[str, Any]) -> str:
    oi_1h = _row_oi_change_pct(row, "1h") or 0.0
    price_24h = _row_price_change_pct(row, "24h")
    if price_24h is None:
        price_24h = _row_price_change_pct(row, "4h") or 0.0
    if oi_1h >= 3.0 and price_24h >= 2.0:
        return "上涨增仓"
    if oi_1h >= 3.0 and price_24h <= -2.0:
        return "下跌增仓"
    if oi_1h <= -3.0 and price_24h >= 2.0:
        return "逼空回补"
    if oi_1h <= -3.0 and price_24h <= -2.0:
        return "踩踏减仓"
    if abs(oi_1h) >= 3.0:
        return "OI背离观察"
    return "同步"


def _monitor_oi_volume_linkage_label(row: Dict[str, Any]) -> str:
    oi_1h = _row_oi_change_pct(row, "1h") or 0.0
    large_1h = _row_window_large_metric(row, "1h", "total") or 0.0
    volume_ratio = _monitor_window_volume_ratio(row, "1h") or 0.0
    if abs(oi_1h) >= 3.0 and (large_1h >= 1_000_000.0 or volume_ratio >= 2.0):
        return "OI/成交共振"
    if abs(oi_1h) >= 3.0 and (large_1h >= 500_000.0 or volume_ratio >= 1.4):
        return "OI/Volume 联动"
    if abs(oi_1h) >= 3.0:
        return "OI独立异动"
    return "常态"


def _monitor_oi_window_column(oi_window: str) -> str:
    return f"OI {_normalize_monitor_oi_window(oi_window)}(%)"


def _monitor_oi_delta_column(oi_window: str) -> str:
    return f"OI {_normalize_monitor_oi_window(oi_window)}变化额"


def _monitor_whale_window_columns(whale_window: str) -> Dict[str, str]:
    normalized_window = _normalize_monitor_whale_window(whale_window)
    return {
        "window": normalized_window,
        "total": f"{normalized_window}大额成交额",
        "buy": f"{normalized_window}大额买入额",
        "sell": f"{normalized_window}大额卖出额",
        "count": f"{normalized_window}大额成交笔数",
    }


def _monitor_item_coin(item: Any, default_coin: str = "") -> str:
    if not hasattr(item, "get"):
        return _normalize_coin_symbol(default_coin)
    selection = item.get("__selection") if isinstance(item.get("__selection"), dict) else {}
    symbol_text = str(item.get("symbol") or "").upper().strip()
    for suffix in ("-USDT-SWAP", "_USDT_SWAP", "USDT-SWAP", "USDT_SWAP", "-SWAP", "_SWAP", "SWAP", "-PERP", "_PERP", "PERP"):
        if symbol_text.endswith(suffix):
            symbol_text = symbol_text[: -len(suffix)]
            break
    return (
        _normalize_coin_symbol(selection.get("coin"))
        or _normalize_coin_symbol(item.get("coin"))
        or _normalize_coin_symbol(item.get("币种"))
        or _normalize_coin_symbol(symbol_text)
        or _normalize_coin_symbol(item.get("symbol"))
        or _normalize_coin_symbol(default_coin)
    )


def _monitor_match_anomaly_type(
    row: Dict[str, Any],
    *,
    anomaly_type: str,
    time_window: str,
    whale_window: str,
    oi_window: str,
) -> bool:
    normalized_type = _normalize_monitor_anomaly_type(anomaly_type)
    if normalized_type == "all":
        return True
    move_value = _row_price_change_pct(row, _normalize_time_window(time_window)) or 0.0
    buy_value = _row_window_large_metric(row, whale_window, "buy") or 0.0
    sell_value = _row_window_large_metric(row, whale_window, "sell") or 0.0
    oi_value = _row_oi_change_pct(row, oi_window) or 0.0
    if normalized_type == "price_up":
        return move_value > 0
    if normalized_type == "price_down":
        return move_value < 0
    if normalized_type == "whale_buy":
        return buy_value > sell_value and buy_value > 0
    if normalized_type == "whale_sell":
        return sell_value > buy_value and sell_value > 0
    if normalized_type == "oi_up":
        return oi_value > 0
    if normalized_type == "oi_down":
        return oi_value < 0
    return True


def _build_monitor_oi_window_rank_frame(
    frame: pd.DataFrame,
    *,
    top_n: int,
    oi_window: str,
    rank_mode: str,
) -> pd.DataFrame:
    columns = ["排名", "交易对", "合约持仓额(USDT)", "最新价格", "24h涨跌幅", "24h成交额", "所属交易所", "OI变化值", "OI变化率", "OI/Price 背离标签", "OI/Volume 联动标签", "__selection"]
    if frame is None or frame.empty:
        return pd.DataFrame(columns=columns)
    working = canonicalize_market_frame_columns(frame.copy())
    oi_pct_column = _monitor_oi_window_column(oi_window)
    oi_delta_column = _monitor_oi_delta_column(oi_window)
    normalized_rank_mode = str(rank_mode or "notional").strip().lower()
    if normalized_rank_mode == "delta" and oi_delta_column in working.columns:
        ranked = working.sort_values([oi_delta_column, "OI总额"], ascending=[False, False], na_position="last").head(top_n)
    elif normalized_rank_mode == "pct" and oi_pct_column in working.columns:
        ranked = working.sort_values([oi_pct_column, "OI总额"], ascending=[False, False], na_position="last").head(top_n)
    else:
        sort_column = oi_pct_column if oi_pct_column in working.columns else "OI 1h(%)"
        ranked = working.sort_values(["OI总额", sort_column], ascending=[False, False], na_position="last").head(top_n)
    rows: List[Dict[str, Any]] = []
    for record in ranked.to_dict("records"):
        coin = str(record.get("币种") or "").upper().strip()
        normalized_record = _with_standard_metric_aliases(dict(record))
        rows.append(
            {
                "交易对": f"{coin}USDT" if coin else "-",
                "合约持仓额(USDT)": _row_oi_notional(normalized_record),
                "最新价格": _row_last_price(normalized_record),
                "24h涨跌幅": _payload_float(normalized_record.get("24h%")),
                "24h成交额": _row_volume_24h_notional(normalized_record),
                "所属交易所": _row_exchange_name(normalized_record) or "-",
                "OI变化值": _payload_float(normalized_record.get(oi_delta_column) or normalized_record.get("OI变化额")),
                "OI变化率": _payload_float(normalized_record.get(oi_pct_column) or normalized_record.get("OI 1h(%)")),
                "OI/Price 背离标签": _monitor_oi_price_divergence_label(normalized_record),
                "OI/Volume 联动标签": _monitor_oi_volume_linkage_label(normalized_record),
                "__selection": normalized_record.get("__selection") or {"coin": coin, "exchange": _row_exchange_key(normalized_record)},
            }
        )
    return pd.DataFrame(_rank_records(rows), columns=columns)


def _build_monitor_oi_multi_window_rank_frame(frame: pd.DataFrame, *, top_n: int) -> pd.DataFrame:
    columns = ["排名", "交易对", "合约持仓额(USDT)", "OI 5m(%)", "OI 30m(%)", "OI 1h(%)", "OI 4h(%)", "OI 1d(%)", "所属交易所", "__selection"]
    if frame is None or frame.empty:
        return pd.DataFrame(columns=columns)
    working = canonicalize_market_frame_columns(frame.copy())
    ranked = (
        working.assign(
            _oi_multi_rank=(
                _series_abs_fill(working, "OI 5m(%)")
                + _series_abs_fill(working, "OI 30m(%)")
                + _series_abs_fill(working, "OI 1h(%)")
                + _series_abs_fill(working, "OI 4h(%)")
                + _series_abs_fill(working, "OI 1d(%)")
            )
        )
        .sort_values(["_oi_multi_rank", "OI总额"], ascending=[False, False], na_position="last")
        .head(top_n)
    )
    rows: List[Dict[str, Any]] = []
    for record in ranked.to_dict("records"):
        coin = str(record.get("币种") or "").upper().strip()
        normalized_record = _with_standard_metric_aliases(dict(record))
        rows.append(
            {
                "交易对": f"{coin}USDT" if coin else "-",
                "合约持仓额(USDT)": _row_oi_notional(normalized_record),
                "OI 5m(%)": _payload_float(normalized_record.get("OI 5m(%)")),
                "OI 30m(%)": _payload_float(normalized_record.get("OI 30m(%)")),
                "OI 1h(%)": _payload_float(normalized_record.get("OI 1h(%)")),
                "OI 4h(%)": _payload_float(normalized_record.get("OI 4h(%)")),
                "OI 1d(%)": _payload_float(normalized_record.get("OI 1d(%)")),
                "所属交易所": _row_exchange_name(normalized_record) or "-",
                "__selection": normalized_record.get("__selection") or {"coin": coin, "exchange": _row_exchange_key(normalized_record)},
            }
        )
    return pd.DataFrame(_rank_records(rows), columns=columns)


def _rank_records(rows: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    ranked: List[Dict[str, Any]] = []
    for index, row in enumerate(rows, start=1):
        payload = dict(row)
        payload["排名"] = index
        ranked.append(payload)
    return ranked


def _monitor_signal_score(row: Dict[str, Any]) -> float:
    move_5m = abs(_row_price_change_pct(row, "5m") or 0.0)
    move_30m = abs(_row_price_change_pct(row, "30m") or 0.0)
    oi_1h = abs(_row_oi_change_pct(row, "1h") or 0.0)
    funding_bps = abs(_row_funding_bps(row) or 0.0)
    large_5m = abs(_row_window_large_metric(row, "5m", "total") or 0.0)
    volume_24h = abs(_row_volume_24h_notional(row) or 0.0)
    return round(
        move_5m * 3.0
        + move_30m * 1.5
        + oi_1h * 1.8
        + min(funding_bps, 40.0) * 0.9
        + min(large_5m / 100_000.0, 12.0) * 1.5
        + min(volume_24h / 1_000_000.0, 20.0) * 0.4,
        2,
    )


def _aggregate_monitor_records(items: List[Dict[str, Any]], aggregate_mode: str) -> List[Dict[str, Any]]:
    normalized_mode = _normalize_monitor_aggregate_mode(aggregate_mode)
    if normalized_mode == "trade" or not items:
        return list(items or [])
    bucket_seconds = 1 if normalized_mode == "1s" else 5
    grouped: Dict[tuple, Dict[str, Any]] = {}
    for item in items or []:
        timestamp_ms = int(item.get("timestamp_ms") or 0)
        bucket_ms = (timestamp_ms // (bucket_seconds * 1000)) * bucket_seconds * 1000
        side = str(item.get("side") or "").strip().lower()
        exchange_key = _normalize_exchange_value(item.get("exchange_key") or item.get("exchange"))
        market = _normalize_market_value(item.get("market"))
        selection_coin = str(((item.get("__selection") or {}).get("coin") or "")).upper()
        group_key = (bucket_ms, exchange_key, market, side, selection_coin)
        payload = grouped.setdefault(
            group_key,
            {
                "timestamp_ms": bucket_ms,
                "exchange": item.get("exchange"),
                "exchange_key": exchange_key,
                "market": market,
                "side": side,
                "side_label": item.get("side_label"),
                "price": None,
                "size": 0.0,
                "notional": 0.0,
                "trade_count": 0,
                "__selection": item.get("__selection") or {},
            },
        )
        payload["trade_count"] = int(payload.get("trade_count") or 0) + 1
        payload["size"] = float(payload.get("size") or 0.0) + float(abs(item.get("size") or 0.0))
        payload["notional"] = float(payload.get("notional") or 0.0) + float(abs(item.get("notional") or 0.0))
        last_price = _payload_float(item.get("price"))
        if last_price is not None:
            payload["price"] = last_price
        payload["side_label"] = "买盘扫单" if side == "buy" else "卖盘砸盘" if side == "sell" else payload.get("side_label")
    return sorted(grouped.values(), key=lambda item: int(item.get("timestamp_ms") or 0), reverse=True)


def _confidence_score_from_label(label: Any) -> float:
    text = str(label or "").strip().lower()
    if "高" in text or "high" in text or "真值" in text:
        return 1.0
    if "中" in text or "medium" in text:
        return 0.65
    if "低" in text or "low" in text:
        return 0.3
    if "代理" in text:
        return 0.45
    return 0.5


def _confidence_label(score: Any) -> str:
    numeric = _payload_float(score)
    if numeric is None:
        return "中"
    if numeric >= 0.8:
        return "高"
    if numeric >= 0.5:
        return "中"
    return "低"


def _alert_bias_from_text(title: str, explanation: str) -> Optional[int]:
    text = f"{title} {explanation}".lower()
    bullish_keywords = ["偏多", "现货领先", "空头回补", "看多", "买墙", "多头推进", "吸收", "空头衰竭"]
    bearish_keywords = ["偏空", "流动性塌陷", "看空", "卖墙", "空头推进", "上方卖盘", "多头拥挤", "多头衰竭"]
    bullish_score = sum(1 for keyword in bullish_keywords if keyword in text)
    bearish_score = sum(1 for keyword in bearish_keywords if keyword in text)
    if bullish_score > bearish_score:
        return 1
    if bearish_score > bullish_score:
        return -1
    return None


def _select_panel_columns(frame: pd.DataFrame, limit: int = 12) -> List[str]:
    if frame is None or frame.empty:
        return []
    columns = [str(column) for column in frame.columns]
    if len(columns) <= limit:
        return columns
    preferred = [column for column in columns if column in ("时间", "交易所", "市场", "等级", "告警", "解释", "状态", "动作", "说明")]
    remaining = [column for column in columns if column not in preferred]
    return (preferred + remaining)[:limit]


def _panel_from_frame(
    panel_id: str,
    title: str,
    frame: pd.DataFrame,
    *,
    note: str = "",
    limit: int = 24,
    empty_text: str = "当前暂无样本。",
    data_source: str = "",
    updated_at_ms: Any = None,
    truth_level: str = "",
    compute_ms: Any = None,
) -> Dict[str, Any]:
    composed_note = str(note or "").strip()
    normalized_truth_level = str(truth_level or "").strip()
    if (frame is None or frame.empty) and not normalized_truth_level:
        normalized_truth_level = "sample_limited"
    meta = {
        "source": str(data_source or "").strip(),
        "updated_at_ms": _best_updated_at_ms(updated_at_ms),
        "truth_level": normalized_truth_level,
        "compute_ms": _payload_float(compute_ms),
    }
    if frame is None or frame.empty:
        return {
            "id": panel_id,
            "title": title,
            "note": composed_note,
            "meta": meta,
            "columns": [],
            "rows": [],
            "empty_text": empty_text,
        }
    normalized_frame = frame.copy()
    normalized_frame.columns = [str(column) for column in normalized_frame.columns]
    hidden_columns = [column for column in normalized_frame.columns if str(column).startswith("__")]
    selected_columns = [column for column in _select_panel_columns(normalized_frame) if column not in hidden_columns]
    selected_frame = normalized_frame[selected_columns + hidden_columns].copy()
    return {
        "id": panel_id,
        "title": title,
        "note": composed_note,
        "meta": meta,
        "columns": selected_columns,
        "rows": _frame_to_records(selected_frame, limit=limit),
        "empty_text": empty_text,
    }


def _panel_from_figure(
    panel_id: str,
    title: str,
    figure: Any,
    *,
    note: str = "",
    empty_text: str = "当前暂无图表样本。",
    data_source: str = "",
    updated_at_ms: Any = None,
    truth_level: str = "",
    compute_ms: Any = None,
) -> Dict[str, Any]:
    composed_note = str(note or "").strip()
    figure_json = _serialize_plotly_figure(figure)
    normalized_truth_level = str(truth_level or "").strip()
    if (figure_json is None or not list(figure_json.get("data") or [])) and not normalized_truth_level:
        normalized_truth_level = "sample_limited"
    meta = {
        "source": str(data_source or "").strip(),
        "updated_at_ms": _best_updated_at_ms(updated_at_ms),
        "truth_level": normalized_truth_level,
        "compute_ms": _payload_float(compute_ms),
    }
    return {
        "id": panel_id,
        "title": title,
        "note": composed_note,
        "meta": meta,
        "kind": "plotly",
        "figure": figure_json,
        "empty_text": empty_text,
    }


