def _attach_panel_meta(
    panels: List[Dict[str, Any]],
    *,
    data_source: str = "",
    updated_at_ms: Any = None,
    truth_level: str = "",
) -> List[Dict[str, Any]]:
    attached: List[Dict[str, Any]] = []
    for panel in panels or []:
        if not isinstance(panel, dict):
            continue
        cloned = dict(panel)
        meta = dict(cloned.get("meta") or {})
        if str(data_source or "").strip() and not str(meta.get("source") or "").strip():
            meta["source"] = str(data_source or "").strip()
        normalized_updated_at_ms = _best_updated_at_ms(updated_at_ms)
        if normalized_updated_at_ms and not _payload_float(meta.get("updated_at_ms")):
            meta["updated_at_ms"] = normalized_updated_at_ms
        if str(truth_level or "").strip() and not str(meta.get("truth_level") or "").strip():
            meta["truth_level"] = str(truth_level or "").strip()
        cloned["meta"] = meta
        attached.append(cloned)
    return attached


def _best_updated_at_ms(*values: Any) -> Optional[int]:
    candidates: List[int] = []
    for value in values:
        numeric = _payload_float(value)
        if numeric is not None and numeric > 0:
            candidates.append(int(numeric))
    return max(candidates) if candidates else None


def _build_data_meta(
    source: str,
    updated_at_ms: Any,
    *,
    truth_level: Any = "",
) -> Dict[str, Any]:
    normalized_ts = _best_updated_at_ms(updated_at_ms)
    meta = {
        "source": str(source or "").strip(),
        "updated_at_ms": normalized_ts,
        "stale_ms": (int(time.time() * 1000) - int(normalized_ts)) if normalized_ts else None,
    }
    normalized_truth_level = str(truth_level or "").strip()
    if normalized_truth_level:
        meta["truth_level"] = normalized_truth_level
    return meta


def _snapshot_mode(status: Any, timestamp_ms: Any) -> Dict[str, Any]:
    normalized_status = str(status or "").strip().lower()
    now_ms = int(time.time() * 1000)
    ts_ms = _best_updated_at_ms(timestamp_ms)
    stale_ms = (now_ms - int(ts_ms)) if ts_ms else None
    if normalized_status in {"ok", "synced", "live"}:
        mode = "realtime"
        truth_level = "ws_live"
    elif normalized_status in {"proxy", "degraded", "cooldown", "backoff"}:
        mode = "degraded"
        truth_level = "proxy"
    elif normalized_status in {"error", "idle"} and ts_ms:
        mode = "cache_only"
        truth_level = "rest_backfill"
    else:
        mode = "unavailable"
        truth_level = "sample_limited"
    return {"mode": mode, "truth_level": truth_level, "stale_ms": stale_ms}


def _compute_oi_change_pct_minutes(points: List[Any], minutes: int) -> Optional[float]:
    if len(points) < 2:
        return None

    def _oi_value(point: Any) -> Optional[float]:
        return _payload_float(getattr(point, "open_interest_notional", None) or getattr(point, "open_interest", None))

    ordered = [point for point in points if _oi_value(point) not in (None, 0)]
    if len(ordered) < 2:
        return None
    latest = ordered[-1]
    latest_ts = int(getattr(latest, "timestamp_ms", 0) or 0)
    latest_value = _oi_value(latest)
    if latest_value in (None, 0):
        return None
    cutoff_ms = latest_ts - max(1, int(minutes)) * 60_000
    reference = next((point for point in reversed(ordered[:-1]) if int(getattr(point, "timestamp_ms", 0) or 0) <= cutoff_ms), ordered[0])
    reference_value = _oi_value(reference)
    if reference_value in (None, 0):
        return None
    return (float(latest_value) - float(reference_value)) / float(reference_value) * 100.0


def _compute_oi_change_pct(points: List[Any], hours: int) -> Optional[float]:
    return _compute_oi_change_pct_minutes(points, max(1, int(hours)) * 60)


def _compute_trade_price_change_pct_minutes(trades: List[Any], minutes: int) -> Optional[float]:
    if len(trades) < 2:
        return None
    ordered = [
        trade
        for trade in trades
        if _payload_float(getattr(trade, "price", None) or (trade.get("price") if isinstance(trade, dict) else None)) not in (None, 0)
    ]
    if len(ordered) < 2:
        return None

    def _trade_ts(trade: Any) -> int:
        if isinstance(trade, dict):
            return int(trade.get("timestamp_ms") or 0)
        return int(getattr(trade, "timestamp_ms", 0) or 0)

    def _trade_price(trade: Any) -> Optional[float]:
        if isinstance(trade, dict):
            return _payload_float(trade.get("price"))
        return _payload_float(getattr(trade, "price", None))

    latest = ordered[-1]
    latest_ts = _trade_ts(latest)
    latest_price = _trade_price(latest)
    if latest_price in (None, 0):
        return None
    cutoff_ms = latest_ts - max(1, int(minutes)) * 60_000
    reference = next((trade for trade in reversed(ordered[:-1]) if _trade_ts(trade) <= cutoff_ms), ordered[0])
    reference_price = _trade_price(reference)
    if reference_price in (None, 0):
        return None
    return (float(latest_price) - float(reference_price)) / float(reference_price) * 100.0


def _aggregate_trades_to_candles(
    trades: List[Any],
    *,
    interval_minutes: int = 5,
    limit: Optional[int] = None,
) -> List[Candle]:
    if not trades:
        return []
    interval_ms = max(int(interval_minutes), 1) * 60_000
    buckets: Dict[int, Dict[str, float]] = {}

    for trade in sorted(trades, key=lambda item: int(getattr(item, "timestamp_ms", 0) or (item.get("timestamp_ms") if isinstance(item, dict) else 0) or 0)):
        if isinstance(trade, dict):
            timestamp_ms = int(trade.get("timestamp_ms") or 0)
            price = _payload_float(trade.get("price"))
            size = _payload_float(trade.get("size"))
            notional = _payload_float(trade.get("notional"))
        else:
            timestamp_ms = int(getattr(trade, "timestamp_ms", 0) or 0)
            price = _payload_float(getattr(trade, "price", None))
            size = _payload_float(getattr(trade, "size", None))
            notional = _payload_float(getattr(trade, "notional", None))
        if timestamp_ms <= 0 or price in (None, 0.0):
            continue
        bucket_ts = (timestamp_ms // interval_ms) * interval_ms
        entry = buckets.get(bucket_ts)
        if entry is None:
            entry = {
                "open": float(price),
                "high": float(price),
                "low": float(price),
                "close": float(price),
                "volume": 0.0,
            }
            buckets[bucket_ts] = entry
        else:
            entry["high"] = max(entry["high"], float(price))
            entry["low"] = min(entry["low"], float(price))
            entry["close"] = float(price)
        if size not in (None, 0.0):
            entry["volume"] += float(size)
        elif notional not in (None, 0.0):
            entry["volume"] += float(notional) / max(float(price), 1e-9)

    candles = [
        Candle(
            timestamp_ms=bucket_ts,
            open=row["open"],
            high=row["high"],
            low=row["low"],
            close=row["close"],
            volume=row["volume"],
        )
        for bucket_ts, row in sorted(buckets.items())
    ]
    if limit is not None and limit > 0:
        candles = candles[-int(limit):]
    return candles


def _compute_price_change_pct(candles: List[Any], hours: int) -> Optional[float]:
    if len(candles) < 2:
        return None
    ordered = [candle for candle in candles if _payload_float(getattr(candle, "close", None)) not in (None, 0)]
    if len(ordered) < 2:
        return None
    latest = ordered[-1]
    latest_ts = int(getattr(latest, "timestamp_ms", 0) or 0)
    latest_close = _payload_float(getattr(latest, "close", None))
    if latest_close in (None, 0):
        return None
    cutoff_ms = latest_ts - max(1, int(hours)) * 3_600_000
    reference = next((candle for candle in reversed(ordered[:-1]) if int(getattr(candle, "timestamp_ms", 0) or 0) <= cutoff_ms), ordered[0])
    reference_close = _payload_float(getattr(reference, "close", None))
    if reference_close in (None, 0):
        return None
    return (float(latest_close) - float(reference_close)) / float(reference_close) * 100.0


def _compute_price_change_pct_by_steps(candles: List[Any], steps_back: int) -> Optional[float]:
    ordered = [candle for candle in candles if _payload_float(getattr(candle, "close", None)) not in (None, 0)]
    if len(ordered) <= max(int(steps_back), 0):
        return None
    latest_close = _payload_float(getattr(ordered[-1], "close", None))
    reference_close = _payload_float(getattr(ordered[-(int(steps_back) + 1)], "close", None))
    if latest_close in (None, 0) or reference_close in (None, 0):
        return None
    return (float(latest_close) - float(reference_close)) / float(reference_close) * 100.0


