def _series_abs_fill(frame: pd.DataFrame, column: str) -> pd.Series:
    if frame is None or not isinstance(frame, pd.DataFrame):
        return pd.Series(dtype=float)
    if column not in frame.columns:
        return pd.Series(0.0, index=frame.index, dtype=float)
    return pd.to_numeric(frame[column], errors="coerce").abs().fillna(0.0)


def _compute_candle_range_pct(candles: List[Any], steps: int) -> Optional[float]:
    ordered = [candle for candle in candles if _payload_float(getattr(candle, "close", None)) not in (None, 0)]
    if not ordered:
        return None
    window = ordered[-max(int(steps), 1):]
    highs = [_payload_float(getattr(candle, "high", None)) for candle in window]
    lows = [_payload_float(getattr(candle, "low", None)) for candle in window]
    opens = [_payload_float(getattr(candle, "open", None)) for candle in window]
    valid_highs = [value for value in highs if value is not None]
    valid_lows = [value for value in lows if value is not None]
    reference = next((value for value in opens if value not in (None, 0)), None) or _payload_float(getattr(window[0], "close", None))
    if not valid_highs or not valid_lows or reference in (None, 0):
        return None
    return (max(valid_highs) - min(valid_lows)) / float(reference) * 100.0


def _compute_last_candle_range_pct(candles: List[Any]) -> Optional[float]:
    if not candles:
        return None
    return _compute_candle_range_pct(candles[-1:], 1)


def _estimate_delta_notional(current_notional: float | None, change_pct: float | None) -> Optional[float]:
    if current_notional in (None, 0) or change_pct is None:
        return None
    denominator = 1.0 + float(change_pct) / 100.0
    if abs(denominator) < 1e-9:
        return None
    anchor_notional = float(current_notional) / denominator
    return float(current_notional) - anchor_notional


def _signal_color(label: Any, score: Any = None) -> str:
    text = str(label or "").strip()
    score_value = _payload_float(score)
    if "偏多" in text or "现货领先" in text or "空头回补" in text:
        return "#2dd4bf"
    if "偏空" in text or "流动性塌陷" in text or "多头减仓" in text:
        return "#ff6b6b"
    if score_value is not None:
        if score_value >= 6.0:
            return "#34d399"
        if score_value <= -6.0:
            return "#fb7185"
    return "#67d1ff"


def _quadrant_bucket(label: Any) -> str:
    text = str(label or "").strip()
    if "多头主动加仓" in text:
        return "多头加仓"
    if "空头主动加仓" in text:
        return "空头加仓"
    if "空头回补" in text:
        return "空头回补"
    if "多头减仓" in text:
        return "多头减仓"
    return "中性"


def _start_of_local_day_ms() -> int:
    return int(pd.Timestamp.now().normalize().timestamp() * 1000)


def _resolve_liquidation_archive_window(window_key: str, now_ms: int) -> tuple[Optional[int], str, str]:
    normalized = normalize_request_choice(window_key, allowed=LIQUIDATION_ARCHIVE_WINDOWS, default="4h")
    if normalized == "30m":
        return now_ms - 30 * 60_000, "30m", "最近 30 分钟"
    if normalized == "today":
        return _start_of_local_day_ms(), "today", "今天"
    if normalized == "all":
        return None, "all", "全部本地缓存"
    return now_ms - 4 * 3_600_000, "4h", "最近 4 小时"


def _default_liquidation_stats_window_minutes(window_key: str, now_ms: int, since_ms: Optional[int]) -> int:
    normalized = str(window_key or "4h").strip().lower()
    if normalized == "30m":
        return 30
    if normalized == "4h":
        return 240
    if normalized == "today" and since_ms is not None:
        return max(30, min(24 * 60, int((now_ms - since_ms) / 60_000)))
    return 60


def _merge_liquidation_event_groups(*groups: List[LiquidationEvent]) -> List[LiquidationEvent]:
    merged: List[LiquidationEvent] = []
    seen: set[tuple[Any, ...]] = set()
    for group in groups:
        for event in sorted(list(group or []), key=lambda item: int(item.timestamp_ms or 0)):
            event_key = (
                str(event.exchange or ""),
                str(event.symbol or ""),
                int(event.timestamp_ms or 0),
                str(event.side or ""),
                round(float(event.price or 0.0), 6),
                round(float(event.size or 0.0), 6),
            )
            if event_key in seen:
                continue
            seen.add(event_key)
            merged.append(event)
    return merged


def _cluster_liquidation_events(
    events: List[LiquidationEvent],
    *,
    cluster_window_seconds: int = 30,
) -> List[Dict[str, Any]]:
    if not events:
        return []
    ordered = sorted(list(events), key=lambda item: int(item.timestamp_ms or 0))
    window_ms = max(int(cluster_window_seconds or 30), 5) * 1000
    clusters: List[Dict[str, Any]] = []
    current: Optional[Dict[str, Any]] = None
    for event in ordered:
        event_ts = int(event.timestamp_ms or 0)
        if current is None or event_ts - int(current["last_ts"]) > window_ms:
            if current is not None:
                clusters.append(current)
            current = {
                "start_ts": event_ts,
                "end_ts": event_ts,
                "last_ts": event_ts,
                "events": [],
                "exchanges": set(),
            }
        current["last_ts"] = event_ts
        current["end_ts"] = event_ts
        current["events"].append(event)
        current["exchanges"].add(str(event.exchange or "").strip().lower())
    if current is not None:
        clusters.append(current)
    return clusters


def _select_scope_liquidation_events(
    events: List[LiquidationEvent],
    *,
    scope: str = "all",
    cluster_window_seconds: int = 30,
) -> List[LiquidationEvent]:
    normalized_scope = _normalize_liquidation_scope(scope)
    if normalized_scope == "all":
        return sorted(list(events or []), key=lambda item: int(item.timestamp_ms or 0))
    selected: List[LiquidationEvent] = []
    for cluster in _cluster_liquidation_events(events or [], cluster_window_seconds=cluster_window_seconds):
        is_cross = len(cluster.get("exchanges") or set()) > 1
        if normalized_scope == "cross" and is_cross:
            selected.extend(cluster.get("events") or [])
        if normalized_scope == "single" and not is_cross:
            selected.extend(cluster.get("events") or [])
    return sorted(selected, key=lambda item: int(item.timestamp_ms or 0))


def _filter_liquidation_events_by_side(
    events: List[LiquidationEvent],
    *,
    side: str = "all",
) -> List[LiquidationEvent]:
    normalized_side = _normalize_liquidation_side(side)
    if normalized_side == "all":
        return sorted(list(events or []), key=lambda item: int(item.timestamp_ms or 0))
    return sorted(
        [
            event
            for event in events or []
            if str(event.side or "").strip().lower() == normalized_side
        ],
        key=lambda item: int(item.timestamp_ms or 0),
    )


def _build_liquidation_exchange_totals_frame(events: List[LiquidationEvent]) -> pd.DataFrame:
    if not events:
        return pd.DataFrame(columns=["交易所", "事件数", "总名义金额", "多头爆仓额", "空头爆仓额", "最近时间"])
    frame = pd.DataFrame(
        {
            "交易所": [event.exchange for event in events],
            "方向": [event.side for event in events],
            "名义金额": [event.notional or 0.0 for event in events],
            "时间": [pd.to_datetime(event.timestamp_ms, unit="ms") for event in events],
        }
    )
    grouped = frame.groupby("交易所", as_index=False).agg(
        事件数=("交易所", "size"),
        总名义金额=("名义金额", "sum"),
        最近时间=("时间", "max"),
    )
    long_notional = frame[frame["方向"] == "long"].groupby("交易所")["名义金额"].sum()
    short_notional = frame[frame["方向"] == "short"].groupby("交易所")["名义金额"].sum()
    grouped["多头爆仓额"] = grouped["交易所"].map(long_notional).fillna(0.0)
    grouped["空头爆仓额"] = grouped["交易所"].map(short_notional).fillna(0.0)
    return grouped.sort_values("总名义金额", ascending=False).reset_index(drop=True)


def _build_liquidation_price_zone_summary(
    events: List[LiquidationEvent],
    *,
    bucket_count: int = 10,
) -> Dict[str, Any]:
    valid_events = [
        event
        for event in (events or [])
        if _payload_float(getattr(event, "price", None)) not in (None, 0.0)
        and _payload_float(getattr(event, "notional", None)) not in (None, 0.0)
    ]
    if not valid_events:
        return {"zone_label": "-", "zone_notional": 0.0, "reference_price": None, "last_price": None}
    prices = [_payload_float(event.price) or 0.0 for event in valid_events]
    lower = min(prices)
    upper = max(prices)
    reference_price = prices[-1] if prices else None
    if lower <= 0 or upper <= 0:
        return {"zone_label": "-", "zone_notional": 0.0, "reference_price": reference_price, "last_price": reference_price}
    if math.isclose(lower, upper):
        zone_notional = sum(abs(_payload_float(event.notional) or 0.0) for event in valid_events)
        return {
            "zone_label": f"{lower:,.4f}",
            "zone_notional": zone_notional,
            "reference_price": reference_price,
            "last_price": reference_price,
        }
    bucket_total = max(int(bucket_count or 10), 4)
    step = max((upper - lower) / bucket_total, lower * 0.0005)
    buckets: Dict[int, Dict[str, float]] = {}
    for event in valid_events:
        price = _payload_float(event.price) or 0.0
        notional = abs(_payload_float(event.notional) or 0.0)
        index = min(bucket_total - 1, max(0, int((price - lower) / step)))
        bucket = buckets.setdefault(index, {"notional": 0.0, "min_price": price, "max_price": price})
        bucket["notional"] += notional
        bucket["min_price"] = min(bucket["min_price"], price)
        bucket["max_price"] = max(bucket["max_price"], price)
    best_bucket = max(buckets.values(), key=lambda item: float(item.get("notional") or 0.0))
    min_price = float(best_bucket.get("min_price") or 0.0)
    max_price = float(best_bucket.get("max_price") or min_price)
    zone_label = f"{min_price:,.4f} - {max_price:,.4f}" if not math.isclose(min_price, max_price) else f"{min_price:,.4f}"
    return {
        "zone_label": zone_label,
        "zone_notional": float(best_bucket.get("notional") or 0.0),
        "reference_price": reference_price,
        "last_price": reference_price,
    }


def _build_liquidation_map_heatmap_figure(rows: List[Dict[str, Any]], *, exchange_keys: Optional[List[str]] = None) -> go.Figure:
    figure = go.Figure()
    if not rows:
        figure.add_annotation(text="等待清算地图样本", showarrow=False, x=0.5, y=0.5, xref="paper", yref="paper")
        figure.update_layout(height=360, margin=dict(l=12, r=12, t=24, b=12))
        return figure
    frame = pd.DataFrame(rows)
    if frame.empty or "coin" not in frame.columns or "exchange_key" not in frame.columns:
        figure.add_annotation(text="等待清算地图样本", showarrow=False, x=0.5, y=0.5, xref="paper", yref="paper")
        figure.update_layout(height=360, margin=dict(l=12, r=12, t=24, b=12))
        return figure
    working = frame.copy()
    working["coin"] = working["coin"].astype(str).str.upper()
    working["exchange_key"] = working["exchange_key"].astype(str).str.lower()
    working["total_notional"] = pd.to_numeric(working.get("total_notional"), errors="coerce").fillna(0.0)
    working["event_count"] = pd.to_numeric(working.get("event_count"), errors="coerce").fillna(0.0)
    coins = list(dict.fromkeys(item for item in working["coin"].tolist() if item))
    normalized_exchange_keys = _normalize_liquidation_map_exchange_keys(exchange_keys)
    exchanges = [EXCHANGE_TITLE_MAP.get(key, key.title()) for key in normalized_exchange_keys]
    z_values: List[List[float]] = []
    text_values: List[List[str]] = []
    for coin in coins:
        coin_frame = working[working["coin"] == coin]
        coin_z: List[float] = []
        coin_text: List[str] = []
        for exchange_key in normalized_exchange_keys:
            exchange_frame = coin_frame[coin_frame["exchange_key"] == exchange_key]
            total_notional = float(exchange_frame["total_notional"].sum()) if not exchange_frame.empty else 0.0
            event_count = int(exchange_frame["event_count"].sum()) if not exchange_frame.empty else 0
            top_zone_label = str(exchange_frame.iloc[0].get("top_zone_label") or "-") if not exchange_frame.empty else "-"
            data_status = str(exchange_frame.iloc[0].get("data_status") or "") if not exchange_frame.empty else ""
            status_meta = _liquidation_map_status_details(data_status)
            coin_z.append(total_notional)
            coin_text.append(
                f"{coin} / {EXCHANGE_TITLE_MAP.get(exchange_key, exchange_key.title())}<br>爆仓额 {_fmt_compact(total_notional)}<br>事件 {event_count}<br>核心价带 {top_zone_label}"
                + (f"<br>状态 {status_meta['status_label']}<br>说明 {status_meta['status_detail']}" if data_status else "")
            )
        z_values.append(coin_z)
        text_values.append(coin_text)
    figure.add_trace(
        go.Heatmap(
            z=z_values,
            x=exchanges,
            y=coins,
            colorscale=[
                [0.0, "rgba(33, 48, 69, 0.65)"],
                [0.25, "rgba(56, 92, 163, 0.82)"],
                [0.5, "rgba(41, 170, 123, 0.86)"],
                [0.75, "rgba(240, 166, 56, 0.9)"],
                [1.0, "rgba(244, 76, 89, 0.95)"],
            ],
            text=text_values,
            hovertemplate="%{text}<extra></extra>",
            colorbar=dict(title="爆仓额"),
        )
    )
    figure.update_layout(
        height=max(360, 64 * max(len(coins), 4)),
        margin=dict(l=16, r=20, t=58, b=16),
        paper_bgcolor="rgba(14, 22, 35, 0.56)",
        plot_bgcolor="rgba(255, 255, 255, 0.045)",
        font=dict(color="#f6f9ff", family="SF Pro Display, Segoe UI, sans-serif"),
        title=dict(text="清算地图（近期爆仓热度）", x=0.03, y=0.98, xanchor="left", font=dict(size=18, color="#f7fbff")),
    )
    figure.update_xaxes(showgrid=False)
    figure.update_yaxes(showgrid=False)
    return figure


def _build_realized_liquidation_price_map_figure(
    events: List[Dict[str, Any]],
    *,
    focus_coin: str,
    exchange_keys: Optional[List[str]] = None,
) -> go.Figure:
    figure = go.Figure()
    normalized_focus_coin = _normalize_coin_symbol(focus_coin)
    if not normalized_focus_coin:
        figure.add_annotation(text="等待清算价带样本", showarrow=False, x=0.5, y=0.5, xref="paper", yref="paper")
        figure.update_layout(height=380, margin=dict(l=12, r=12, t=24, b=12))
        return figure
    frame = pd.DataFrame(events or [])
    if frame.empty:
        figure.add_annotation(text="等待清算价带样本", showarrow=False, x=0.5, y=0.5, xref="paper", yref="paper")
        figure.update_layout(height=380, margin=dict(l=12, r=12, t=24, b=12))
        return figure
    working = frame.copy()
    working["coin_code"] = working.apply(
        lambda row: _normalize_coin_symbol(row.get("coin") or row.get("币种") or row.get("symbol")),
        axis=1,
    )
    working = working[working["coin_code"] == normalized_focus_coin]
    normalized_exchange_keys = set(_normalize_liquidation_map_exchange_keys(exchange_keys))
    if normalized_exchange_keys:
        working["exchange_key"] = working.apply(
            lambda row: _normalize_exchange_value(row.get("exchange_key") or row.get("交易所键") or row.get("exchange")),
            axis=1,
        )
        working = working[working["exchange_key"].isin(normalized_exchange_keys)]
    working["price"] = pd.to_numeric(working.get("price"), errors="coerce")
    working["notional"] = pd.to_numeric(working.get("notional"), errors="coerce").abs()
    working["side"] = working.get("side", "").astype(str).str.lower()
    working = working[(working["price"] > 0) & (working["notional"] > 0)]
    if working.empty:
        figure.add_annotation(text="当前窗口没有可绘制的真实爆仓价带", showarrow=False, x=0.5, y=0.5, xref="paper", yref="paper")
        figure.update_layout(height=380, margin=dict(l=12, r=12, t=24, b=12))
        return figure
    reference_price = float(
        pd.to_numeric(working.sort_values("timestamp_ms").tail(1).get("price"), errors="coerce").dropna().iloc[-1]
        if "timestamp_ms" in working.columns and not working.sort_values("timestamp_ms").tail(1).empty
        else working["price"].median()
    )
    price_min = float(working["price"].min())
    price_max = float(working["price"].max())
    lower_bound = min(price_min, reference_price * 0.94)
    upper_bound = max(price_max, reference_price * 1.06)
    if not np or not math.isfinite(lower_bound) or not math.isfinite(upper_bound) or lower_bound >= upper_bound:
        lower_bound = price_min
        upper_bound = max(price_max, price_min * 1.01)
    bucket_count = 36
    bucket_edges = np.linspace(lower_bound, upper_bound, bucket_count + 1) if np is not None else None
    if bucket_edges is None:
        figure.add_annotation(text="缺少价格分桶能力", showarrow=False, x=0.5, y=0.5, xref="paper", yref="paper")
        figure.update_layout(height=380, margin=dict(l=12, r=12, t=24, b=12))
        return figure
    working["bucket"] = pd.cut(working["price"], bins=bucket_edges, include_lowest=True, duplicates="drop")
    grouped = (
        working.groupby(["bucket", "side"], dropna=True, observed=False)["notional"].sum().reset_index()
        if not working.empty
        else pd.DataFrame(columns=["bucket", "side", "notional"])
    )
    bucket_labels: List[float] = []
    long_values: List[float] = []
    short_values: List[float] = []
    bucket_mid_lookup: Dict[str, float] = {}
    for bucket in working["bucket"].dropna().cat.categories:
        left_value = float(bucket.left)
        right_value = float(bucket.right)
        bucket_mid = (left_value + right_value) / 2.0
        bucket_key = str(bucket)
        bucket_mid_lookup[bucket_key] = bucket_mid
        bucket_labels.append(bucket_mid)
        long_notional = grouped[(grouped["bucket"].astype(str) == bucket_key) & (grouped["side"] == "long")]["notional"].sum()
        short_notional = grouped[(grouped["bucket"].astype(str) == bucket_key) & (grouped["side"] == "short")]["notional"].sum()
        long_values.append(-float(long_notional or 0.0))
        short_values.append(float(short_notional or 0.0))
    max_abs_notional = max([abs(value) for value in [*long_values, *short_values]] or [0.0])
    figure.add_trace(
        go.Bar(
            x=bucket_labels,
            y=short_values,
            name="空头爆仓",
            marker_color="rgba(244, 76, 89, 0.88)",
            hovertemplate="价带 %{x:,.2f}<br>空头爆仓 %{y:,.0f}<extra></extra>",
        )
    )
    figure.add_trace(
        go.Bar(
            x=bucket_labels,
            y=long_values,
            name="多头爆仓",
            marker_color="rgba(41, 170, 123, 0.88)",
            hovertemplate="价带 %{x:,.2f}<br>多头爆仓 %{customdata:,.0f}<extra></extra>",
            customdata=[abs(value) for value in long_values],
        )
    )
    figure.add_vline(
        x=reference_price,
        line_width=1.5,
        line_dash="dash",
        line_color="#7ee787",
        annotation_text=f"现价 {reference_price:,.2f}",
        annotation_position="top",
    )
    figure.update_layout(
        barmode="relative",
        height=430,
        margin=dict(l=16, r=20, t=64, b=24),
        paper_bgcolor="rgba(14, 22, 35, 0.56)",
        plot_bgcolor="rgba(255, 255, 255, 0.045)",
        font=dict(color="#f6f9ff", family="SF Pro Display, Segoe UI, sans-serif"),
        title=dict(
            text=f"{normalized_focus_coin} 近期真实爆仓价带图",
            x=0.03,
            y=0.98,
            xanchor="left",
            font=dict(size=18, color="#f7fbff"),
        ),
        legend=dict(orientation="h", x=0.02, y=1.08),
        yaxis=dict(
            title="爆仓额（USDT）",
            tickformat="~s",
            range=[-max_abs_notional * 1.15, max_abs_notional * 1.15] if max_abs_notional > 0 else None,
            zeroline=True,
            zerolinecolor="rgba(255,255,255,0.12)",
        ),
    )
    figure.update_xaxes(title="价格区间", showgrid=False)
    return figure


def _build_realized_liquidation_price_map_dataset(
    events: List[Dict[str, Any]],
    *,
    focus_coin: str,
    exchange_keys: Optional[List[str]] = None,
    reference_rows: Optional[List[Dict[str, Any]]] = None,
    max_events: int = 8000,
) -> Dict[str, Any]:
    normalized_focus_coin = _normalize_coin_symbol(focus_coin)
    normalized_exchange_keys = _normalize_liquidation_map_exchange_keys(exchange_keys)
    allowed_exchange_keys = set(normalized_exchange_keys)
    frame = pd.DataFrame(events or [])
    windows = [{"key": key, "label": key.upper(), "minutes": minutes} for key, minutes in LIQUIDATION_PRICE_MAP_WINDOWS.items()]
    exchange_options = [{"key": key, "label": EXCHANGE_TITLE_MAP.get(key, key.title())} for key in normalized_exchange_keys]
    empty_payload = {
        "windows": windows,
        "default_window": "1d",
        "default_coin": normalized_focus_coin,
        "default_exchange": "all",
        "coins": [normalized_focus_coin] if normalized_focus_coin else [],
        "exchanges": exchange_options,
        "events": [],
        "reference_prices": [],
    }
    if frame.empty:
        return empty_payload

    working = frame.copy()
    working["coin"] = working.apply(lambda row: _normalize_coin_symbol(row.get("coin") or row.get("symbol")), axis=1)
    working["exchange_key"] = working.apply(
        lambda row: _normalize_exchange_value(row.get("exchange_key") or row.get("exchange")),
        axis=1,
    )
    working["timestamp_ms"] = pd.to_numeric(working.get("timestamp_ms"), errors="coerce")
    working["price"] = pd.to_numeric(working.get("price"), errors="coerce")
    working["notional"] = pd.to_numeric(working.get("notional"), errors="coerce").abs()
    working["side"] = working.get("side", "").astype(str).str.lower()
    working = working[
        working["coin"].astype(str).str.len().gt(0)
        & working["exchange_key"].astype(str).str.len().gt(0)
        & working["timestamp_ms"].notna()
        & working["price"].gt(0)
        & working["notional"].gt(0)
        & working["side"].isin(["long", "short"])
    ]
    if allowed_exchange_keys:
        working = working[working["exchange_key"].isin(allowed_exchange_keys)]
    if working.empty:
        return empty_payload

    working = working.sort_values("timestamp_ms", ascending=False).head(max_events).copy()
    coins: List[str] = []
    if normalized_focus_coin:
        coins.append(normalized_focus_coin)
    for coin_code in working["coin"].astype(str).tolist():
        if coin_code and coin_code not in coins:
            coins.append(coin_code)

    reference_price_lookup: Dict[tuple[str, str], float] = {}
    for row in reference_rows or []:
        coin_code = _normalize_coin_symbol(row.get("Coin") or row.get("coin"))
        exchange_key = _normalize_exchange_value(row.get("exchange_key") or row.get("Exchange"))
        price_value = _payload_float(row.get("Price") or row.get("reference_price") or row.get("last_price"))
        if coin_code and exchange_key and price_value not in (None, 0.0):
            reference_price_lookup[(coin_code, exchange_key)] = float(price_value)

    normalized_events: List[Dict[str, Any]] = []
    for row in working.to_dict("records"):
        exchange_key = str(row.get("exchange_key") or "").strip().lower()
        normalized_events.append(
            {
                "coin": str(row.get("coin") or "").strip().upper(),
                "exchange_key": exchange_key,
                "exchange": EXCHANGE_TITLE_MAP.get(exchange_key, exchange_key.title()),
                "timestamp_ms": int(row.get("timestamp_ms") or 0),
                "price": float(row.get("price") or 0.0),
                "notional": float(row.get("notional") or 0.0),
                "side": str(row.get("side") or "").strip().lower(),
            }
        )

    reference_price_rows: List[Dict[str, Any]] = []
    grouped = working.sort_values("timestamp_ms", ascending=True).groupby(["coin", "exchange_key"], dropna=True, observed=False)
    for (coin_code, exchange_key), group in grouped:
        latest_price = _payload_float(group.iloc[-1].get("price"))
        resolved_price = reference_price_lookup.get((str(coin_code), str(exchange_key)))
        if resolved_price in (None, 0.0):
            resolved_price = latest_price
        reference_price_rows.append(
            {
                "coin": str(coin_code),
                "exchange_key": str(exchange_key),
                "exchange": EXCHANGE_TITLE_MAP.get(str(exchange_key), str(exchange_key).title()),
                "reference_price": float(resolved_price) if resolved_price not in (None, 0.0) else None,
                "latest_event_price": float(latest_price) if latest_price not in (None, 0.0) else None,
                "event_count": int(len(group)),
                "last_timestamp_ms": int(group["timestamp_ms"].max() or 0),
            }
        )

    return {
        "windows": windows,
        "default_window": "1d",
        "default_coin": normalized_focus_coin or (coins[0] if coins else ""),
        "default_exchange": "all",
        "coins": coins,
        "exchanges": exchange_options,
        "events": normalized_events,
        "reference_prices": reference_price_rows,
    }


def _resolve_liquidation_visual_reference_price(
    reference_rows: Optional[List[Dict[str, Any]]],
    *,
    coin_code: str,
    exchange_key: str,
    fallback_prices: Optional[List[float]] = None,
) -> Optional[float]:
    normalized_coin = _normalize_coin_symbol(coin_code)
    normalized_exchange = str(exchange_key or "all").strip().lower()
    candidates = [
        row
        for row in (reference_rows or [])
        if _normalize_coin_symbol(row.get("coin") or row.get("Coin")) == normalized_coin
    ]
    if normalized_exchange and normalized_exchange != "all":
        for row in candidates:
            row_exchange = _normalize_exchange_value(row.get("exchange_key") or row.get("Exchange") or row.get("exchange"))
            if row_exchange != normalized_exchange:
                continue
            value = _payload_float(row.get("reference_price") or row.get("Price") or row.get("latest_event_price") or row.get("last_price"))
            if value not in (None, 0.0):
                return float(value)
    values = [
        float(value)
        for value in (
            _payload_float(row.get("reference_price") or row.get("Price") or row.get("latest_event_price") or row.get("last_price"))
            for row in candidates
        )
        if value not in (None, 0.0)
    ]
    if values:
        return float(statistics.median(values))
    fallback = [float(value) for value in (fallback_prices or []) if value not in (None, 0.0)]
    if fallback:
        return float(statistics.median(fallback))
    return None


def _build_behavioral_liquidation_heatmap_dataset(
    liquidation_rows: List[Dict[str, Any]],
    *,
    focus_coin: str,
    exchange_key: str,
    window_key: str,
    now_ms: int,
    allowed_exchange_keys: Optional[List[str]] = None,
    reference_rows: Optional[List[Dict[str, Any]]] = None,
    trade_rows_by_exchange: Optional[Dict[str, List[TradeEvent]]] = None,
    oi_rows_by_exchange: Optional[Dict[str, List[OIPoint]]] = None,
    quality_rows_by_exchange: Optional[Dict[str, List[OrderBookQualityPoint]]] = None,
    orderbook_rows_by_exchange: Optional[Dict[str, List[OrderBookLevel]]] = None,
) -> Dict[str, Any]:
    normalized_coin = _normalize_coin_symbol(focus_coin)
    normalized_window = _normalize_liquidation_visual_window(window_key)
    normalized_exchange = str(exchange_key or "all").strip().lower()
    normalized_allowed_exchanges = _normalize_liquidation_map_exchange_keys(allowed_exchange_keys)
    exchange_options = [{"key": "all", "label": "全部已选交易所"}] + [
        {"key": key, "label": EXCHANGE_TITLE_MAP.get(key, key.title())}
        for key in normalized_allowed_exchanges
    ]
    empty_payload = {
        "model": "model3",
        "model_label": "模型3 · 升级算法版（更聪明）",
        "coin": normalized_coin,
        "exchange_key": normalized_exchange if normalized_exchange else "all",
        "exchange": "全部已选交易所" if normalized_exchange in {"", "all"} else EXCHANGE_TITLE_MAP.get(normalized_exchange, normalized_exchange.title()),
        "window_key": normalized_window,
        "window_label": normalized_window.upper(),
        "time_labels": [],
        "time_values": [],
        "price_axis": [],
        "z": [],
        "price_path": [],
        "current_price": None,
        "top_bands": [],
        "stats": {
            "event_count": 0,
            "trade_count": 0,
            "oi_points": 0,
            "quality_points": 0,
            "chain_score": 0.0,
            "path_score": 0.0,
            "fake_hotspot_pct": 0.0,
            "dynamic_score": 0.0,
            "data_quality": "empty",
        },
        "signals": {
            "trade_flow_bias": "样本不足",
            "oi_bias": "样本不足",
            "liquidity_path": "样本不足",
        },
        "windows": [{"key": key, "label": key.upper(), "minutes": minutes} for key, minutes in LIQUIDATION_PRICE_MAP_WINDOWS.items()],
        "exchanges": exchange_options,
    }
    if np is None or not normalized_coin:
        return empty_payload

    if normalized_exchange not in {"", "all"} and normalized_exchange not in normalized_allowed_exchanges:
        normalized_exchange = "all"
    selected_exchange_keys = (
        [normalized_exchange]
        if normalized_exchange not in {"", "all"}
        else list(normalized_allowed_exchanges)
    )
    since_ms = now_ms - int(LIQUIDATION_PRICE_MAP_WINDOWS[normalized_window] * 60 * 1000)
    time_bucket_count = int(LIQUIDATION_MODEL3_TIME_BUCKETS.get(normalized_window, 48))
    price_bucket_count = int(LIQUIDATION_MODEL3_PRICE_BUCKETS)
    filtered_events = [
        row
        for row in (liquidation_rows or [])
        if _normalize_coin_symbol(row.get("coin")) == normalized_coin
        and str(row.get("exchange_key") or "").strip().lower() in selected_exchange_keys
        and int(row.get("timestamp_ms") or 0) >= since_ms
        and _payload_float(row.get("price")) not in (None, 0.0)
        and _payload_float(row.get("notional")) not in (None, 0.0)
    ]
    fallback_prices = [_payload_float(row.get("price")) for row in filtered_events]
    selected_trade_rows: List[TradeEvent] = []
    for key in selected_exchange_keys:
        for trade in (trade_rows_by_exchange or {}).get(key, []):
            if int(trade.timestamp_ms or 0) >= since_ms:
                selected_trade_rows.append(trade)
                trade_price = _payload_float(trade.price)
                if trade_price not in (None, 0.0):
                    fallback_prices.append(float(trade_price))
    selected_oi_rows: List[OIPoint] = []
    for key in selected_exchange_keys:
        selected_oi_rows.extend(
            [point for point in (oi_rows_by_exchange or {}).get(key, []) if int(point.timestamp_ms or 0) >= since_ms]
        )
    selected_quality_rows: List[OrderBookQualityPoint] = []
    for key in selected_exchange_keys:
        selected_quality_rows.extend(
            [point for point in (quality_rows_by_exchange or {}).get(key, []) if int(point.timestamp_ms or 0) >= since_ms]
        )
    selected_orderbook_rows: List[OrderBookLevel] = []
    for key in selected_exchange_keys:
        selected_orderbook_rows.extend((orderbook_rows_by_exchange or {}).get(key, []))
        for level in (orderbook_rows_by_exchange or {}).get(key, []):
            level_price = _payload_float(getattr(level, "price", None))
            if level_price not in (None, 0.0):
                fallback_prices.append(float(level_price))
    reference_price = _resolve_liquidation_visual_reference_price(
        reference_rows,
        coin_code=normalized_coin,
        exchange_key=normalized_exchange,
        fallback_prices=fallback_prices,
    )
    if reference_price in (None, 0.0):
        return empty_payload

    raw_prices = [float(value) for value in fallback_prices if value not in (None, 0.0)]
    if not raw_prices:
        raw_prices = [float(reference_price)]
    price_min = min(raw_prices)
    price_max = max(raw_prices)
    deviation_floor = {"5m": 0.012, "15m": 0.02, "1h": 0.035, "4h": 0.055, "1d": 0.12}.get(normalized_window, 0.08)
    observed_deviation = max(
        abs(float(price_min) / float(reference_price) - 1.0),
        abs(float(price_max) / float(reference_price) - 1.0),
        deviation_floor,
    )
    deviation = min(observed_deviation * 1.12, 0.22)
    lower_bound = min(float(price_min), float(reference_price) * (1.0 - deviation))
    upper_bound = max(float(price_max), float(reference_price) * (1.0 + deviation))
    if upper_bound <= lower_bound:
        upper_bound = lower_bound * 1.04
    bucket_ms = max(60_000, int((now_ms - since_ms) / max(time_bucket_count, 1)))
    price_step = max((upper_bound - lower_bound) / float(max(price_bucket_count, 1)), max(float(reference_price) * 0.0008, 1e-6))
    price_axis = [lower_bound + (index + 0.5) * price_step for index in range(price_bucket_count)]
    time_values = [since_ms + int((index + 0.5) * bucket_ms) for index in range(time_bucket_count)]
    time_labels = [
        pd.to_datetime(value, unit="ms", utc=True).tz_convert("Europe/Rome").strftime("%m-%d %H:%M" if LIQUIDATION_PRICE_MAP_WINDOWS[normalized_window] >= 720 else "%H:%M")
        for value in time_values
    ]

    def _time_index(timestamp_ms: Any) -> int:
        normalized = int(timestamp_ms or 0)
        if normalized <= since_ms:
            return 0
        if normalized >= now_ms:
            return time_bucket_count - 1
        return max(0, min(time_bucket_count - 1, int((normalized - since_ms) / bucket_ms)))

    def _price_index(price: Any) -> int:
        normalized = float(price or 0.0)
        raw_index = int((normalized - lower_bound) / price_step)
        return max(0, min(price_bucket_count - 1, raw_index))

    seed_matrix = np.zeros((price_bucket_count, time_bucket_count), dtype=float)
    chain_matrix = np.zeros((price_bucket_count, time_bucket_count), dtype=float)
    ambient_matrix = np.zeros((price_bucket_count, time_bucket_count), dtype=float)
    background_matrix = np.zeros((price_bucket_count, time_bucket_count), dtype=float)
    buy_flow = np.zeros(time_bucket_count, dtype=float)
    sell_flow = np.zeros(time_bucket_count, dtype=float)
    price_samples: List[List[float]] = [[] for _ in range(time_bucket_count)]

    for trade in selected_trade_rows:
        trade_price = _payload_float(trade.price)
        trade_notional = _payload_float(trade.notional)
        if trade_price in (None, 0.0) or trade_notional in (None, 0.0):
            continue
        time_index = _time_index(trade.timestamp_ms)
        price_samples[time_index].append(float(trade_price))
        if str(trade.side or "").strip().lower() == "buy":
            buy_flow[time_index] += abs(float(trade_notional))
        elif str(trade.side or "").strip().lower() == "sell":
            sell_flow[time_index] += abs(float(trade_notional))

    if not any(price_samples):
        for row in filtered_events:
            event_price = _payload_float(row.get("price"))
            if event_price in (None, 0.0):
                continue
            price_samples[_time_index(row.get("timestamp_ms"))].append(float(event_price))

    price_path: List[Optional[float]] = []
    last_price = float(reference_price)
    for samples in price_samples:
        if samples:
            last_price = float(statistics.median(samples))
        price_path.append(last_price)

    total_trade_flow = buy_flow + sell_flow
    max_trade_flow = float(np.max(total_trade_flow)) if total_trade_flow.size else 0.0
    flow_activity = np.log1p(total_trade_flow)
    flow_delta = (buy_flow - sell_flow) / np.maximum(total_trade_flow, 1.0)
    flow_support_up = np.clip(flow_delta, 0.0, 1.0) * (flow_activity / max(float(np.max(flow_activity)), 1.0))
    flow_support_down = np.clip(-flow_delta, 0.0, 1.0) * (flow_activity / max(float(np.max(flow_activity)), 1.0))

    oi_levels = np.full(time_bucket_count, np.nan, dtype=float)
    oi_bucket_values: List[List[float]] = [[] for _ in range(time_bucket_count)]
    for point in selected_oi_rows:
        value = _payload_float(point.open_interest_notional if point.open_interest_notional not in (None, 0) else point.open_interest)
        if value in (None, 0.0):
            continue
        oi_bucket_values[_time_index(point.timestamp_ms)].append(float(value))
    for index, values in enumerate(oi_bucket_values):
        if values:
            oi_levels[index] = float(sum(values))
    if np.isnan(oi_levels).all():
        oi_delta_norm = np.zeros(time_bucket_count, dtype=float)
    else:
        last_known = None
        for index in range(time_bucket_count):
            if not np.isnan(oi_levels[index]):
                last_known = oi_levels[index]
            elif last_known is not None:
                oi_levels[index] = last_known
        next_known = None
        for index in range(time_bucket_count - 1, -1, -1):
            if not np.isnan(oi_levels[index]):
                next_known = oi_levels[index]
            elif next_known is not None:
                oi_levels[index] = next_known
        oi_delta_norm = np.zeros(time_bucket_count, dtype=float)
        for index in range(1, time_bucket_count):
            previous = oi_levels[index - 1]
            current = oi_levels[index]
            if previous in (None, 0.0) or current in (None, 0.0) or np.isnan(previous) or np.isnan(current):
                continue
            oi_delta_norm[index] = max(-1.0, min(1.0, (float(current) - float(previous)) / abs(float(previous)) * 10.0))

    imbalance_values = np.zeros(time_bucket_count, dtype=float)
    persistence_values = np.zeros(time_bucket_count, dtype=float)
    fake_values = np.zeros(time_bucket_count, dtype=float)
    quality_counts = np.zeros(time_bucket_count, dtype=float)
    for point in selected_quality_rows:
        time_index = _time_index(point.timestamp_ms)
        quality_counts[time_index] += 1.0
        imbalance_values[time_index] += float(point.imbalance_pct or 0.0)
        persistence_values[time_index] += max(
            float(point.bid_wall_persistence_s or 0.0),
            float(point.ask_wall_persistence_s or 0.0),
        )
        fake_values[time_index] += min(
            1.0,
            (float(point.spoof_events or 0.0) * 0.16)
            + (
                float(point.near_canceled_notional or 0.0)
                / max(float(point.near_added_notional or 0.0) + float(point.near_canceled_notional or 0.0), 1.0)
                * 0.75
            ),
        )
    nonzero_quality = np.where(quality_counts > 0, quality_counts, 1.0)
    imbalance_norm = np.clip((imbalance_values / nonzero_quality) / 12.0, -1.0, 1.0)
    persistence_norm = np.clip((persistence_values / nonzero_quality) / 45.0, 0.0, 1.0)
    fake_penalty = np.clip(fake_values / nonzero_quality, 0.0, 1.0)

    path_costs = np.zeros(price_bucket_count, dtype=float)
    band_profile = np.full(price_bucket_count, 0.12, dtype=float)
    orderbook_rows = [
        {
            "price": float(getattr(level, "price", 0.0) or 0.0),
            "notional": float(getattr(level, "price", 0.0) or 0.0) * float(getattr(level, "size", 0.0) or 0.0),
            "side": str(getattr(level, "side", "") or "").strip().lower(),
        }
        for level in selected_orderbook_rows
        if _payload_float(getattr(level, "price", None)) not in (None, 0.0) and _payload_float(getattr(level, "size", None)) not in (None, 0.0)
    ]
    bid_levels = sorted([row for row in orderbook_rows if row["side"].startswith("b")], key=lambda item: item["price"], reverse=True)
    ask_levels = sorted([row for row in orderbook_rows if row["side"].startswith("a")], key=lambda item: item["price"])
    baseline_notional = statistics.median([row["notional"] for row in orderbook_rows]) if orderbook_rows else 0.0
    local_band_notional = np.zeros(price_bucket_count, dtype=float)
    for index, price in enumerate(price_axis):
        if price >= reference_price:
            cumulative = sum(row["notional"] for row in ask_levels if float(reference_price) <= row["price"] <= price)
            local = sum(row["notional"] for row in ask_levels if abs(row["price"] - price) <= price_step * 0.8)
        else:
            cumulative = sum(row["notional"] for row in bid_levels if price <= row["price"] <= float(reference_price))
            local = sum(row["notional"] for row in bid_levels if abs(row["price"] - price) <= price_step * 0.8)
        path_costs[index] = cumulative
        local_band_notional[index] = local
    if baseline_notional > 0:
        max_local_band = float(np.max(local_band_notional)) if local_band_notional.size else 0.0
        for index in range(price_bucket_count):
            path_ease = 1.0 / (1.0 + (path_costs[index] / (baseline_notional * 16.0 + 1.0)))
            wall_score = (
                math.log1p(local_band_notional[index]) / max(math.log1p(max_local_band + 1.0), 1.0)
                if max_local_band > 0
                else 0.0
            )
            band_profile[index] = max(0.12, 0.42 * path_ease + 0.58 * wall_score)

    event_band_profile = np.zeros(price_bucket_count, dtype=float)
    event_scale = max(
        statistics.median([abs(float(row.get("notional") or 0.0)) for row in filtered_events]) if filtered_events else 0.0,
        50_000.0,
    )
    for row in filtered_events:
        price = _payload_float(row.get("price"))
        notional = _payload_float(row.get("notional"))
        side = str(row.get("side") or "").strip().lower()
        if price in (None, 0.0) or notional in (None, 0.0):
            continue
        time_index = _time_index(row.get("timestamp_ms"))
        price_index = _price_index(price)
        base_seed = math.log1p(abs(float(notional)) / event_scale * 4.0 + 1.0)
        direction = -1 if side == "long" else 1
        event_band_profile[price_index] += base_seed
        for offset, weight in [(-2, 0.18), (-1, 0.45), (0, 1.0), (1, 0.45), (2, 0.18)]:
            target_index = price_index + offset
            if target_index < 0 or target_index >= price_bucket_count:
                continue
            same_side_bias = 1.0
            if direction > 0 and price_axis[target_index] < float(reference_price):
                same_side_bias = 0.7
            if direction < 0 and price_axis[target_index] > float(reference_price):
                same_side_bias = 0.7
            seed_matrix[target_index, time_index] += base_seed * weight * same_side_bias
        support_boost = float(flow_support_up[time_index] if direction > 0 else flow_support_down[time_index])
        support_boost += max(0.0, float(oi_delta_norm[time_index])) * 0.7
        support_boost += float(persistence_norm[time_index]) * 0.25
        support_penalty = 1.0 - float(fake_penalty[time_index]) * 0.42
        for step_t in range(1, 4):
            target_time = min(time_bucket_count - 1, time_index + step_t)
            time_decay = 0.74 ** (step_t - 1)
            for step_p in range(1, 5):
                target_price = price_index + direction * step_p
                if target_price < 0 or target_price >= price_bucket_count:
                    break
                chain_matrix[target_price, target_time] += (
                    base_seed
                    * (0.26 * time_decay)
                    * (0.82 ** (step_p - 1))
                    * (1.0 + support_boost + float(band_profile[target_price]) * 0.4)
                    * support_penalty
                )

    if float(np.max(event_band_profile)) > 0:
        event_band_profile = event_band_profile / float(np.max(event_band_profile))
        band_profile = np.maximum(band_profile, 0.2 + event_band_profile * 0.8)

    for index in range(price_bucket_count):
        background_matrix[index, :] = float(band_profile[index]) * 0.16

    for time_index in range(time_bucket_count):
        up_support = max(0.0, float(flow_support_up[time_index])) + max(0.0, float(oi_delta_norm[time_index])) * 0.65 + max(0.0, float(imbalance_norm[time_index])) * 0.35
        down_support = max(0.0, float(flow_support_down[time_index])) + max(0.0, float(oi_delta_norm[time_index])) * 0.65 + max(0.0, float(-imbalance_norm[time_index])) * 0.35
        quality_support = 0.55 + float(persistence_norm[time_index]) * 0.45
        fake_discount = 1.0 - float(fake_penalty[time_index]) * 0.55
        for price_index, price in enumerate(price_axis):
            distance = abs(float(price) / float(reference_price) - 1.0)
            distance_weight = 0.62 + math.exp(-(distance / 0.07)) * 0.38
            directional_support = up_support if price >= float(reference_price) else down_support
            ambient_matrix[price_index, time_index] = (
                float(band_profile[price_index])
                * directional_support
                * quality_support
                * fake_discount
                * distance_weight
            )

    heatmap = np.maximum(seed_matrix + chain_matrix + ambient_matrix + background_matrix, 0.0)
    normalized_heatmap = np.log1p(heatmap)
    max_heat = float(np.max(normalized_heatmap)) if normalized_heatmap.size else 0.0
    if max_heat > 0:
        normalized_heatmap = normalized_heatmap / max_heat * 100.0
    band_scores = np.mean(normalized_heatmap, axis=1) if normalized_heatmap.size else np.zeros(price_bucket_count, dtype=float)
    top_band_indices = list(np.argsort(band_scores)[::-1][:4]) if band_scores.size else []
    top_bands = []
    for index in top_band_indices:
        top_bands.append(
            {
                "price": float(price_axis[index]),
                "score": round(float(band_scores[index]), 2),
                "bias": "short-cascade" if float(price_axis[index]) >= float(reference_price) else "long-cascade",
            }
        )

    average_flow = float(np.mean(flow_delta)) if flow_delta.size else 0.0
    average_oi_build = float(np.mean(np.clip(oi_delta_norm, -1.0, 1.0))) if oi_delta_norm.size else 0.0
    path_score = round(float(np.mean(band_profile)) * 100.0, 1)
    chain_score = round(
        (float(np.sum(chain_matrix)) / max(float(np.sum(seed_matrix + chain_matrix + ambient_matrix)), 1e-6)) * 100.0,
        1,
    )
    fake_hotspot_pct = round(float(np.mean(fake_penalty)) * 100.0, 1)
    dynamic_score = round(min(100.0, max(0.0, 18.0 + chain_score * 0.42 + path_score * 0.34 + max(0.0, average_oi_build) * 18.0 + max(abs(average_flow), 0.0) * 22.0)), 1)
    support_flags = {
        "liquidations": bool(filtered_events),
        "trades": bool(selected_trade_rows),
        "oi": bool(selected_oi_rows),
        "quality": bool(selected_quality_rows),
        "orderbook": bool(selected_orderbook_rows),
    }
    support_count = sum(1 for value in support_flags.values() if value)
    data_quality = "full" if support_count >= 5 else "partial" if support_count >= 3 else "liquidation_only" if support_flags["liquidations"] else "empty"
    trade_flow_label = "买盘推动更容易扫上方" if average_flow >= 0.08 else "卖盘推动更容易扫下方" if average_flow <= -0.08 else "买卖力量相对均衡"
    oi_bias_label = "持仓扩张，连锁传播更容易放大" if average_oi_build >= 0.05 else "持仓收缩，连锁传播相对受限" if average_oi_build <= -0.05 else "持仓变化平稳"
    liquidity_path_label = "路径偏顺畅，热点更容易被扫到" if path_score >= 62.0 else "路径一般，更多依赖事件触发" if path_score >= 45.0 else "路径阻力偏强，假热点概率更高"

    return {
        "model": "model3",
        "model_label": "模型3 · 升级算法版（更聪明）",
        "coin": normalized_coin,
        "exchange_key": normalized_exchange if normalized_exchange else "all",
        "exchange": "全部已选交易所" if normalized_exchange in {"", "all"} else EXCHANGE_TITLE_MAP.get(normalized_exchange, normalized_exchange.title()),
        "window_key": normalized_window,
        "window_label": normalized_window.upper(),
        "time_labels": time_labels,
        "time_values": time_values,
        "price_axis": [float(value) for value in price_axis],
        "z": normalized_heatmap.tolist(),
        "price_path": [float(value if value not in (None, 0.0) else reference_price) for value in price_path],
        "current_price": float(reference_price),
        "top_bands": top_bands,
        "stats": {
            "event_count": len(filtered_events),
            "trade_count": len(selected_trade_rows),
            "oi_points": len(selected_oi_rows),
            "quality_points": len(selected_quality_rows),
            "chain_score": chain_score,
            "path_score": path_score,
            "fake_hotspot_pct": fake_hotspot_pct,
            "dynamic_score": dynamic_score,
            "data_quality": data_quality,
        },
        "signals": {
            "trade_flow_bias": trade_flow_label,
            "oi_bias": oi_bias_label,
            "liquidity_path": liquidity_path_label,
        },
        "windows": [{"key": key, "label": key.upper(), "minutes": minutes} for key, minutes in LIQUIDATION_PRICE_MAP_WINDOWS.items()],
        "exchanges": exchange_options,
    }


def _build_statistical_liquidation_heatmap_dataset(
    *,
    focus_coin: str,
    exchange_key: str,
    window_key: str,
    now_ms: int,
    allowed_exchange_keys: Optional[List[str]] = None,
    reference_rows: Optional[List[Dict[str, Any]]] = None,
    candle_rows_by_exchange: Optional[Dict[str, List[Candle]]] = None,
    oi_rows_by_exchange: Optional[Dict[str, List[OIPoint]]] = None,
    funding_bps_by_exchange: Optional[Dict[str, Optional[float]]] = None,
    realized_liquidation_rows: Optional[List[Dict[str, Any]]] = None,
    trade_rows_by_exchange: Optional[Dict[str, List[TradeEvent]]] = None,
    quality_rows_by_exchange: Optional[Dict[str, List[OrderBookQualityPoint]]] = None,
    orderbook_rows_by_exchange: Optional[Dict[str, List[OrderBookLevel]]] = None,
) -> Dict[str, Any]:
    normalized_coin = _normalize_coin_symbol(focus_coin)
    normalized_window = _normalize_liquidation_visual_window(window_key)
    normalized_exchange = str(exchange_key or "all").strip().lower()
    normalized_allowed_exchanges = _normalize_liquidation_map_exchange_keys(allowed_exchange_keys)
    if normalized_exchange not in {"", "all"} and normalized_exchange not in normalized_allowed_exchanges:
        normalized_exchange = "all"
    selected_exchange_keys = [normalized_exchange] if normalized_exchange not in {"", "all"} else list(normalized_allowed_exchanges)
    exchange_options = [{"key": "all", "label": "全部已选交易所"}] + [
        {"key": key, "label": EXCHANGE_TITLE_MAP.get(key, key.title())}
        for key in normalized_allowed_exchanges
    ]
    empty_payload = {
        "model": "model3",
        "model_label": "模型3 · 升级算法版（统计热力图）",
        "coin": normalized_coin,
        "exchange_key": normalized_exchange if normalized_exchange else "all",
        "exchange": "全部已选交易所" if normalized_exchange in {"", "all"} else EXCHANGE_TITLE_MAP.get(normalized_exchange, normalized_exchange.title()),
        "window_key": normalized_window,
        "window_label": normalized_window.upper(),
        "time_labels": [],
        "time_values": [],
        "price_axis": [],
        "z": [],
        "z_range": {"min": -3.0, "max": 3.0},
        "price_path": [],
        "current_price": None,
        "top_bands": [],
        "stats": {
            "event_count": 0,
            "trade_count": 0,
            "oi_points": 0,
            "quality_points": 0,
            "chain_score": 0.0,
            "path_score": 0.0,
            "fake_hotspot_pct": 0.0,
            "dynamic_score": 0.0,
            "data_quality": "empty",
            "attraction_up": 0.0,
            "attraction_down": 0.0,
            "attraction_bias": "样本不足",
        },
        "signals": {
            "trade_flow_bias": "样本不足",
            "oi_bias": "样本不足",
            "liquidity_path": "样本不足",
            "funding_mode": "当前 funding 代理历史倾向",
        },
        "windows": [{"key": key, "label": key.upper(), "minutes": minutes} for key, minutes in LIQUIDATION_PRICE_MAP_WINDOWS.items()],
        "exchanges": exchange_options,
    }
    if np is None or not normalized_coin or not selected_exchange_keys:
        return empty_payload

    window_minutes = int(LIQUIDATION_PRICE_MAP_WINDOWS.get(normalized_window, 1440))
    step_ms = {
        "5m": 10_000,
        "15m": 15_000,
        "1h": 30_000,
        "4h": 120_000,
        "1d": 600_000,
    }.get(normalized_window, 300_000)
    since_ms = now_ms - window_minutes * 60 * 1000
    lookback_candles = {"5m": 30, "15m": 48, "1h": 84, "4h": 144, "1d": 420}.get(normalized_window, 120)
    history_buffer_ms = lookback_candles * step_ms
    time_values = list(range(since_ms + step_ms, now_ms + 1, step_ms))
    if not time_values:
        time_values = [now_ms]

    prepared_candles: Dict[str, List[Candle]] = {}
    fallback_prices: List[float] = []
    for exchange_name in selected_exchange_keys:
        candles = [
            candle
            for candle in (candle_rows_by_exchange or {}).get(exchange_name, [])
            if int(candle.timestamp_ms or 0) >= since_ms - history_buffer_ms
            and int(candle.timestamp_ms or 0) <= now_ms
            and _payload_float(candle.close) not in (None, 0.0)
        ]
        candles.sort(key=lambda item: int(item.timestamp_ms or 0))
        if candles:
            prepared_candles[exchange_name] = candles
            for candle in candles:
                for value in (_payload_float(candle.low), _payload_float(candle.high), _payload_float(candle.close)):
                    if value not in (None, 0.0):
                        fallback_prices.append(float(value))
    if not prepared_candles:
        return empty_payload

    realized_rows = [
        row
        for row in (realized_liquidation_rows or [])
        if _normalize_coin_symbol(row.get("coin")) == normalized_coin
        and str(row.get("exchange_key") or "").strip().lower() in selected_exchange_keys
        and int(row.get("timestamp_ms") or 0) >= since_ms
    ]
    for row in realized_rows:
        price_value = _payload_float(row.get("price"))
        if price_value not in (None, 0.0):
            fallback_prices.append(float(price_value))
    selected_orderbook_rows: List[OrderBookLevel] = []
    for exchange_name in selected_exchange_keys:
        for level in (orderbook_rows_by_exchange or {}).get(exchange_name, []):
            selected_orderbook_rows.append(level)
            level_price = _payload_float(getattr(level, "price", None))
            if level_price not in (None, 0.0):
                fallback_prices.append(float(level_price))
    reference_price = _resolve_liquidation_visual_reference_price(
        reference_rows,
        coin_code=normalized_coin,
        exchange_key=normalized_exchange,
        fallback_prices=fallback_prices,
    )
    if reference_price in (None, 0.0):
        return empty_payload

    raw_prices = [float(value) for value in fallback_prices if value not in (None, 0.0)]
    if not raw_prices:
        raw_prices = [float(reference_price)]
    deviation_floor = {"5m": 0.012, "15m": 0.018, "1h": 0.035, "4h": 0.055, "1d": 0.12}.get(normalized_window, 0.08)
    price_min = min(raw_prices)
    price_max = max(raw_prices)
    observed_deviation = max(
        abs(float(price_min) / float(reference_price) - 1.0),
        abs(float(price_max) / float(reference_price) - 1.0),
        deviation_floor,
    )
    deviation = min(observed_deviation * 1.08, 0.24)
    lower_bound = min(float(price_min), float(reference_price) * (1.0 - deviation))
    upper_bound = max(float(price_max), float(reference_price) * (1.0 + deviation))
    if upper_bound <= lower_bound:
        upper_bound = lower_bound * 1.04
    price_bucket_count = 320
    price_step = max((upper_bound - lower_bound) / float(price_bucket_count), max(float(reference_price) * 0.001, 1e-6))
    price_axis = [lower_bound + (index + 0.5) * price_step for index in range(price_bucket_count)]

    def _time_index(timestamp_ms: Any) -> int:
        normalized = int(timestamp_ms or 0)
        if normalized <= since_ms:
            return 0
        if normalized >= now_ms:
            return len(time_values) - 1
        return max(0, min(len(time_values) - 1, int((normalized - since_ms) / step_ms)))

    def _price_index(price: Any) -> int:
        normalized = float(price or 0.0)
        raw_index = int((normalized - lower_bound) / price_step)
        return max(0, min(price_bucket_count - 1, raw_index))

    def _liq_price(entry_price: float, leverage: int, side: str) -> float:
        mmr = 0.004 + max(0.0, math.log(max(leverage, 2) / 20.0, 2)) * 0.0009 if leverage > 20 else 0.004
        if side == "long":
            return float(entry_price) * (1.0 - 1.0 / float(leverage) + mmr)
        return float(entry_price) * (1.0 + 1.0 / float(leverage) - mmr)

    def _sigmoid(value: float) -> float:
        return 1.0 / (1.0 + math.exp(-max(-8.0, min(8.0, value))))

    def _leverage_profile(funding_bps: float, range_pct: float, oi_delta_pct: float, body_pct: float) -> List[Tuple[int, float]]:
        leverages = [2, 3, 5, 10, 20, 25, 50, 100, 125]
        center = 12.0 + max(0.0, abs(funding_bps) - 0.8) * 2.2 + max(0.0, range_pct - 0.35) * 11.0 + max(0.0, abs(oi_delta_pct) - 0.2) * 8.0
        center = max(5.0, min(40.0, center))
        sigma = 0.95 - min(0.28, max(0.0, abs(funding_bps) - 1.5) * 0.04)
        tail_boost = min(0.55, max(0.0, abs(funding_bps) - 2.0) * 0.05 + max(0.0, range_pct - 0.6) * 0.35 + max(0.0, abs(body_pct) - 0.0035) * 30.0)
        weights: List[float] = []
        for leverage in leverages:
            score = math.exp(-0.5 * ((math.log(float(leverage)) - math.log(center)) / max(sigma, 0.45)) ** 2)
            if leverage >= 50:
                score *= 1.0 + tail_boost
            elif leverage <= 5 and abs(funding_bps) < 1.0:
                score *= 1.08
            weights.append(score)
        total = sum(weights) or 1.0
        return list(zip(leverages, [weight / total for weight in weights]))

    path_profile = np.ones(price_bucket_count, dtype=float)
    if selected_orderbook_rows:
        orderbook_rows = [
            {
                "price": float(getattr(level, "price", 0.0) or 0.0),
                "notional": float(getattr(level, "price", 0.0) or 0.0) * float(getattr(level, "size", 0.0) or 0.0),
                "side": str(getattr(level, "side", "") or "").strip().lower(),
            }
            for level in selected_orderbook_rows
            if _payload_float(getattr(level, "price", None)) not in (None, 0.0) and _payload_float(getattr(level, "size", None)) not in (None, 0.0)
        ]
        bid_levels = sorted([row for row in orderbook_rows if row["side"].startswith("b")], key=lambda item: item["price"], reverse=True)
        ask_levels = sorted([row for row in orderbook_rows if row["side"].startswith("a")], key=lambda item: item["price"])
        baseline_notional = statistics.median([row["notional"] for row in orderbook_rows]) if orderbook_rows else 0.0
        if baseline_notional > 0:
            local_band_notional = np.zeros(price_bucket_count, dtype=float)
            path_costs = np.zeros(price_bucket_count, dtype=float)
            for index, price in enumerate(price_axis):
                if price >= reference_price:
                    cumulative = sum(row["notional"] for row in ask_levels if float(reference_price) <= row["price"] <= price)
                    local = sum(row["notional"] for row in ask_levels if abs(row["price"] - price) <= price_step * 0.9)
                else:
                    cumulative = sum(row["notional"] for row in bid_levels if price <= row["price"] <= float(reference_price))
                    local = sum(row["notional"] for row in bid_levels if abs(row["price"] - price) <= price_step * 0.9)
                path_costs[index] = cumulative
                local_band_notional[index] = local
            max_local = float(np.max(local_band_notional)) if local_band_notional.size else 0.0
            for index in range(price_bucket_count):
                path_ease = 1.0 / (1.0 + (path_costs[index] / (baseline_notional * 16.0 + 1.0)))
                wall_score = math.log1p(local_band_notional[index]) / max(math.log1p(max_local + 1.0), 1.0) if max_local > 0 else 0.0
                path_profile[index] = max(0.25, min(1.0, 0.58 * path_ease + 0.42 * wall_score))

    quality_modifier = np.ones(len(time_values), dtype=float)
    fake_penalty_series = np.zeros(len(time_values), dtype=float)
    selected_quality_rows: List[OrderBookQualityPoint] = []
    for exchange_name in selected_exchange_keys:
        selected_quality_rows.extend(
            [point for point in (quality_rows_by_exchange or {}).get(exchange_name, []) if int(point.timestamp_ms or 0) >= since_ms]
        )
    if selected_quality_rows:
        bucket_counts = np.zeros(len(time_values), dtype=float)
        persistence_values = np.zeros(len(time_values), dtype=float)
        spoof_values = np.zeros(len(time_values), dtype=float)
        near_cancel_ratios = np.zeros(len(time_values), dtype=float)
        for point in selected_quality_rows:
            time_index = _time_index(point.timestamp_ms)
            bucket_counts[time_index] += 1.0
            persistence_values[time_index] += max(float(point.bid_wall_persistence_s or 0.0), float(point.ask_wall_persistence_s or 0.0))
            spoof_values[time_index] += float(point.spoof_events or 0.0)
            near_cancel_ratios[time_index] += (
                float(point.near_canceled_notional or 0.0)
                / max(float(point.near_added_notional or 0.0) + float(point.near_canceled_notional or 0.0), 1.0)
            )
        for index in range(len(time_values)):
            if bucket_counts[index] <= 0:
                continue
            persistence_score = min(1.0, (persistence_values[index] / bucket_counts[index]) / 45.0)
            fake_penalty = min(1.0, (spoof_values[index] / bucket_counts[index]) * 0.18 + (near_cancel_ratios[index] / bucket_counts[index]) * 0.72)
            fake_penalty_series[index] = fake_penalty
            quality_modifier[index] = max(0.55, min(1.18, 0.86 + persistence_score * 0.22 - fake_penalty * 0.28))

    selected_trade_rows: List[TradeEvent] = []
    for exchange_name in selected_exchange_keys:
        selected_trade_rows.extend(
            [trade for trade in (trade_rows_by_exchange or {}).get(exchange_name, []) if int(trade.timestamp_ms or 0) >= since_ms]
        )
    trade_flow_bias = 0.0
    if selected_trade_rows:
        buy_notional = sum(float(abs(trade.notional or 0.0)) for trade in selected_trade_rows if str(trade.side or "").lower() == "buy")
        sell_notional = sum(float(abs(trade.notional or 0.0)) for trade in selected_trade_rows if str(trade.side or "").lower() == "sell")
        trade_flow_bias = (buy_notional - sell_notional) / max(buy_notional + sell_notional, 1.0)
    funding_samples = [
        float(value)
        for exchange_name in selected_exchange_keys
        for value in [_payload_float((funding_bps_by_exchange or {}).get(exchange_name))]
        if value is not None
    ]
    funding_bias = float(statistics.median(funding_samples)) if funding_samples else 0.0

    raw_matrix = np.zeros((price_bucket_count, len(time_values)), dtype=float)
    validated_matrix = np.zeros((price_bucket_count, len(time_values)), dtype=float)
    aggregated_price_path = np.full(len(time_values), np.nan, dtype=float)
    exchange_counter = np.zeros(len(time_values), dtype=float)

    for exchange_name in selected_exchange_keys:
        candles = prepared_candles.get(exchange_name, [])
        if not candles:
            continue
        funding_bps = float(_payload_float((funding_bps_by_exchange or {}).get(exchange_name)) or 0.0)
        oi_points = [
            point
            for point in sorted((oi_rows_by_exchange or {}).get(exchange_name, []), key=lambda item: int(item.timestamp_ms or 0))
            if int(point.timestamp_ms or 0) >= since_ms - history_buffer_ms
        ]
        oi_pointer = 0
        last_oi_value: Optional[float] = None
        aligned_oi: List[Optional[float]] = []
        for candle in candles:
            while oi_pointer < len(oi_points) and int(oi_points[oi_pointer].timestamp_ms or 0) <= int(candle.timestamp_ms or 0):
                last_oi_value = _payload_float(
                    oi_points[oi_pointer].open_interest_notional
                    if oi_points[oi_pointer].open_interest_notional not in (None, 0)
                    else oi_points[oi_pointer].open_interest
                )
                oi_pointer += 1
            aligned_oi.append(last_oi_value)

        visible_end = -1
        for time_index, current_time in enumerate(time_values):
            while visible_end + 1 < len(candles) and int(candles[visible_end + 1].timestamp_ms or 0) <= current_time:
                visible_end += 1
            if visible_end < 0:
                continue
            latest_close = _payload_float(candles[visible_end].close)
            if latest_close not in (None, 0.0):
                if np.isnan(aggregated_price_path[time_index]):
                    aggregated_price_path[time_index] = float(latest_close)
                else:
                    aggregated_price_path[time_index] += float(latest_close)
                exchange_counter[time_index] += 1.0
            window_start = max(0, visible_end + 1 - lookback_candles)
            half_life = max(16.0, lookback_candles / 3.2)
            for candle_index in range(window_start, visible_end + 1):
                candle = candles[candle_index]
                entry_price = _payload_float(candle.close)
                candle_open = _payload_float(candle.open)
                candle_high = _payload_float(candle.high)
                candle_low = _payload_float(candle.low)
                if entry_price in (None, 0.0) or candle_open in (None, 0.0):
                    continue
                oi_now = aligned_oi[candle_index]
                oi_prev = aligned_oi[candle_index - 1] if candle_index > 0 else oi_now
                oi_now_value = float(oi_now or 0.0)
                oi_prev_value = float(oi_prev or oi_now_value or 0.0)
                oi_delta = max(0.0, oi_now_value - oi_prev_value)
                oi_delta_pct = ((oi_now_value - oi_prev_value) / abs(oi_prev_value) * 100.0) if oi_prev_value not in (None, 0.0) else 0.0
                volume_notional = abs(float(entry_price) * float(_payload_float(candle.volume) or 0.0))
                body_pct = (float(entry_price) - float(candle_open)) / max(abs(float(candle_open)), 1e-9)
                range_pct = (
                    max(float(candle_high or entry_price), float(entry_price)) - min(float(candle_low or entry_price), float(entry_price))
                ) / max(abs(float(entry_price)), 1e-9) * 100.0
                position_weight = max(
                    0.0,
                    0.72 * oi_delta + 0.28 * min(volume_notional, max(oi_delta * 1.5, oi_now_value * 0.22, volume_notional)),
                )
                if position_weight <= 0.0:
                    continue
                age = visible_end - candle_index
                age_decay = math.exp(-float(age) / half_life)
                long_prob = _sigmoid(
                    (funding_bps / 3.2)
                    + (body_pct * 120.0)
                    + max(oi_delta_pct, 0.0) * 0.22
                    - max(-oi_delta_pct, 0.0) * 0.12
                    + trade_flow_bias * 0.8
                )
                short_prob = 1.0 - long_prob
                leverage_profile = _leverage_profile(funding_bps, range_pct, oi_delta_pct, body_pct)
                for leverage, leverage_weight in leverage_profile:
                    unit_weight = position_weight * age_decay * leverage_weight
                    if unit_weight <= 0:
                        continue
                    long_price = _liq_price(float(entry_price), leverage, "long")
                    short_price = _liq_price(float(entry_price), leverage, "short")
                    for target_price, target_weight in ((long_price, unit_weight * long_prob), (short_price, unit_weight * short_prob)):
                        if target_price <= lower_bound or target_price >= upper_bound:
                            continue
                        price_index = _price_index(target_price)
                        for offset, kernel in [(-1, 0.28), (0, 1.0), (1, 0.28)]:
                            bucket_index = price_index + offset
                            if 0 <= bucket_index < price_bucket_count:
                                raw_matrix[bucket_index, time_index] += target_weight * kernel

    if realized_rows:
        event_scale = max(statistics.median([abs(float(row.get("notional") or 0.0)) for row in realized_rows]), 50_000.0)
        for row in realized_rows:
            event_price = _payload_float(row.get("price"))
            event_notional = _payload_float(row.get("notional"))
            if event_price in (None, 0.0) or event_notional in (None, 0.0):
                continue
            time_index = _time_index(row.get("timestamp_ms"))
            price_index = _price_index(event_price)
            boost = math.log1p(abs(float(event_notional)) / event_scale * 4.0 + 1.0)
            for price_offset, price_kernel in [(-2, 0.18), (-1, 0.52), (0, 1.0), (1, 0.52), (2, 0.18)]:
                bucket_index = price_index + price_offset
                if 0 <= bucket_index < price_bucket_count:
                    validated_matrix[bucket_index, time_index] += boost * price_kernel

    averaged_path = []
    running_last = float(reference_price)
    for index, value in enumerate(aggregated_price_path):
        if exchange_counter[index] > 0:
            running_last = float(value / exchange_counter[index])
        averaged_path.append(running_last)

    cascade_matrix = np.zeros_like(raw_matrix)
    for time_index in range(len(time_values) - 1):
        column = raw_matrix[:, time_index]
        column_max = float(np.max(column)) if column.size else 0.0
        if column_max <= 0.0:
            continue
        reference_at_time = float(averaged_path[min(time_index, len(averaged_path) - 1)] if averaged_path else reference_price)
        directional_skew = max(-1.0, min(1.0, trade_flow_bias * 0.58 + funding_bias / 7.5))
        hotspot_indices = list(np.argsort(column)[::-1][:6])
        for hotspot_index in hotspot_indices:
            hotspot_strength = float(column[hotspot_index]) / max(column_max, 1e-9)
            if hotspot_strength < 0.24:
                continue
            hotspot_price = float(price_axis[hotspot_index])
            direction = 1 if hotspot_price >= reference_at_time else -1
            direction_boost = 1.0 + (
                max(0.0, directional_skew) * 0.46 if direction > 0 else max(0.0, -directional_skew) * 0.46
            )
            travel_steps = 1 + int(
                min(
                    5,
                    max(1.0, abs(hotspot_price / max(reference_at_time, 1e-9) - 1.0) / 0.006),
                )
            )
            for step_t in range(1, 4):
                future_time = min(len(time_values) - 1, time_index + step_t)
                time_decay = 0.7 ** (step_t - 1)
                future_quality = quality_modifier[future_time] * (1.0 - fake_penalty_series[future_time] * 0.34)
                for step_p in range(1, travel_steps + 1):
                    target_index = hotspot_index + direction * step_p
                    if target_index < 0 or target_index >= price_bucket_count:
                        break
                    cascade_matrix[target_index, future_time] += (
                        float(column[hotspot_index])
                        * 0.14
                        * hotspot_strength
                        * time_decay
                        * (0.84 ** (step_p - 1))
                        * direction_boost
                        * (0.58 + path_profile[target_index] * 0.42)
                        * future_quality
                    )

    if not float(np.max(raw_matrix + validated_matrix + cascade_matrix)) > 0:
        return empty_payload

    raw_matrix *= path_profile[:, None]
    raw_matrix *= quality_modifier[None, :]
    raw_matrix += cascade_matrix
    raw_matrix += validated_matrix * (0.32 + path_profile[:, None] * 0.18)
    for time_index in range(1, raw_matrix.shape[1]):
        raw_matrix[:, time_index] = np.maximum(raw_matrix[:, time_index], raw_matrix[:, time_index - 1] * 0.93)
    for time_index in range(raw_matrix.shape[1] - 2, -1, -1):
        raw_matrix[:, time_index] = np.maximum(raw_matrix[:, time_index], raw_matrix[:, time_index + 1] * 0.87)
    column_max = np.max(raw_matrix, axis=0, keepdims=True)
    normalized_map = raw_matrix / np.where(column_max > 1e-9, column_max, 1.0)
    for _ in range(4):
        normalized_map[1:-1, :] = (
            normalized_map[1:-1, :] * 0.58
            + normalized_map[:-2, :] * 0.21
            + normalized_map[2:, :] * 0.21
        )
        normalized_map[:, 1:-1] = (
            normalized_map[:, 1:-1] * 0.54
            + normalized_map[:, :-2] * 0.23
            + normalized_map[:, 2:] * 0.23
        )
    row_mean = np.mean(normalized_map, axis=1, keepdims=True)
    row_std = np.std(normalized_map, axis=1, keepdims=True)
    z_matrix = np.clip((normalized_map - row_mean) / np.where(row_std > 1e-8, row_std, 1.0), -3.0, 3.0)

    recent_window = min(6, z_matrix.shape[1]) if z_matrix.ndim == 2 else 0
    if recent_window > 0:
        recent_weights = np.linspace(0.55, 1.0, recent_window, dtype=float)
        recent_profile = np.average(z_matrix[:, -recent_window:], axis=1, weights=recent_weights)
    else:
        recent_profile = np.zeros(price_bucket_count, dtype=float)
    recent_positive_profile = np.clip(recent_profile, 0.0, None)
    top_band_indices = list(np.argsort(recent_positive_profile)[::-1][:5])
    top_bands = []
    for index in top_band_indices:
        score = float(recent_profile[index])
        if score <= 0:
            continue
        bias = "上方清算吸引带" if float(price_axis[index]) >= float(reference_price) else "下方清算吸引带"
        top_bands.append({"price": float(price_axis[index]), "score": round(score, 2), "bias": bias})

    attraction_reference = float(averaged_path[-1] if averaged_path else reference_price)
    distance_profile = np.array([math.exp(-abs(float(price) / attraction_reference - 1.0) / 0.055) for price in price_axis], dtype=float)
    upper_mask = np.array([1.0 if float(price) >= attraction_reference else 0.0 for price in price_axis], dtype=float)
    lower_mask = 1.0 - upper_mask
    upper_attraction = float(np.sum(recent_positive_profile * distance_profile * path_profile * upper_mask))
    lower_attraction = float(np.sum(recent_positive_profile * distance_profile * path_profile * lower_mask))
    cascade_ratio = float(np.sum(cascade_matrix)) / max(float(np.sum(raw_matrix) + np.sum(validated_matrix) + np.sum(cascade_matrix)), 1e-6)
    chain_score = round(
        min(
            100.0,
            max(
                0.0,
                float(np.mean(recent_positive_profile)) * 18.0
                + cascade_ratio * 60.0
                + abs(trade_flow_bias) * 14.0,
            ),
        ),
        1,
    )
    path_score = round(float(np.mean(path_profile)) * 100.0, 1)
    fake_hotspot_pct = round(float(np.mean(fake_penalty_series)) * 100.0, 1)
    avg_oi_delta = 0.0
    oi_samples = [
        _payload_float(point.open_interest_notional if point.open_interest_notional not in (None, 0) else point.open_interest)
        for exchange_name in selected_exchange_keys
        for point in (oi_rows_by_exchange or {}).get(exchange_name, [])
        if int(point.timestamp_ms or 0) >= since_ms
    ]
    if len([value for value in oi_samples if value not in (None, 0.0)]) >= 2:
        valid_oi = [float(value) for value in oi_samples if value not in (None, 0.0)]
        avg_oi_delta = (valid_oi[-1] - valid_oi[0]) / max(abs(valid_oi[0]), 1.0)
    attraction_gap = abs(upper_attraction - lower_attraction) / max(upper_attraction + lower_attraction, 1e-6)
    dominant_direction = "更容易被上方清算密集区吸引" if upper_attraction > lower_attraction * 1.08 else "更容易被下方清算密集区吸引" if lower_attraction > upper_attraction * 1.08 else "上下吸引相对均衡"
    dynamic_score = round(
        min(
            100.0,
            max(
                0.0,
                22.0
                + chain_score * 0.5
                + path_score * 0.24
                + attraction_gap * 28.0
                + min(18.0, abs(avg_oi_delta) * 100.0 * 0.22),
            ),
        ),
        1,
    )
    trade_flow_label = "主动买盘更强，价格更容易向上方清算区靠拢" if trade_flow_bias >= 0.08 else "主动卖盘更强，价格更容易向下方清算区靠拢" if trade_flow_bias <= -0.08 else "主动买卖力量相对均衡"
    oi_bias_label = "持仓持续扩张，潜在连锁清算更容易放大" if avg_oi_delta >= 0.03 else "持仓收缩，潜在连锁清算更偏短促" if avg_oi_delta <= -0.03 else "持仓变化平稳"
    liquidity_path_label = "流动性路径偏顺畅，热点位更容易被扫到" if path_score >= 62.0 else "路径中性，热点仍需事件触发" if path_score >= 46.0 else "路径阻力偏强，假热点概率更高"
    data_quality_flags = {
        "candles": any(prepared_candles.get(exchange_name) for exchange_name in selected_exchange_keys),
        "oi": any((oi_rows_by_exchange or {}).get(exchange_name) for exchange_name in selected_exchange_keys),
        "quality": bool(selected_quality_rows),
        "orderbook": bool(selected_orderbook_rows),
        "realized": bool(realized_rows),
        "trades": bool(selected_trade_rows),
    }
    support_count = sum(1 for value in data_quality_flags.values() if value)
    data_quality = "full" if support_count >= 5 else "partial" if support_count >= 3 else "liquidation_only" if data_quality_flags["realized"] else "empty"

    time_labels = [
        pd.to_datetime(value, unit="ms", utc=True).tz_convert("Europe/Rome").strftime("%m-%d %H:%M" if window_minutes >= 720 else "%H:%M")
        for value in time_values
    ]
    display_interval_minutes = {
        "5m": 1,
        "15m": 1,
        "1h": 2,
        "4h": 5,
        "1d": 15,
    }.get(normalized_window, 5)
    merged_price_candles: List[Dict[str, Any]] = []
    candle_buckets: Dict[int, Dict[str, List[float]]] = {}
    for exchange_name in selected_exchange_keys:
        display_candles = prepared_candles.get(exchange_name, [])
        trade_candles = _aggregate_trades_to_candles(
            [trade for trade in (trade_rows_by_exchange or {}).get(exchange_name, []) if int(trade.timestamp_ms or 0) >= since_ms],
            interval_minutes=display_interval_minutes,
        )
        if len(trade_candles) >= max(4, min(24, len(display_candles) // 2 or 4)):
            display_candles = trade_candles
        for candle in display_candles:
            candle_ts = int(candle.timestamp_ms or 0)
            if candle_ts < since_ms or candle_ts > now_ms:
                continue
            entry = candle_buckets.setdefault(candle_ts, {"open": [], "high": [], "low": [], "close": []})
            for key, value in (
                ("open", _payload_float(candle.open)),
                ("high", _payload_float(candle.high)),
                ("low", _payload_float(candle.low)),
                ("close", _payload_float(candle.close)),
            ):
                if value not in (None, 0.0):
                    entry[key].append(float(value))
    for candle_ts in sorted(candle_buckets):
        entry = candle_buckets.get(candle_ts) or {}
        if not all(entry.get(key) for key in ("open", "high", "low", "close")):
            continue
        merged_price_candles.append(
            {
                "timestamp_ms": candle_ts,
                "label": pd.to_datetime(candle_ts, unit="ms", utc=True).tz_convert("Europe/Rome").strftime(
                    "%m-%d %H:%M" if window_minutes >= 720 else "%H:%M"
                ),
                "open": float(statistics.median(entry["open"])),
                "high": float(max(entry["high"])),
                "low": float(min(entry["low"])),
                "close": float(statistics.median(entry["close"])),
            }
        )
    minimum_display_candles = {"5m": 20, "15m": 36, "1h": 72, "4h": 72, "1d": 120}.get(normalized_window, 24)
    if len(merged_price_candles) < minimum_display_candles:
        valid_path_points = [
            (int(timestamp_ms), float(price_value))
            for timestamp_ms, price_value in zip(time_values, averaged_path)
            if price_value not in (None, 0.0)
        ]
        if valid_path_points:
            target_candle_count = {"5m": 30, "15m": 60, "1h": 120, "4h": 120, "1d": 144}.get(normalized_window, 48)
            group_size = max(1, int(len(valid_path_points) / max(1, min(target_candle_count, len(valid_path_points)))))
            synthesized_candles: List[Dict[str, Any]] = []
            overall_path_prices = [price for _, price in valid_path_points]
            overall_span = max(overall_path_prices) - min(overall_path_prices) if overall_path_prices else 0.0
            previous_close: Optional[float] = None
            for start in range(0, len(valid_path_points), group_size):
                chunk = valid_path_points[start : start + group_size]
                if not chunk:
                    continue
                chunk_prices = [price for _, price in chunk]
                open_price = float(previous_close if previous_close is not None else chunk_prices[0])
                close_price = float(chunk_prices[-1])
                high_price = float(max(chunk_prices))
                low_price = float(min(chunk_prices))
                reference_scale = max(abs(float(reference_price)), abs(close_price), 1.0)
                wick_pad = max((high_price - low_price) * 0.24, reference_scale * 0.00055, overall_span * 0.012, 0.02)
                body_pad = max(reference_scale * 0.00024, overall_span * 0.0035, 0.015)
                if abs(close_price - open_price) < body_pad:
                    anchor_price = float(previous_close if previous_close is not None else open_price)
                    if close_price > anchor_price:
                        open_price = close_price - body_pad
                    elif close_price < anchor_price:
                        open_price = close_price + body_pad
                    else:
                        open_price = close_price - body_pad * 0.5
                high_price = max(high_price, open_price, close_price) + wick_pad * 0.38
                low_price = min(low_price, open_price, close_price) - wick_pad * 0.38
                candle_ts = int(chunk[-1][0])
                synthesized_candles.append(
                    {
                        "timestamp_ms": candle_ts,
                        "label": pd.to_datetime(candle_ts, unit="ms", utc=True).tz_convert("Europe/Rome").strftime(
                            "%m-%d %H:%M" if window_minutes >= 720 else "%H:%M"
                        ),
                        "open": open_price,
                        "high": high_price,
                        "low": low_price,
                        "close": close_price,
                    }
                )
                previous_close = close_price
            if len(synthesized_candles) > len(merged_price_candles):
                merged_price_candles = synthesized_candles

    return {
        "model": "model3",
        "model_label": "模型3 · 升级算法版（统计热力图）",
        "coin": normalized_coin,
        "exchange_key": normalized_exchange if normalized_exchange else "all",
        "exchange": "全部已选交易所" if normalized_exchange in {"", "all"} else EXCHANGE_TITLE_MAP.get(normalized_exchange, normalized_exchange.title()),
        "window_key": normalized_window,
        "window_label": normalized_window.upper(),
        "time_labels": time_labels,
        "time_values": time_values,
        "price_axis": [float(value) for value in price_axis],
        "z": z_matrix.tolist(),
        "z_range": {"min": -3.0, "max": 3.0},
        "price_path": averaged_path,
        "price_candles": merged_price_candles,
        "current_price": float(reference_price),
        "top_bands": top_bands,
        "stats": {
            "event_count": len(realized_rows),
            "trade_count": len(selected_trade_rows),
            "oi_points": sum(len((oi_rows_by_exchange or {}).get(exchange_name, [])) for exchange_name in selected_exchange_keys),
            "quality_points": len(selected_quality_rows),
            "chain_score": chain_score,
            "path_score": path_score,
            "fake_hotspot_pct": fake_hotspot_pct,
            "dynamic_score": dynamic_score,
            "data_quality": data_quality,
            "attraction_up": round(upper_attraction, 2),
            "attraction_down": round(lower_attraction, 2),
            "attraction_bias": dominant_direction,
        },
        "signals": {
            "trade_flow_bias": trade_flow_label,
            "oi_bias": oi_bias_label,
            "liquidity_path": liquidity_path_label,
            "funding_mode": "当前 funding 代理历史倾向",
        },
        "windows": [{"key": key, "label": key.upper(), "minutes": minutes} for key, minutes in LIQUIDATION_PRICE_MAP_WINDOWS.items()],
        "exchanges": exchange_options,
    }


def _liquidation_map_status_details(status: Any) -> Dict[str, str]:
    normalized = str(status or "").strip().lower()
    if normalized == "ok":
        return {
            "status_code": "live_public",
            "status_label": "实时真流",
            "status_detail": "已接入公开爆仓实时流，统计以实时流并结合本地归档样本汇总。",
        }
    if normalized in {"sample_limited", "live feed requires tracked/archive samples"}:
        return {
            "status_code": "archive_or_sample",
            "status_label": "仅本地归档/样本",
            "status_detail": "当前主要依赖本地归档、会话缓存或已跟踪样本，实时覆盖仍有限。",
        }
    if normalized == "public platform liquidation feed unavailable":
        return {
            "status_code": "no_public_feed",
            "status_label": "无公开平台流",
            "status_detail": "交易所未提供公开全平台爆仓流，无法给出真实的平台级爆仓统计。",
        }
    if normalized == "symbol unavailable":
        return {
            "status_code": "symbol_unavailable",
            "status_label": "无该币合约",
            "status_detail": "当前交易所在本币种下没有可用合约映射或公开合约符号。",
        }
    return {
        "status_code": "sample_unknown",
        "status_label": "样本不足",
        "status_detail": "当前样本不足，结果仅适合观察，不建议据此做强判断。",
    }


def _build_liquidation_linkage_observation_frame(
    cluster_frame: pd.DataFrame,
    service: LiveTerminalService,
    *,
    limit: int = 12,
) -> pd.DataFrame:
    columns = ["开始时间", "交易所", "主导方向", "总名义金额", "大单额", "大单数", "事件流", "OI变化(%)", "盘口失衡(%)", "联动观察"]
    if cluster_frame is None or cluster_frame.empty:
        return pd.DataFrame(columns=columns)

    rows: List[Dict[str, Any]] = []
    for cluster in cluster_frame.head(limit).to_dict("records"):
        start_value = cluster.get("开始时间")
        start_ms = int(pd.Timestamp(start_value).timestamp() * 1000) if start_value is not None else 0
        duration_seconds = float(cluster.get("持续秒数") or 0.0)
        end_ms = start_ms + int(max(duration_seconds, 1.0) * 1000)
        exchange_keys = [
            str(item or "").strip().lower()
            for item in str(cluster.get("交易所") or "").split("/")
            if str(item or "").strip()
        ]
        large_trade_notional = 0.0
        large_trade_count = 0
        recorded_event_count = 0
        oi_changes: List[float] = []
        imbalance_values: List[float] = []
        for exchange_key in exchange_keys:
            trades = [
                item
                for item in service.get_trade_history(exchange_key)
                if start_ms - 120_000 <= int(item.timestamp_ms or 0) <= end_ms + 120_000
            ]
            large_trades = [item for item in trades if float(item.notional or 0.0) >= 250_000]
            large_trade_notional += sum(float(item.notional or 0.0) for item in large_trades)
            large_trade_count += len(large_trades)
            recorded_event_count += sum(
                1
                for item in service.get_recorded_events(exchange_key)
                if start_ms - 60_000 <= int(item.timestamp_ms or 0) <= end_ms + 60_000
            )
            oi_points = [
                item
                for item in service.get_oi_history(exchange_key)
                if start_ms - 10 * 60_000 <= int(item.timestamp_ms or 0) <= end_ms + 10 * 60_000
            ]
            if len(oi_points) >= 2:
                anchor = oi_points[0].open_interest_notional or oi_points[0].open_interest
                latest = oi_points[-1].open_interest_notional or oi_points[-1].open_interest
                if anchor not in (None, 0) and latest is not None:
                    oi_changes.append((float(latest) - float(anchor)) / abs(float(anchor)) * 100.0)
            quality_points = [
                item
                for item in service.get_orderbook_quality_history(exchange_key)
                if start_ms - 60_000 <= int(item.timestamp_ms or 0) <= end_ms + 60_000
            ]
            if quality_points:
                latest_quality = quality_points[-1]
                if latest_quality.imbalance_pct is not None:
                    imbalance_values.append(float(latest_quality.imbalance_pct))

        oi_change_pct = _safe_mean(oi_changes)
        imbalance_pct = _safe_mean(imbalance_values)
        observations: List[str] = []
        if large_trade_count >= 3 or large_trade_notional >= 1_000_000:
            observations.append("大单放大")
        if oi_change_pct is not None and abs(oi_change_pct) >= 1.0:
            observations.append("OI共振")
        if imbalance_pct is not None and abs(imbalance_pct) >= 8.0:
            observations.append("盘口失衡")
        if recorded_event_count >= 8:
            observations.append("事件流密集")
        rows.append(
            {
                "开始时间": start_value,
                "交易所": cluster.get("交易所"),
                "主导方向": cluster.get("主导方向"),
                "总名义金额": cluster.get("总名义金额"),
                "大单额": large_trade_notional or None,
                "大单数": large_trade_count,
                "事件流": recorded_event_count,
                "OI变化(%)": oi_change_pct,
                "盘口失衡(%)": imbalance_pct,
                "联动观察": " / ".join(observations) if observations else "等待更多共振样本",
            }
        )
    return pd.DataFrame(rows, columns=columns)


def _build_liquidation_waterfall_frame(
    events: List[LiquidationEvent],
    *,
    now_ms: int,
    window_minutes: int = 120,
    bucket_minutes: int = 5,
) -> pd.DataFrame:
    columns = ["时间桶", "净爆仓额", "净方向"]
    cutoff_ms = now_ms - max(window_minutes, 1) * 60_000
    recent_events = [event for event in events if int(event.timestamp_ms or 0) >= cutoff_ms]
    if not recent_events:
        return pd.DataFrame(columns=columns)
    frame = pd.DataFrame(
        {
            "bucket": [pd.to_datetime(event.timestamp_ms, unit="ms").floor(f"{bucket_minutes}min") for event in recent_events],
            "signed_notional": [
                -(float(event.notional or 0.0)) if event.side == "long" else float(event.notional or 0.0)
                for event in recent_events
            ],
        }
    )
    waterfall = frame.groupby("bucket", as_index=False).agg(净爆仓额=("signed_notional", "sum"))
    waterfall["净方向"] = waterfall["净爆仓额"].apply(lambda value: "空头爆仓更重" if value >= 0 else "多头爆仓更重")
    waterfall = waterfall.rename(columns={"bucket": "时间桶"}).sort_values("时间桶", ascending=False)
    return waterfall[columns].reset_index(drop=True)


def _build_liquidation_linkage_grid_frame(
    events: List[LiquidationEvent],
    *,
    now_ms: int,
    window_minutes: int = 120,
    bucket_minutes: int = 5,
) -> pd.DataFrame:
    cutoff_ms = now_ms - max(window_minutes, 1) * 60_000
    recent_events = [event for event in events if int(event.timestamp_ms or 0) >= cutoff_ms]
    if not recent_events:
        return pd.DataFrame(columns=["交易所"])
    frame = pd.DataFrame(
        {
            "交易所": [event.exchange for event in recent_events],
            "时间桶": [pd.to_datetime(event.timestamp_ms, unit="ms").floor(f"{bucket_minutes}min") for event in recent_events],
            "名义金额": [float(event.notional or 0.0) for event in recent_events],
        }
    )
    pivot = frame.pivot_table(index="交易所", columns="时间桶", values="名义金额", aggfunc="sum", fill_value=0.0)
    pivot = pivot.sort_index(axis=1, ascending=False)
    pivot.columns = [column for column in pivot.columns]
    pivot = pivot.reset_index()
    return pivot


def _build_alert_review_frame(
    alert_history_frame: pd.DataFrame,
    market_history_frame: pd.DataFrame,
    *,
    review_window_minutes: int,
) -> pd.DataFrame:
    columns = ["时间", "交易所", "告警", "预期方向", "窗口收益(%)", "顺风区间(%)", "逆风区间(%)", "命中"]
    if alert_history_frame.empty or market_history_frame.empty:
        return pd.DataFrame(columns=columns)
    alert_history_frame = canonicalize_market_frame_columns(alert_history_frame.copy())
    market_history_frame = canonicalize_market_frame_columns(market_history_frame.copy())
    alerts = alert_history_frame[alert_history_frame["动作"] == "触发"].copy()
    if alerts.empty:
        return pd.DataFrame(columns=columns)
    market = market_history_frame.copy()
    market["ts_ms"] = _coerce_timestamp_series_ms(market["时间"]).fillna(0.0).astype(int)
    alerts["ts_ms"] = _coerce_timestamp_series_ms(alerts["时间"]).fillna(0.0).astype(int)
    rows: List[Dict[str, Any]] = []
    window_ms = max(1, int(review_window_minutes)) * 60_000
    for row in alerts.to_dict("records"):
        exchange_key = _row_exchange_key(row)
        title = str(row.get("告警") or "")
        explanation = str(row.get("说明") or "")
        bias = _alert_bias_from_text(title, explanation)
        if bias is None:
            continue
        exchange_market = (
            market[market["交易所键"].astype(str) == exchange_key]
            if exchange_key
            else market[market["交易所"].astype(str) == _row_exchange_name(row)]
        )
        if exchange_market.empty:
            continue
        start_ts = int(row["ts_ms"])
        entry_rows = exchange_market[exchange_market["ts_ms"] >= start_ts].sort_values("ts_ms")
        path_rows = exchange_market[(exchange_market["ts_ms"] >= start_ts) & (exchange_market["ts_ms"] <= start_ts + window_ms)].sort_values("ts_ms")
        exit_rows = exchange_market[exchange_market["ts_ms"] >= start_ts + window_ms].sort_values("ts_ms")
        if entry_rows.empty or exit_rows.empty or path_rows.empty:
            continue
        entry_price = _row_last_price(entry_rows.iloc[0])
        exit_price = _row_last_price(exit_rows.iloc[0])
        if entry_price in (None, 0) or exit_price is None:
            continue
        raw_return_pct = (float(exit_price) - float(entry_price)) / float(entry_price) * 100.0
        path_prices = pd.to_numeric(path_rows.get("最新价"), errors="coerce").dropna()
        if path_prices.empty:
            continue
        if bias > 0:
            favorable_pct = float((path_prices.max() - float(entry_price)) / float(entry_price) * 100.0)
            adverse_pct = float((path_prices.min() - float(entry_price)) / float(entry_price) * 100.0)
        else:
            favorable_pct = float((float(entry_price) - path_prices.min()) / float(entry_price) * 100.0)
            adverse_pct = float((float(entry_price) - path_prices.max()) / float(entry_price) * 100.0)
        rows.append(
            {
                "时间": row.get("时间"),
                "交易所": row.get("交易所"),
                "告警": title,
                "预期方向": "看多" if bias > 0 else "看空",
                "窗口收益(%)": raw_return_pct,
                "顺风区间(%)": favorable_pct,
                "逆风区间(%)": adverse_pct,
                "命中": "是" if raw_return_pct * bias > 0 else "否",
            }
        )
    frame = pd.DataFrame(rows)
    if frame.empty:
        return pd.DataFrame(columns=columns)
    return frame.sort_values("时间", ascending=False).reset_index(drop=True)


def _build_alert_review_summary_frame(alert_review_frame: pd.DataFrame) -> pd.DataFrame:
    columns = ["告警", "样本数", "命中率(%)", "平均收益(%)", "中位收益(%)", "平均顺风(%)", "平均逆风(%)"]
    if alert_review_frame.empty:
        return pd.DataFrame(columns=columns)
    grouped = (
        alert_review_frame.groupby("告警", as_index=False)
        .agg(
            样本数=("命中", "size"),
            命中率=("命中", lambda series: (series == "是").mean() * 100.0),
            平均收益=("窗口收益(%)", _safe_numeric_series_mean),
            中位收益=("窗口收益(%)", _safe_numeric_series_median),
            平均顺风=("顺风区间(%)", _safe_numeric_series_mean),
            平均逆风=("逆风区间(%)", _safe_numeric_series_mean),
        )
        .sort_values(["命中率", "样本数"], ascending=[False, False])
        .reset_index(drop=True)
    )
    return grouped.rename(
        columns={
            "命中率": "命中率(%)",
            "平均收益": "平均收益(%)",
            "中位收益": "中位收益(%)",
            "平均顺风": "平均顺风(%)",
            "平均逆风": "平均逆风(%)",
        }
    )


def _build_alert_history_coverage_summary_frame(alert_history_frame: pd.DataFrame) -> pd.DataFrame:
    columns = ["告警", "样本数", "最近动作", "最近时间", "覆盖交易所"]
    if alert_history_frame.empty:
        return pd.DataFrame(columns=columns)
    history = canonicalize_market_frame_columns(alert_history_frame.copy())
    if "告警" not in history.columns:
        return pd.DataFrame(columns=columns)
    history["时间"] = pd.to_datetime(history.get("时间"), errors="coerce")
    grouped = (
        history.groupby("告警", as_index=False)
        .agg(
            样本数=("告警", "size"),
            最近时间=("时间", "max"),
            覆盖交易所=("交易所", lambda s: len({str(v).strip() for v in s if str(v).strip()})),
        )
        .sort_values(["样本数", "最近时间"], ascending=[False, False], na_position="last")
        .reset_index(drop=True)
    )
    latest_actions = (
        history.sort_values("时间", ascending=False, na_position="last")
        .groupby("告警", as_index=False)
        .first()[["告警", "动作"]]
        .rename(columns={"动作": "最近动作"})
    )
    return grouped.merge(latest_actions, on="告警", how="left")[columns]

def _build_alert_review_window_matrix(
    alert_history_frame: pd.DataFrame,
    market_history_frame: pd.DataFrame,
    *,
    review_windows: List[int],
) -> pd.DataFrame:
    columns = [
        "交易所",
        "告警",
        "预期方向",
        "窗口(min)",
        "样本数",
        "命中率(%)",
        "平均收益(%)",
        "中位收益(%)",
        "平均顺风(%)",
        "平均逆风(%)",
    ]
    rows: List[Dict[str, Any]] = []
    unique_windows = sorted({max(5, int(value)) for value in review_windows if int(value) > 0})
    for review_window in unique_windows:
        review_frame = _build_alert_review_frame(
            alert_history_frame,
            market_history_frame,
            review_window_minutes=review_window,
        )
        if review_frame.empty:
            continue
        grouped = (
            review_frame.groupby(["交易所", "告警", "预期方向"], as_index=False)
            .agg(
                样本数=("命中", "size"),
                命中率=("命中", lambda series: (series == "是").mean() * 100.0),
                平均收益=("窗口收益(%)", _safe_numeric_series_mean),
                中位收益=("窗口收益(%)", _safe_numeric_series_median),
                平均顺风=("顺风区间(%)", _safe_numeric_series_mean),
                平均逆风=("逆风区间(%)", _safe_numeric_series_mean),
            )
            .sort_values(["命中率", "样本数", "平均收益"], ascending=[False, False, False])
            .reset_index(drop=True)
            .rename(
                columns={
                    "命中率": "命中率(%)",
                    "平均收益": "平均收益(%)",
                    "中位收益": "中位收益(%)",
                    "平均顺风": "平均顺风(%)",
                    "平均逆风": "平均逆风(%)",
                }
            )
        )
        grouped["窗口(min)"] = review_window
        rows.extend(grouped.to_dict("records"))
    frame = pd.DataFrame(rows)
    if frame.empty:
        return pd.DataFrame(columns=columns)
    return (
        frame[columns]
        .sort_values(["命中率(%)", "样本数", "平均收益(%)", "窗口(min)"], ascending=[False, False, False, True])
        .reset_index(drop=True)
    )


def _build_alert_best_window_frame(alert_window_frame: pd.DataFrame) -> pd.DataFrame:
    columns = [
        "交易所",
        "告警",
        "预期方向",
        "最佳窗口(min)",
        "样本数",
        "最佳命中率(%)",
        "平均收益(%)",
        "中位收益(%)",
        "平均顺风(%)",
        "平均逆风(%)",
    ]
    if alert_window_frame.empty:
        return pd.DataFrame(columns=columns)
    best_rows = (
        alert_window_frame.sort_values(
            ["命中率(%)", "平均收益(%)", "样本数", "窗口(min)"],
            ascending=[False, False, False, True],
        )
        .groupby(["交易所", "告警", "预期方向"], as_index=False)
        .first()
        .rename(columns={"窗口(min)": "最佳窗口(min)", "命中率(%)": "最佳命中率(%)"})
    )
    return best_rows[columns].reset_index(drop=True)


def _build_alert_window_matrix_from_closure(alert_closure_frame: pd.DataFrame, *, review_window_minutes: int) -> pd.DataFrame:
    columns = [
        "交易所",
        "告警",
        "预期方向",
        "窗口(min)",
        "样本数",
        "命中率(%)",
        "平均收益(%)",
        "中位收益(%)",
        "平均顺风(%)",
        "平均逆风(%)",
    ]
    if alert_closure_frame.empty:
        return pd.DataFrame(columns=columns)
    closure = canonicalize_market_frame_columns(alert_closure_frame.copy())
    if "命中" not in closure.columns:
        closure["命中"] = None
    grouped = (
        closure.groupby(["交易所", "告警"], as_index=False)
        .agg(
            样本数=("告警", "size"),
            命中率=("命中", lambda series: (series == "是").mean() * 100.0 if len(series) else None),
            平均收益=("窗口收益(%)", _safe_numeric_series_mean),
            中位收益=("窗口收益(%)", _safe_numeric_series_median),
            平均顺风=("顺风区间(%)", _safe_numeric_series_mean),
            平均逆风=("逆风区间(%)", _safe_numeric_series_mean),
        )
        .rename(
            columns={
                "命中率": "命中率(%)",
                "平均收益": "平均收益(%)",
                "中位收益": "中位收益(%)",
                "平均顺风": "平均顺风(%)",
                "平均逆风": "平均逆风(%)",
            }
        )
    )
    grouped["预期方向"] = "-"
    grouped["窗口(min)"] = int(max(5, review_window_minutes))
    return grouped[columns].sort_values(["样本数", "平均收益(%)"], ascending=[False, False], na_position="last").reset_index(drop=True)


def _build_alert_timeline_from_history_frame(alert_history_frame: pd.DataFrame) -> pd.DataFrame:
    columns = ["时间", "交易所", "告警", "动作", "说明"]
    if alert_history_frame.empty:
        return pd.DataFrame(columns=columns)
    history = canonicalize_market_frame_columns(alert_history_frame.copy())
    for column in columns:
        if column not in history.columns:
            history[column] = None
    return history[columns].sort_values("时间", ascending=False, na_position="last").reset_index(drop=True)


def _build_alert_closure_frame(
    alert_history_frame: pd.DataFrame,
    market_history_frame: pd.DataFrame,
    event_history_frame: pd.DataFrame,
    quality_history_frame: pd.DataFrame,
    *,
    review_window_minutes: int,
    limit: int = 24,
) -> pd.DataFrame:
    columns = ["时间", "交易所", "告警", "触发价格", "触发Funding", "触发OI", "5m事件额", "5m事件数", "近价撤补比", "顺风区间(%)", "逆风区间(%)", "窗口收益(%)", "命中"]
    if alert_history_frame.empty or market_history_frame.empty:
        return pd.DataFrame(columns=columns)
    alert_history_frame = canonicalize_market_frame_columns(alert_history_frame.copy())
    market_history_frame = canonicalize_market_frame_columns(market_history_frame.copy())
    event_history_frame = canonicalize_market_frame_columns(event_history_frame.copy()) if isinstance(event_history_frame, pd.DataFrame) and not event_history_frame.empty else event_history_frame
    quality_history_frame = canonicalize_market_frame_columns(quality_history_frame.copy()) if isinstance(quality_history_frame, pd.DataFrame) and not quality_history_frame.empty else quality_history_frame
    alert_review_frame = _build_alert_review_frame(alert_history_frame, market_history_frame, review_window_minutes=review_window_minutes)
    alerts = alert_history_frame[alert_history_frame["动作"] == "触发"].copy()
    if alerts.empty:
        return pd.DataFrame(columns=columns)
    alerts["ts_ms"] = _coerce_timestamp_series_ms(alerts["时间"]).fillna(0.0).astype(int)
    market = market_history_frame.copy()
    market["ts_ms"] = _coerce_timestamp_series_ms(market["时间"]).fillna(0.0).astype(int)
    events = event_history_frame.copy()
    if not events.empty:
        events["ts_ms"] = _coerce_timestamp_series_ms(events["时间"]).fillna(0.0).astype(int)
    quality = quality_history_frame.copy()
    if not quality.empty:
        quality["ts_ms"] = _coerce_timestamp_series_ms(quality["时间"]).fillna(0.0).astype(int)
    review_lookup = {
        (str(row.get("时间")), str(row.get("交易所")), str(row.get("告警"))): row
        for row in alert_review_frame.to_dict("records")
    } if not alert_review_frame.empty else {}
    rows: List[Dict[str, Any]] = []
    for row in alerts.sort_values("ts_ms", ascending=False).head(limit).to_dict("records"):
        exchange_key = _row_exchange_key(row)
        exchange_name = _row_exchange_name(row)
        title = str(row.get("告警") or "")
        alert_ts = int(row.get("ts_ms") or 0)
        if exchange_key and "交易所键" in market.columns:
            market_slice = market[market["交易所键"].astype(str) == exchange_key].copy()
        else:
            market_slice = market[market["交易所"].astype(str) == exchange_name].copy()
        if market_slice.empty:
            continue
        trigger_market = market_slice.iloc[(market_slice["ts_ms"] - alert_ts).abs().argsort()[:1]].iloc[0].to_dict()
        event_notional = None
        event_count = 0
        if not events.empty:
            event_slice = events
            if exchange_key and "交易所键" in events.columns:
                event_slice = event_slice[event_slice["交易所键"].astype(str) == exchange_key]
            else:
                event_slice = event_slice[event_slice["交易所"].astype(str) == exchange_name]
            event_slice = event_slice[(event_slice["ts_ms"] >= alert_ts) & (event_slice["ts_ms"] <= alert_ts + 5 * 60_000)]
            event_count = int(len(event_slice))
            if "名义金额" in event_slice.columns and not event_slice.empty:
                event_notional = float(pd.to_numeric(event_slice["名义金额"], errors="coerce").fillna(0.0).sum())
        cancel_refill_ratio = None
        if not quality.empty:
            quality_slice = quality
            if exchange_key and "交易所键" in quality.columns:
                quality_slice = quality_slice[quality_slice["交易所键"].astype(str) == exchange_key]
            else:
                quality_slice = quality_slice[quality_slice["交易所"].astype(str) == exchange_name]
            quality_slice = quality_slice[(quality_slice["ts_ms"] >= alert_ts - 2 * 60_000) & (quality_slice["ts_ms"] <= alert_ts + 2 * 60_000)]
            if not quality_slice.empty:
                added_sum = float(pd.to_numeric(quality_slice["近价新增"], errors="coerce").fillna(0.0).sum()) if "近价新增" in quality_slice.columns else 0.0
                canceled_sum = float(pd.to_numeric(quality_slice["近价撤单"], errors="coerce").fillna(0.0).sum()) if "近价撤单" in quality_slice.columns else 0.0
                cancel_refill_ratio = canceled_sum / max(added_sum, 1.0)
        review_row = review_lookup.get((str(row.get("时间")), exchange_name, title), {})
        rows.append(
            {
                "时间": row.get("时间"),
                "交易所": exchange_name,
                "告警": title,
                "触发价格": _row_last_price(trigger_market),
                "触发Funding": _row_funding_bps(trigger_market),
                "触发OI": _row_oi_notional(trigger_market),
                "5m事件额": event_notional,
                "5m事件数": event_count,
                "近价撤补比": cancel_refill_ratio,
                "顺风区间(%)": _payload_float(review_row.get("顺风区间(%)")),
                "逆风区间(%)": _payload_float(review_row.get("逆风区间(%)")),
                "窗口收益(%)": _payload_float(review_row.get("窗口收益(%)")),
                "命中": review_row.get("命中") or "-",
            }
        )
    frame = pd.DataFrame(rows)
    if frame.empty:
        return pd.DataFrame(columns=columns)
    return frame.reset_index(drop=True)


def _build_alert_closure_frame_v2(
    alert_history_frame: pd.DataFrame,
    market_history_frame: pd.DataFrame,
    event_history_frame: pd.DataFrame,
    quality_history_frame: pd.DataFrame,
    *,
    review_window_minutes: int,
    limit: int = 24,
) -> pd.DataFrame:
    columns = [
        "时间",
        "交易所",
        "告警",
        "预期方向",
        "触发价格",
        "触发Funding",
        "触发OI",
        "触发盘口失衡(%)",
        "触发撤补比",
        "5m事件额",
        "5m事件数",
        "5m大单额",
        "5m爆仓额",
        "15m事件额",
        "1h事件额",
        "5m收益(%)",
        "15m收益(%)",
        "1h收益(%)",
        "5m命中",
        "15m命中",
        "1h命中",
        "顺风区间(%)",
        "逆风区间(%)",
        "窗口收益(%)",
        "命中",
    ]
    if alert_history_frame.empty or market_history_frame.empty:
        return pd.DataFrame(columns=columns)
    alert_history_frame = canonicalize_market_frame_columns(alert_history_frame.copy())
    market_history_frame = canonicalize_market_frame_columns(market_history_frame.copy())
    event_history_frame = canonicalize_market_frame_columns(event_history_frame.copy()) if isinstance(event_history_frame, pd.DataFrame) and not event_history_frame.empty else event_history_frame
    quality_history_frame = canonicalize_market_frame_columns(quality_history_frame.copy()) if isinstance(quality_history_frame, pd.DataFrame) and not quality_history_frame.empty else quality_history_frame
    alert_review_frame = _build_alert_review_frame(alert_history_frame, market_history_frame, review_window_minutes=review_window_minutes)
    window_review_frames = {
        window: _build_alert_review_frame(alert_history_frame, market_history_frame, review_window_minutes=window)
        for window in sorted({*DEFAULT_ALERT_REVIEW_WINDOWS, max(5, int(review_window_minutes))})
    }
    alerts = alert_history_frame[alert_history_frame["动作"] == "触发"].copy()
    if alerts.empty:
        return pd.DataFrame(columns=columns)
    alerts["ts_ms"] = _coerce_timestamp_series_ms(alerts["时间"]).fillna(0.0).astype(int)
    market = market_history_frame.copy()
    market["ts_ms"] = _coerce_timestamp_series_ms(market["时间"]).fillna(0.0).astype(int)
    events = event_history_frame.copy()
    if not events.empty:
        events["ts_ms"] = _coerce_timestamp_series_ms(events["时间"]).fillna(0.0).astype(int)
    quality = quality_history_frame.copy()
    if not quality.empty:
        quality["ts_ms"] = _coerce_timestamp_series_ms(quality["时间"]).fillna(0.0).astype(int)
    review_lookup = {
        (str(item.get("时间")), str(item.get("交易所")), str(item.get("告警"))): item
        for item in alert_review_frame.to_dict("records")
    } if not alert_review_frame.empty else {}
    window_review_lookup = {
        window: {
            (str(item.get("时间")), str(item.get("交易所")), str(item.get("告警"))): item
            for item in frame.to_dict("records")
        }
        for window, frame in window_review_frames.items()
        if not frame.empty
    }
    rows: List[Dict[str, Any]] = []
    for row in alerts.sort_values("ts_ms", ascending=False).head(limit).to_dict("records"):
        exchange_key = _row_exchange_key(row)
        exchange_name = _row_exchange_name(row)
        title = str(row.get("告警") or "")
        alert_ts = int(row.get("ts_ms") or 0)
        review_key = (str(row.get("时间")), exchange_name, title)
        if exchange_key and "交易所键" in market.columns:
            market_slice = market[market["交易所键"].astype(str) == exchange_key].copy()
        else:
            market_slice = market[market["交易所"].astype(str) == exchange_name].copy()
        if market_slice.empty:
            continue
        trigger_market = market_slice.iloc[(market_slice["ts_ms"] - alert_ts).abs().argsort()[:1]].iloc[0].to_dict()
        event_metrics_by_window: Dict[int, Dict[str, Any]] = {}
        if not events.empty:
            event_slice = events
            if exchange_key and "交易所键" in events.columns:
                event_slice = event_slice[event_slice["交易所键"].astype(str) == exchange_key]
            else:
                event_slice = event_slice[event_slice["交易所"].astype(str) == exchange_name]
            kind_series = event_slice.get("类型", pd.Series(dtype="object")).astype(str).str.strip().str.lower()
            notional_series = (
                pd.to_numeric(event_slice.get("名义金额"), errors="coerce").fillna(0.0)
                if "名义金额" in event_slice.columns
                else pd.Series(0.0, index=event_slice.index)
            )
            for window in (5, 15, 60):
                scoped_slice = event_slice[(event_slice["ts_ms"] >= alert_ts) & (event_slice["ts_ms"] <= alert_ts + window * 60_000)]
                if scoped_slice.empty:
                    event_metrics_by_window[window] = {"notional": None, "count": 0, "large_notional": None, "liq_notional": None}
                    continue
                scoped_notional = notional_series.reindex(scoped_slice.index).fillna(0.0)
                scoped_kinds = kind_series.reindex(scoped_slice.index).fillna("")
                event_metrics_by_window[window] = {
                    "notional": float(scoped_notional.sum()),
                    "count": int(len(scoped_slice)),
                    "large_notional": float(scoped_notional[scoped_kinds == "trade"].sum()),
                    "liq_notional": float(scoped_notional[scoped_kinds == "liquidation"].sum()),
                }
        cancel_refill_ratio = None
        trigger_imbalance = None
        if not quality.empty:
            quality_slice = quality
            if exchange_key and "交易所键" in quality.columns:
                quality_slice = quality_slice[quality_slice["交易所键"].astype(str) == exchange_key]
            else:
                quality_slice = quality_slice[quality_slice["交易所"].astype(str) == exchange_name]
            quality_slice = quality_slice[(quality_slice["ts_ms"] >= alert_ts - 2 * 60_000) & (quality_slice["ts_ms"] <= alert_ts + 2 * 60_000)]
            if not quality_slice.empty:
                added_sum = float(pd.to_numeric(quality_slice.get("近价新增"), errors="coerce").fillna(0.0).sum()) if "近价新增" in quality_slice.columns else 0.0
                canceled_sum = float(pd.to_numeric(quality_slice.get("近价撤单"), errors="coerce").fillna(0.0).sum()) if "近价撤单" in quality_slice.columns else 0.0
                cancel_refill_ratio = canceled_sum / max(added_sum, 1.0)
                nearest_quality = quality_slice.iloc[(quality_slice["ts_ms"] - alert_ts).abs().argsort()[:1]].iloc[0].to_dict()
                trigger_imbalance = _payload_float(nearest_quality.get("盘口失衡(%)"))
        review_row = review_lookup.get(review_key, {})
        review_5m = (window_review_lookup.get(5) or {}).get(review_key, {})
        review_15m = (window_review_lookup.get(15) or {}).get(review_key, {})
        review_1h = (window_review_lookup.get(60) or {}).get(review_key, {})
        event_5m = event_metrics_by_window.get(5, {})
        event_15m = event_metrics_by_window.get(15, {})
        event_1h = event_metrics_by_window.get(60, {})
        rows.append(
            {
                "时间": row.get("时间"),
                "交易所": exchange_name,
                "告警": title,
                "预期方向": review_row.get("预期方向") or review_5m.get("预期方向") or review_15m.get("预期方向") or review_1h.get("预期方向") or "-",
                "触发价格": _row_last_price(trigger_market),
                "触发Funding": _row_funding_bps(trigger_market),
                "触发OI": _row_oi_notional(trigger_market),
                "触发盘口失衡(%)": trigger_imbalance,
                "触发撤补比": cancel_refill_ratio,
                "5m事件额": event_5m.get("notional"),
                "5m事件数": event_5m.get("count"),
                "5m大单额": event_5m.get("large_notional"),
                "5m爆仓额": event_5m.get("liq_notional"),
                "15m事件额": event_15m.get("notional"),
                "1h事件额": event_1h.get("notional"),
                "5m收益(%)": _payload_float(review_5m.get("窗口收益(%)")),
                "15m收益(%)": _payload_float(review_15m.get("窗口收益(%)")),
                "1h收益(%)": _payload_float(review_1h.get("窗口收益(%)")),
                "5m命中": review_5m.get("命中") or "-",
                "15m命中": review_15m.get("命中") or "-",
                "1h命中": review_1h.get("命中") or "-",
                "顺风区间(%)": _payload_float(review_row.get("顺风区间(%)")),
                "逆风区间(%)": _payload_float(review_row.get("逆风区间(%)")),
                "窗口收益(%)": _payload_float(review_row.get("窗口收益(%)")),
                "命中": review_row.get("命中") or "-",
            }
        )
    frame = pd.DataFrame(rows)
    if frame.empty:
        return pd.DataFrame(columns=columns)
    return frame[columns].reset_index(drop=True)


def _adaptive_alert_reliability(hit_rate: Any, sample_count: Any) -> str:
    rate = _payload_float(hit_rate)
    samples = int(sample_count or 0)
    if samples < 3 or rate is None:
        return "样本不足"
    if samples >= 6 and float(rate) >= 62.0:
        return "高"
    if float(rate) >= 50.0:
        return "中"
    return "低"


def _alert_driver_from_text(title: Any, explanation: Any, reference_driver: Any = None) -> str:
    text = f"{title or ''} {explanation or ''}".lower()
    has_spot = any(token in text for token in ("现货", "spot", "lead-lag", "先动", "确认"))
    has_perp = any(token in text for token in ("合约", "perp", "funding", "oi", "爆仓", "挤压", "抢跑"))
    if has_spot and has_perp:
        return "现货+合约"
    if has_spot:
        return "现货"
    if has_perp:
        return "合约"
    driver_text = str(reference_driver or "").strip()
    if "现货" in driver_text and "合约" in driver_text:
        return "现货+合约"
    if "现货" in driver_text:
        return "现货"
    if "合约" in driver_text:
        return "合约"
    return "混合"


def _match_alert_review_stats(
    alert_title: Any,
    *,
    exchange_name: Any,
    review_summary_frame: pd.DataFrame,
    best_window_frame: pd.DataFrame,
) -> Dict[str, Any]:
    normalized_title = str(alert_title or "").strip()
    normalized_exchange = str(exchange_name or "").strip()
    summary_row: Dict[str, Any] = {}
    if not review_summary_frame.empty and normalized_title and "告警" in review_summary_frame.columns:
        exact = review_summary_frame[review_summary_frame["告警"].astype(str) == normalized_title]
        if exact.empty:
            exact = review_summary_frame[review_summary_frame["告警"].astype(str).str.contains(normalized_title, na=False)]
        if exact.empty:
            exact = review_summary_frame[review_summary_frame["告警"].astype(str).apply(lambda value: normalized_title in value)]
        if not exact.empty:
            summary_row = exact.iloc[0].to_dict()
    best_row: Dict[str, Any] = {}
    if not best_window_frame.empty and normalized_title and "告警" in best_window_frame.columns:
        scoped = best_window_frame[best_window_frame["告警"].astype(str) == normalized_title]
        if normalized_exchange and "交易所" in best_window_frame.columns:
            exchange_scoped = scoped[scoped["交易所"].astype(str) == normalized_exchange]
            if not exchange_scoped.empty:
                scoped = exchange_scoped
        if scoped.empty:
            scoped = best_window_frame[best_window_frame["告警"].astype(str).str.contains(normalized_title, na=False)]
        if not scoped.empty:
            best_row = scoped.iloc[0].to_dict()
    return {
        "sample_count": int(summary_row.get("样本数") or best_row.get("样本数") or 0),
        "hit_rate_pct": _payload_float(summary_row.get("命中率(%)") or best_row.get("最佳命中率(%)")),
        "avg_return_pct": _payload_float(summary_row.get("平均收益(%)") or best_row.get("平均收益(%)")),
        "best_window_min": int(best_row.get("最佳窗口(min)") or 0) if best_row.get("最佳窗口(min)") not in (None, "") else None,
        "reliability": _adaptive_alert_reliability(
            summary_row.get("命中率(%)") or best_row.get("最佳命中率(%)"),
            summary_row.get("样本数") or best_row.get("样本数"),
        ),
    }


def _build_adaptive_alert_thresholds(
    market_history_frame: pd.DataFrame,
    event_history_frame: pd.DataFrame,
    quality_history_frame: pd.DataFrame,
    bar_history_frame: pd.DataFrame,
    *,
    time_window: str,
    market_scope: str,
) -> Dict[str, Any]:
    normalized_time_window = _normalize_time_window(time_window)
    active_minutes = max(5, _time_window_minutes(normalized_time_window))
    market_history_frame = canonicalize_market_frame_columns(market_history_frame.copy()) if isinstance(market_history_frame, pd.DataFrame) and not market_history_frame.empty else market_history_frame
    event_history_frame = canonicalize_market_frame_columns(event_history_frame.copy()) if isinstance(event_history_frame, pd.DataFrame) and not event_history_frame.empty else event_history_frame
    quality_history_frame = canonicalize_market_frame_columns(quality_history_frame.copy()) if isinstance(quality_history_frame, pd.DataFrame) and not quality_history_frame.empty else quality_history_frame
    price_thresholds: Dict[str, float] = {}
    if bar_history_frame is not None and not bar_history_frame.empty and {"exchange_key", "bucket_ms", "close"}.issubset(set(bar_history_frame.columns)):
        working = bar_history_frame.copy()
        working["close"] = pd.to_numeric(working["close"], errors="coerce")
        working["bucket_ms"] = pd.to_numeric(working["bucket_ms"], errors="coerce")
        working = working.dropna(subset=["close", "bucket_ms"])
        for window_key, minutes in (("5m", 5), ("15m", 15), ("30m", 30), ("1h", 60), ("4h", 240)):
            changes: List[float] = []
            for _, exchange_frame in working.groupby("exchange_key", sort=False):
                exchange_frame = exchange_frame.sort_values("bucket_ms").reset_index(drop=True)
                if len(exchange_frame) <= minutes:
                    continue
                series = exchange_frame["close"].pct_change(periods=minutes).abs() * 100.0
                changes.extend([float(value) for value in series.dropna().tolist() if pd.notna(value)])
            if changes:
                price_thresholds[window_key] = round(max(0.25, float(pd.Series(changes).quantile(0.9))), 3)
    event_notional = (
        pd.to_numeric(event_history_frame.get("名义金额"), errors="coerce").abs().dropna()
        if event_history_frame is not None and not event_history_frame.empty and "名义金额" in event_history_frame.columns
        else pd.Series(dtype="float64")
    )
    event_kind_series = (
        event_history_frame.get("类型", pd.Series(dtype="object")).astype(str).str.strip().str.lower()
        if event_history_frame is not None and not event_history_frame.empty
        else pd.Series(dtype="object")
    )
    trade_notional = event_notional[event_kind_series == "trade"] if not event_notional.empty else pd.Series(dtype="float64")
    liquidation_notional = event_notional[event_kind_series == "liquidation"] if not event_notional.empty else pd.Series(dtype="float64")
    funding_series = (
        pd.to_numeric(market_history_frame.get("Funding(bp)"), errors="coerce").abs().dropna()
        if market_history_frame is not None and not market_history_frame.empty and "Funding(bp)" in market_history_frame.columns
        else pd.Series(dtype="float64")
    )
    oi_change_values: List[float] = []
    if market_history_frame is not None and not market_history_frame.empty and {"交易所键", "时间", "OI总额"}.issubset(set(market_history_frame.columns)):
        market_working = market_history_frame.copy()
        market_working["ts_ms"] = _coerce_timestamp_series_ms(market_working["时间"]).fillna(0.0).astype("int64")
        market_working["OI总额"] = pd.to_numeric(market_working["OI总额"], errors="coerce")
        market_working = market_working.dropna(subset=["ts_ms", "OI总额"])
        for _, exchange_frame in market_working.groupby("交易所键", sort=False):
            exchange_frame = exchange_frame.sort_values("ts_ms").reset_index(drop=True)
            if len(exchange_frame) < 2:
                continue
            pct_series = exchange_frame["OI总额"].pct_change().abs() * 100.0
            oi_change_values.extend([float(value) for value in pct_series.dropna().tolist() if pd.notna(value)])
    imbalance_series = (
        pd.to_numeric(quality_history_frame.get("盘口失衡(%)"), errors="coerce").abs().dropna()
        if quality_history_frame is not None and not quality_history_frame.empty and "盘口失衡(%)" in quality_history_frame.columns
        else pd.Series(dtype="float64")
    )
    cancel_refill_values: List[float] = []
    if quality_history_frame is not None and not quality_history_frame.empty and {"近价撤单", "近价新增"}.issubset(set(quality_history_frame.columns)):
        canceled = pd.to_numeric(quality_history_frame["近价撤单"], errors="coerce").fillna(0.0).abs()
        added = pd.to_numeric(quality_history_frame["近价新增"], errors="coerce").fillna(0.0).abs()
        ratio_series = canceled / added.clip(lower=1.0)
        cancel_refill_values.extend([float(value) for value in ratio_series.dropna().tolist() if pd.notna(value)])
    active_price_threshold = price_thresholds.get(normalized_time_window) or price_thresholds.get("1h") or 1.0
    thresholds = {
        "mode": "adaptive_v1",
        "market_scope": market_scope,
        "time_window": normalized_time_window,
        "active_price_move_pct": round(float(active_price_threshold), 3),
        "price_move_pct": price_thresholds,
        "trade_notional": round(max(TAPE_MIN_NOTIONAL_FLOOR, float(trade_notional.quantile(0.9)) if not trade_notional.empty else TAPE_MIN_NOTIONAL_FLOOR), 2),
        "liquidation_notional": round(max(TAPE_MIN_NOTIONAL_FLOOR, float(liquidation_notional.quantile(0.9)) if not liquidation_notional.empty else TAPE_MIN_NOTIONAL_FLOOR), 2),
        "oi_change_pct": round(max(0.8, float(pd.Series(oi_change_values).quantile(0.85)) if oi_change_values else 0.8), 3),
        "funding_bps": round(max(1.5, float(funding_series.quantile(0.85)) if not funding_series.empty else 1.5), 3),
        "orderbook_imbalance_pct": round(max(6.0, float(imbalance_series.quantile(0.85)) if not imbalance_series.empty else 6.0), 3),
        "cancel_refill_ratio": round(max(1.15, float(pd.Series(cancel_refill_values).quantile(0.85)) if cancel_refill_values else 1.15), 3),
        "sample_counts": {
            "market": int(len(market_history_frame)) if isinstance(market_history_frame, pd.DataFrame) else 0,
            "events": int(len(event_history_frame)) if isinstance(event_history_frame, pd.DataFrame) else 0,
            "quality": int(len(quality_history_frame)) if isinstance(quality_history_frame, pd.DataFrame) else 0,
            "bars": int(len(bar_history_frame)) if isinstance(bar_history_frame, pd.DataFrame) else 0,
        },
    }
    thresholds["summary_text"] = (
        f"{normalized_time_window}波动>{thresholds['active_price_move_pct']:.2f}% | "
        f"大额>{_fmt_compact(thresholds['trade_notional'])} | "
        f"OI>{thresholds['oi_change_pct']:.2f}% | "
        f"Funding>{thresholds['funding_bps']:.2f}bps"
    )
    return thresholds


def _build_adaptive_threshold_frame(thresholds: Dict[str, Any]) -> pd.DataFrame:
    sample_counts = thresholds.get("sample_counts") if isinstance(thresholds.get("sample_counts"), dict) else {}
    price_windows = thresholds.get("price_move_pct") if isinstance(thresholds.get("price_move_pct"), dict) else {}
    rows: List[Dict[str, Any]] = [
        {"指标": "当前窗口价格异动", "自适应阈值": thresholds.get("active_price_move_pct"), "口径": f"{thresholds.get('time_window') or '-'} 90分位绝对涨跌幅", "样本量": int(sample_counts.get("bars") or 0)},
        {"指标": "大额成交", "自适应阈值": thresholds.get("trade_notional"), "口径": "近24h trade 名义金额 90分位", "样本量": int(sample_counts.get("events") or 0)},
        {"指标": "爆仓异动", "自适应阈值": thresholds.get("liquidation_notional"), "口径": "近24h liquidation 名义金额 90分位", "样本量": int(sample_counts.get("events") or 0)},
        {"指标": "OI变化", "自适应阈值": thresholds.get("oi_change_pct"), "口径": "近24h OI金额相邻变化 85分位", "样本量": int(sample_counts.get("market") or 0)},
        {"指标": "Funding极值", "自适应阈值": thresholds.get("funding_bps"), "口径": "近24h Funding 绝对值 85分位", "样本量": int(sample_counts.get("market") or 0)},
        {"指标": "盘口失衡", "自适应阈值": thresholds.get("orderbook_imbalance_pct"), "口径": "近24h 盘口失衡绝对值 85分位", "样本量": int(sample_counts.get("quality") or 0)},
        {"指标": "撤补比", "自适应阈值": thresholds.get("cancel_refill_ratio"), "口径": "近24h 近价撤单/新增 85分位", "样本量": int(sample_counts.get("quality") or 0)},
    ]
    for window_key, value in sorted(price_windows.items(), key=lambda item: RATIO_WINDOW_OPTIONS.get(item[0], 0)):
        rows.append({"指标": f"{window_key}价格阈值", "自适应阈值": value, "口径": "基于1m bars 的滚动涨跌幅", "样本量": int(sample_counts.get("bars") or 0)})
    return pd.DataFrame(rows, columns=["指标", "自适应阈值", "口径", "样本量"])


def _build_alert_explanation_frame(
    alert_frame: pd.DataFrame,
    review_summary_frame: pd.DataFrame,
    best_window_frame: pd.DataFrame,
    *,
    adaptive_thresholds: Dict[str, Any],
    reference_driver: Any,
    reference_suggestion: Any,
    limit: int = 18,
) -> pd.DataFrame:
    columns = ["时间", "交易所", "告警", "为什么触发", "谁在推动", "历史命中率(%)", "样本数", "最佳窗口(min)", "过去准不准", "阈值参考", "执行建议", "__selection"]
    if alert_frame.empty:
        return pd.DataFrame(columns=columns)
    rows: List[Dict[str, Any]] = []
    for row in alert_frame.head(limit).to_dict("records"):
        title = str(row.get("告警") or "-")
        explanation = str(row.get("解释") or row.get("说明") or row.get("触发说明") or title)
        exchange_name = str(row.get("交易所") or "-")
        review_stats = _match_alert_review_stats(
            title,
            exchange_name=exchange_name,
            review_summary_frame=review_summary_frame,
            best_window_frame=best_window_frame,
        )
        driver = _alert_driver_from_text(title, explanation, reference_driver)
        reliability = review_stats.get("reliability") or "样本不足"
        if reference_suggestion and reliability in {"低", "样本不足"}:
            suggestion = f"先轻仓观察；{reference_suggestion}"
        elif reference_suggestion:
            suggestion = str(reference_suggestion)
        else:
            suggestion = "优先看后续确认"
        rows.append(
            {
                "时间": row.get("时间"),
                "交易所": exchange_name,
                "告警": title,
                "为什么触发": explanation,
                "谁在推动": driver,
                "历史命中率(%)": review_stats.get("hit_rate_pct"),
                "样本数": review_stats.get("sample_count"),
                "最佳窗口(min)": review_stats.get("best_window_min"),
                "过去准不准": reliability,
                "阈值参考": adaptive_thresholds.get("summary_text"),
                "执行建议": suggestion,
                "__selection": {
                    **(row.get("__selection") if isinstance(row.get("__selection"), dict) else {}),
                    "event_title": title,
                    "event_time_ms": int(pd.to_datetime(row.get("时间"), errors="coerce").value // 10**6) if row.get("时间") not in (None, "") else None,
                },
            }
        )
    return pd.DataFrame(rows, columns=columns)


def _build_alert_replay_frame(
    alert_history_frame: pd.DataFrame,
    market_history_frame: pd.DataFrame,
    event_history_frame: pd.DataFrame,
    quality_history_frame: pd.DataFrame,
    review_summary_frame: pd.DataFrame,
    best_window_frame: pd.DataFrame,
    *,
    adaptive_thresholds: Dict[str, Any],
    reference_driver: Any,
    limit: int = 12,
) -> pd.DataFrame:
    columns = [
        "时间",
        "交易所",
        "告警",
        "谁在推动",
        "触发前5m(%)",
        "触发后5m(%)",
        "触发后15m(%)",
        "Funding变化(bps)",
        "OI变化(%)",
        "5m大单额",
        "5m爆仓额",
        "盘口质量",
        "历史命中率(%)",
        "过去准不准",
        "回放摘要",
        "__selection",
    ]
    if alert_history_frame.empty or market_history_frame.empty:
        return pd.DataFrame(columns=columns)
    alert_history_frame = canonicalize_market_frame_columns(alert_history_frame.copy())
    market_history_frame = canonicalize_market_frame_columns(market_history_frame.copy())
    event_history_frame = canonicalize_market_frame_columns(event_history_frame.copy()) if isinstance(event_history_frame, pd.DataFrame) and not event_history_frame.empty else event_history_frame
    quality_history_frame = canonicalize_market_frame_columns(quality_history_frame.copy()) if isinstance(quality_history_frame, pd.DataFrame) and not quality_history_frame.empty else quality_history_frame
    alerts = alert_history_frame[alert_history_frame["动作"].astype(str) == "触发"].copy() if "动作" in alert_history_frame.columns else alert_history_frame.copy()
    if alerts.empty:
        return pd.DataFrame(columns=columns)
    alerts["ts_ms"] = _coerce_timestamp_series_ms(alerts["时间"]).fillna(0.0).astype(int)
    market = market_history_frame.copy()
    market["ts_ms"] = _coerce_timestamp_series_ms(market["时间"]).fillna(0.0).astype(int)
    events = event_history_frame.copy()
    if not events.empty:
        events["ts_ms"] = _coerce_timestamp_series_ms(events["时间"]).fillna(0.0).astype(int)
        events["名义金额"] = pd.to_numeric(events.get("名义金额"), errors="coerce").fillna(0.0)
        events["类型"] = events.get("类型", pd.Series(dtype="object")).astype(str).str.strip().str.lower()
    quality = quality_history_frame.copy()
    if not quality.empty:
        quality["ts_ms"] = _coerce_timestamp_series_ms(quality["时间"]).fillna(0.0).astype(int)

    def nearest_row(frame: pd.DataFrame, target_ms: int, *, exchange_key: str, exchange_name: str, prefer_before: bool = False) -> Dict[str, Any]:
        scoped = frame
        if exchange_key and "交易所键" in scoped.columns:
            scoped = scoped[scoped["交易所键"].astype(str) == exchange_key]
        elif "交易所" in scoped.columns:
            scoped = scoped[scoped["交易所"].astype(str) == exchange_name]
        if scoped.empty:
            return {}
        if prefer_before:
            before = scoped[scoped["ts_ms"] <= target_ms]
            if not before.empty:
                scoped = before
        return scoped.iloc[(scoped["ts_ms"] - target_ms).abs().argsort()[:1]].iloc[0].to_dict()

    rows: List[Dict[str, Any]] = []
    imbalance_threshold = _payload_float(adaptive_thresholds.get("orderbook_imbalance_pct")) or 0.0
    cancel_refill_threshold = _payload_float(adaptive_thresholds.get("cancel_refill_ratio")) or 0.0
    for row in alerts.sort_values("ts_ms", ascending=False).head(limit).to_dict("records"):
        exchange_key = _row_exchange_key(row)
        exchange_name = _row_exchange_name(row)
        alert_ts = int(row.get("ts_ms") or 0)
        title = str(row.get("告警") or "-")
        trigger_market = nearest_row(market, alert_ts, exchange_key=exchange_key, exchange_name=exchange_name)
        if not trigger_market:
            continue
        pre_market = nearest_row(market, alert_ts - 5 * 60_000, exchange_key=exchange_key, exchange_name=exchange_name, prefer_before=True)
        post_5m_market = nearest_row(market, alert_ts + 5 * 60_000, exchange_key=exchange_key, exchange_name=exchange_name)
        post_15m_market = nearest_row(market, alert_ts + 15 * 60_000, exchange_key=exchange_key, exchange_name=exchange_name)
        trigger_price = _row_last_price(trigger_market)
        pre_price = _row_last_price(pre_market)
        post_5m_price = _row_last_price(post_5m_market)
        post_15m_price = _row_last_price(post_15m_market)
        trigger_oi = _row_oi_notional(trigger_market)
        post_15m_oi = _row_oi_notional(post_15m_market)
        trigger_funding = _row_funding_bps(trigger_market)
        post_15m_funding = _row_funding_bps(post_15m_market)
        pre_5m_pct = None if pre_price in (None, 0) or trigger_price in (None, 0) else (float(trigger_price) - float(pre_price)) / float(pre_price) * 100.0
        post_5m_pct = None if trigger_price in (None, 0) or post_5m_price in (None, 0) else (float(post_5m_price) - float(trigger_price)) / float(trigger_price) * 100.0
        post_15m_pct = None if trigger_price in (None, 0) or post_15m_price in (None, 0) else (float(post_15m_price) - float(trigger_price)) / float(trigger_price) * 100.0
        oi_change_pct = None if trigger_oi in (None, 0) or post_15m_oi is None else (float(post_15m_oi) - float(trigger_oi)) / float(trigger_oi) * 100.0
        funding_change_bps = None if trigger_funding is None or post_15m_funding is None else float(post_15m_funding) - float(trigger_funding)
        event_slice = events
        if not event_slice.empty:
            if exchange_key and "交易所键" in event_slice.columns:
                event_slice = event_slice[event_slice["交易所键"].astype(str) == exchange_key]
            elif "交易所" in event_slice.columns:
                event_slice = event_slice[event_slice["交易所"].astype(str) == exchange_name]
            event_slice = event_slice[(event_slice["ts_ms"] >= alert_ts) & (event_slice["ts_ms"] <= alert_ts + 5 * 60_000)]
        large_trade_notional = float(event_slice.loc[event_slice["类型"] == "trade", "名义金额"].sum()) if not event_slice.empty else 0.0
        liquidation_notional = float(event_slice.loc[event_slice["类型"] == "liquidation", "名义金额"].sum()) if not event_slice.empty else 0.0
        quality_slice = quality
        if not quality_slice.empty:
            if exchange_key and "交易所键" in quality_slice.columns:
                quality_slice = quality_slice[quality_slice["交易所键"].astype(str) == exchange_key]
            elif "交易所" in quality_slice.columns:
                quality_slice = quality_slice[quality_slice["交易所"].astype(str) == exchange_name]
            quality_slice = quality_slice[(quality_slice["ts_ms"] >= alert_ts - 2 * 60_000) & (quality_slice["ts_ms"] <= alert_ts + 2 * 60_000)]
        imbalance_peak = float(pd.to_numeric(quality_slice.get("盘口失衡(%)"), errors="coerce").abs().max()) if not quality_slice.empty and "盘口失衡(%)" in quality_slice.columns else None
        added_sum = float(pd.to_numeric(quality_slice.get("近价新增"), errors="coerce").fillna(0.0).sum()) if not quality_slice.empty and "近价新增" in quality_slice.columns else 0.0
        canceled_sum = float(pd.to_numeric(quality_slice.get("近价撤单"), errors="coerce").fillna(0.0).sum()) if not quality_slice.empty and "近价撤单" in quality_slice.columns else 0.0
        cancel_refill_ratio = canceled_sum / max(added_sum, 1.0) if (added_sum or canceled_sum) else None
        if (imbalance_peak or 0.0) >= imbalance_threshold or (cancel_refill_ratio or 0.0) >= cancel_refill_threshold:
            quality_label = "盘口恶化"
        elif imbalance_peak is not None or cancel_refill_ratio is not None:
            quality_label = "盘口平稳"
        else:
            quality_label = "样本不足"
        review_stats = _match_alert_review_stats(
            title,
            exchange_name=exchange_name,
            review_summary_frame=review_summary_frame,
            best_window_frame=best_window_frame,
        )
        driver = _alert_driver_from_text(title, row.get("说明"), reference_driver)
        replay_summary = (
            f"前5m {pre_5m_pct:+.2f}% / 后15m {post_15m_pct:+.2f}% / "
            f"OI {oi_change_pct:+.2f}% / 大单 {_fmt_compact(large_trade_notional)} / 爆仓 {_fmt_compact(liquidation_notional)}"
            if pre_5m_pct is not None and post_15m_pct is not None and oi_change_pct is not None
            else f"后5m {post_5m_pct:+.2f}% / 盘口 {quality_label}"
            if post_5m_pct is not None
            else f"盘口 {quality_label} / 阈值 {adaptive_thresholds.get('summary_text')}"
        )
        rows.append(
            {
                "时间": row.get("时间"),
                "交易所": exchange_name,
                "告警": title,
                "谁在推动": driver,
                "触发前5m(%)": pre_5m_pct,
                "触发后5m(%)": post_5m_pct,
                "触发后15m(%)": post_15m_pct,
                "Funding变化(bps)": funding_change_bps,
                "OI变化(%)": oi_change_pct,
                "5m大单额": large_trade_notional or None,
                "5m爆仓额": liquidation_notional or None,
                "盘口质量": quality_label,
                "历史命中率(%)": review_stats.get("hit_rate_pct"),
                "过去准不准": review_stats.get("reliability"),
                "回放摘要": replay_summary,
                "__selection": {
                    **({"coin": row.get("币种") or "", "exchange": exchange_key} if exchange_key else {"coin": row.get("币种") or ""}),
                    "event_title": title,
                    "event_time_ms": alert_ts,
                },
            }
        )
    return pd.DataFrame(rows, columns=columns)


def _to_exchange_key(snapshot: ExchangeSnapshot) -> str:
    name = str(snapshot.exchange or "").lower()
    if "binance" in name:
        return "binance"
    if "bybit" in name:
        return "bybit"
    if "okx" in name:
        return "okx"
    if "hyperliquid" in name:
        return "hyperliquid"
    return name


def _snapshot_to_dict(snapshot: ExchangeSnapshot) -> Dict[str, Any]:
    payload = {
        "exchange": snapshot.exchange,
        "exchange_key": _to_exchange_key(snapshot),
        "symbol": snapshot.symbol,
        "last_price": snapshot.last_price,
        "mark_price": snapshot.mark_price,
        "index_price": snapshot.index_price,
        "premium_pct": snapshot.premium_pct,
        "open_interest": snapshot.open_interest,
        "open_interest_notional": snapshot.open_interest_notional,
        "funding_rate": snapshot.funding_rate,
        "funding_bps": snapshot.funding_bps,
        "volume_24h_base": snapshot.volume_24h_base,
        "volume_24h_notional": snapshot.volume_24h_notional,
        "timestamp_ms": snapshot.timestamp_ms,
        "status": snapshot.status,
        "error": snapshot.error,
    }
    payload.update(_snapshot_mode(snapshot.status, snapshot.timestamp_ms))
    return _with_standard_metric_aliases(payload)


def _spot_snapshot_to_dict(snapshot: Optional[SpotSnapshot], exchange_key: str) -> Dict[str, Any]:
    if snapshot is None:
        payload = {
            "exchange": EXCHANGE_TITLE_MAP.get(exchange_key, exchange_key.title()),
            "exchange_key": exchange_key,
            "symbol": "",
            "last_price": None,
            "bid_price": None,
            "ask_price": None,
            "spread_bps": None,
            "volume_24h_base": None,
            "volume_24h_notional": None,
            "timestamp_ms": None,
            "status": "error",
            "error": "waiting for data",
        }
        payload.update(_snapshot_mode("error", None))
        return payload
    payload = {
        "exchange": snapshot.exchange,
        "exchange_key": exchange_key,
        "symbol": snapshot.symbol,
        "last_price": snapshot.last_price,
        "bid_price": snapshot.bid_price,
        "ask_price": snapshot.ask_price,
        "spread_bps": snapshot.spread_bps,
        "volume_24h_base": snapshot.volume_24h_base,
        "volume_24h_notional": snapshot.volume_24h_notional,
        "timestamp_ms": snapshot.timestamp_ms,
        "status": snapshot.status,
        "error": snapshot.error,
    }
    payload.update(_snapshot_mode(snapshot.status, snapshot.timestamp_ms))
    return _with_standard_metric_aliases(payload)


def _orderbook_summary(levels: List[OrderBookLevel]) -> Dict[str, Optional[float]]:
    bid_levels = [item for item in levels if item.side == "bid" and item.price > 0 and item.size > 0]
    ask_levels = [item for item in levels if item.side == "ask" and item.price > 0 and item.size > 0]
    bid_notional = sum(item.price * item.size for item in bid_levels)
    ask_notional = sum(item.price * item.size for item in ask_levels)
    bid_size = sum(item.size for item in bid_levels)
    ask_size = sum(item.size for item in ask_levels)
    best_bid = None
    best_ask = None
    mid = None
    spread_bps = None
    if bid_levels and ask_levels:
        best_bid = max(item.price for item in bid_levels)
        best_ask = min(item.price for item in ask_levels)
        mid = (best_bid + best_ask) * 0.5
        if mid > 0:
            spread_bps = (best_ask - best_bid) / mid * 10000.0
    total = bid_notional + ask_notional
    imbalance_pct = ((bid_notional - ask_notional) / total * 100.0) if total > 0 else None
    return {
        "best_bid": best_bid,
        "best_ask": best_ask,
        "mid_price": mid,
        "bid_notional": bid_notional or None,
        "ask_notional": ask_notional or None,
        "bid_size": bid_size or None,
        "ask_size": ask_size or None,
        "spread_bps": spread_bps,
        "imbalance_pct": imbalance_pct,
        "bid_levels": float(len(bid_levels)),
        "ask_levels": float(len(ask_levels)),
    }


def _latest_quality_orderbook_fallback(quality_points: List[Any]) -> Dict[str, Optional[float]]:
    if not quality_points:
        return {}
    spread_bps = next(
        (_payload_float(getattr(point, "spread_bps", None)) for point in reversed(quality_points) if _payload_float(getattr(point, "spread_bps", None)) is not None),
        None,
    )
    imbalance_pct = next(
        (_payload_float(getattr(point, "imbalance_pct", None)) for point in reversed(quality_points) if _payload_float(getattr(point, "imbalance_pct", None)) is not None),
        None,
    )
    best_bid = next(
        (_payload_float(getattr(point, "best_bid", None)) for point in reversed(quality_points) if _payload_float(getattr(point, "best_bid", None)) is not None),
        None,
    )
    best_ask = next(
        (_payload_float(getattr(point, "best_ask", None)) for point in reversed(quality_points) if _payload_float(getattr(point, "best_ask", None)) is not None),
        None,
    )
    mid_price = None
    if best_bid not in (None, 0) and best_ask not in (None, 0):
        mid_price = (float(best_bid) + float(best_ask)) * 0.5
    return {
        "best_bid": best_bid,
        "best_ask": best_ask,
        "mid_price": mid_price,
        "spread_bps": spread_bps,
        "imbalance_pct": imbalance_pct,
    }


def _merge_orderbook_summary_with_quality(summary: Dict[str, Optional[float]], quality_points: List[Any]) -> Dict[str, Optional[float]]:
    merged = dict(summary or {})
    fallback = _latest_quality_orderbook_fallback(quality_points)
    for key, value in fallback.items():
        if merged.get(key) is None and value is not None:
            merged[key] = value
    return merged


def _serialize_orderbook(levels: List[OrderBookLevel], *, limit: int = 20) -> Dict[str, List[Dict[str, float]]]:
    bid_levels = [item for item in levels if item.side == "bid" and item.price > 0 and item.size > 0]
    ask_levels = [item for item in levels if item.side == "ask" and item.price > 0 and item.size > 0]
    bid_levels.sort(key=lambda item: item.price, reverse=True)
    ask_levels.sort(key=lambda item: item.price)
    return {
        "bids": [{"price": item.price, "size": item.size, "notional": item.price * item.size} for item in bid_levels[:limit]],
        "asks": [{"price": item.price, "size": item.size, "notional": item.price * item.size} for item in ask_levels[:limit]],
    }


def _trade_side_label(side: str) -> str:
    if side == "buy":
        return "主动买"
    if side == "sell":
        return "主动卖"
    return side or "未知"


def _liquidation_side_label(side: str) -> str:
    if side == "long":
        return "多头爆仓"
    if side == "short":
        return "空头爆仓"
    return side or "未知"


def _liquidation_market_bias(side: str) -> str:
    if side == "long":
        return "bearish"
    if side == "short":
        return "bullish"
    return "neutral"


def _serialize_trade(event: TradeEvent, *, market: str) -> Dict[str, Any]:
    exchange_key = _to_exchange_key(ExchangeSnapshot(exchange=event.exchange, symbol=event.symbol))
    return {
        "kind": "trade",
        "market": market,
        "exchange": event.exchange,
        "exchange_key": exchange_key,
        "symbol": event.symbol,
        "timestamp_ms": event.timestamp_ms,
        "side": event.side,
        "side_label": _trade_side_label(event.side),
        "price": event.price,
        "size": event.size,
        "notional": event.notional,
        "source": event.source,
    }


def _serialize_liquidation(event: LiquidationEvent) -> Dict[str, Any]:
    exchange_key = _to_exchange_key(ExchangeSnapshot(exchange=event.exchange, symbol=event.symbol))
    return {
        "kind": "liquidation",
        "market": "perp",
        "exchange": event.exchange,
        "exchange_key": exchange_key,
        "symbol": event.symbol,
        "timestamp_ms": event.timestamp_ms,
        "side": event.side,
        "position_side": event.side,
        "side_label": _liquidation_side_label(event.side),
        "side_semantics": "liquidated_position",
        "market_bias": _liquidation_market_bias(event.side),
        "price": event.price,
        "size": event.size,
        "notional": event.notional,
        "source": event.source,
    }


def _serialize_recorded_event(event: Any) -> Dict[str, Any]:
    category = str(getattr(event, "category", "") or "event").strip().lower()
    side = getattr(event, "side", None)
    if category == "trade":
        side_label = _trade_side_label(str(side or ""))
    elif category == "liquidation":
        side_label = _liquidation_side_label(str(side or ""))
    elif side:
        side_label = str(side)
    else:
        side_label = str(getattr(event, "label", "") or category or "-")
    return {
        "kind": category,
        "market": getattr(event, "market", "perp"),
        "exchange": getattr(event, "exchange", ""),
        "exchange_key": _to_exchange_key(ExchangeSnapshot(exchange=getattr(event, "exchange", ""), symbol=getattr(event, "symbol", ""))),
        "symbol": getattr(event, "symbol", ""),
        "timestamp_ms": getattr(event, "timestamp_ms", 0),
        "side": side,
        "position_side": side if category == "liquidation" else None,
        "side_label": side_label,
        "side_semantics": "liquidated_position" if category == "liquidation" else None,
        "market_bias": _liquidation_market_bias(str(side or "")) if category == "liquidation" else None,
        "price": getattr(event, "price", None),
        "size": getattr(event, "size", None),
        "notional": getattr(event, "notional", None),
        "source": getattr(event, "label", None) or getattr(event, "raw", {}).get("source") or getattr(event, "market", "perp"),
    }


def _build_tape_monitor_row_lookup(frame: pd.DataFrame) -> Dict[str, Dict[str, Any]]:
    if frame is None or frame.empty:
        return {}
    working = canonicalize_market_frame_columns(frame.copy())
    lookup: Dict[str, Dict[str, Any]] = {}
    for row in working.to_dict("records"):
        normalized = _with_standard_metric_aliases(dict(row))
        exchange_key = _row_exchange_key(normalized)
        market = _normalize_market_value(normalized.get("市场")) or "perp"
        if not exchange_key:
            continue
        lookup[f"{exchange_key}::{market}"] = normalized
    return lookup


def _tape_item_matches_anomaly(
    item: Dict[str, Any],
    anomaly_type: str,
    *,
    row_lookup: Optional[Dict[str, Dict[str, Any]]] = None,
    time_window: str = "1h",
    whale_window: str = "5m",
    oi_window: str = "1h",
    now_ms: Optional[int] = None,
) -> bool:
    normalized_type = _normalize_monitor_anomaly_type(anomaly_type)
    if normalized_type == "all":
        return True
    current_ms = int(now_ms or time.time() * 1000)
    timestamp_ms = _coerce_timestamp_ms(item.get("timestamp_ms")) or 0
    kind = str(item.get("kind") or "").strip().lower()
    side = str(item.get("side") or "").strip().lower()
    market = _normalize_market_value(item.get("market")) or "perp"
    if normalized_type == "whale_buy":
        whale_since_ms = current_ms - MONITOR_WHALE_WINDOWS[_normalize_monitor_whale_window(whale_window)] * 60_000
        return kind == "trade" and side == "buy" and timestamp_ms >= whale_since_ms
    if normalized_type == "whale_sell":
        whale_since_ms = current_ms - MONITOR_WHALE_WINDOWS[_normalize_monitor_whale_window(whale_window)] * 60_000
        return kind == "trade" and side == "sell" and timestamp_ms >= whale_since_ms
    if normalized_type == "price_up":
        if kind == "trade" and side != "buy":
            return False
        if kind == "liquidation" and str(item.get("market_bias") or "").strip().lower() != "bullish":
            return False
    if normalized_type == "price_down":
        if kind == "trade" and side != "sell":
            return False
        if kind == "liquidation" and str(item.get("market_bias") or "").strip().lower() != "bearish":
            return False
    if normalized_type in {"oi_up", "oi_down"} and market == "spot":
        return False
    if normalized_type in {"oi_up", "oi_down"} and kind in {"trade", "liquidation"}:
        return False
    exchange_key = _normalize_exchange_value(item.get("exchange_key") or item.get("exchange"))
    if not exchange_key:
        return False
    lookup = row_lookup or {}
    row = lookup.get(f"{exchange_key}::{market}") or lookup.get(f"{exchange_key}::perp") or lookup.get(f"{exchange_key}::spot")
    if not row:
        return False
    return _monitor_match_anomaly_type(
        row,
        anomaly_type=normalized_type,
        time_window=time_window,
        whale_window=whale_window,
        oi_window=oi_window,
    )


def _cluster_liquidation_windows(events: List[LiquidationEvent], cluster_window_seconds: int = 30) -> List[Dict[str, Any]]:
    if not events:
        return []
    threshold_ms = max(int(cluster_window_seconds), 1) * 1000
    ordered = sorted(events, key=lambda item: int(item.timestamp_ms or 0))
    clusters: List[Dict[str, Any]] = []
    current: Optional[Dict[str, Any]] = None
    for event in ordered:
        ts_ms = int(event.timestamp_ms or 0)
        if current is None or ts_ms - int(current["last_ts"]) > threshold_ms:
            if current is not None:
                clusters.append(current)
            current = {
                "start_ts": ts_ms,
                "end_ts": ts_ms,
                "last_ts": ts_ms,
                "events": [event],
                "exchanges": {str(event.exchange or "")},
            }
            continue
        current["last_ts"] = ts_ms
        current["end_ts"] = ts_ms
        current["events"].append(event)
        current["exchanges"].add(str(event.exchange or ""))
    if current is not None:
        clusters.append(current)
    return clusters


class MarketRuntimeSession:
    def __init__(self, coin: str, *, timeout: int = 8, catalog: Optional[Dict[str, Any]] = None, manager: Optional["MarketRuntimeManager"] = None) -> None:
        self.coin = str(coin or "BTC").upper().strip()
        self.manager = manager
        self.timeout = max(int(timeout), 5)
        self.created_at = time.time()
        self.last_access_at = self.created_at
        self.catalog = dict(catalog or fetch_exchange_coin_catalog(timeout=self.timeout))
        self.history_store = TerminalHistoryStore()
        self._cache_lock = threading.Lock()
        self._cache: Dict[str, Dict[str, Any]] = {}
        self._cache_inflight: Dict[str, threading.Event] = {}
        self._runtime_observation_lock = threading.Lock()
        self._runtime_observations: Dict[str, Dict[str, int]] = {
            "cache": {
                "hit": 0,
                "stale_hit": 0,
                "miss": 0,
                "build": 0,
                "wait": 0,
                "peek_hit": 0,
                "peek_stale": 0,
                "peek_miss": 0,
                "warm_schedule": 0,
                "heavy_warm_schedule": 0,
            },
            "cache_namespace": {},
            "source": {},
            "truth": {},
            "stage": {},
        }
        self._warm_jobs_lock = threading.Lock()
        self._warm_executor = ThreadPoolExecutor(max_workers=2, thread_name_prefix=f"warm-{self.coin}")
        self._warm_jobs: Dict[str, Any] = {}
        self._heavy_jobs_lock = threading.Lock()
        self._heavy_executor = ThreadPoolExecutor(max_workers=2, thread_name_prefix=f"heavy-{self.coin}")
        self._heavy_jobs: Dict[str, Any] = {}
        self._alert_engine_lock = threading.Lock()
        self._alert_engine_state: Dict[str, Dict[str, object]] = {}
        self._alert_engine_timeline: List[Dict[str, object]] = []
        self._last_alert_history_persist_ms = 0
        self._last_signal_history_persist_ms = 0
        self._last_runtime_history_persist_ms = 0
        self._last_history_retention_prune_ms = 0
        self._last_history_vacuum_ms = 0
        self._share_baseline_records: List[Dict[str, Any]] = []
        self._address_stream_lock = threading.Lock()
        self._address_streams: Dict[str, Dict[str, Any]] = {}
        self._address_stream_idle_seconds = 20 * 60
        self._maintenance_lock = threading.Lock()
        self._maintenance_thread: Optional[threading.Thread] = None
        self.symbol_map = self._build_symbol_map()
        self.spot_symbol_map = self._build_spot_symbol_map()
        self.service = LiveTerminalService(
            symbol_map=self.symbol_map,
            spot_symbol_map=self.spot_symbol_map,
            timeout=self.timeout,
            sample_seconds=DEFAULT_SESSION_SAMPLE_SECONDS,
            history_size=240,
            liquidation_history_size=240,
            trade_history_size=360,
            record_history_size=480,
            orderbook_limit=60,
            spot_symbol=self.spot_symbol_map.get("binance") or f"{self.coin}USDT",
            shared_hub=(self.manager.shared_realtime_hub if self.manager is not None else None),
            source_update_callback=self._handle_service_source_update,
            autostart=False,
        )
        self._hydrate_service_from_history()
        self.service.ensure_started(background=True)

    def _cache_store(self, cache_key: str, value: Any, *, ts: Optional[float] = None) -> None:
        stored_at = float(ts if ts is not None else time.time())
        with self._cache_lock:
            self._cache[cache_key] = {"ts": stored_at, "value": value}
        if self.manager is not None:
            try:
                self.manager.notify_cache_update(cache_key)
            except Exception:
                pass

    def _build_symbol_map(self) -> Dict[str, str]:
        base = default_symbols(self.coin)
        availability = self.catalog.get("availability", {}).get(self.coin, {})
        status = self.catalog.get("status", {})
        for exchange_key in EXCHANGE_ORDER:
            market_status = str(status.get(exchange_key, {}).get("perp") or "")
            is_listed = bool(availability.get(exchange_key, {}).get("perp"))
            if market_status == "ok" and not is_listed:
                base[exchange_key] = ""
        return base

    def _build_spot_symbol_map(self) -> Dict[str, str]:
        base = default_spot_symbols(self.coin)
        availability = self.catalog.get("availability", {}).get(self.coin, {})
        status = self.catalog.get("status", {})
        for exchange_key in list(base):
            market_status = str(status.get(exchange_key, {}).get("spot") or "")
            is_listed = bool(availability.get(exchange_key, {}).get("spot"))
            if market_status == "ok" and not is_listed:
                base[exchange_key] = ""
        return base

    def touch(self) -> None:
        self.last_access_at = time.time()
        self.service.ensure_started(background=True)
        self._schedule_maintenance()

    def _handle_service_source_update(self, exchange_key: str, market: str, channel: str) -> None:
        if self.manager is None:
            return
        source_key = f"runtime::{self.coin}::{str(channel or '').lower().strip()}::{str(exchange_key or '').lower().strip()}::{str(market or 'perp').lower().strip()}"
        self.manager.notify_cache_update(source_key)

    def _cached_runtime_session(self, coin: str) -> Optional["MarketRuntimeSession"]:
        normalized = str(coin or self.coin).upper().strip() or self.coin
        if normalized == self.coin:
            return self
        if self.manager is None:
            return None
        return self.manager.get_cached_runtime(normalized)

    def _schedule_maintenance(self) -> None:
        now_ms = int(time.time() * 1000)
        last_runtime_ms = int(self._last_runtime_history_persist_ms or 0)
        last_retention_ms = int(self._last_history_retention_prune_ms or 0)
        if now_ms - max(last_runtime_ms, last_retention_ms) < 45_000:
            return
        with self._maintenance_lock:
            current = self._maintenance_thread
            if current is not None and current.is_alive():
                return

            def runner() -> None:
                try:
                    self._enforce_history_retention()
                except Exception:
                    pass
                try:
                    self._persist_runtime_history_samples()
                except Exception:
                    pass
                finally:
                    with self._maintenance_lock:
                        active = self._maintenance_thread
                        if active is threading.current_thread():
                            self._maintenance_thread = None

            thread = threading.Thread(target=runner, name=f"runtime-maint::{self.coin}", daemon=True)
            self._maintenance_thread = thread
            thread.start()

    def stop(self) -> None:
        self.service.stop()
        try:
            self._warm_executor.shutdown(wait=False, cancel_futures=True)
        except Exception:
            pass
        try:
            self._heavy_executor.shutdown(wait=False, cancel_futures=True)
        except Exception:
            pass
        with self._address_stream_lock:
            streams = [entry.get("stream") for entry in self._address_streams.values()]
            self._address_streams.clear()
        for stream in streams:
            try:
                if stream is not None:
                    stream.stop()
            except Exception:
                continue

    def _effective_history_retention_days(self) -> int:
        preferences = _load_ui_preferences_snapshot()
        try:
            requested = int(preferences.get("archive_retention_days", DEFAULT_HISTORY_RETENTION_DAYS) or DEFAULT_HISTORY_RETENTION_DAYS)
        except (TypeError, ValueError):
            requested = DEFAULT_HISTORY_RETENTION_DAYS
        requested = max(1, requested)
        return min(requested, MAX_HISTORY_RETENTION_DAYS)

    def _hydrate_service_from_history(self) -> None:
        if not self._history_sqlite_enabled():
            return
        try:
            perp_history = self.history_store.load_snapshot_rows(coin=self.coin, exchange_keys=EXCHANGE_ORDER, market="perp", limit=240)
            spot_history = self.history_store.load_snapshot_rows(coin=self.coin, exchange_keys=SPOT_EXCHANGE_ORDER, market="spot", limit=180)
            oi_frame = self.history_store.load_oi_points(
                coin=self.coin,
                exchange_keys=EXCHANGE_ORDER,
                since_ms=int(time.time() * 1000) - 6 * 60 * 60 * 1000,
                limit=1200,
                include_archive=True,
            )
        except Exception:
            return
        with self.service.lock:
            if isinstance(perp_history, pd.DataFrame) and not perp_history.empty:
                for exchange_key in EXCHANGE_ORDER:
                    rows = perp_history[perp_history["exchange_key"].astype(str).str.lower() == exchange_key]
                    if rows.empty:
                        continue
                    latest = rows.sort_values("ts_ms", ascending=False).iloc[0]
                    self.service.sampled_by_exchange[exchange_key] = ExchangeSnapshot(
                        exchange=str(latest.get("exchange_name") or EXCHANGE_TITLE_MAP.get(exchange_key, exchange_key.title())),
                        symbol=str(latest.get("symbol") or self.symbol_map.get(exchange_key) or ""),
                        last_price=_payload_float(latest.get("last_price")),
                        mark_price=_payload_float(latest.get("mark_price")),
                        index_price=_payload_float(latest.get("index_price")),
                        funding_rate=(
                            float(_payload_float(latest.get("funding_bps")) or 0.0) / 10000.0
                            if _payload_float(latest.get("funding_bps")) is not None
                            else None
                        ),
                        open_interest=_payload_float(latest.get("open_interest")),
                        open_interest_notional=_payload_float(latest.get("open_interest_notional")),
                        volume_24h_notional=_payload_float(latest.get("volume_24h_notional")),
                        timestamp_ms=_coerce_timestamp_ms(latest.get("ts_ms")),
                        status="proxy",
                        error="hydrated from local history",
                    )
            if isinstance(spot_history, pd.DataFrame) and not spot_history.empty:
                for exchange_key in SPOT_EXCHANGE_ORDER:
                    rows = spot_history[spot_history["exchange_key"].astype(str).str.lower() == exchange_key]
                    if rows.empty:
                        continue
                    latest = rows.sort_values("ts_ms", ascending=False).iloc[0]
                    self.service.spot_snapshots[exchange_key] = SpotSnapshot(
                        exchange=str(latest.get("exchange_name") or EXCHANGE_TITLE_MAP.get(exchange_key, exchange_key.title())),
                        symbol=str(latest.get("symbol") or self.spot_symbol_map.get(exchange_key) or ""),
                        last_price=_payload_float(latest.get("last_price")),
                        volume_24h_notional=_payload_float(latest.get("volume_24h_notional")),
                        timestamp_ms=_coerce_timestamp_ms(latest.get("ts_ms")),
                        status="proxy",
                        error="hydrated from local history",
                    )
            if isinstance(oi_frame, pd.DataFrame) and not oi_frame.empty:
                ordered = oi_frame.sort_values("ts_ms", ascending=True)
                for exchange_key in EXCHANGE_ORDER:
                    exchange_rows = ordered[ordered["exchange_key"].astype(str).str.lower() == exchange_key]
                    if exchange_rows.empty:
                        continue
                    history = self.service.oi_history.get(exchange_key)
                    if history is None:
                        continue
                    history.clear()
                    for row in exchange_rows.tail(history.maxlen or len(exchange_rows)).to_dict("records"):
                        history.append(
                            OIPoint(
                                timestamp_ms=int(row.get("ts_ms") or 0),
                                open_interest=_payload_float(row.get("open_interest")),
                                open_interest_notional=_payload_float(row.get("open_interest_notional")),
                            )
                        )

    def _history_sqlite_enabled(self) -> bool:
        preferences = _load_ui_preferences_snapshot()
        return bool(preferences.get("history_sqlite_enabled", True))

    def _enforce_history_retention(self) -> None:
        now_ms = int(time.time() * 1000)
        if now_ms - int(self._last_history_retention_prune_ms or 0) < 30 * 60_000:
            return
        retention_days = self._effective_history_retention_days()
        cutoff_ms = now_ms - retention_days * 24 * 60 * 60 * 1000
        quality_hot_cutoff_ms = now_ms - int(PERSISTED_QUALITY_HOT_RETENTION_HOURS * 60 * 60 * 1000)
        archived_quality = self.history_store.archive_quality_points_before(quality_hot_cutoff_ms, prefer_parquet=True)
        archived_other_tables = self.history_store.archive_before(cutoff_ms, prefer_parquet=True)
        result = self.history_store.prune_before(cutoff_ms, include_archive=True)
        compacted_trade_rows = self.history_store.compact_market_events(min_trade_notional=PERSISTED_EVENT_MIN_NOTIONAL)
        compacted_quality_rows = self.history_store.compact_orderbook_quality_points(
            min_notional=PERSISTED_QUALITY_MIN_NOTIONAL,
            min_imbalance_pct=PERSISTED_QUALITY_IMBALANCE_PCT,
        )
        compacted_duplicate_quality_event_rows = self.history_store.compact_duplicate_orderbook_quality_events(
            keep_recent_ms=int(PERSISTED_QUALITY_EVENT_RETENTION_HOURS * 60 * 60 * 1000),
        )
        compacted_blob_rows = self.history_store.compact_payload_blobs()
        deleted_rows = result.get("deleted_rows") or {}
        total_deleted = sum(int(value or 0) for value in deleted_rows.values())
        total_deleted += sum(int(item.get("rows") or 0) for item in (archived_quality or []))
        total_deleted += sum(int(item.get("rows") or 0) for item in (archived_other_tables or []))
        total_deleted += int(compacted_trade_rows or 0)
        total_deleted += int(compacted_quality_rows or 0)
        total_deleted += int(compacted_duplicate_quality_event_rows or 0)
        total_deleted += sum(int(value or 0) for value in (compacted_blob_rows or {}).values())
        if total_deleted > 0 and now_ms - int(self._last_history_vacuum_ms or 0) >= 6 * 60 * 60_000:
            self.history_store.vacuum()
            self._last_history_vacuum_ms = now_ms
        self._last_history_retention_prune_ms = now_ms

    def _persist_runtime_history_samples(self) -> None:
        if not self._history_sqlite_enabled():
            return
        now_ms = int(time.time() * 1000)
        if now_ms - int(self._last_runtime_history_persist_ms or 0) < 30_000:
            return
        snapshots = {
            _to_exchange_key(snapshot): snapshot
            for snapshot in self.service.current_snapshots()
            if snapshot is not None and snapshot.status == "ok"
        }
        if snapshots:
            self.history_store.record_snapshots(self.coin, snapshots, market="perp")
        spot_snapshots = {
            exchange_key: snapshot
            for exchange_key in SPOT_EXCHANGE_ORDER
            for snapshot in [self.service.get_spot_snapshot(exchange_key)]
            if snapshot is not None and snapshot.status == "ok"
        }
        if spot_snapshots:
            self.history_store.record_snapshots(self.coin, spot_snapshots, market="spot")
        perp_recorded = {
            exchange_key: _filter_persisted_events(list(self.service.get_recorded_events(exchange_key))[-120:])
            for exchange_key in EXCHANGE_ORDER
            if self.symbol_map.get(exchange_key)
        }
        spot_recorded = {
            exchange_key: _filter_persisted_events(list(self.service.get_spot_recorded_events(exchange_key))[-120:])
            for exchange_key in SPOT_EXCHANGE_ORDER
            if self.spot_symbol_map.get(exchange_key)
        }
        if any(perp_recorded.values()):
            self.history_store.record_recorded_events(self.coin, perp_recorded)
        if any(spot_recorded.values()):
            self.history_store.record_recorded_events(self.coin, spot_recorded)
        oi_rows: List[Dict[str, Any]] = []
        for exchange_key in EXCHANGE_ORDER:
            if not self.symbol_map.get(exchange_key):
                continue
            oi_rows.extend(
                {
                    "ts_ms": int(point.timestamp_ms or now_ms),
                    "exchange_key": exchange_key,
                    "exchange_name": EXCHANGE_TITLE_MAP.get(exchange_key, exchange_key.title()),
                    "symbol": self.symbol_map.get(exchange_key) or "",
                    "open_interest": point.open_interest,
                    "open_interest_notional": point.open_interest_notional,
                }
                for point in list(self.service.get_oi_history(exchange_key))[-80:]
            )
            quality_points = _filter_persisted_quality_points(list(self.service.get_orderbook_quality_history(exchange_key))[-80:])
            if not quality_points:
                pass
            else:
                exchange_name = EXCHANGE_TITLE_MAP.get(exchange_key, exchange_key.title())
                symbol = self.symbol_map.get(exchange_key) or ""
                self.history_store.record_quality_points(
                    self.coin,
                    exchange_key=exchange_key,
                    exchange_name=exchange_name,
                    symbol=symbol,
                    points=quality_points,
                    market="perp",
                )
        for exchange_key in SPOT_EXCHANGE_ORDER:
            if not self.spot_symbol_map.get(exchange_key):
                continue
            quality_points = _filter_persisted_quality_points(list(self.service.get_spot_orderbook_quality_history(exchange_key))[-80:])
            if not quality_points:
                continue
            exchange_name = f"{EXCHANGE_TITLE_MAP.get(exchange_key, exchange_key.title())} Spot"
            symbol = self.spot_symbol_map.get(exchange_key) or ""
            self.history_store.record_quality_points(
                self.coin,
                exchange_key=exchange_key,
                exchange_name=exchange_name,
                symbol=symbol,
                points=quality_points,
                market="spot",
            )
        if oi_rows:
            self.history_store.record_oi_points(self.coin, oi_rows)
        transport_rows: List[Dict[str, Any]] = []
        for exchange_key in EXCHANGE_ORDER:
            if self.symbol_map.get(exchange_key):
                transport_rows.append(
                    {
                        "ts_ms": now_ms,
                        "exchange_key": exchange_key,
                        "market": "perp",
                        **self.service.get_transport_health(exchange_key, spot=False),
                    }
                )
        for exchange_key in SPOT_EXCHANGE_ORDER:
            if self.spot_symbol_map.get(exchange_key):
                transport_rows.append(
                    {
                        "ts_ms": now_ms,
                        "exchange_key": exchange_key,
                        "market": "spot",
                        **self.service.get_transport_health(exchange_key, spot=True),
                    }
                )
        if transport_rows:
            self.history_store.record_transport_states(self.coin, transport_rows)
        bars = self._build_runtime_bars_1m(now_ms)
        if bars:
            self.history_store.record_market_bars_1m(self.coin, bars)
        self._last_runtime_history_persist_ms = now_ms

    def _build_runtime_bars_1m(self, now_ms: int) -> List[Dict[str, Any]]:
        bucket_ms = (int(now_ms) // 60_000) * 60_000
        rows: List[Dict[str, Any]] = []
        for exchange_key in EXCHANGE_ORDER:
            symbol = self.symbol_map.get(exchange_key) or ""
            if not symbol:
                continue
            trades = [
                event for event in self.service.get_trade_history(exchange_key)
                if int(getattr(event, "timestamp_ms", 0) or 0) >= bucket_ms
            ]
            prices = [_payload_float(getattr(event, "price", None)) for event in trades if _payload_float(getattr(event, "price", None)) is not None]
            notionals = [abs(float(getattr(event, "notional", 0.0) or 0.0)) for event in trades]
            if not prices:
                snapshot = next((item for item in self.service.current_snapshots() if _to_exchange_key(item) == exchange_key), None)
                reference = _payload_float(getattr(snapshot, "last_price", None)) if snapshot is not None else None
                if reference is None:
                    continue
                prices = [reference]
            rows.append(
                {
                    "bucket_ms": bucket_ms,
                    "exchange_key": exchange_key,
                    "market": "perp",
                    "symbol": symbol,
                    "open": prices[0],
                    "high": max(prices),
                    "low": min(prices),
                    "close": prices[-1],
                    "volume_notional": sum(notionals) if notionals else None,
                    "large_trade_notional": sum(value for value in notionals if value >= MONITOR_WHALE_BUCKETS[0]) if notionals else None,
                    "trade_count": len(trades),
                }
            )
        for exchange_key in SPOT_EXCHANGE_ORDER:
            symbol = self.spot_symbol_map.get(exchange_key) or ""
            if not symbol:
                continue
            trades = [
                event for event in self.service.get_spot_trade_history(exchange_key)
                if int(getattr(event, "timestamp_ms", 0) or 0) >= bucket_ms
            ]
            prices = [_payload_float(getattr(event, "price", None)) for event in trades if _payload_float(getattr(event, "price", None)) is not None]
            notionals = [abs(float(getattr(event, "notional", 0.0) or 0.0)) for event in trades]
            if not prices:
                snapshot = self.service.get_spot_snapshot(exchange_key)
                reference = _payload_float(getattr(snapshot, "last_price", None)) if snapshot is not None else None
                if reference is None:
                    continue
                prices = [reference]
            rows.append(
                {
                    "bucket_ms": bucket_ms,
                    "exchange_key": exchange_key,
                    "market": "spot",
                    "symbol": symbol,
                    "open": prices[0],
                    "high": max(prices),
                    "low": min(prices),
                    "close": prices[-1],
                    "volume_notional": sum(notionals) if notionals else None,
                    "large_trade_notional": sum(value for value in notionals if value >= MONITOR_WHALE_BUCKETS[0]) if notionals else None,
                    "trade_count": len(trades),
                }
            )
        return rows

    def _cache_get_or_build(self, cache_key: str, ttl_seconds: int, builder) -> Any:
        wait_timeout = max(float(ttl_seconds or 0), 1.0) * 2.0
        while True:
            wait_event: Optional[threading.Event] = None
            should_build = False
            now = time.time()
            with self._cache_lock:
                entry = self._cache.get(cache_key)
                if entry and now - float(entry.get("ts") or 0.0) < ttl_seconds:
                    self._record_cache_observation("hit", cache_key=cache_key)
                    return entry.get("value")
                wait_event = self._cache_inflight.get(cache_key)
                if wait_event is None:
                    wait_event = threading.Event()
                    self._cache_inflight[cache_key] = wait_event
                    should_build = True
                    self._record_cache_observation("miss", cache_key=cache_key)
                else:
                    self._record_cache_observation("wait", cache_key=cache_key)
            if should_build:
                try:
                    value = builder()
                    built_at = time.time()
                    self._cache_store(cache_key, value, ts=built_at)
                    self._record_cache_observation("build", cache_key=cache_key)
                    return value
                finally:
                    with self._cache_lock:
                        inflight = self._cache_inflight.pop(cache_key, None)
                    if inflight is not None:
                        inflight.set()
            else:
                if wait_event is not None:
                    wait_event.wait(timeout=wait_timeout)

    def _cache_peek(self, cache_key: str, ttl_seconds: Optional[int] = None) -> Any:
        now = time.time()
        with self._cache_lock:
            entry = self._cache.get(cache_key)
            if entry is None:
                self._record_cache_observation("peek_miss", cache_key=cache_key)
                return None
            if ttl_seconds is not None and now - float(entry.get("ts") or 0.0) >= ttl_seconds:
                self._record_cache_observation("peek_stale", cache_key=cache_key)
                return None
            self._record_cache_observation("peek_hit", cache_key=cache_key)
            return entry.get("value")

    def _cache_revision_token(self, cache_key: str, ttl_seconds: Optional[int] = None) -> Optional[str]:
        now = time.time()
        with self._cache_lock:
            entry = self._cache.get(cache_key)
            if entry is None:
                return None
            entry_ts = float(entry.get("ts") or 0.0)
            if ttl_seconds is not None and now - entry_ts >= ttl_seconds:
                return None
        return str(int(entry_ts * 1000))

    def _derived_payload_snapshot(
        self,
        *,
        cache_key: str,
        ttl_seconds: int,
        builder,
        placeholder_builder=None,
        sync_on_miss: bool = False,
    ) -> Any:
        cached = self._cache_peek(cache_key, ttl_seconds=ttl_seconds)
        if cached is not None:
            return self._augment_payload_runtime_meta(cached)
        stale = self._cache_peek(cache_key, ttl_seconds=None)
        if stale is not None:
            self._record_cache_observation("stale_hit", cache_key=cache_key)
            self._schedule_cache_warm(cache_key, ttl_seconds, builder)
            return self._augment_payload_runtime_meta(stale)
        if sync_on_miss:
            return self._augment_payload_runtime_meta(self._cache_get_or_build(cache_key, ttl_seconds, builder))
        self._schedule_cache_warm(cache_key, ttl_seconds, builder)
        return self._augment_payload_runtime_meta(placeholder_builder() if placeholder_builder is not None else {})

    def _warming_data_meta(self, source: str, updated_at_ms: Optional[int] = None) -> Dict[str, Any]:
        meta = _build_data_meta(source, updated_at_ms or int(time.time() * 1000))
        meta["truth_level"] = "warming_up"
        meta["status"] = "warming_up"
        return self._augment_data_meta_with_runtime(meta)

    @staticmethod
    def _cache_namespace_key(cache_key: str) -> str:
        namespace = str(cache_key or "").split("::", 1)[0].strip().lower()
        return namespace or "unknown"

    @staticmethod
    def _runtime_source_key(source: Any) -> str:
        normalized = str(source or "").strip().lower()
        if not normalized:
            return "unknown"
        if "manager" in normalized:
            return "manager_cache"
        if "legacy" in normalized:
            return "legacy_cache"
        if "warming" in normalized:
            return "warming_cache"
        if "runtime" in normalized or "history fallback" in normalized or "sqlite" in normalized or "archive" in normalized:
            return "local_runtime"
        if "ws" in normalized or "realtime" in normalized:
            return "ws_live"
        if "reference" in normalized or "lead-lag" in normalized or "aggregation" in normalized:
            return "composite_reference"
        return normalized.replace("/", "_").replace(" ", "_")[:32]

    def _increment_runtime_counter(self, group: str, key: str, delta: int = 1) -> None:
        normalized_group = str(group or "").strip()
        normalized_key = str(key or "").strip()
        if not normalized_group or not normalized_key:
            return
        with self._runtime_observation_lock:
            bucket = self._runtime_observations.setdefault(normalized_group, {})
            bucket[normalized_key] = int(bucket.get(normalized_key) or 0) + max(int(delta), 1)

    def _record_cache_observation(self, event: str, *, cache_key: str = "") -> None:
        normalized_event = str(event or "").strip().lower()
        if not normalized_event:
            return
        self._increment_runtime_counter("cache", normalized_event)
        namespace = self._cache_namespace_key(cache_key)
        if namespace:
            self._increment_runtime_counter("cache_namespace", namespace)

    def _record_runtime_data_meta(self, *, source: Any = "", truth_level: Any = "", stage_name: str = "") -> None:
        source_key = self._runtime_source_key(source)
        truth_key = str(truth_level or "").strip() or "unknown"
        stage_key = str(stage_name or "").strip()
        if source_key:
            self._increment_runtime_counter("source", source_key)
        if truth_key:
            self._increment_runtime_counter("truth", truth_key)
        if stage_key:
            self._increment_runtime_counter("stage", stage_key)

    @staticmethod
    def _top_runtime_counts(counts: Dict[str, int], *, limit: int = 3) -> List[Dict[str, Any]]:
        ordered = sorted(
            ((str(key), int(value)) for key, value in (counts or {}).items() if int(value or 0) > 0),
            key=lambda item: (-item[1], item[0]),
        )
        return [{"key": key, "count": value} for key, value in ordered[: max(int(limit), 1)]]

    @staticmethod
    def _format_runtime_top_counts(items: List[Dict[str, Any]]) -> str:
        return ", ".join(f"{item['key']}:{item['count']}" for item in (items or []) if item.get("key"))

    def _runtime_observation_snapshot(self) -> Dict[str, Any]:
        with self._runtime_observation_lock:
            cache_counts = dict(self._runtime_observations.get("cache") or {})
            cache_namespace_counts = dict(self._runtime_observations.get("cache_namespace") or {})
            source_counts = dict(self._runtime_observations.get("source") or {})
            truth_counts = dict(self._runtime_observations.get("truth") or {})
            stage_counts = dict(self._runtime_observations.get("stage") or {})
        source_mix = self._top_runtime_counts(source_counts)
        truth_mix = self._top_runtime_counts(truth_counts)
        stage_mix = self._top_runtime_counts(stage_counts)
        cache_namespace_mix = self._top_runtime_counts(cache_namespace_counts)
        hit = int(cache_counts.get("hit") or 0)
        stale_hit = int(cache_counts.get("stale_hit") or 0)
        miss = int(cache_counts.get("miss") or 0)
        build = int(cache_counts.get("build") or 0)
        wait = int(cache_counts.get("wait") or 0)
        warm = int(cache_counts.get("warm_schedule") or 0) + int(cache_counts.get("heavy_warm_schedule") or 0)
        summary_parts = [
            f"缓存 hit {hit} / stale {stale_hit} / miss {miss} / build {build} / wait {wait}",
        ]
        if warm:
            summary_parts.append(f"warm {warm}")
        source_summary = self._format_runtime_top_counts(source_mix)
        truth_summary = self._format_runtime_top_counts(truth_mix)
        if source_summary:
            summary_parts.append(f"来源 {source_summary}")
        if truth_summary:
            summary_parts.append(f"真值 {truth_summary}")
        compact_parts = [f"H{hit} M{miss} B{build} W{wait}"]
        if warm:
            compact_parts.append(f"Warm{warm}")
        if truth_summary:
            compact_parts.append(truth_summary)
        return {
            "session_age_sec": max(int(time.time() - float(self.created_at or time.time())), 0),
            "cache": cache_counts,
            "cache_namespace_mix": cache_namespace_mix,
            "source_mix": source_mix,
            "truth_mix": truth_mix,
            "stage_mix": stage_mix,
            "summary": " | ".join(summary_parts),
            "compact_summary": " | ".join(compact_parts),
        }

    def _augment_data_meta_with_runtime(self, meta: Optional[Dict[str, Any]], *, stage_name: str = "") -> Dict[str, Any]:
        augmented = dict(meta or {})
        normalized_stage = str(stage_name or "").strip()
        self._record_runtime_data_meta(
            source=augmented.get("source"),
            truth_level=augmented.get("truth_level"),
            stage_name=normalized_stage,
        )
        runtime_snapshot = self._runtime_observation_snapshot()
        augmented["runtime"] = runtime_snapshot
        augmented["runtime_summary"] = str(runtime_snapshot.get("summary") or "")
        augmented["runtime_compact_summary"] = str(runtime_snapshot.get("compact_summary") or "")
        return augmented

    def _augment_payload_runtime_meta(self, payload: Any, *, stage_name: str = "") -> Any:
        if not isinstance(payload, dict):
            return _standardize_payload_metrics(payload)
        cloned = dict(payload)
        normalized_stage = str(stage_name or cloned.get("stage") or "").strip()
        if "data_meta" in cloned or normalized_stage:
            cloned["data_meta"] = self._augment_data_meta_with_runtime(
                cloned.get("data_meta") if isinstance(cloned.get("data_meta"), dict) else {},
                stage_name=normalized_stage,
            )
        return _standardize_payload_metrics(cloned)

    def _schedule_cache_warm(self, cache_key: str, ttl_seconds: int, builder) -> None:
        self._record_cache_observation("warm_schedule", cache_key=cache_key)
        self._schedule_executor_cache_warm(
            cache_key,
            ttl_seconds,
            builder,
            executor=self._warm_executor,
            jobs=self._warm_jobs,
            jobs_lock=self._warm_jobs_lock,
        )

    def _schedule_heavy_cache_warm(self, cache_key: str, ttl_seconds: int, builder) -> None:
        self._record_cache_observation("heavy_warm_schedule", cache_key=cache_key)
        self._schedule_executor_cache_warm(
            cache_key,
            ttl_seconds,
            builder,
            executor=self._heavy_executor,
            jobs=self._heavy_jobs,
            jobs_lock=self._heavy_jobs_lock,
        )

    def _schedule_executor_cache_warm(
        self,
        cache_key: str,
        ttl_seconds: int,
        builder,
        *,
        executor: ThreadPoolExecutor,
        jobs: Dict[str, Any],
        jobs_lock: threading.Lock,
    ) -> None:
        now = time.time()
        with self._cache_lock:
            entry = self._cache.get(cache_key)
            if entry and now - float(entry.get("ts") or 0.0) < ttl_seconds:
                return
        with jobs_lock:
            current = jobs.get(cache_key)
            if current is not None and self._warm_job_active(current):
                return

            def runner() -> None:
                try:
                    self._cache_get_or_build(cache_key, ttl_seconds, builder)
                except Exception:
                    pass
                finally:
                    with jobs_lock:
                        active = jobs.get(cache_key)
                        if active is job_ref[0]:
                            jobs.pop(cache_key, None)

            job_ref: List[Any] = [None]
            future = executor.submit(runner)
            job_ref[0] = future
            jobs[cache_key] = future

    @staticmethod
    def _warm_job_active(job: Any) -> bool:
        if job is None:
            return False
        if hasattr(job, "is_alive"):
            try:
                return bool(job.is_alive())
            except Exception:
                return False
        if hasattr(job, "done"):
            try:
                return not bool(job.done())
            except Exception:
                return False
        return False

    def runtime_status_snapshot(self) -> Dict[str, Any]:
        now_ms = int(time.time() * 1000)
        with self._cache_lock:
            cache_entries = int(len(self._cache))
        with self._warm_jobs_lock:
            active_warm_jobs = int(sum(1 for job in self._warm_jobs.values() if self._warm_job_active(job)))
        with self._heavy_jobs_lock:
            active_heavy_jobs = int(sum(1 for job in self._heavy_jobs.values() if self._warm_job_active(job)))
        with self._address_stream_lock:
            active_address_streams = int(len(self._address_streams))
        return {
            "coin": self.coin,
            "created_at_ms": int(self.created_at * 1000),
            "last_access_at_ms": int(self.last_access_at * 1000),
            "session_age_s": round(max(0.0, time.time() - self.created_at), 1),
            "cache_entries": cache_entries,
            "active_warm_jobs": active_warm_jobs,
            "active_heavy_jobs": active_heavy_jobs,
            "active_address_streams": active_address_streams,
            "symbols": {
                "perp": dict(self.symbol_map),
                "spot": dict(self.spot_symbol_map),
            },
            "transport": {
                exchange_key: self.service.get_transport_health(exchange_key, spot=False)
                for exchange_key in EXCHANGE_ORDER
                if self.symbol_map.get(exchange_key)
            },
            "spot_transport": {
                exchange_key: self.service.get_transport_health(exchange_key, spot=True)
                for exchange_key in SPOT_EXCHANGE_ORDER
                if self.spot_symbol_map.get(exchange_key)
            },
            "captured_at_ms": now_ms,
        }

    def hot_precompute_payloads(
        self,
        *,
        watch_group: str = "board",
        exchange_key: str = "binance",
        exchange_keys: Optional[List[str]] = None,
        market_scope: str = "merged",
        time_window: str = "1h",
        ratio_window: str = "15m",
        coin_scope: str = "majors",
        min_notional: float = 0.0,
        oi_threshold_pct: float = 0.0,
        sentiment_mode: str = "all",
    ) -> Dict[str, Any]:
        normalized_exchange_key = str(exchange_key or "binance").strip().lower()
        if normalized_exchange_key not in EXCHANGE_ORDER:
            normalized_exchange_key = "binance"
        normalized_exchange_keys = _normalize_exchange_keys(exchange_keys)
        normalized_watch_group = _normalize_watch_group(watch_group)
        normalized_market_scope = _normalize_market_scope(market_scope)
        normalized_time_window = _normalize_time_window(time_window)
        normalized_ratio_window = _normalize_ratio_window(ratio_window)
        normalized_coin_scope = _normalize_coin_scope(coin_scope)
        normalized_min_notional = max(_normalize_notional_threshold(min_notional), TAPE_MIN_NOTIONAL_FLOOR)
        normalized_oi_threshold = _normalize_oi_threshold(oi_threshold_pct)
        normalized_sentiment_mode = _normalize_sentiment_mode(sentiment_mode)
        self.touch()
        started_ms = int(time.time() * 1000)
        backpressure = _request_backpressure(normalized_exchange_keys)
        heavy_rest_tasks = {
            "overview-rich-lite",
            "overview-rich-charts-a-warm",
            "overview-rich-charts-b-warm",
        }
        skip_heavy_reason = (
            f"REST 冷却中，最大剩余 {int(backpressure.get('max_cooldown_s') or 0)}s，暂缓重 REST 预热"
            if int(backpressure.get("max_cooldown_s") or 0) > 0
            else None
        )
        if self.manager is not None and not skip_heavy_reason:
            try:
                self.manager.monitor_base_frame(
                    coin=self.coin,
                    watch_group=normalized_watch_group,
                    coin_scope=normalized_coin_scope,
                    exchange_keys=normalized_exchange_keys,
                    market_scope=normalized_market_scope,
                    large_trade_threshold=max(float(normalized_min_notional or 0.0), 100_000.0),
                    read_only=False,
                )
            except Exception:
                pass
        sentiment_watchlist = self._watchlist_coins(normalized_watch_group)
        for sentiment_coin in sentiment_watchlist[: max(4, min(8, len(sentiment_watchlist)))]:
            sentiment_cache_key = f"sentiment::{str(sentiment_coin or '').upper().strip()}::{normalized_ratio_window}"
            self._schedule_heavy_cache_warm(
                sentiment_cache_key,
                20,
                lambda sentiment_coin=sentiment_coin: self._sentiment_payloads(
                    normalized_ratio_window,
                    coin=sentiment_coin,
                    sync_on_miss=True,
                ),
            )

        def schedule_charts_a_overview() -> Dict[str, Any]:
            self._schedule_overview_rich_charts_a_warm(
                exchange_key=normalized_exchange_key,
                watch_group=normalized_watch_group,
                custom_coins=[],
                exchange_keys=normalized_exchange_keys,
                market_scope=normalized_market_scope,
                time_window=normalized_time_window,
                ratio_window=normalized_ratio_window,
                coin_scope=normalized_coin_scope,
                min_notional=normalized_min_notional,
                oi_threshold_pct=normalized_oi_threshold,
                sentiment_mode=normalized_sentiment_mode,
            )
            return {"scheduled": True, "stage": "charts-a"}

        def schedule_heavy_overview() -> Dict[str, Any]:
            self._schedule_overview_rich_charts_b_warm(
                exchange_key=normalized_exchange_key,
                exchange_keys=normalized_exchange_keys,
                market_scope=normalized_market_scope,
                time_window=normalized_time_window,
                ratio_window=normalized_ratio_window,
                min_notional=normalized_min_notional,
            )
            return {"scheduled": True, "stage": "charts-b"}

        tasks = [
            ("overview", 8, lambda: self.overview_payload()),
            (
                "overview-rich-lite",
                12,
                lambda: self.overview_rich_payload(
                    exchange_key=normalized_exchange_key,
                    watch_group=normalized_watch_group,
                    exchange_keys=normalized_exchange_keys,
                    market_scope=normalized_market_scope,
                    time_window=normalized_time_window,
                    ratio_window=normalized_ratio_window,
                    coin_scope=normalized_coin_scope,
                    min_notional=normalized_min_notional,
                    oi_threshold_pct=normalized_oi_threshold,
                    sentiment_mode=normalized_sentiment_mode,
                    stage="lite-tables",
                ),
            ),
            ("overview-rich-charts-a-warm", 16, schedule_charts_a_overview),
            ("overview-rich-charts-b-warm", 16, schedule_heavy_overview),
            (
                "multicoin",
                14,
                lambda: self.multicoin_payload(
                    watch_group=normalized_watch_group,
                    coin_scope=normalized_coin_scope,
                    exchange_keys=normalized_exchange_keys,
                    market_scope=normalized_market_scope,
                    time_window=normalized_time_window,
                    min_notional=normalized_min_notional,
                    oi_threshold_pct=normalized_oi_threshold,
                    sentiment_mode=normalized_sentiment_mode,
                    _sync_on_miss=True,
                ),
            ),
            (
                "monitor",
                14,
                lambda: self.monitor_payload(
                    watch_group=normalized_watch_group,
                    coin_scope=normalized_coin_scope,
                    exchange_keys=normalized_exchange_keys,
                    market_scope=normalized_market_scope,
                    time_window=normalized_time_window,
                    min_notional=normalized_min_notional,
                    oi_threshold_pct=normalized_oi_threshold,
                    sentiment_mode=normalized_sentiment_mode,
                    _sync_on_miss=True,
                ),
            ),
            (
                "execution",
                14,
                lambda: self.execution_payload(
                    exchange_keys=normalized_exchange_keys,
                    market_scope=normalized_market_scope,
                    time_window=normalized_time_window,
                    _sync_on_miss=True,
                ),
            ),
            (
                "alerts",
                10,
                lambda: self.alerts_payload(
                    exchange_keys=normalized_exchange_keys,
                    market_scope=normalized_market_scope,
                    time_window=normalized_time_window,
                    _sync_on_miss=True,
                ),
            ),
            (
                "orderbook-center",
                10,
                lambda: self.orderbook_center_payload(
                    normalized_exchange_key,
                    min_notional=normalized_min_notional,
                    event_kind="all",
                ),
            ),
        ]
        skipped_tasks: Dict[str, str] = {}
        if skip_heavy_reason:
            tasks = [task for task in tasks if task[0] not in heavy_rest_tasks]
            skipped_tasks = {task_name: skip_heavy_reason for task_name in heavy_rest_tasks}
        results: List[Dict[str, Any]] = []
        for task_name, ttl_seconds, builder in tasks:
            task_started = time.perf_counter()
            status = "ok"
            error = None
            cards = 0
            panels = 0
            revision = None
            try:
                payload = builder()
                if isinstance(payload, dict):
                    cards = len(payload.get("cards", []) or [])
                    panels = len(payload.get("panels", []) or [])
                    revision = _cache_signature_token(
                        {
                            "generated_at_ms": payload.get("generated_at_ms"),
                            "updated_at_ms": (payload.get("data_meta") or {}).get("updated_at_ms"),
                            "cards": cards,
                            "panels": panels,
                            "status": (payload.get("data_meta") or {}).get("status"),
                        }
                    )
                    if str((payload.get("data_meta") or {}).get("status") or "") == "warming_up":
                        status = "warming_up"
                else:
                    status = "scheduled"
                    revision = json.dumps(payload, sort_keys=True, default=str)
            except Exception as exc:
                status = "error"
                error = str(exc)
            results.append(
                {
                    "task": task_name,
                    "status": status,
                    "duration_ms": round((time.perf_counter() - task_started) * 1000.0, 2),
                    "cards": cards,
                    "panels": panels,
                    "revision": revision,
                    "error": error,
                }
            )
        for task_name, reason in skipped_tasks.items():
            results.append(
                {
                    "task": task_name,
                    "status": "skipped",
                    "duration_ms": 0.0,
                    "cards": 0,
                    "panels": 0,
                    "revision": None,
                    "error": reason,
                }
            )
        finished_ms = int(time.time() * 1000)
        return {
            "coin": self.coin,
            "started_at_ms": started_ms,
            "finished_at_ms": finished_ms,
            "duration_ms": max(0, finished_ms - started_ms),
            "filters": {
                "exchange_key": normalized_exchange_key,
                "exchange_keys": normalized_exchange_keys,
                "watch_group": normalized_watch_group,
                "market_scope": normalized_market_scope,
                "time_window": normalized_time_window,
                "coin_scope": normalized_coin_scope,
                "min_notional": normalized_min_notional,
                "oi_threshold_pct": normalized_oi_threshold,
                "sentiment_mode": normalized_sentiment_mode,
            },
            "backpressure": {
                "cooldown_count": int(backpressure.get("cooldown_count") or 0),
                "rate_limit_count": int(backpressure.get("rate_limit_count") or 0),
                "max_cooldown_s": int(backpressure.get("max_cooldown_s") or 0),
            },
            "tasks": results,
            "runtime": self.runtime_status_snapshot(),
        }

    def _prune_address_streams_locked(self) -> None:
        now = time.time()
        stale_keys = [
            stream_key
            for stream_key, entry in self._address_streams.items()
            if now - float(entry.get("last_access_at") or 0.0) >= self._address_stream_idle_seconds
        ]
        for stream_key in stale_keys:
            entry = self._address_streams.pop(stream_key, None)
            stream = entry.get("stream") if isinstance(entry, dict) else None
            if stream is not None:
                try:
                    stream.stop()
                except Exception:
                    continue

    def _get_address_stream(
        self,
        address: str,
        *,
        lookback_hours: int,
        enable_stream: bool,
    ) -> Optional[HyperliquidAddressStreamService]:
        if not enable_stream:
            return None
        normalized_address = normalize_onchain_address(address)
        if not is_valid_onchain_address(normalized_address):
            return None
        stream_key = f"{normalized_address}::{self.coin}::{int(lookback_hours)}"
        now = time.time()
        with self._address_stream_lock:
            self._prune_address_streams_locked()
            entry = self._address_streams.get(stream_key)
            if entry is None:
                stream = HyperliquidAddressStreamService(
                    normalized_address,
                    self.coin,
                    timeout=self.timeout,
                    lookback_hours=int(lookback_hours),
                )
                entry = {"stream": stream, "last_access_at": now}
                self._address_streams[stream_key] = entry
            else:
                entry["last_access_at"] = now
            stream = entry.get("stream")
        return stream if isinstance(stream, HyperliquidAddressStreamService) else None

    def _build_headlines(
        self,
        snapshots: List[ExchangeSnapshot],
        spot_snapshots: Dict[str, Optional[SpotSnapshot]],
    ) -> List[Dict[str, Any]]:
        now_ms = int(time.time() * 1000)
        headline_notional_floor = 500_000.0
        items: List[Dict[str, Any]] = []
        oi_candidates: List[Dict[str, Any]] = []
        for snapshot in snapshots:
            exchange_key = _to_exchange_key(snapshot)
            history = self.service.get_oi_history(exchange_key)
            current_oi = snapshot.open_interest_notional or snapshot.open_interest
            anchor_oi = next(
                (
                    point.open_interest_notional or point.open_interest
                    for point in history
                    if (point.open_interest_notional or point.open_interest) not in (None, 0)
                ),
                None,
            )
            if current_oi not in (None, 0) and anchor_oi not in (None, 0):
                delta = float(current_oi) - float(anchor_oi)
                pct = delta / float(anchor_oi) * 100.0
                if abs(delta) < headline_notional_floor:
                    continue
                oi_candidates.append(
                    {
                        "exchange": snapshot.exchange,
                        "exchange_key": exchange_key,
                        "text": f"{snapshot.exchange} {self.coin} OI {'增加' if delta >= 0 else '减少'} {pct:+.1f}% | ${_fmt_compact(current_oi)}（变化 ${_fmt_compact(delta)}）",
                        "score": abs(delta),
                    }
                )
        oi_candidates.sort(key=lambda item: item["score"], reverse=True)
        items.extend(
            {
                "kind": "oi",
                "label": "OI",
                "text": row["text"],
                "exchange_key": row["exchange_key"],
                "exchange": row.get("exchange"),
                "score": row.get("score"),
                "timestamp_ms": now_ms,
                "anchor": "overview-snapshots",
            }
            for row in oi_candidates[:2]
        )

        liquidation_candidates: List[Dict[str, Any]] = []
        default_symbol_map = {**default_symbols(self.coin), **(self.symbol_map or {})}
        for exchange_key in EXCHANGE_ORDER:
            symbol = default_symbol_map.get(exchange_key) or ""
            persisted_recent = self.service.get_persisted_liquidations(
                exchange_key,
                symbol,
                since_ms=now_ms - 15 * 60_000,
                limit=1200,
            )
            session_recent = [
                event
                for event in self.service.get_liquidation_history(exchange_key)
                if event.timestamp_ms >= now_ms - 15 * 60_000
            ]
            recent = _merge_liquidation_event_groups(persisted_recent, session_recent)
            if not recent:
                continue
            long_notional = sum(event.notional or 0.0 for event in recent if event.side == "long")
            short_notional = sum(event.notional or 0.0 for event in recent if event.side == "short")
            total = long_notional + short_notional
            if total <= 0:
                continue
            dominant_side = "long" if long_notional >= short_notional else "short"
            dominant_value = long_notional if dominant_side == "long" else short_notional
            if dominant_value < headline_notional_floor and total < headline_notional_floor:
                continue
            liquidation_candidates.append(
                {
                    "exchange_key": exchange_key,
                    "exchange": EXCHANGE_TITLE_MAP.get(exchange_key, exchange_key.title()),
                    "text": f"{EXCHANGE_TITLE_MAP.get(exchange_key, exchange_key.title())} {self.coin} {_liquidation_side_label(dominant_side)} ${_fmt_compact(dominant_value)} | 总爆仓 ${_fmt_compact(total)}",
                    "score": dominant_value,
                }
            )
        liquidation_candidates.sort(key=lambda item: float(item["score"]), reverse=True)
        items.extend(
            {
                "kind": "liquidation",
                "label": "爆仓",
                "text": row["text"],
                "exchange_key": row["exchange_key"],
                "exchange": row.get("exchange"),
                "score": row.get("score"),
                "timestamp_ms": now_ms,
                "anchor": "tape-feed",
            }
            for row in liquidation_candidates[:2]
        )

        anomaly_candidates: List[Dict[str, Any]] = []
        for snapshot in snapshots:
            if snapshot.status != "ok" or snapshot.mark_price in (None, 0) or snapshot.last_price is None:
                continue
            premium_pct = snapshot.premium_pct or 0.0
            if abs(premium_pct) >= 0.08:
                anomaly_candidates.append(
                    {
                        "exchange_key": _to_exchange_key(snapshot),
                        "exchange": snapshot.exchange,
                        "text": f"{snapshot.exchange} {self.coin} {'上涨偏离' if premium_pct > 0 else '贴水偏离'} {premium_pct:+.3f}%",
                        "score": abs(premium_pct),
                    }
                )
            exchange_key = _to_exchange_key(snapshot)
            trades = [event for event in self.service.get_trade_history(exchange_key) if event.notional and event.notional >= headline_notional_floor]
            if trades:
                biggest = max(trades, key=lambda item: float(item.notional or 0.0))
                anomaly_candidates.append(
                    {
                        "exchange_key": exchange_key,
                        "exchange": snapshot.exchange,
                        "text": f"{snapshot.exchange} {self.coin} {_trade_side_label(biggest.side)}大单 ${_fmt_compact(biggest.notional)} @ {biggest.price or '-'}",
                        "score": float(biggest.notional or 0.0),
                    }
                )
            spot_snapshot = spot_snapshots.get(exchange_key)
            if spot_snapshot is not None and spot_snapshot.status == "ok" and snapshot.last_price and spot_snapshot.last_price:
                divergence = (snapshot.last_price - spot_snapshot.last_price) / spot_snapshot.last_price * 100.0
                if abs(divergence) >= 0.05:
                    anomaly_candidates.append(
                        {
                            "exchange_key": exchange_key,
                            "exchange": snapshot.exchange,
                            "text": f"{snapshot.exchange} {self.coin} 现货/合约偏离 {divergence:+.3f}%",
                            "score": abs(divergence),
                        }
                    )
        anomaly_candidates.sort(key=lambda item: float(item["score"]), reverse=True)
        items.extend(
            {
                "kind": "anomaly",
                "label": "异动",
                "text": row["text"],
                "exchange_key": row["exchange_key"],
                "exchange": row.get("exchange"),
                "score": row.get("score"),
                "timestamp_ms": row.get("timestamp_ms", now_ms),
                "anchor": "overview-snapshots",
            }
            for row in anomaly_candidates[:4]
        )
        return items[:16]

    def _build_global_headlines(
        self,
        *,
        exchange_keys: Optional[List[str]] = None,
        market_scope: str = "merged",
        time_window: str = "1h",
        min_notional: float = 500_000.0,
        custom_min_notional: float = 500_000.0,
        oi_threshold_pct: float = 0.0,
        anomaly_type: str = "all",
        whale_window: str = "5m",
        oi_window: str = "1h",
    ) -> List[Dict[str, Any]]:
        headline_notional_floor = 500_000.0
        monitor_kwargs = {
            "watch_group": "board",
            "coin_scope": "board",
            "exchange_keys": _normalize_exchange_keys(exchange_keys or list(EXCHANGE_ORDER)),
            "market_scope": _normalize_market_scope(market_scope),
            "time_window": _normalize_time_window(time_window),
            "top_n": 60,
            "min_notional": max(_normalize_notional_threshold(min_notional), headline_notional_floor),
            "custom_min_notional": max(_normalize_custom_notional_threshold(custom_min_notional), headline_notional_floor),
            "oi_threshold_pct": _normalize_oi_threshold(oi_threshold_pct),
            "sentiment_mode": "all",
            "side": "all",
            "sort_by": "signal_desc",
            "aggregate_mode": "1s",
            "anomaly_type": _normalize_monitor_anomaly_type(anomaly_type),
            "whale_window": _normalize_monitor_whale_window(whale_window),
            "oi_window": _normalize_monitor_oi_window(oi_window),
        }
        monitor_cache_key = self.monitor_payload_cache_key(**monitor_kwargs)
        monitor_snapshot = self._cache_peek(monitor_cache_key, ttl_seconds=4)
        if monitor_snapshot is None:
            monitor_snapshot = self._cache_peek(monitor_cache_key, ttl_seconds=None)
        if monitor_snapshot is None:
            monitor_snapshot = self.monitor_payload(
                **monitor_kwargs,
                _sync_on_miss=True,
                _cache_only=False,
            )
        whale_events = list((monitor_snapshot or {}).get("whale_events") or [])
        flash_alerts = list((monitor_snapshot or {}).get("flash_alerts") or [])
        oi_rows = list((monitor_snapshot or {}).get("oi_rows") or [])
        signal_rows = list((monitor_snapshot or {}).get("signals") or [])
        summary_rows = list((monitor_snapshot or {}).get("rows") or [])
        summary_by_coin = {
            _normalize_coin_symbol((row or {}).get("coin") or (row or {}).get("币种")): _with_standard_metric_aliases(dict(row or {}))
            for row in summary_rows
            if isinstance(row, dict) and _normalize_coin_symbol((row or {}).get("coin") or (row or {}).get("币种"))
        }
        overview_frame = canonicalize_market_frame_columns(self._build_market_overview_frame("board", light=False))

        def passes_alt_gate(coin_value: Any, *values: Any) -> bool:
            coin_token = _normalize_coin_symbol(coin_value)
            if not coin_token:
                return False
            max_value = 0.0
            for value in values:
                normalized = _payload_float(value)
                if normalized is not None:
                    max_value = max(max_value, abs(float(normalized)))
            return max_value >= headline_notional_floor

        items: List[Dict[str, Any]] = []
        for row in signal_rows:
            if not isinstance(row, dict):
                continue
            normalized_row = _with_standard_metric_aliases(dict(row))
            selection = row.get("__selection") or {}
            coin_token = _normalize_coin_symbol(selection.get("coin") or normalized_row.get("coin") or normalized_row.get("币种"))
            summary_row = summary_by_coin.get(coin_token, {})
            signal_score = _payload_float(normalized_row.get("score") or normalized_row.get("评分")) or 0.0
            activity_notional = max(
                abs(float(_row_window_large_metric(summary_row, "5m", "total") or 0.0)),
                abs(float(_payload_float(summary_row.get("事件样本额")) or 0.0)),
                abs(float(_payload_float(summary_row.get("OI变化额")) or 0.0)),
            )
            if not coin_token:
                continue
            if not passes_alt_gate(coin_token, activity_notional):
                continue
            exchange_name = str(normalized_row.get("exchange") or normalized_row.get("交易所") or selection.get("exchange") or "-").strip()
            signal_type = str(normalized_row.get("类型") or "信号").strip()
            context_text = str(normalized_row.get("上下文") or normalized_row.get("标签") or signal_type).strip()
            items.append(
                {
                    "kind": "oi" if "OI" in signal_type.upper() else "anomaly",
                    "label": "OI" if "OI" in signal_type.upper() else "异动",
                    "coin": coin_token,
                    "exchange_key": _normalize_exchange_value(selection.get("exchange") or exchange_name),
                    "exchange": exchange_name,
                    "text": f"{exchange_name} {coin_token} {signal_type} | {context_text}",
                    "score": max(float(signal_score), activity_notional),
                    "timestamp_ms": int(_coerce_timestamp_ms(normalized_row.get("time") or normalized_row.get("时间")) or int(time.time() * 1000)),
                    "anchor": "monitor-signals",
                }
            )
        for row in whale_events:
            if not isinstance(row, dict):
                continue
            selection = row.get("__selection") or {}
            coin_token = _normalize_coin_symbol(selection.get("coin") or row.get("coin"))
            notional = _payload_float(row.get("notional")) or 0.0
            if not passes_alt_gate(coin_token, notional):
                continue
            exchange_name = str(row.get("exchange") or row.get("exchange_key") or "-").strip()
            side_label = str(row.get("side_label") or row.get("side") or "大单").strip()
            items.append(
                {
                    "kind": "anomaly",
                    "label": "异动",
                    "coin": coin_token,
                    "exchange_key": _normalize_exchange_value(row.get("exchange_key") or row.get("exchange")),
                    "exchange": exchange_name,
                    "text": f"{exchange_name} {coin_token} {side_label} ${_fmt_compact(notional)}",
                    "score": float(abs(notional)),
                    "timestamp_ms": int(row.get("timestamp_ms") or 0) or int(time.time() * 1000),
                    "anchor": "monitor-whales",
                }
            )
        for row in flash_alerts:
            if not isinstance(row, dict):
                continue
            normalized_row = _with_standard_metric_aliases(dict(row))
            selection = row.get("__selection") or {}
            coin_token = _normalize_coin_symbol(selection.get("coin") or normalized_row.get("coin") or normalized_row.get("币种"))
            summary_row = summary_by_coin.get(coin_token, {})
            move_1h = _row_price_change_pct(normalized_row, "1h")
            move_30m = _row_price_change_pct(normalized_row, "30m")
            move_5m = _row_price_change_pct(normalized_row, "5m")
            move_abs = max(abs(float(value or 0.0)) for value in (move_5m, move_30m, move_1h))
            activity_notional = max(
                abs(float(_row_window_large_metric(summary_row, "5m", "total") or 0.0)),
                abs(float(_payload_float(summary_row.get("事件样本额")) or 0.0)),
                abs(float(_payload_float(summary_row.get("OI变化额")) or 0.0)),
            )
            if not coin_token or not passes_alt_gate(coin_token, activity_notional):
                continue
            exchange_name = str(normalized_row.get("exchange") or normalized_row.get("交易所") or summary_row.get("主交易所") or summary_row.get("交易所") or "-").strip()
            alert_text = str(normalized_row.get("告警") or normalized_row.get("异动标签") or "").strip()
            items.append(
                {
                    "kind": "anomaly",
                    "label": "异动",
                    "coin": coin_token,
                    "exchange_key": _normalize_exchange_value(summary_row.get("主交易所键") or summary_row.get("交易所键") or exchange_name),
                    "exchange": exchange_name,
                    "text": f"{exchange_name} {coin_token} {alert_text or f'1h {move_1h:+.2f}%'}",
                    "score": max(move_abs, activity_notional),
                    "timestamp_ms": int(_coerce_timestamp_ms(normalized_row.get("time") or normalized_row.get("时间")) or int(time.time() * 1000)),
                    "anchor": "monitor-flash",
                }
            )
        for row in oi_rows:
            if not isinstance(row, dict):
                continue
            normalized_row = _with_standard_metric_aliases(dict(row))
            pair = str(normalized_row.get("交易对") or normalized_row.get("coin") or normalized_row.get("币种") or "").strip()
            coin_token = _normalize_coin_symbol(pair)
            exchange_name = str(_row_exchange_name(normalized_row) or normalized_row.get("所属交易所") or normalized_row.get("交易所") or "-").strip()
            oi_change = _row_oi_change_pct(normalized_row, "1h") or _payload_float(normalized_row.get("OI变化率"))
            oi_total = _row_oi_notional(normalized_row) or _payload_float(normalized_row.get("合约持仓额(USDT)"))
            summary_row = summary_by_coin.get(coin_token, {})
            oi_delta_notional = abs(float(_payload_float(summary_row.get("OI变化额")) or 0.0))
            if oi_change is None:
                continue
            if not passes_alt_gate(coin_token, oi_delta_notional):
                continue
            items.append(
                {
                    "kind": "oi",
                    "label": "OI",
                    "coin": coin_token,
                    "exchange_key": _normalize_exchange_value(exchange_name),
                    "exchange": exchange_name,
                    "text": f"{exchange_name} {coin_token} OI {oi_change:+.1f}% | 变化额 ${_fmt_compact(oi_delta_notional)} | 总额 ${_fmt_compact(oi_total)}",
                    "score": oi_delta_notional,
                    "timestamp_ms": int(time.time() * 1000),
                    "anchor": "monitor-oi",
                }
            )
        for row in summary_rows:
            if not isinstance(row, dict):
                continue
            normalized_row = _with_standard_metric_aliases(dict(row))
            coin_token = _normalize_coin_symbol(normalized_row.get("coin") or normalized_row.get("币种"))
            if not coin_token:
                continue
            basis_value = (
                _payload_float(normalized_row.get("最大偏离(%)"))
                or _payload_float(normalized_row.get("Basis(%)"))
                or _payload_float(normalized_row.get("spot_perp_basis_pct"))
            )
            if basis_value is None or abs(float(basis_value)) < 0.08:
                continue
            exchange_name = str(normalized_row.get("偏离交易所") or normalized_row.get("主交易所") or normalized_row.get("交易所") or "-").strip()
            items.append(
                {
                    "kind": "basis",
                    "label": "偏离",
                    "coin": coin_token,
                    "exchange_key": _normalize_exchange_value(normalized_row.get("交易所键") or normalized_row.get("主交易所键") or exchange_name),
                    "exchange": exchange_name,
                    "text": f"{exchange_name} {coin_token} 现货/合约偏离 {float(basis_value):+.3f}%",
                    "score": abs(float(basis_value)),
                    "timestamp_ms": int(_coerce_timestamp_ms(normalized_row.get("时间")) or int(time.time() * 1000)),
                    "anchor": "monitor-basis",
                }
            )
        if isinstance(overview_frame, pd.DataFrame) and not overview_frame.empty:
            for row in overview_frame.to_dict("records"):
                normalized_row = _with_standard_metric_aliases(dict(row))
                coin_token = _normalize_coin_symbol(normalized_row.get("coin") or normalized_row.get("币种"))
                if not coin_token:
                    continue
                exchange_name = str(normalized_row.get("主交易所") or normalized_row.get("交易所") or "-").strip()
                exchange_key = _normalize_exchange_value(normalized_row.get("主交易所键") or normalized_row.get("交易所键") or exchange_name)
                oi_change = _row_oi_change_pct(normalized_row, "1h")
                oi_delta_notional = abs(float(_payload_float(normalized_row.get("OI变化额")) or 0.0))
                liquidation_notional = abs(float(_payload_float(normalized_row.get("24h爆仓样本额")) or 0.0))
                basis_value = (
                    _payload_float(normalized_row.get("最大偏离(%)"))
                    or _payload_float(normalized_row.get("Basis(%)"))
                    or _payload_float(normalized_row.get("spot_perp_basis_pct"))
                )
                if oi_change is not None and oi_delta_notional >= headline_notional_floor:
                    items.append(
                        {
                            "kind": "oi",
                            "label": "OI",
                            "coin": coin_token,
                            "exchange_key": exchange_key,
                            "exchange": exchange_name,
                            "text": f"{exchange_name} {coin_token} OI {float(oi_change):+.1f}% | 变化额 ${_fmt_compact(oi_delta_notional)}",
                            "score": oi_delta_notional,
                            "timestamp_ms": int(time.time() * 1000),
                            "anchor": "overview-board",
                        }
                    )
                if liquidation_notional >= headline_notional_floor:
                    items.append(
                        {
                            "kind": "liquidation",
                            "label": "爆仓",
                            "coin": coin_token,
                            "exchange_key": exchange_key,
                            "exchange": exchange_name,
                            "text": f"{exchange_name} {coin_token} 爆仓样本 ${_fmt_compact(liquidation_notional)}",
                            "score": liquidation_notional,
                            "timestamp_ms": int(time.time() * 1000),
                            "anchor": "overview-board",
                        }
                    )
                if basis_value is not None and abs(float(basis_value)) >= 0.08:
                    items.append(
                        {
                            "kind": "basis",
                            "label": "偏离",
                            "coin": coin_token,
                            "exchange_key": exchange_key,
                            "exchange": exchange_name,
                            "text": f"{exchange_name} {coin_token} 现货/合约偏离 {float(basis_value):+.3f}%",
                            "score": abs(float(basis_value)),
                            "timestamp_ms": int(time.time() * 1000),
                            "anchor": "overview-board",
                        }
                    )
        deduped: List[Dict[str, Any]] = []
        seen_keys: set[str] = set()
        anchor_priority = {
            "monitor-signals": 0,
            "monitor-oi": 1,
            "monitor-flash": 2,
            "monitor-whales": 3,
            "monitor-basis": 4,
            "overview-board": 5,
        }
        for item in sorted(
            items,
            key=lambda value: (
                -int(anchor_priority.get(str(value.get("anchor") or ""), 9)),
                float(abs(value.get("score") or 0.0)),
            ),
            reverse=True,
        ):
            token = f"{item.get('kind')}::{item.get('coin')}::{item.get('exchange_key')}::{item.get('text')}"
            if token in seen_keys:
                continue
            seen_keys.add(token)
            deduped.append(item)
            if len(deduped) >= 24:
                break
        return deduped

    def global_headlines_cache_key(
        self,
        *,
        exchange_keys: Optional[List[str]] = None,
        market_scope: str = "merged",
        time_window: str = "1h",
        min_notional: float = 500_000.0,
        custom_min_notional: float = 500_000.0,
        oi_threshold_pct: float = 0.0,
        anomaly_type: str = "all",
        whale_window: str = "5m",
        oi_window: str = "1h",
    ) -> str:
        return (
            f"global-headlines::{self.coin}::{','.join(_normalize_exchange_keys(exchange_keys or list(EXCHANGE_ORDER)))}::"
            f"{_normalize_market_scope(market_scope)}::{_normalize_time_window(time_window)}::"
            f"{_normalize_notional_threshold(min_notional)}::{_normalize_custom_notional_threshold(custom_min_notional)}::"
            f"{_normalize_oi_threshold(oi_threshold_pct)}::{_normalize_monitor_anomaly_type(anomaly_type)}::"
            f"{_normalize_monitor_whale_window(whale_window)}::{_normalize_monitor_oi_window(oi_window)}"
        )

    def _global_headlines_snapshot(
        self,
        *,
        exchange_keys: Optional[List[str]] = None,
        market_scope: str = "merged",
        time_window: str = "1h",
        min_notional: float = 500_000.0,
        custom_min_notional: float = 500_000.0,
        oi_threshold_pct: float = 0.0,
        anomaly_type: str = "all",
        whale_window: str = "5m",
        oi_window: str = "1h",
        sync_on_miss: bool = False,
    ) -> List[Dict[str, Any]]:
        cache_key = self.global_headlines_cache_key(
            exchange_keys=exchange_keys,
            market_scope=market_scope,
            time_window=time_window,
            min_notional=min_notional,
            custom_min_notional=custom_min_notional,
            oi_threshold_pct=oi_threshold_pct,
            anomaly_type=anomaly_type,
            whale_window=whale_window,
            oi_window=oi_window,
        )
        builder = lambda: self._build_global_headlines(
            exchange_keys=exchange_keys,
            market_scope=market_scope,
            time_window=time_window,
            min_notional=min_notional,
            custom_min_notional=custom_min_notional,
            oi_threshold_pct=oi_threshold_pct,
            anomaly_type=anomaly_type,
            whale_window=whale_window,
            oi_window=oi_window,
        )
        cached = self._cache_peek(cache_key, ttl_seconds=8)
        if isinstance(cached, list):
            return cached
        stale = self._cache_peek(cache_key, ttl_seconds=None)
        if isinstance(stale, list):
            self._schedule_heavy_cache_warm(cache_key, 8, builder)
            return stale
        if sync_on_miss:
            built = self._cache_get_or_build(cache_key, 8, builder)
            return built if isinstance(built, list) else []
        self._schedule_heavy_cache_warm(cache_key, 8, builder)
        return []

    def _persist_signal_history(self, items: List[Dict[str, Any]]) -> None:
        if not items:
            return
        if not self._history_sqlite_enabled():
            return
        now_ms = int(time.time() * 1000)
        if now_ms - int(self._last_signal_history_persist_ms or 0) < 15_000:
            return
        payload_rows: List[Dict[str, Any]] = []
        for item in items:
            text = str(item.get("text") or "").strip()
            if not text:
                continue
            kind = str(item.get("kind") or "signal").strip().lower() or "signal"
            label = str(item.get("label") or kind.upper()).strip() or kind.upper()
            if kind == "anomaly" and "大单" in text:
                kind = "large"
                label = "大单"
            payload_rows.append(
                {
                    "kind": kind,
                    "label": label,
                    "text": text,
                    "exchange_key": str(item.get("exchange_key") or ""),
                    "exchange": str(item.get("exchange") or item.get("exchange_key") or ""),
                    "score": item.get("score"),
                    "anchor": item.get("anchor"),
                    "timestamp_ms": int(item.get("timestamp_ms") or now_ms),
                }
            )
        if not payload_rows:
            return
        persist_cache_key = f"persist-signal-history::{self.coin}::{now_ms // 15_000}"
        self._schedule_cache_warm(
            persist_cache_key,
            20,
            lambda rows=tuple(payload_rows): self.history_store.record_signal_events(self.coin, rows, bucket_ms=30_000),
        )
        self._last_signal_history_persist_ms = now_ms

    def _build_reference_layers(
        self,
        snapshot_rows: List[Dict[str, Any]],
        *,
        lead_lag_rows: Optional[List[Dict[str, Any]]] = None,
    ) -> Dict[str, Any]:
        spot_reference_frame = build_spot_reference_frame(snapshot_rows, lead_lag_rows=lead_lag_rows or [])
        perp_reference_frame = build_perp_reference_frame(snapshot_rows)
        spot_reference_frame = _attach_selection_column(spot_reference_frame, coin=self.coin)
        perp_reference_frame = _attach_selection_column(perp_reference_frame, coin=self.coin)
        spot_metrics = compute_spot_reference_metrics(spot_reference_frame)
        perp_metrics = compute_perp_reference_metrics(perp_reference_frame)
        conclusion_frame = build_market_conclusion_frame(spot_metrics, perp_metrics)
        conclusion = conclusion_frame.iloc[0].to_dict() if not conclusion_frame.empty else {}
        return {
            "spot_frame": spot_reference_frame,
            "perp_frame": perp_reference_frame,
            "conclusion_frame": conclusion_frame,
            "spot_metrics": spot_metrics,
            "perp_metrics": perp_metrics,
            "conclusion": conclusion,
        }

    def _build_reference_cards(self, reference_layers: Dict[str, Any]) -> List[Dict[str, str]]:
        spot_metrics = reference_layers.get("spot_metrics") or {}
        perp_metrics = reference_layers.get("perp_metrics") or {}
        conclusion = reference_layers.get("conclusion") or {}
        spot_anchor = _payload_float(spot_metrics.get("anchor_price"))
        spot_score = _payload_float(spot_metrics.get("confirmation_score"))
        perp_score = _payload_float(perp_metrics.get("crowding_score"))
        return [
            {
                "label": "现货锚点",
                "value": "-" if spot_anchor is None else f"{spot_anchor:,.2f}",
                "sub": str(spot_metrics.get("status") or "样本不足"),
            },
            {
                "label": "现货确认分",
                "value": "-" if spot_score is None else f"{spot_score:.1f}",
                "sub": str(spot_metrics.get("best_exchange") or "等待现货确认"),
            },
            {
                "label": "合约拥挤分",
                "value": "-" if perp_score is None else f"{perp_score:.1f}",
                "sub": f"{perp_metrics.get('bias') or '中性'} | {perp_metrics.get('dominant_state') or '样本不足'}",
            },
            {
                "label": "市场主导",
                "value": str(conclusion.get("市场驱动") or "样本不足"),
                "sub": str(conclusion.get("执行建议") or "等待更多样本"),
            },
        ]

    def _overview_reference_rows(
        self,
        *,
        exchange_keys: Optional[List[str]] = None,
    ) -> tuple[List[Dict[str, Any]], List[Dict[str, Any]]]:
        overview_payload = self.overview_payload()
        normalized_exchange_keys = _normalize_exchange_keys(exchange_keys)
        snapshot_rows = list(overview_payload.get("snapshots", []) or [])
        if normalized_exchange_keys:
            snapshot_rows = [
                row
                for row in snapshot_rows
                if str(row.get("exchange_key") or "").strip().lower() in normalized_exchange_keys
            ]
        lead_lag_rows = list(((overview_payload.get("reference") or {}).get("lead_lag") or []))
        if normalized_exchange_keys:
            lead_lag_rows = [
                row
                for row in lead_lag_rows
                if _normalize_exchange_value(row.get("exchange_key") or row.get("exchange")) in normalized_exchange_keys
            ]
        candidate_exchange_keys = normalized_exchange_keys or [
            _normalize_exchange_value(row.get("exchange_key") or row.get("exchange"))
            for row in snapshot_rows
            if _normalize_exchange_value(row.get("exchange_key") or row.get("exchange"))
        ]
        if not lead_lag_rows:
            lead_lag_rows = self._build_runtime_lead_lag_rows(candidate_exchange_keys, lookback_minutes=20)
        existing_exchange_keys = {
            _normalize_exchange_value(row.get("exchange_key") or row.get("exchange"))
            for row in lead_lag_rows
            if _normalize_exchange_value(row.get("exchange_key") or row.get("exchange"))
        }
        lead_lag_rows.extend(
            self._build_proxy_lead_lag_rows(
                snapshot_rows,
                exchange_keys=candidate_exchange_keys,
                existing_exchange_keys=existing_exchange_keys,
            )
        )
        return snapshot_rows, lead_lag_rows

    def _build_runtime_lead_lag_rows(
        self,
        exchange_keys: List[str],
        *,
        lookback_minutes: int = 20,
    ) -> List[Dict[str, Any]]:
        rows: List[Dict[str, Any]] = []
        seen: set[str] = set()
        for exchange_key in exchange_keys:
            normalized_exchange = _normalize_exchange_value(exchange_key)
            if not normalized_exchange or normalized_exchange in seen:
                continue
            seen.add(normalized_exchange)
            spot_trades = self.service.get_spot_trade_history(normalized_exchange)
            perp_trades = self.service.get_trade_history(normalized_exchange)
            if not spot_trades and not perp_trades:
                continue
            lead_metrics = compute_spot_perp_lead_lag(
                spot_trades,
                perp_trades,
                now_ms=int(time.time() * 1000),
                lookback_minutes=max(5, int(lookback_minutes or 20)),
            )
            rows.append(
                {
                    "交易所": EXCHANGE_TITLE_MAP.get(normalized_exchange, normalized_exchange.title()),
                    "exchange": normalized_exchange,
                    "exchange_key": normalized_exchange,
                    "领先方": str(lead_metrics.get("leader_label") or lead_metrics.get("leader") or "同步"),
                    "摘要": str(lead_metrics.get("summary") or "等待更多样本"),
                    "样本数": int(lead_metrics.get("samples") or 0),
                    "置信度": round(float(lead_metrics.get("confidence") or 0.0) * 100.0, 1),
                }
            )
        return rows

    def _build_proxy_lead_lag_rows(
        self,
        snapshot_rows: List[Dict[str, Any]],
        *,
        exchange_keys: List[str],
        existing_exchange_keys: Optional[set[str]] = None,
    ) -> List[Dict[str, Any]]:
        snapshot_by_exchange: Dict[str, Dict[str, Any]] = {}
        for row in snapshot_rows or []:
            normalized_exchange = _normalize_exchange_value(row.get("exchange_key") or row.get("exchange"))
            if normalized_exchange and normalized_exchange not in snapshot_by_exchange:
                snapshot_by_exchange[normalized_exchange] = row
        emitted = set(existing_exchange_keys or set())
        rows: List[Dict[str, Any]] = []
        for exchange_key in exchange_keys:
            normalized_exchange = _normalize_exchange_value(exchange_key)
            if not normalized_exchange or normalized_exchange in emitted:
                continue
            snapshot = snapshot_by_exchange.get(normalized_exchange) or {}
            premium_pct = _payload_float(snapshot.get("premium_pct") or snapshot.get("spot_perp_basis_pct") or snapshot.get("Basis(%)"))
            funding_bps = _payload_float(snapshot.get("funding_bps") or snapshot.get("Funding(bp)") or snapshot.get("Funding(bps)"))
            spread_bps = _payload_float(snapshot.get("orderbook_spread_bps"))
            leader = "同步"
            summary = "现货 / 合约暂未拉开明显先后。"
            confidence_seed = 0.0
            if premium_pct is not None and premium_pct >= 0.08:
                leader = "合约领先"
                summary = f"基差 {premium_pct:+.3f}% 偏正，合约侧更强。"
                confidence_seed = abs(float(premium_pct)) * 180.0
            elif premium_pct is not None and premium_pct <= -0.08:
                leader = "现货领先"
                summary = f"基差 {premium_pct:+.3f}% 偏负，现货侧更强。"
                confidence_seed = abs(float(premium_pct)) * 180.0
            elif funding_bps is not None and funding_bps >= 1.0:
                leader = "合约领先"
                summary = f"资金费率 {_format_funding_rate_percent(funding_bps)} 偏正，合约交易更活跃。"
                confidence_seed = abs(float(funding_bps)) * 8.0
            elif funding_bps is not None and funding_bps <= -1.0:
                leader = "现货领先"
                summary = f"资金费率 {_format_funding_rate_percent(funding_bps)} 偏负，现货承接更强。"
                confidence_seed = abs(float(funding_bps)) * 8.0
            elif spread_bps is not None:
                summary = f"盘口点差 {spread_bps:.2f}bp，当前按同步观察。"
                confidence_seed = max(0.0, 12.0 - abs(float(spread_bps)))
            rows.append(
                {
                    "交易所": EXCHANGE_TITLE_MAP.get(normalized_exchange, normalized_exchange.title()),
                    "exchange": normalized_exchange,
                    "exchange_key": normalized_exchange,
                    "领先方": leader,
                    "摘要": summary,
                    "样本数": 0,
                    "置信度": round(min(78.0, max(8.0, confidence_seed)), 1),
                    "mode": "proxy",
                }
            )
            emitted.add(normalized_exchange)
        return rows

    def _resolve_overview_reference_bundle(
        self,
        *,
        exchange_keys: Optional[List[str]] = None,
    ) -> Dict[str, Any]:
        normalized_exchange_keys = _normalize_exchange_keys(exchange_keys)
        snapshot_rows, lead_lag_rows = self._overview_reference_rows(exchange_keys=normalized_exchange_keys)
        reference_layers = self._build_reference_layers(snapshot_rows, lead_lag_rows=lead_lag_rows)
        payload = {
            "snapshot_rows": snapshot_rows,
            "lead_lag_rows": lead_lag_rows,
            "reference_layers": reference_layers,
        }
        return _standardize_payload_metrics(payload)

    def _build_reference_panels(
        self,
        *,
        prefix: str,
        reference_layers: Dict[str, Any],
        now_ms: int,
        market_scope: str = "merged",
        spot_title: str,
        perp_title: str,
        composite_title: str,
        spot_note: str,
        perp_note: str,
        composite_note: str,
        spot_data_source: str,
        perp_data_source: str,
        composite_data_source: str,
        spot_truth_level: str = "ws_live",
        perp_truth_level: str = "proxy",
        composite_truth_level: str = "proxy",
        spot_limit: int = 12,
        perp_limit: int = 12,
        composite_limit: int = 4,
    ) -> List[Dict[str, Any]]:
        panels: List[Dict[str, Any]] = []
        spot_frame = (
            canonicalize_market_frame_columns(reference_layers.get("spot_frame").copy())
            if isinstance(reference_layers.get("spot_frame"), pd.DataFrame)
            else pd.DataFrame()
        )
        perp_frame = (
            canonicalize_market_frame_columns(reference_layers.get("perp_frame").copy())
            if isinstance(reference_layers.get("perp_frame"), pd.DataFrame)
            else pd.DataFrame()
        )
        conclusion_frame = (
            canonicalize_market_frame_columns(reference_layers.get("conclusion_frame").copy())
            if isinstance(reference_layers.get("conclusion_frame"), pd.DataFrame)
            else pd.DataFrame()
        )
        if market_scope != "perp":
            panels.append(
                _panel_from_frame(
                    f"{prefix}-spot",
                    spot_title,
                    spot_frame,
                    note=spot_note,
                    limit=spot_limit,
                    data_source=spot_data_source,
                    updated_at_ms=now_ms,
                    truth_level=spot_truth_level,
                )
            )
        if market_scope != "spot":
            panels.append(
                _panel_from_frame(
                    f"{prefix}-perp",
                    perp_title,
                    perp_frame,
                    note=perp_note,
                    limit=perp_limit,
                    data_source=perp_data_source,
                    updated_at_ms=now_ms,
                    truth_level=perp_truth_level,
                )
            )
        panels.append(
            _panel_from_frame(
                f"{prefix}-composite",
                composite_title,
                conclusion_frame,
                note=composite_note,
                limit=composite_limit,
                data_source=composite_data_source,
                updated_at_ms=now_ms,
                truth_level=composite_truth_level,
            )
        )
        return panels

    def _build_ai_market_summary_frame(
        self,
        *,
        reference_layers: Dict[str, Any],
        focus_frame: pd.DataFrame,
        market_scope: str = "merged",
    ) -> pd.DataFrame:
        columns = ["AI模块", "当前结论", "关键证据", "执行动作", "风险提示", "置信度", "__selection"]
        spot_metrics = reference_layers.get("spot_metrics") if isinstance(reference_layers.get("spot_metrics"), dict) else {}
        perp_metrics = reference_layers.get("perp_metrics") if isinstance(reference_layers.get("perp_metrics"), dict) else {}
        conclusion = reference_layers.get("conclusion") if isinstance(reference_layers.get("conclusion"), dict) else {}
        selection = {"coin": self.coin}
        rows: List[Dict[str, Any]] = []

        confidence = _payload_float(conclusion.get("置信度"))
        spot_score = _payload_float(spot_metrics.get("confirmation_score"))
        perp_score = _payload_float(perp_metrics.get("crowding_score"))
        spot_anchor = _payload_float(spot_metrics.get("anchor_price"))
        avg_funding_bps = _payload_float(perp_metrics.get("avg_funding_bps"))

        rows.append(
            {
                "AI模块": "市场主导",
                "当前结论": str(conclusion.get("市场驱动") or "样本不足"),
                "关键证据": " / ".join(
                    [
                        f"现货确认 {'-' if spot_score is None else f'{spot_score:.1f}'}",
                        f"合约拥挤 {'-' if perp_score is None else f'{perp_score:.1f}'}",
                        str(conclusion.get("综合判断") or "等待更多样本"),
                    ]
                ),
                "执行动作": str(conclusion.get("执行建议") or "先观察更多现货与合约样本"),
                "风险提示": str(conclusion.get("风险提示") or "当前结论可信度有限"),
                "置信度": confidence,
                "__selection": selection,
            }
        )
        if market_scope != "perp":
            rows.append(
                {
                    "AI模块": "现货确认",
                    "当前结论": str(spot_metrics.get("status") or "样本不足"),
                    "关键证据": " / ".join(
                        [
                            f"锚点 {'-' if spot_anchor is None else f'{spot_anchor:,.2f}'}",
                            f"先手 {spot_metrics.get('best_exchange') or spot_metrics.get('leader_coin') or '-'}",
                            f"确认分 {'-' if spot_score is None else f'{spot_score:.1f}'}",
                        ]
                    ),
                    "执行动作": "优先看多所现货是否继续确认，再决定是否放大仓位",
                    "风险提示": "单所异动和现货分歧时，不把拉升直接当成趋势",
                    "置信度": spot_score,
                    "__selection": selection,
                }
            )
        if market_scope != "spot":
            rows.append(
                {
                    "AI模块": "合约挤压",
                    "当前结论": str(perp_metrics.get("dominant_state") or "样本不足"),
                    "关键证据": " / ".join(
                        [
                            f"偏向 {perp_metrics.get('bias') or '中性'}",
                            f"资金费率 {'-' if avg_funding_bps is None else _format_funding_rate_percent(avg_funding_bps)}",
                            f"拥挤分 {'-' if perp_score is None else f'{perp_score:.1f}'}",
                        ]
                    ),
                    "执行动作": "先看现货是否补确认，避免把合约急拉直接当真突破",
                    "风险提示": "Funding、溢价、OI 同时极端时，挤压后回落风险更高",
                    "置信度": perp_score,
                    "__selection": selection,
                }
            )
        if isinstance(focus_frame, pd.DataFrame) and not focus_frame.empty:
            working = focus_frame.copy()
            score_column = next((column for column in ["信号分数", "情绪评分", "24h成交额", "OI总额"] if column in working.columns), None)
            if score_column:
                working[score_column] = pd.to_numeric(working[score_column], errors="coerce")
                working = working.sort_values(score_column, ascending=False, na_position="last")
            focus_row = working.iloc[0].to_dict()
            focus_coin = str(focus_row.get("币种") or self.coin or "").upper()
            focus_signal = str(focus_row.get("信号") or focus_row.get("异动标签") or focus_row.get("Lead/Lag") or "-")
            focus_move = _payload_float(focus_row.get("5m%") if "5m%" in focus_row else focus_row.get("24h%"))
            focus_selection = focus_row.get("__selection") if isinstance(focus_row.get("__selection"), dict) else {"coin": focus_coin}
            rows.append(
                {
                    "AI模块": "当前焦点",
                    "当前结论": focus_coin or self.coin,
                    "关键证据": " / ".join(
                        [
                            focus_signal,
                            f"价格 {'-' if focus_move is None else f'{focus_move:+.2f}%'}",
                            str(focus_row.get("市场标签") or focus_row.get("市场") or "-"),
                        ]
                    ),
                    "执行动作": "把这只币放到监控、深度和 Tape 一起看，确认是否继续放量",
                    "风险提示": "若只有合约侧单边发热、现货不确认，优先防假动作",
                    "置信度": _payload_float(focus_row.get("信号分数") or focus_row.get("情绪评分")),
                    "__selection": focus_selection,
                }
            )
        return pd.DataFrame(rows, columns=columns)

    def _build_ai_alert_copilot_frame(
        self,
        *,
        explanation_frame: pd.DataFrame,
        replay_frame: pd.DataFrame,
        priority_frame: pd.DataFrame,
        adaptive_thresholds: Dict[str, Any],
        reference_layers: Dict[str, Any],
    ) -> pd.DataFrame:
        columns = ["AI模块", "当前结论", "关键证据", "执行动作", "可靠度", "__selection"]
        rows: List[Dict[str, Any]] = []
        conclusion = reference_layers.get("conclusion") if isinstance(reference_layers.get("conclusion"), dict) else {}

        if isinstance(explanation_frame, pd.DataFrame) and not explanation_frame.empty:
            row = explanation_frame.iloc[0].to_dict()
            hit_rate_pct = _payload_float(row.get("历史命中率(%)"))
            rows.append(
                {
                    "AI模块": "告警主线",
                    "当前结论": str(row.get("告警") or "-"),
                    "关键证据": " / ".join(
                        [
                            str(row.get("为什么触发") or "-"),
                            f"推动方 {row.get('谁在推动') or '-'}",
                            f"命中率 {'-' if hit_rate_pct is None else f'{float(hit_rate_pct):.1f}%'}",
                        ]
                    ),
                    "执行动作": str(row.get("执行建议") or conclusion.get("执行建议") or "先观察后续确认"),
                    "可靠度": str(row.get("过去准不准") or "样本不足"),
                    "__selection": row.get("__selection") if isinstance(row.get("__selection"), dict) else {"coin": self.coin},
                }
            )

        if isinstance(replay_frame, pd.DataFrame) and not replay_frame.empty:
            row = replay_frame.iloc[0].to_dict()
            rows.append(
                {
                    "AI模块": "回放提要",
                    "当前结论": str(row.get("告警") or row.get("标签") or "最近事件"),
                    "关键证据": " / ".join(
                        [
                            str(row.get("回放摘要") or "-"),
                            f"盘口 {row.get('盘口质量') or '-'}",
                        ]
                    ),
                    "执行动作": "回看触发前 5m 到触发后 15m，确认价格、OI 与大额成交是否共振",
                    "可靠度": str(row.get("过去准不准") or "复盘优先"),
                    "__selection": row.get("__selection") if isinstance(row.get("__selection"), dict) else {"coin": self.coin},
                }
            )

        if isinstance(priority_frame, pd.DataFrame) and not priority_frame.empty:
            row = priority_frame.iloc[0].to_dict()
            rows.append(
                {
                    "AI模块": "当前最高优先级",
                    "当前结论": str(row.get("交易对") or row.get("币种") or "-"),
                    "关键证据": " / ".join(
                        [
                            str(row.get("来源") or "-"),
                            str(row.get("分类") or "-"),
                            str(row.get("触发说明") or row.get("标签") or "-"),
                        ]
                    ),
                    "执行动作": "优先切到对应交易所和币种，看深度、Tape 与现货/合约分账是否同步",
                    "可靠度": "-" if _payload_float(row.get("强度")) is None else f"{float(_payload_float(row.get('强度'))):.1f}",
                    "__selection": row.get("__selection") if isinstance(row.get("__selection"), dict) else {"coin": self.coin},
                }
            )

        rows.append(
            {
                "AI模块": "阈值与风控",
                "当前结论": str(adaptive_thresholds.get("mode") or "adaptive_v1"),
                "关键证据": str(adaptive_thresholds.get("summary_text") or "等待更多样本热起来"),
                "执行动作": str(conclusion.get("执行建议") or "先轻仓观察，再按现货/合约确认度调整"),
                "可靠度": str(conclusion.get("市场驱动") or "样本不足"),
                "__selection": {"coin": self.coin},
            }
        )
        return pd.DataFrame(rows, columns=columns)

    def _build_ai_event_drilldown_frame(
        self,
        *,
        explanation_frame: pd.DataFrame,
        replay_frame: pd.DataFrame,
        priority_frame: pd.DataFrame,
        reference_layers: Dict[str, Any],
    ) -> pd.DataFrame:
        columns = ["步骤", "结论", "细节", "__selection"]
        conclusion = reference_layers.get("conclusion") if isinstance(reference_layers.get("conclusion"), dict) else {}

        explanation_row = explanation_frame.iloc[0].to_dict() if isinstance(explanation_frame, pd.DataFrame) and not explanation_frame.empty else {}
        replay_row = replay_frame.iloc[0].to_dict() if isinstance(replay_frame, pd.DataFrame) and not replay_frame.empty else {}
        priority_row = priority_frame.iloc[0].to_dict() if isinstance(priority_frame, pd.DataFrame) and not priority_frame.empty else {}

        selection = (
            explanation_row.get("__selection")
            if isinstance(explanation_row.get("__selection"), dict)
            else replay_row.get("__selection")
            if isinstance(replay_row.get("__selection"), dict)
            else priority_row.get("__selection")
            if isinstance(priority_row.get("__selection"), dict)
            else {"coin": self.coin}
        )
        title = str(
            explanation_row.get("告警")
            or replay_row.get("告警")
            or priority_row.get("交易对")
            or priority_row.get("币种")
            or self.coin
        )
        driver = str(explanation_row.get("谁在推动") or replay_row.get("谁在推动") or conclusion.get("市场驱动") or "样本不足")
        explanation_hit_rate_pct = _payload_float(explanation_row.get("历史命中率(%)"))
        replay_pre_5m_pct = _payload_float(replay_row.get("触发前5m(%)"))
        replay_post_15m_pct = _payload_float(replay_row.get("触发后15m(%)"))
        conclusion_confidence = _payload_float(conclusion.get("置信度"))
        rows = [
            {
                "步骤": "1. 事件识别",
                "结论": title,
                "细节": " / ".join(
                    [
                        f"推动方 {driver}",
                        str(priority_row.get("来源") or "当前告警"),
                        str(priority_row.get("分类") or explanation_row.get("过去准不准") or "-"),
                    ]
                ),
                "__selection": selection,
            },
            {
                "步骤": "2. 为什么触发",
                "结论": str(explanation_row.get("为什么触发") or explanation_row.get("告警") or "等待解释样本"),
                "细节": " / ".join(
                    [
                        f"历史 {'-' if explanation_hit_rate_pct is None else f'{float(explanation_hit_rate_pct):.1f}%'}",
                        f"可靠度 {explanation_row.get('过去准不准') or '样本不足'}",
                        f"建议 {explanation_row.get('执行建议') or conclusion.get('执行建议') or '-'}",
                    ]
                ),
                "__selection": selection,
            },
            {
                "步骤": "3. 事件回放",
                "结论": str(replay_row.get("回放摘要") or "等待回放样本"),
                "细节": " / ".join(
                    [
                        f"前5m {'-' if replay_pre_5m_pct is None else f'{float(replay_pre_5m_pct):+.2f}%'}",
                        f"后15m {'-' if replay_post_15m_pct is None else f'{float(replay_post_15m_pct):+.2f}%'}",
                        f"盘口 {replay_row.get('盘口质量') or '样本不足'}",
                    ]
                ),
                "__selection": selection,
            },
            {
                "步骤": "4. 交易动作",
                "结论": str(conclusion.get("执行建议") or explanation_row.get("执行建议") or "先观察更多确认"),
                "细节": " / ".join(
                    [
                        f"风险 {conclusion.get('风险提示') or '当前风险待确认'}",
                        f"市场 {conclusion.get('市场驱动') or driver}",
                        f"置信度 {'-' if conclusion_confidence is None else f'{float(conclusion_confidence):.1f}'}",
                    ]
                ),
                "__selection": selection,
            },
        ]
        return pd.DataFrame(rows, columns=columns)

    def _focus_ai_event_frame(
        self,
        frame: pd.DataFrame,
        *,
        event_title: Any = None,
        event_time_ms: Any = None,
        title_columns: Optional[List[str]] = None,
        time_column: str = "时间",
    ) -> pd.DataFrame:
        if frame.empty:
            return frame.copy()
        working = frame.copy()
        normalized_title = str(event_title or "").strip()
        try:
            normalized_time_ms = int(event_time_ms or 0)
        except (TypeError, ValueError):
            normalized_time_ms = 0
        candidate_columns = [column for column in (title_columns or ["告警", "交易对", "领跑标的", "当前结论"]) if column in working.columns]
        if normalized_title and candidate_columns:
            match_frames = []
            lowered_title = normalized_title.lower()
            for column in candidate_columns:
                series = working[column].astype(str)
                matched = working[
                    series.str.strip().str.lower().eq(lowered_title)
                    | series.str.contains(normalized_title, case=False, na=False)
                    | series.apply(lambda value: lowered_title in str(value).strip().lower())
                ]
                if not matched.empty:
                    match_frames.append(matched)
            if match_frames:
                working = pd.concat(match_frames, ignore_index=False).drop_duplicates().reset_index(drop=True)
        if normalized_time_ms > 0 and time_column in working.columns:
            timestamps = pd.to_datetime(working[time_column], errors="coerce")
            working = working.assign(_ai_event_ts_ms=(timestamps.astype("int64") // 10**6))
            valid = working[pd.to_numeric(working["_ai_event_ts_ms"], errors="coerce").notna()].copy()
            if not valid.empty:
                valid["_ai_event_delta"] = (pd.to_numeric(valid["_ai_event_ts_ms"], errors="coerce") - normalized_time_ms).abs()
                working = valid.sort_values("_ai_event_delta", ascending=True).head(1).drop(columns=["_ai_event_delta"], errors="ignore")
            working = working.drop(columns=["_ai_event_ts_ms"], errors="ignore")
        return working.reset_index(drop=True)

    def _build_watch_reference_layers(self, frame: pd.DataFrame) -> Dict[str, Any]:
        base_frame = frame.copy() if isinstance(frame, pd.DataFrame) else pd.DataFrame()
        if base_frame.empty:
            return {
                "spot_frame": pd.DataFrame(),
                "perp_frame": pd.DataFrame(),
                "conclusion_frame": pd.DataFrame(),
                "spot_metrics": {},
                "perp_metrics": {},
                "conclusion": {},
            }
        if "Spot/OI" not in base_frame.columns or "Lead/Lag" not in base_frame.columns:
            base_frame = self._build_multicoin_base_frame_from_monitor_frame(base_frame)
        if base_frame.empty:
            return {
                "spot_frame": pd.DataFrame(),
                "perp_frame": pd.DataFrame(),
                "conclusion_frame": pd.DataFrame(),
                "spot_metrics": {},
                "perp_metrics": {},
                "conclusion": {},
            }

        working = base_frame.copy()
        columns = list(working.columns)
        volume_column = _find_column_by_tokens(columns, includes=["24h"], excludes=["%"])
        oi_total_column = _find_column_by_tokens(columns, includes=["OI"], excludes=["1h", "4h", "%", "/", "Funding", "Spot", "变化"])
        oi_change_column = _find_column_by_tokens(columns, includes=["OI", "1h"])
        funding_column = _find_column_by_tokens(columns, includes=["Funding(bp)"])
        lead_lag_column = _find_column_by_tokens(columns, includes=["Lead/Lag"])
        spot_oi_column = _find_column_by_tokens(columns, includes=["Spot/OI"])
        basis_column = _find_column_by_tokens(columns, includes=["Basis", "偏离"], excludes=["平均"])

        for column in [item for item in [volume_column, oi_total_column, oi_change_column, funding_column, spot_oi_column, basis_column] if item]:
            working[column] = pd.to_numeric(working[column], errors="coerce")

        def _rank_score(series: pd.Series) -> pd.Series:
            numeric = pd.to_numeric(series, errors="coerce")
            valid = numeric.dropna()
            scores = pd.Series(0.0, index=numeric.index, dtype=float)
            if valid.empty:
                return scores
            if len(valid) == 1:
                scores.loc[valid.index] = 1.0
                return scores
            scores.loc[valid.index] = valid.rank(method="average", pct=True)
            return scores

        def _weighted_metric(rows: List[Dict[str, Any]], *, value_key: str, weight_key: str) -> Optional[float]:
            total_weight = 0.0
            weighted_value = 0.0
            for row in rows:
                value = _payload_float(row.get(value_key))
                weight = max(float(_payload_float(row.get(weight_key)) or 0.0), 1.0)
                if value is None:
                    continue
                weighted_value += float(value) * weight
                total_weight += weight
            if total_weight <= 0:
                return None
            return weighted_value / total_weight

        volume_rank = _rank_score(working[volume_column]) if volume_column else pd.Series(0.0, index=working.index, dtype=float)
        oi_rank = _rank_score(working[oi_total_column]) if oi_total_column else pd.Series(0.0, index=working.index, dtype=float)
        oi_change_rank = (
            _rank_score(pd.to_numeric(working[oi_change_column], errors="coerce").abs())
            if oi_change_column
            else pd.Series(0.0, index=working.index, dtype=float)
        )
        spot_oi_rank = (
            _rank_score(pd.to_numeric(working[spot_oi_column], errors="coerce"))
            if spot_oi_column
            else pd.Series(0.0, index=working.index, dtype=float)
        )
        basis_penalty = (
            pd.to_numeric(working[basis_column], errors="coerce").abs().fillna(0.0).apply(lambda value: max(0.0, min(1.0, float(value) / 0.35)))
            if basis_column
            else pd.Series(0.0, index=working.index, dtype=float)
        )

        total_oi_notional = float(pd.to_numeric(working[oi_total_column], errors="coerce").fillna(0.0).sum()) if oi_total_column else 0.0
        spot_rows: List[Dict[str, Any]] = []
        perp_rows: List[Dict[str, Any]] = []
        for idx, row in working.iterrows():
            selection = row.get("__selection") if isinstance(row.get("__selection"), dict) else {}
            coin_name = str(selection.get("coin") or self.coin or "").upper() or self.coin
            exchange_key = _normalize_exchange_value(selection.get("exchange"))
            lead_text = str(row.get(lead_lag_column) or "").strip() if lead_lag_column else ""
            spot_oi_value = _payload_float(row.get(spot_oi_column)) if spot_oi_column else None
            volume_value = _payload_float(row.get(volume_column)) if volume_column else None
            basis_value = _payload_float(row.get(basis_column)) if basis_column else None
            funding_value = _payload_float(row.get(funding_column)) if funding_column else None
            oi_total_value = _payload_float(row.get(oi_total_column)) if oi_total_column else None
            oi_change_value = _payload_float(row.get(oi_change_column)) if oi_change_column else None

            lead_score = 1.0 if ("现货" in lead_text or "spot" in lead_text.lower()) else 0.65 if ("同步" in lead_text or "sync" in lead_text.lower()) else 0.2
            spot_score = max(
                0.0,
                min(
                    100.0,
                    (
                        0.38 * float(volume_rank.loc[idx] if idx in volume_rank.index else 0.0)
                        + 0.28 * float(spot_oi_rank.loc[idx] if idx in spot_oi_rank.index else 0.0)
                        + 0.20 * (1.0 - float(basis_penalty.loc[idx] if idx in basis_penalty.index else 0.0))
                        + 0.14 * lead_score
                    )
                    * 100.0
                ),
            )
            if basis_value is not None and abs(float(basis_value)) >= 0.25:
                spot_view = "合约偏离过大"
            elif "合约" in lead_text or "永续" in lead_text or "perp" in lead_text.lower():
                spot_view = "合约先动"
            elif spot_score >= 68.0:
                spot_view = "现货确认较强"
            elif spot_score >= 52.0:
                spot_view = "现货有跟随"
            else:
                spot_view = "现货确认偏弱"
            spot_rows.append(
                {
                    "Coin": coin_name,
                    "Lead/Lag": lead_text or "-",
                    "Spot/OI": spot_oi_value,
                    "24h Volume": volume_value,
                    "Basis(%)": basis_value,
                    "Spot Score": round(float(spot_score), 1),
                    "Spot View": spot_view,
                    "__selection": {"coin": coin_name, "exchange": exchange_key} if exchange_key else {"coin": coin_name},
                }
            )

            oi_share_pct = (float(oi_total_value or 0.0) / max(total_oi_notional, 1.0) * 100.0) if total_oi_notional > 0 else None
            funding_score = max(0.0, min(1.0, abs(float(funding_value or 0.0)) / 8.0))
            crowding_score = max(
                0.0,
                min(
                    100.0,
                    (
                        0.36 * funding_score
                        + 0.28 * float(oi_change_rank.loc[idx] if idx in oi_change_rank.index else 0.0)
                        + 0.22 * float(oi_rank.loc[idx] if idx in oi_rank.index else 0.0)
                        + 0.14 * float(basis_penalty.loc[idx] if idx in basis_penalty.index else 0.0)
                    )
                    * 100.0
                ),
            )
            directional_bias = float(funding_value or 0.0) * 0.7 + float(oi_change_value or 0.0) * 0.35
            if crowding_score >= 66.0 and directional_bias >= 1.0:
                perp_view = "上行拥挤"
            elif crowding_score >= 66.0 and directional_bias <= -1.0:
                perp_view = "下行拥挤"
            elif crowding_score >= 54.0:
                perp_view = "杠杆偏热"
            else:
                perp_view = "相对中性"
            perp_rows.append(
                {
                    "Coin": coin_name,
                    "Funding(bp)": funding_value,
                    "OI Total": oi_total_value,
                    "OI 1h(%)": oi_change_value,
                    "OI Share(%)": oi_share_pct,
                    "Basis(%)": basis_value,
                    "Crowding Score": round(float(crowding_score), 1),
                    "Perp View": perp_view,
                    "__selection": {"coin": coin_name, "exchange": exchange_key} if exchange_key else {"coin": coin_name},
                }
            )

        spot_frame = pd.DataFrame(spot_rows)
        perp_frame = pd.DataFrame(perp_rows)
        if not spot_frame.empty:
            spot_frame = spot_frame.sort_values(["Spot Score", "24h Volume"], ascending=[False, False], na_position="last").reset_index(drop=True)
        if not perp_frame.empty:
            perp_frame = perp_frame.sort_values(["Crowding Score", "OI Total"], ascending=[False, False], na_position="last").reset_index(drop=True)

        spot_metrics = {
            "confirmation_score": _weighted_metric(spot_rows, value_key="Spot Score", weight_key="24h Volume"),
            "leader_coin": str(spot_frame.iloc[0].get("Coin") or "") if not spot_frame.empty else None,
            "status": str(spot_frame.iloc[0].get("Spot View") or "样本不足") if not spot_frame.empty else "样本不足",
            "exchange_count": int(len(spot_frame)),
        }
        avg_funding_bps = _weighted_metric(perp_rows, value_key="Funding(bp)", weight_key="OI Total")
        bias_value = _weighted_metric(perp_rows, value_key="OI 1h(%)", weight_key="OI Total")
        if bias_value is None or abs(float(bias_value)) < 0.5:
            perp_bias = "中性"
        elif float(bias_value) > 0:
            perp_bias = "偏多"
        else:
            perp_bias = "偏空"
        perp_metrics = {
            "crowding_score": _weighted_metric(perp_rows, value_key="Crowding Score", weight_key="OI Total"),
            "avg_funding_bps": avg_funding_bps,
            "leader_coin": str(perp_frame.iloc[0].get("Coin") or "") if not perp_frame.empty else None,
            "dominant_state": str(perp_frame.iloc[0].get("Perp View") or "样本不足") if not perp_frame.empty else "样本不足",
            "bias": perp_bias,
            "exchange_count": int(len(perp_frame)),
            "total_oi_notional": total_oi_notional if total_oi_notional > 0 else None,
        }

        spot_score = _payload_float(spot_metrics.get("confirmation_score"))
        perp_score = _payload_float(perp_metrics.get("crowding_score"))
        if spot_score is None and perp_score is None:
            driver = "样本不足"
            verdict = "监控篮子的现货和合约样本都还不够，先让实时流继续热起来。"
            suggestion = "继续等待更多币种的现货成交、OI 与 Funding 样本。"
            risk = "当前全局结论可信度低"
            confidence = 24.0
        elif (spot_score or 0.0) >= 62.0 and (perp_score or 0.0) < 58.0:
            driver = "现货主导篮子"
            verdict = "全局更像是现货先行，合约还没进入明显拥挤。"
            suggestion = "优先看多所现货是否继续确认，再决定是否放大仓位。"
            risk = "合约确认不足，追价性价比一般"
            confidence = 72.0
        elif (spot_score or 0.0) >= 62.0 and (perp_score or 0.0) >= 58.0:
            driver = "现货+合约共振"
            verdict = "现货确认与合约活跃同时出现，全局驱动更一致。"
            suggestion = "可以顺势，但要盯 Funding 和 basis 是否继续扩张。"
            risk = "共振末端容易转成 squeeze 后回落"
            confidence = 82.0
        elif (spot_score or 0.0) < 55.0 and (perp_score or 0.0) >= 62.0:
            driver = "合约主导篮子"
            verdict = "全局更像是杠杆资金在推动，现货确认还不够。"
            suggestion = "先等现货补到确认，不要把合约急拉直接当真突破。"
            risk = "假突破和挤压后回落仍是主要风险"
            confidence = 76.0
        else:
            driver = "混合驱动"
            verdict = "全局现货和合约都不算特别强，更像混合或震荡结构。"
            suggestion = "优先轻仓、快进快出，等更明确的主导币出现。"
            risk = "噪音较大，短线信号容易反复"
            confidence = 58.0
        if avg_funding_bps is not None and abs(float(avg_funding_bps)) >= 5.0 and driver != "样本不足":
            risk = f"{risk}；Funding 已进入极端区"
        conclusion_frame = pd.DataFrame(
            [
                {
                    "市场驱动": driver,
                    "置信度": round(confidence, 1),
                    "现货先手": spot_metrics.get("leader_coin"),
                    "现货确认分": round(float(spot_score), 1) if spot_score is not None else None,
                    "合约先手": perp_metrics.get("leader_coin"),
                    "合约拥挤分": round(float(perp_score), 1) if perp_score is not None else None,
                    "合约偏向": perp_metrics.get("bias"),
                    "综合判断": verdict,
                    "执行建议": suggestion,
                    "风险提示": risk,
                }
            ]
        )
        conclusion = conclusion_frame.iloc[0].to_dict() if not conclusion_frame.empty else {}
        return {
            "spot_frame": spot_frame,
            "perp_frame": perp_frame,
            "conclusion_frame": conclusion_frame,
            "spot_metrics": spot_metrics,
            "perp_metrics": perp_metrics,
            "conclusion": conclusion,
        }

    def _build_watch_reference_cards(self, reference_layers: Dict[str, Any]) -> List[Dict[str, str]]:
        spot_metrics = reference_layers.get("spot_metrics") or {}
        perp_metrics = reference_layers.get("perp_metrics") or {}
        conclusion = reference_layers.get("conclusion") or {}
        spot_frame = canonicalize_market_frame_columns(reference_layers.get("spot_frame").copy()) if isinstance(reference_layers.get("spot_frame"), pd.DataFrame) else pd.DataFrame()
        perp_frame = canonicalize_market_frame_columns(reference_layers.get("perp_frame").copy()) if isinstance(reference_layers.get("perp_frame"), pd.DataFrame) else pd.DataFrame()
        spot_score = _payload_float(spot_metrics.get("confirmation_score"))
        perp_score = _payload_float(perp_metrics.get("crowding_score"))
        spot_leader_coin = str(spot_metrics.get("leader_coin") or "").strip() or (str(spot_frame.iloc[0].get("币种") or "").strip() if not spot_frame.empty else "") or "-"
        perp_leader_coin = str(perp_metrics.get("leader_coin") or "").strip() or (str(perp_frame.iloc[0].get("币种") or "").strip() if not perp_frame.empty else "") or "-"
        return [
            {
                "label": "现货参考层",
                "value": spot_leader_coin,
                "sub": f"确认分 {'-' if spot_score is None else f'{spot_score:.1f}'} | {spot_metrics.get('status') or '样本不足'}",
            },
            {
                "label": "合约参考层",
                "value": perp_leader_coin,
                "sub": f"拥挤分 {'-' if perp_score is None else f'{perp_score:.1f}'} | {perp_metrics.get('dominant_state') or '样本不足'}",
            },
            {
                "label": "综合结论层",
                "value": str(conclusion.get("市场驱动") or "样本不足"),
                "sub": str(conclusion.get("执行建议") or "等待更多样本"),
            },
        ]

    def _build_overview_payload_legacy_unused(self) -> Dict[str, Any]:
        snapshots = self.service.current_snapshots()
        spot_snapshots = {
            exchange_key: self.service.get_spot_snapshot(exchange_key)
            for exchange_key in SPOT_EXCHANGE_ORDER
        }
        recent_perp_history = (
            self._cache_get_or_build(
                f"overview-history-perp::{self.coin}",
                15,
                lambda: self.history_store.load_market_history(
                    coin=self.coin,
                    exchange_keys=EXCHANGE_ORDER,
                    market="perp",
                    limit=240,
                ),
            )
            if self._history_sqlite_enabled()
            else pd.DataFrame()
        )
        if isinstance(recent_perp_history, pd.DataFrame) and not recent_perp_history.empty:
            recent_perp_history = canonicalize_market_frame_columns(recent_perp_history.copy())
        recent_spot_history = (
            self._cache_get_or_build(
                f"overview-history-spot::{self.coin}",
                15,
                lambda: self.history_store.load_market_history(
                    coin=self.coin,
                    exchange_keys=SPOT_EXCHANGE_ORDER,
                    market="spot",
                    limit=120,
                ),
            )
            if self._history_sqlite_enabled()
            else pd.DataFrame()
        )
        latest_perp_history_by_exchange: Dict[str, Dict[str, Any]] = {}
        latest_perp_oi_by_exchange: Dict[str, Dict[str, Any]] = {}
        if isinstance(recent_perp_history, pd.DataFrame) and not recent_perp_history.empty:
            for row in recent_perp_history.to_dict("records"):
                exchange_key = _row_exchange_key(row)
                if not exchange_key:
                    continue
                latest_perp_history_by_exchange.setdefault(exchange_key, row)
                oi_value = _row_oi_notional(row)
                if oi_value is not None:
                    latest_perp_oi_by_exchange.setdefault(exchange_key, row)
        latest_spot_history_by_exchange: Dict[str, Dict[str, Any]] = {}
        if isinstance(recent_spot_history, pd.DataFrame) and not recent_spot_history.empty:
            for row in recent_spot_history.to_dict("records"):
                exchange_key = _row_exchange_key(row)
                if exchange_key and exchange_key not in latest_spot_history_by_exchange:
                    latest_spot_history_by_exchange[exchange_key] = row
        snapshot_rows: List[Dict[str, Any]] = []
        for snapshot in snapshots:
            exchange_key = _to_exchange_key(snapshot)
            perp_quality_history = list(self.service.get_orderbook_quality_history(exchange_key))
            spot_quality_history = list(self.service.get_spot_orderbook_quality_history(exchange_key)) if exchange_key in SPOT_EXCHANGE_ORDER else []
            orderbook_summary = _merge_orderbook_summary_with_quality(
                _orderbook_summary(self.service.get_orderbook(exchange_key)),
                perp_quality_history,
            )
            transport = self.service.get_transport_health(exchange_key)
            spot_snapshot = spot_snapshots.get(exchange_key)
            recent_perp_row = latest_perp_history_by_exchange.get(exchange_key) or {}
            recent_perp_oi_row = latest_perp_oi_by_exchange.get(exchange_key) or recent_perp_row
            recent_spot_row = latest_spot_history_by_exchange.get(exchange_key) or {}
            row = _snapshot_to_dict(snapshot)
            if row.get("last_price") is None:
                row["last_price"] = (
                    _payload_float(orderbook_summary.get("mid_price"))
                    or next(
                        (
                            _payload_float(event.price)
                            for event in reversed(self.service.get_trade_history(exchange_key))
                            if _payload_float(event.price) is not None
                        ),
                        None,
                    )
                    or _row_last_price(recent_perp_row)
                )
            if row.get("open_interest_notional") is None:
                row["open_interest_notional"] = (
                    next(
                        (
                            _payload_float(point.open_interest_notional if point.open_interest_notional is not None else point.open_interest)
                            for point in reversed(self.service.get_oi_history(exchange_key))
                            if _payload_float(point.open_interest_notional if point.open_interest_notional is not None else point.open_interest) is not None
                        ),
                        None,
                    )
                    or _row_oi_notional(recent_perp_oi_row)
                )
            if row.get("mark_price") is None:
                row["mark_price"] = _payload_float(recent_perp_row.get("标记价"))
            if row.get("index_price") is None:
                row["index_price"] = _payload_float(recent_perp_row.get("指数价"))
            if row.get("funding_bps") is None:
                row["funding_bps"] = _row_funding_bps(recent_perp_row)
            spot_orderbook_summary = (
                _merge_orderbook_summary_with_quality(
                    _orderbook_summary(self.service.get_spot_orderbook(exchange_key)),
                    spot_quality_history,
                )
                if exchange_key in SPOT_EXCHANGE_ORDER
                else {}
            )
            row["spot_reference_price"] = (
                spot_snapshot.last_price
                if spot_snapshot is not None and spot_snapshot.status == "ok" and spot_snapshot.last_price is not None
                else _payload_float(spot_orderbook_summary.get("mid_price"))
                or next(
                    (
                        _payload_float(event.price)
                        for event in reversed(self.service.get_spot_trade_history(exchange_key))
                        if _payload_float(event.price) is not None
                        ),
                        None,
                    )
                or _row_last_price(recent_spot_row)
            )
            row["spot_volume_24h_notional"] = (
                spot_snapshot.volume_24h_notional
                if spot_snapshot is not None and spot_snapshot.status == "ok" and spot_snapshot.volume_24h_notional is not None
                else _row_volume_24h_notional(recent_spot_row)
            )
            row["spot_orderbook_imbalance_pct"] = _payload_float(spot_orderbook_summary.get("imbalance_pct"))
            row["spot_spread_bps"] = _payload_float(spot_orderbook_summary.get("spread_bps"))
            row["orderbook_imbalance_pct"] = _payload_float(orderbook_summary.get("imbalance_pct"))
            row["orderbook_spread_bps"] = _payload_float(orderbook_summary.get("spread_bps"))
            if row.get("premium_pct") is None:
                last_price = _payload_float(row.get("last_price"))
                spot_reference_price = _payload_float(row.get("spot_reference_price"))
                if last_price not in (None, 0) and spot_reference_price not in (None, 0):
                    row["premium_pct"] = (float(last_price) - float(spot_reference_price)) / float(spot_reference_price) * 100.0
            row["orderbook"] = orderbook_summary
            row["transport"] = transport
            snapshot_rows.append(row)
        lead_lag_rows: List[Dict[str, Any]] = []
        for exchange_key in SPOT_EXCHANGE_ORDER:
            spot_snapshot = spot_snapshots.get(exchange_key)
            if spot_snapshot is None or spot_snapshot.status != "ok":
                continue
            if not any(str(row.get("exchange_key") or "") == exchange_key for row in snapshot_rows):
                continue
            lead_metrics = compute_spot_perp_lead_lag(
                self.service.get_spot_trade_history(exchange_key),
                self.service.get_trade_history(exchange_key),
                now_ms=int(time.time() * 1000),
                lookback_minutes=20,
            )
            lead_lag_rows.append(
                {
                    "交易所": EXCHANGE_TITLE_MAP.get(exchange_key, exchange_key.title()),
                    "领先方": str(lead_metrics.get("leader") or "同步"),
                    "摘要": str(lead_metrics.get("summary") or "等待更多样本"),
                    "样本数": int(lead_metrics.get("samples") or 0),
                    "置信度": round(float(lead_metrics.get("confidence") or 0.0) * 100.0, 1),
                }
            )
        reference_layers = self._build_reference_layers(snapshot_rows, lead_lag_rows=lead_lag_rows)
        market_reference_price = _safe_median(
            [
                _payload_float(row.get("mark_price")) or _payload_float(row.get("last_price"))
                for row in snapshot_rows
                if (_payload_float(row.get("mark_price")) or _payload_float(row.get("last_price"))) is not None
            ]
        )
        if market_reference_price is None:
            market_reference_price = _payload_float(((reference_layers.get("spot_metrics") or {}).get("anchor_price")))
        average_funding_bps = _safe_mean(
            [
                _payload_float(row.get("funding_bps"))
                for row in snapshot_rows
                if _payload_float(row.get("funding_bps")) is not None
            ]
        )
        if average_funding_bps is None:
            average_funding_bps = _payload_float(((reference_layers.get("perp_metrics") or {}).get("avg_funding_bps")))
        snapshot_total_oi_notional = sum(float(_payload_float(row.get("open_interest_notional")) or 0.0) for row in snapshot_rows)
        history_total_oi_notional = sum(
            float(_payload_float(row.get("OI閲戦")) or 0.0)
            for row in latest_perp_oi_by_exchange.values()
        )
        reference_total_oi_notional = _payload_float(((reference_layers.get("perp_metrics") or {}).get("total_oi_notional")))
        positive_oi_candidates = [
            float(value)
            for value in [snapshot_total_oi_notional, history_total_oi_notional, reference_total_oi_notional]
            if value not in (None, 0) and float(value) > 0
        ]
        total_oi_notional = max(positive_oi_candidates) if positive_oi_candidates else None
        local_headline_items = self._build_headlines(snapshots, spot_snapshots)
        self._persist_signal_history(local_headline_items)
        global_headline_items = self._build_global_headlines() if self.manager is not None else []
        headline_items = []
        seen_headlines: set[str] = set()
        for item in list(global_headline_items) + list(local_headline_items):
            if not isinstance(item, dict):
                continue
            token = f"{item.get('kind')}::{item.get('coin') or self.coin}::{item.get('exchange_key')}::{item.get('text')}"
            if token in seen_headlines:
                continue
            seen_headlines.add(token)
            payload = dict(item)
            payload.setdefault("coin", _normalize_coin_symbol(payload.get("coin")) or self.coin)
            headline_items.append(payload)
            if len(headline_items) >= 24:
                break
        payload = _standardize_payload_metrics({
            "coin": self.coin,
            "generated_at_ms": int(time.time() * 1000),
            "market_reference_price": market_reference_price,
            "reference_price": market_reference_price,
            "total_oi_notional": total_oi_notional,
            "oi_notional_usdt": total_oi_notional,
            "average_funding_bps": average_funding_bps,
            "funding_bps": average_funding_bps,
            "snapshots": snapshot_rows,
            "cards": self._build_reference_cards(reference_layers),
            "spot_snapshots": {
                exchange_key: _spot_snapshot_to_dict(snapshot, exchange_key)
                for exchange_key, snapshot in spot_snapshots.items()
            },
            "headline_items": headline_items,
            "reference": {
                "spot": reference_layers.get("spot_metrics"),
                "perp": reference_layers.get("perp_metrics"),
                "composite": reference_layers.get("conclusion"),
                "lead_lag": lead_lag_rows,
            },
            "catalog": {
                "summary": self.catalog.get("summary", {}),
                "status": self.catalog.get("status", {}),
                "errors": self.catalog.get("errors", {}),
            },
        })

    def overview_payload_cache_key(
        self,
        *,
        exchange_keys: Optional[List[str]] = None,
        market_scope: str = "merged",
        time_window: str = "1h",
        min_notional: float = 0.0,
        custom_min_notional: float = 0.0,
        oi_threshold_pct: float = 0.0,
        anomaly_type: str = "all",
        whale_window: str = "5m",
        oi_window: str = "1h",
    ) -> str:
        normalized_exchange_keys = _normalize_exchange_keys(exchange_keys)
        normalized_market_scope = _normalize_market_scope(market_scope)
        normalized_time_window = _normalize_time_window(time_window)
        normalized_min_notional = _normalize_notional_threshold(min_notional)
        normalized_custom_min_notional = _normalize_custom_notional_threshold(custom_min_notional)
        normalized_oi_threshold_pct = _normalize_oi_threshold(oi_threshold_pct)
        normalized_anomaly_type = _normalize_monitor_anomaly_type(anomaly_type)
        normalized_whale_window = _normalize_monitor_whale_window(whale_window)
        normalized_oi_window = _normalize_monitor_oi_window(oi_window)
        return (
            f"payload-overview::{self.coin}::{','.join(normalized_exchange_keys)}::{normalized_market_scope}::{normalized_time_window}::"
            f"{normalized_min_notional}::{normalized_custom_min_notional}::{normalized_oi_threshold_pct}::{normalized_anomaly_type}::"
            f"{normalized_whale_window}::{normalized_oi_window}"
        )

    def overview_payload(
        self,
        *,
        exchange_keys: Optional[List[str]] = None,
        market_scope: str = "merged",
        time_window: str = "1h",
        min_notional: float = 0.0,
        custom_min_notional: float = 0.0,
        oi_threshold_pct: float = 0.0,
        anomaly_type: str = "all",
        whale_window: str = "5m",
        oi_window: str = "1h",
        _sync_on_miss: bool = False,
    ) -> Dict[str, Any]:
        self.touch()
        cache_key = self.overview_payload_cache_key(
            exchange_keys=exchange_keys,
            market_scope=market_scope,
            time_window=time_window,
            min_notional=min_notional,
            custom_min_notional=custom_min_notional,
            oi_threshold_pct=oi_threshold_pct,
            anomaly_type=anomaly_type,
            whale_window=whale_window,
            oi_window=oi_window,
        )
        return self._derived_payload_snapshot(
            cache_key=cache_key,
            ttl_seconds=2,
            builder=lambda: self._build_overview_payload(
                exchange_keys=exchange_keys,
                market_scope=market_scope,
                time_window=time_window,
                min_notional=min_notional,
                custom_min_notional=custom_min_notional,
                oi_threshold_pct=oi_threshold_pct,
                anomaly_type=anomaly_type,
                whale_window=whale_window,
                oi_window=oi_window,
            ),
            placeholder_builder=self._build_overview_placeholder_payload,
            sync_on_miss=bool(_sync_on_miss),
        )

    def overview_payload_cache_revision(self, **kwargs: Any) -> Optional[str]:
        return self._cache_revision_token(self.overview_payload_cache_key(**kwargs), ttl_seconds=2)

    def _build_overview_placeholder_payload(self) -> Dict[str, Any]:
        now_ms = int(time.time() * 1000)
        snapshot_rows = [
            _snapshot_to_dict(snapshot)
            for snapshot in self.service.current_snapshots()
            if snapshot is not None
        ]
        spot_snapshots = {
            exchange_key: _spot_snapshot_to_dict(self.service.get_spot_snapshot(exchange_key), exchange_key)
            for exchange_key in SPOT_EXCHANGE_ORDER
        }
        return {
            "coin": self.coin,
            "generated_at_ms": now_ms,
            "market_reference_price": _safe_median(
                [
                    _payload_float(row.get("mark_price")) or _payload_float(row.get("last_price"))
                    for row in snapshot_rows
                    if (_payload_float(row.get("mark_price")) or _payload_float(row.get("last_price"))) is not None
                ]
            ),
            "reference_price": None,
            "total_oi_notional": sum(float(_payload_float(row.get("open_interest_notional")) or 0.0) for row in snapshot_rows) or None,
            "oi_notional_usdt": sum(float(_payload_float(row.get("open_interest_notional")) or 0.0) for row in snapshot_rows) or None,
            "average_funding_bps": _safe_mean(
                [
                    _payload_float(row.get("funding_bps"))
                    for row in snapshot_rows
                    if _payload_float(row.get("funding_bps")) is not None
                ]
            ),
            "funding_bps": _safe_mean(
                [
                    _payload_float(row.get("funding_bps"))
                    for row in snapshot_rows
                    if _payload_float(row.get("funding_bps")) is not None
                ]
            ),
            "snapshots": snapshot_rows,
            "cards": [],
            "spot_snapshots": spot_snapshots,
            "headline_items": [],
            "reference": {
                "spot": {},
                "perp": {},
                "composite": {},
                "lead_lag": [],
            },
            "catalog": {
                "summary": self.catalog.get("summary", {}),
                "status": self.catalog.get("status", {}),
                "errors": self.catalog.get("errors", {}),
            },
            "data_meta": self._warming_data_meta("overview cache warming", now_ms),
        }

    def _watchlist_coins(self, watch_group: str = "board", custom_coins: Optional[List[str]] = None) -> List[str]:
        normalized_watch_group = _normalize_watch_group(watch_group)
        if normalized_watch_group == "focus":
            seeds = [self.coin, "BTC", "ETH", "XRP", "SOL"]
        else:
            seeds = list(MULTICOIN_WATCH_GROUPS.get(normalized_watch_group, MULTICOIN_WATCH_GROUPS["majors"]))
        seeds.extend(_normalize_custom_coins(custom_coins))
        ordered: List[str] = []
        for coin in seeds:
            normalized = str(coin or "").upper().strip()
            if normalized and normalized not in ordered:
                ordered.append(normalized)
        if self.coin not in ordered:
            ordered.insert(0, self.coin)
        return ordered

    def _load_multicoin_overview_row(
        self,
        coin: str,
        *,
        liquidation_limit: int = 80,
        light: bool = False,
    ) -> Dict[str, Any]:
        normalized_coin = str(coin or self.coin).upper().strip() or self.coin

        def builder() -> Dict[str, Any]:
            now_ms = int(time.time() * 1000)
            symbol_map = default_symbols(normalized_coin)
            spot_symbol_map = default_spot_symbols(normalized_coin)
            oi_history_limit = 26 if light else 36
            price_candle_limit = 28 if light else 40
            availability = self.catalog.get("availability", {}).get(normalized_coin, {})
            status = self.catalog.get("status", {})
            for exchange_key in EXCHANGE_ORDER:
                if str(status.get(exchange_key, {}).get("perp") or "") == "ok" and not bool(availability.get(exchange_key, {}).get("perp")):
                    symbol_map[exchange_key] = ""
            for exchange_key in list(spot_symbol_map):
                if str(status.get(exchange_key, {}).get("spot") or "") == "ok" and not bool(availability.get(exchange_key, {}).get("spot")):
                    spot_symbol_map[exchange_key] = ""
            health_lookup = _request_health_lookup()
            local_session = self._cached_runtime_session(normalized_coin)
            recent_perp_history = (
                self._cache_get_or_build(
                    f"overview-row-history-perp::{normalized_coin}",
                    15,
                    lambda: self.history_store.load_market_history(
                        coin=normalized_coin,
                        exchange_keys=EXCHANGE_ORDER,
                        market="perp",
                        limit=360,
                    ),
                )
                if self._history_sqlite_enabled()
                else pd.DataFrame()
            )
            recent_spot_history = (
                self._cache_get_or_build(
                    f"overview-row-history-spot::{normalized_coin}",
                    15,
                    lambda: self.history_store.load_market_history(
                        coin=normalized_coin,
                        exchange_keys=SPOT_EXCHANGE_ORDER,
                        market="spot",
                        limit=180,
                    ),
                )
                if self._history_sqlite_enabled()
                else pd.DataFrame()
            )
            latest_perp_history_by_exchange = {
                exchange_key: _history_latest_row(recent_perp_history, exchange_key)
                for exchange_key in EXCHANGE_ORDER
            }
            latest_spot_history_by_exchange = {
                exchange_key: _history_latest_row(recent_spot_history, exchange_key)
                for exchange_key in SPOT_EXCHANGE_ORDER
            }
            local_snapshot_map: Dict[str, ExchangeSnapshot] = {}
            if local_session is not None:
                local_snapshot_map = {
                    _to_exchange_key(snapshot): snapshot
                    for snapshot in local_session.service.current_snapshots()
                }
            snapshot_map: Dict[str, ExchangeSnapshot] = {}
            snapshots: List[ExchangeSnapshot] = []
            for exchange_key in EXCHANGE_ORDER:
                symbol = symbol_map.get(exchange_key) or ""
                if not symbol:
                    snapshot = ExchangeSnapshot(
                        exchange=EXCHANGE_TITLE_MAP.get(exchange_key, exchange_key.title()),
                        symbol="",
                        status="error",
                        error="未上架此币",
                    )
                    snapshot_map[exchange_key] = snapshot
                    snapshots.append(snapshot)
                    continue
                snapshot = local_snapshot_map.get(exchange_key)
                if snapshot is None or (
                    snapshot.status != "ok"
                    and _payload_float(snapshot.last_price) is None
                    and _payload_float(snapshot.open_interest_notional) is None
                ):
                    history_row = latest_perp_history_by_exchange.get(exchange_key) or {}
                    history_funding_bps = _row_funding_bps(history_row)
                    history_timestamp_ms = _coerce_timestamp_ms(history_row.get("时间"))
                    if history_row:
                        snapshot = ExchangeSnapshot(
                            exchange=EXCHANGE_TITLE_MAP.get(exchange_key, exchange_key.title()),
                            symbol=symbol,
                            last_price=_row_last_price(history_row),
                            mark_price=_payload_float(history_row.get("标记价")),
                            index_price=_payload_float(history_row.get("指数价")),
                            open_interest_notional=_row_oi_notional(history_row),
                            funding_rate=(float(history_funding_bps) / 10000.0) if history_funding_bps is not None else None,
                            volume_24h_notional=_row_volume_24h_notional(history_row),
                            timestamp_ms=history_timestamp_ms,
                            status="proxy",
                            error=_exchange_market_request_health(exchange_key, "perp", health_lookup=health_lookup).get("display_error"),
                        )
                    else:
                        snapshot = ExchangeSnapshot(
                            exchange=EXCHANGE_TITLE_MAP.get(exchange_key, exchange_key.title()),
                            symbol=symbol,
                            status="error",
                            error=_exchange_market_request_health(exchange_key, "perp", health_lookup=health_lookup).get("display_error") or "waiting for data",
                        )
                snapshot_map[exchange_key] = snapshot
                snapshots.append(snapshot)
            active_snapshots = [
                snapshot
                for snapshot in snapshots
                if any(
                    value is not None
                    for value in (
                        snapshot.last_price,
                        snapshot.open_interest_notional,
                        snapshot.volume_24h_notional,
                        snapshot.funding_bps,
                    )
                )
            ]
            ok_snapshots = [snapshot for snapshot in snapshots if snapshot.status == "ok"]
            market_price = _safe_median([snapshot.last_price for snapshot in active_snapshots if snapshot.last_price is not None])
            total_oi_notional = sum(float(snapshot.open_interest_notional or 0.0) for snapshot in active_snapshots)
            total_volume_notional = sum(float(snapshot.volume_24h_notional or 0.0) for snapshot in active_snapshots)
            weighted_funding_rows = [
                (
                    float(snapshot.funding_bps),
                    max(float(snapshot.open_interest_notional or 0.0), 0.0),
                )
                for snapshot in active_snapshots
                if snapshot.funding_bps is not None
            ]
            if weighted_funding_rows:
                total_funding_weight = sum(weight for _, weight in weighted_funding_rows)
                if total_funding_weight > 0:
                    avg_funding_bps = sum(value * weight for value, weight in weighted_funding_rows) / total_funding_weight
                else:
                    avg_funding_bps = float(pd.Series([value for value, _ in weighted_funding_rows]).median())
            else:
                avg_funding_bps = None

            primary_perp_exchange = next((key for key in ("binance", "bybit", "okx", "hyperliquid") if symbol_map.get(key)), None)
            primary_spot_exchange = next((key for key in ("binance", "bybit", "okx") if spot_symbol_map.get(key)), None)
            primary_perp_symbol = symbol_map.get(primary_perp_exchange or "", "")
            primary_spot_symbol = spot_symbol_map.get(primary_spot_exchange or "", "")

            parallel_fetches: Dict[str, Any] = {}
            future_map: Dict[Any, str] = {}
            if local_session is not None and primary_perp_exchange:
                parallel_fetches["oi_history"] = list(local_session.service.get_oi_history(primary_perp_exchange))
                if not light:
                    parallel_fetches["perp_trades"] = list(local_session.service.get_trade_history(primary_perp_exchange))
            if local_session is not None and not light and primary_spot_exchange:
                parallel_fetches["spot_trades"] = list(local_session.service.get_spot_trade_history(primary_spot_exchange))
                parallel_fetches["spot_snapshot"] = local_session.service.get_spot_snapshot(primary_spot_exchange)
            if local_session is not None and not light:
                for exchange_key in ("binance", "bybit", "okx"):
                    parallel_fetches[f"liq::{exchange_key}"] = list(local_session.service.get_liquidation_history(exchange_key))
            sentiment_payloads_1h = (
                self._sentiment_payloads("1h", coin=normalized_coin, sync_on_miss=True)
                if not light
                else {}
            )
            oi_history = parallel_fetches.get("oi_history") or []
            price_candles = parallel_fetches.get("price_candles") or []
            perp_trades = parallel_fetches.get("perp_trades") or []
            spot_trades = parallel_fetches.get("spot_trades") or []
            lead_lag = (
                compute_spot_perp_lead_lag(
                    spot_trades,
                    perp_trades,
                    now_ms=now_ms,
                    lookback_minutes=10,
                    bucket_seconds=1,
                    max_lag_buckets=3,
                )
                if spot_trades and perp_trades
                else {}
            )
            trade_metrics = build_trade_metrics(perp_trades, now_ms=now_ms, window_minutes=30) if perp_trades else {}

            def latest_ratio(payload: Dict[str, List[dict]], dataset_key: str, field: str) -> Optional[float]:
                items = payload.get(dataset_key) or []
                if not items:
                    return None
                return _payload_float(items[-1].get(field))

            binance_sentiment = sentiment_payloads_1h.get("binance", {}) if isinstance(sentiment_payloads_1h, dict) else {}
            bybit_sentiment = sentiment_payloads_1h.get("bybit", {}) if isinstance(sentiment_payloads_1h, dict) else {}

            ratio_candidates = [
                latest_ratio(binance_sentiment, "global_account", "longShortRatio"),
                latest_ratio(binance_sentiment, "top_account", "longShortRatio"),
                latest_ratio(binance_sentiment, "top_position", "longShortRatio"),
                latest_ratio(bybit_sentiment, "account_ratio", "longShortRatio"),
            ]
            ratio_candidates = [value for value in ratio_candidates if value is not None]
            contract_ratio = float(pd.Series(ratio_candidates).median()) if ratio_candidates else None

            liquidation_events: List[LiquidationEvent] = []
            for exchange_key in ("binance", "bybit", "okx"):
                fetched_events = parallel_fetches.get(f"liq::{exchange_key}") or []
                if isinstance(fetched_events, list):
                    liquidation_events.extend(fetched_events)

            liquidation_metrics = build_liquidation_metrics(liquidation_events, now_ms=now_ms, window_minutes=24 * 60)
            oi_change_1h = _compute_oi_change_pct(oi_history, 1) if oi_history else _history_change_pct(recent_perp_history, primary_perp_exchange, "OI金额", 60)
            oi_change_4h = _compute_oi_change_pct(oi_history, 4) if oi_history else _history_change_pct(recent_perp_history, primary_perp_exchange, "OI金额", 4 * 60)
            oi_change_24h = _compute_oi_change_pct(oi_history, 24) if oi_history else _history_change_pct(recent_perp_history, primary_perp_exchange, "OI金额", 24 * 60)
            price_change_5m = _compute_price_change_pct_by_steps(price_candles, MONITOR_PRICE_WINDOWS["5m"]) if price_candles else _history_change_pct(recent_perp_history, primary_perp_exchange, "最新价", 5)
            price_change_30m = _compute_price_change_pct_by_steps(price_candles, MONITOR_PRICE_WINDOWS["30m"]) if price_candles else _history_change_pct(recent_perp_history, primary_perp_exchange, "最新价", 30)
            price_change_1h = _compute_price_change_pct_by_steps(price_candles, MONITOR_PRICE_WINDOWS["1h"]) if price_candles else _history_change_pct(recent_perp_history, primary_perp_exchange, "最新价", 60)
            price_change_4h = _compute_price_change_pct_by_steps(price_candles, MONITOR_PRICE_WINDOWS["4h"]) if price_candles else _history_change_pct(recent_perp_history, primary_perp_exchange, "最新价", 4 * 60)
            price_change_24h = _compute_price_change_pct(price_candles, 24) if price_candles else _history_change_pct(recent_perp_history, primary_perp_exchange, "最新价", 24 * 60)
            estimated_oi_delta = _estimate_delta_notional(total_oi_notional or None, oi_change_1h)

            composite_signal = build_composite_signal(
                snapshot_map.get(primary_perp_exchange or ""),
                {"price_change_pct": price_change_24h, "oi_change_pct": oi_change_1h},
                trade_metrics,
                crowd_position_ratio=latest_ratio(binance_sentiment, "top_position", "longShortRatio"),
                crowd_account_ratio=latest_ratio(binance_sentiment, "top_account", "longShortRatio"),
                global_ratio=latest_ratio(binance_sentiment, "global_account", "longShortRatio"),
            )

            spot_volume = None
            spot_snapshot = parallel_fetches.get("spot_snapshot")
            if isinstance(spot_snapshot, SpotSnapshot) and spot_snapshot.status == "ok":
                spot_volume = spot_snapshot.volume_24h_notional
            if spot_volume is None:
                spot_volume = _payload_float((latest_spot_history_by_exchange.get(primary_spot_exchange or "") or {}).get("24h成交额"))

            spot_oi_ratio = None
            if spot_volume not in (None, 0) and total_oi_notional > 0:
                spot_oi_ratio = float(spot_volume) / float(total_oi_notional)

            liquidation_count = int(liquidation_metrics.get("count") or 0)
            multi_long_pct = None
            if liquidation_count > 0:
                multi_long_pct = float(liquidation_metrics.get("short_count") or 0) / float(liquidation_count) * 100.0

            if light:
                lead_lag = {}
                trade_metrics = {}
                contract_ratio = None
                liquidation_metrics = {}
                liquidation_count = 0
                multi_long_pct = None
                spot_oi_ratio = None
                composite_signal = build_composite_signal(
                    snapshot_map.get(primary_perp_exchange or ""),
                    {"price_change_pct": price_change_24h, "oi_change_pct": oi_change_1h},
                    {},
                    crowd_position_ratio=None,
                    crowd_account_ratio=None,
                    global_ratio=None,
                )

            return {
                "币种": normalized_coin,
                "价格": market_price,
                "5m%": price_change_5m,
                "30m%": price_change_30m,
                "1h%": price_change_1h,
                "4h%": price_change_4h,
                "24h%": price_change_24h,
                "24h成交额": total_volume_notional or None,
                "OI总额": total_oi_notional or None,
                "OI 1h(%)": oi_change_1h,
                "OI 4h(%)": oi_change_4h,
                "OI 24h(%)": oi_change_24h,
                "Funding(bp)": avg_funding_bps,
                "24h爆仓": liquidation_count or None,
                "多头爆%": multi_long_pct,
                "24h爆仓样本额": liquidation_metrics.get("notional") if liquidation_metrics else None,
                "L/S比": contract_ratio,
                "Spot/OI": spot_oi_ratio,
                "Lead/Lag": "待重图补充" if light else (lead_lag.get("summary") or "样本不足"),
                "领先方": lead_lag.get("leader"),
                "领先秒数": lead_lag.get("lead_seconds"),
                "相关性": lead_lag.get("correlation"),
                "信号": composite_signal.get("label") or "信号混合",
                "情绪评分": composite_signal.get("score"),
                "置信度": float(composite_signal.get("confidence") or 0.0) * 100.0,
                "OI变化额": estimated_oi_delta,
                "主交易所键": primary_perp_exchange,
                "主交易所": EXCHANGE_TITLE_MAP.get(primary_perp_exchange or "", primary_perp_exchange or "-"),
                "reference_price": market_price,
                "oi_notional_usdt": total_oi_notional or None,
                "funding_bps": avg_funding_bps,
                "volume_24h_notional": total_volume_notional or None,
                "price_change_1h_pct": price_change_1h,
                "price_change_4h_pct": price_change_4h,
                "price_change_24h_pct": price_change_24h,
                "__selection": {"coin": normalized_coin, "exchange": primary_perp_exchange},
                "状态": "正常" if ok_snapshots else "降级",
            }

        cache_key = f"overview-row::{normalized_coin}::{'light' if light else 'full'}"
        return self._cache_get_or_build(cache_key, 45 if light else 60, builder)

    def _build_market_overview_frame(
        self,
        watch_group: str = "board",
        *,
        custom_coins: Optional[List[str]] = None,
        light: bool = False,
    ) -> pd.DataFrame:
        normalized_watch_group = _normalize_watch_group(watch_group)
        normalized_custom_coins = _normalize_custom_coins(custom_coins)
        watchlist = self._watchlist_coins(normalized_watch_group, normalized_custom_coins)

        def builder() -> pd.DataFrame:
            rows: List[Dict[str, Any]] = []
            with ThreadPoolExecutor(max_workers=min(8 if light else 6, max(2, len(watchlist)))) as executor:
                future_map = {
                    executor.submit(self._load_multicoin_overview_row, coin, light=light): coin
                    for coin in watchlist
                }
                for future in as_completed(future_map):
                    coin = future_map[future]
                    try:
                        rows.append(future.result())
                    except Exception:
                        rows.append(
                            {
                                "币种": coin,
                                "价格": None,
                                "5m%": None,
                                "30m%": None,
                                "1h%": None,
                                "4h%": None,
                                "24h%": None,
                                "24h成交额": None,
                                "OI总额": None,
                                "OI 1h(%)": None,
                                "OI 4h(%)": None,
                                "OI 24h(%)": None,
                                "Funding(bp)": None,
                                "24h爆仓": None,
                                "多头爆%": None,
                                "24h爆仓样本额": None,
                                "L/S比": None,
                                "Spot/OI": None,
                                "Lead/Lag": "加载失败",
                                "信号": "加载失败",
                                "情绪评分": None,
                                "置信度": 0.0,
                                "OI变化额": None,
                                "主交易所": "-",
                                "状态": "失败",
                            }
                        )
            frame = pd.DataFrame(rows)
            if frame.empty:
                return pd.DataFrame(
                    columns=[
                        "币种",
                        "价格",
                        "5m%",
                        "30m%",
                        "1h%",
                        "4h%",
                        "24h%",
                        "24h成交额",
                        "OI总额",
                        "OI 1h(%)",
                        "OI 4h(%)",
                        "OI 24h(%)",
                        "Funding(bp)",
                        "24h爆仓",
                        "多头爆%",
                        "24h爆仓样本额",
                        "L/S比",
                        "Spot/OI",
                        "Lead/Lag",
                        "信号",
                        "情绪评分",
                        "置信度",
                        "OI变化额",
                        "主交易所",
                        "状态",
                    ]
                )
            return frame.sort_values(["OI总额", "币种"], ascending=[False, True], na_position="last").reset_index(drop=True)

        custom_token = compose_custom_token(normalized_custom_coins)
        cache_key = f"overview-frame::{normalized_watch_group}::{custom_token}::{'light' if light else 'full'}"
        return self._cache_get_or_build(cache_key, 45 if light else 60, builder)

    def _build_cached_panel(
        self,
        cache_key: str,
        *,
        signature: Any,
        ttl_seconds: int = PANEL_CACHE_TTL_SECONDS,
        builder=None,
    ) -> Dict[str, Any]:
        token = _cache_signature_token(signature)
        panel_cache_key = f"panel::{cache_key}::{token}"
        cached = self._cache_peek(panel_cache_key, ttl_seconds=ttl_seconds)
        if isinstance(cached, dict):
            return self._panel_with_runtime_meta(cached)
        stale = self._cache_peek(panel_cache_key, ttl_seconds=None)
        if isinstance(stale, dict):
            self._schedule_cache_warm(panel_cache_key, ttl_seconds, builder)
            return self._panel_with_runtime_meta(stale, status="refreshing")
        cached = self._cache_get_or_build(panel_cache_key, ttl_seconds, builder)
        return self._panel_with_runtime_meta(cached)

    def _panel_with_runtime_meta(self, panel: Any, *, status: Optional[str] = None) -> Dict[str, Any]:
        cloned = dict(panel or {})
        meta = dict(cloned.get("meta") or {})
        updated_at_ms = _best_updated_at_ms(meta.get("updated_at_ms"))
        meta["updated_at_ms"] = updated_at_ms
        meta["stale_ms"] = (int(time.time() * 1000) - int(updated_at_ms)) if updated_at_ms else None
        if status:
            meta["status"] = status
        cloned["meta"] = meta
        return cloned

    def _build_timed_frame_panel(
        self,
        panel_id: str,
        title: str,
        *,
        signature: Any,
        frame_builder,
        note: str = "",
        limit: int = 24,
        empty_text: str = "当前暂无样本。",
        data_source: str = "",
        updated_at_ms: Any = None,
        truth_level: str = "",
        ttl_seconds: int = PANEL_CACHE_TTL_SECONDS,
    ) -> Dict[str, Any]:
        def builder() -> Dict[str, Any]:
            started = time.perf_counter()
            frame = frame_builder()
            compute_ms = (time.perf_counter() - started) * 1000.0
            return _panel_from_frame(
                panel_id,
                title,
                frame,
                note=note,
                limit=limit,
                empty_text=empty_text,
                data_source=data_source,
                updated_at_ms=updated_at_ms,
                truth_level=truth_level,
                compute_ms=round(compute_ms, 2),
            )

        return self._build_cached_panel(panel_id, signature=signature, ttl_seconds=ttl_seconds, builder=builder)

    def _build_timed_figure_panel(
        self,
        panel_id: str,
        title: str,
        *,
        signature: Any,
        figure_builder,
        note: str = "",
        empty_text: str = "当前暂无图表样本。",
        data_source: str = "",
        updated_at_ms: Any = None,
        truth_level: str = "",
        ttl_seconds: int = PANEL_CACHE_TTL_SECONDS,
        heavy: bool = False,
        sync_on_miss: bool = True,
    ) -> Dict[str, Any]:
        token = _cache_signature_token(signature)
        cache_key = f"panel::{panel_id}::{token}"

        def builder() -> Dict[str, Any]:
            started = time.perf_counter()
            figure = figure_builder()
            compute_ms = (time.perf_counter() - started) * 1000.0
            return _panel_from_figure(
                panel_id,
                title,
                figure,
                note=note,
                empty_text=empty_text,
                data_source=data_source,
                updated_at_ms=updated_at_ms,
                truth_level=truth_level,
                compute_ms=round(compute_ms, 2),
            )
        cached = self._cache_peek(cache_key, ttl_seconds=ttl_seconds)
        if cached is not None:
            return self._panel_with_runtime_meta(cached)
        stale = self._cache_peek(cache_key, ttl_seconds=None)
        if stale is not None:
            if heavy:
                self._schedule_heavy_cache_warm(cache_key, ttl_seconds, builder)
            else:
                self._schedule_cache_warm(cache_key, ttl_seconds, builder)
            return self._panel_with_runtime_meta(stale, status="refreshing")
        if heavy and not sync_on_miss:
            self._schedule_heavy_cache_warm(cache_key, ttl_seconds, builder)
            return self._panel_with_runtime_meta(
                _warming_figure_panel(
                    panel_id,
                    title,
                    note=note,
                    empty_text=empty_text,
                    data_source=data_source,
                    updated_at_ms=updated_at_ms,
                )
            )
        cached = self._cache_get_or_build(cache_key, ttl_seconds, builder)
        return self._panel_with_runtime_meta(cached)

    def _build_timed_multi_figure_panel(
        self,
        panel_id: str,
        title: str,
        *,
        signature: Any,
        figures_builder,
        note: str = "",
        empty_text: str = "当前暂无图表样本。",
        data_source: str = "",
        updated_at_ms: Any = None,
        truth_level: str = "",
        ttl_seconds: int = PANEL_CACHE_TTL_SECONDS,
        heavy: bool = False,
        sync_on_miss: bool = True,
        control_tabs: Optional[List[Dict[str, str]]] = None,
        default_variant: str = "",
    ) -> Dict[str, Any]:
        token = _cache_signature_token(signature)
        cache_key = f"panel::{panel_id}::{token}"

        def builder() -> Dict[str, Any]:
            started = time.perf_counter()
            figure_variants = figures_builder() or {}
            compute_ms = (time.perf_counter() - started) * 1000.0
            normalized_variants: Dict[str, Any] = {}
            for key, figure in figure_variants.items():
                if figure is None:
                    normalized_variants[str(key)] = None
                    continue
                normalized_variants[str(key)] = _serialize_plotly_figure(figure)
            selected_variant = str(default_variant or "").strip()
            if not selected_variant or selected_variant not in normalized_variants:
                selected_variant = next(iter(normalized_variants), "")
            selected_figure = normalized_variants.get(selected_variant)
            panel = {
                "id": panel_id,
                "title": title,
                "note": str(note or "").strip(),
                "meta": {
                    "source": str(data_source or "").strip(),
                    "updated_at_ms": _best_updated_at_ms(updated_at_ms),
                    "truth_level": (
                        str(truth_level or "").strip()
                        or ("sample_limited" if not (selected_figure and list((selected_figure or {}).get("data") or [])) else "")
                    ),
                    "compute_ms": round(compute_ms, 2),
                    "default_variant": selected_variant or None,
                },
                "kind": "plotly",
                "figure": selected_figure,
                "figure_variants": normalized_variants,
                "empty_text": empty_text,
            }
            if control_tabs:
                panel["control_tabs"] = list(control_tabs)
            if selected_variant:
                panel["default_variant"] = selected_variant
            return panel

        cached = self._cache_peek(cache_key, ttl_seconds=ttl_seconds)
        if cached is not None:
            return self._panel_with_runtime_meta(cached)
        stale = self._cache_peek(cache_key, ttl_seconds=None)
        if stale is not None:
            if heavy:
                self._schedule_heavy_cache_warm(cache_key, ttl_seconds, builder)
            else:
                self._schedule_cache_warm(cache_key, ttl_seconds, builder)
            return self._panel_with_runtime_meta(stale, status="refreshing")
        if heavy and not sync_on_miss:
            self._schedule_heavy_cache_warm(cache_key, ttl_seconds, builder)
            warming = _warming_figure_panel(
                panel_id,
                title,
                note=note,
                empty_text=empty_text,
                data_source=data_source,
                updated_at_ms=updated_at_ms,
            )
            if control_tabs:
                warming["control_tabs"] = list(control_tabs)
            if default_variant:
                warming["default_variant"] = str(default_variant)
            return self._panel_with_runtime_meta(warming)
        cached = self._cache_get_or_build(cache_key, ttl_seconds, builder)
        return self._panel_with_runtime_meta(cached)

    def _filter_multicoin_focus_frame(
        self,
        frame: pd.DataFrame,
        *,
        coin_scope: str,
        oi_threshold_pct: float = 0.0,
        sentiment_mode: str = "all",
    ) -> pd.DataFrame:
        if frame is None or frame.empty:
            return frame
        working = canonicalize_market_frame_columns(frame.copy())
        normalized_scope = _normalize_coin_scope(coin_scope)
        normalized_sentiment_mode = _normalize_sentiment_mode(sentiment_mode)
        if normalized_scope == "current":
            working = working[working["币种"].astype(str).str.upper() == self.coin].reset_index(drop=True)
        elif normalized_scope == "majors":
            working = working[working["币种"].astype(str).isin(DEFAULT_MAJOR_WORKBENCH_COINS)].reset_index(drop=True)
        elif normalized_scope == "board":
            working = working.reset_index(drop=True)
        else:
            oi_series = pd.to_numeric(working.get("OI 1h(%)"), errors="coerce").abs().fillna(0.0)
            funding_series = pd.to_numeric(working.get("Funding(bp)"), errors="coerce").abs().fillna(0.0)
            liq_series = pd.to_numeric(working.get("24h爆仓样本额"), errors="coerce").fillna(0.0)
            liq_scale = float(liq_series.max() or 1.0)
            working = working.assign(
                _extreme_score=oi_series * 1.8 + funding_series * 2.1 + (liq_series / max(liq_scale, 1.0)) * 12.0
            )
            working = working.sort_values("_extreme_score", ascending=False, na_position="last").head(8).drop(columns="_extreme_score")
        if oi_threshold_pct > 0 and "OI 1h(%)" in working.columns:
            oi_series = pd.to_numeric(working["OI 1h(%)"], errors="coerce").abs().fillna(0.0)
            narrowed = working[oi_series >= float(oi_threshold_pct)].reset_index(drop=True)
            if not narrowed.empty:
                working = narrowed
        if normalized_sentiment_mode != "all" and "情绪评分" in working.columns:
            score_series = pd.to_numeric(working["情绪评分"], errors="coerce")
            if normalized_sentiment_mode == "extreme":
                narrowed = working[score_series.abs() >= 8.0].reset_index(drop=True)
            elif normalized_sentiment_mode == "bull":
                narrowed = working[score_series >= 0.0].reset_index(drop=True)
            else:
                narrowed = working[score_series <= 0.0].reset_index(drop=True)
            if not narrowed.empty:
                working = narrowed
        if working.empty:
            return frame.head(min(6, len(frame))).reset_index(drop=True)
        return working.reset_index(drop=True)

    def _build_multicoin_liquidation_linkage_frame(
        self,
        coins: List[str],
        *,
        exchange_keys: List[str],
        time_window: str,
        min_notional: float = 0.0,
    ) -> pd.DataFrame:
        normalized_coins = [str(coin or "").upper().strip() for coin in coins if str(coin or "").strip()]
        normalized_exchange_keys = [key for key in _normalize_exchange_keys(exchange_keys) if key != "hyperliquid"]
        cutoff_ms = int(time.time() * 1000) - _time_window_minutes(time_window) * 60_000
        threshold = max(float(min_notional or 0.0), 0.0)
        if not normalized_coins or not normalized_exchange_keys:
            return pd.DataFrame(columns=["币种", "联动交易所", "最早联动时间", "事件数", "爆仓样本额", "联动状态"])

        tasks: Dict[Any, tuple[str, str]] = {}
        fetched: Dict[str, Dict[str, List[LiquidationEvent]]] = {coin: {} for coin in normalized_coins}
        with ThreadPoolExecutor(max_workers=min(8, max(2, len(normalized_coins) * len(normalized_exchange_keys)))) as executor:
            for coin in normalized_coins:
                symbol_map = default_symbols(coin)
                for exchange_key in normalized_exchange_keys:
                    symbol = symbol_map.get(exchange_key) or ""
                    if not symbol:
                        continue
                    tasks[executor.submit(fetch_exchange_liquidations, exchange_key, symbol, 60, timeout=self.timeout)] = (coin, exchange_key)
            for future in as_completed(tasks):
                coin, exchange_key = tasks[future]
                try:
                    rows = list(future.result() or [])
                except Exception:
                    rows = []
                fetched[coin][exchange_key] = rows

        rows: List[Dict[str, Any]] = []
        for coin in normalized_coins:
            earliest_ms: Optional[int] = None
            total_notional = 0.0
            total_events = 0
            active_exchange_keys: List[str] = []
            first_exchange_key: Optional[str] = None
            for exchange_key in normalized_exchange_keys:
                events = [
                    event
                    for event in fetched.get(coin, {}).get(exchange_key, [])
                    if int(event.timestamp_ms or 0) >= cutoff_ms and float(abs(event.notional or 0.0)) >= threshold
                ]
                if not events:
                    continue
                active_exchange_keys.append(exchange_key)
                total_events += len(events)
                total_notional += sum(float(abs(event.notional or 0.0)) for event in events)
                exchange_first_ms = min(int(event.timestamp_ms or 0) for event in events)
                if earliest_ms is None or exchange_first_ms < earliest_ms:
                    earliest_ms = exchange_first_ms
                    first_exchange_key = exchange_key
            rows.append(
                {
                    "币种": coin,
                    "联动交易所": len(active_exchange_keys),
                    "最早联动时间": pd.to_datetime(int(earliest_ms), unit="ms") if earliest_ms else None,
                    "事件数": total_events,
                    "爆仓样本额": total_notional if total_notional > 0 else None,
                    "联动状态": "跨所联动" if len(active_exchange_keys) >= 2 else "单所触发" if total_events > 0 else "暂无样本",
                    "__selection": {"coin": coin, "exchange": first_exchange_key},
                }
            )
        frame = pd.DataFrame(rows)
        if frame.empty:
            return frame
        sort_key = pd.to_datetime(frame["最早联动时间"], errors="coerce")
        frame = frame.assign(_sort_time=sort_key)
        frame = frame.sort_values(
            ["联动交易所", "爆仓样本额", "_sort_time"],
            ascending=[False, False, True],
            na_position="last",
        ).drop(columns="_sort_time")
        return frame.reset_index(drop=True)

    def _build_multicoin_spot_perp_divergence_frame(
        self,
        coins: List[str],
        *,
        exchange_keys: List[str],
    ) -> pd.DataFrame:
        normalized_coins = [str(coin or "").upper().strip() for coin in coins if str(coin or "").strip()]
        normalized_exchange_keys = [key for key in _normalize_exchange_keys(exchange_keys) if key in SPOT_EXCHANGE_ORDER]
        rows: List[Dict[str, Any]] = []
        if not normalized_coins or not normalized_exchange_keys:
            return pd.DataFrame(columns=["币种", "偏离交易所", "最大偏离(%)", "平均偏离(%)", "可比交易所"])

        for coin in normalized_coins:
            symbol_map = default_symbols(coin)
            spot_symbol_map = default_spot_symbols(coin)
            health_lookup = _request_health_lookup()
            local_session = self._cached_runtime_session(coin)
            local_snapshot_map = (
                {
                    _to_exchange_key(snapshot): snapshot
                    for snapshot in local_session.service.current_snapshots()
                }
                if local_session is not None
                else {}
            )
            recent_perp_history = (
                self._cache_get_or_build(
                    f"multicoin-divergence-perp::{coin}",
                    15,
                    lambda: self.history_store.load_market_history(
                        coin=coin,
                        exchange_keys=normalized_exchange_keys,
                        market="perp",
                        limit=180,
                    ),
                )
                if self._history_sqlite_enabled()
                else pd.DataFrame()
            )
            if isinstance(recent_perp_history, pd.DataFrame) and not recent_perp_history.empty:
                recent_perp_history = canonicalize_market_frame_columns(recent_perp_history.copy())
            recent_spot_history = (
                self._cache_get_or_build(
                    f"multicoin-divergence-spot::{coin}",
                    15,
                    lambda: self.history_store.load_market_history(
                        coin=coin,
                        exchange_keys=normalized_exchange_keys,
                        market="spot",
                        limit=180,
                    ),
                )
                if self._history_sqlite_enabled()
                else pd.DataFrame()
            )
            if isinstance(recent_spot_history, pd.DataFrame) and not recent_spot_history.empty:
                recent_spot_history = canonicalize_market_frame_columns(recent_spot_history.copy())
            snapshots: Dict[str, ExchangeSnapshot] = {}
            for exchange_key in normalized_exchange_keys:
                symbol = symbol_map.get(exchange_key) or ""
                snapshot = local_snapshot_map.get(exchange_key)
                if (
                    symbol
                    and (snapshot is None or snapshot.status != "ok")
                    and not _exchange_market_rest_hard_degraded(exchange_key, "perp", health_lookup=health_lookup)
                ):
                    try:
                        snapshot = fetch_exchange_snapshot(exchange_key, symbol, timeout=self.timeout)
                    except Exception:
                        snapshot = None
                if snapshot is None or (snapshot.status != "ok" and _payload_float(snapshot.last_price) is None):
                    history_row = _history_latest_row(recent_perp_history, exchange_key)
                    if history_row:
                        snapshot = ExchangeSnapshot(
                            exchange=EXCHANGE_TITLE_MAP.get(exchange_key, exchange_key.title()),
                            symbol=symbol,
                            last_price=_row_last_price(history_row),
                            timestamp_ms=_coerce_timestamp_ms(history_row.get("时间")),
                            status="proxy",
                        )
                if snapshot is not None:
                    snapshots[exchange_key] = snapshot
            basis_rows: List[tuple[str, float]] = []
            for exchange_key in normalized_exchange_keys:
                snapshot = snapshots.get(exchange_key)
                symbol = spot_symbol_map.get(exchange_key) or ""
                if snapshot is None or snapshot.last_price in (None, 0) or not symbol:
                    continue
                spot_snapshot = local_session.service.get_spot_snapshot(exchange_key) if local_session is not None else None
                if (
                    (spot_snapshot is None or spot_snapshot.status != "ok")
                    and not _exchange_market_rest_hard_degraded(exchange_key, "spot", health_lookup=health_lookup)
                ):
                    try:
                        spot_snapshot = fetch_spot_snapshot(exchange_key, symbol, timeout=self.timeout)
                    except Exception:
                        spot_snapshot = None
                spot_price = (
                    _payload_float(getattr(spot_snapshot, "last_price", None))
                    or _row_last_price(_history_latest_row(recent_spot_history, exchange_key))
                )
                if spot_price in (None, 0):
                    continue
                basis_pct = (float(snapshot.last_price) - float(spot_price)) / float(spot_price) * 100.0
                basis_rows.append((exchange_key, basis_pct))
            if basis_rows:
                max_exchange_key, max_basis_pct = max(basis_rows, key=lambda item: abs(float(item[1])))
                avg_basis_pct = float(pd.Series([item[1] for item in basis_rows]).mean())
            else:
                max_exchange_key, max_basis_pct, avg_basis_pct = None, None, None
            rows.append(
                {
                    "币种": coin,
                    "偏离交易所": EXCHANGE_TITLE_MAP.get(max_exchange_key or "", max_exchange_key or "-"),
                    "最大偏离(%)": max_basis_pct,
                    "平均偏离(%)": avg_basis_pct,
                    "可比交易所": len(basis_rows),
                    "__selection": {"coin": coin, "exchange": max_exchange_key},
                }
            )
        frame = pd.DataFrame(rows)
        if frame.empty:
            return frame
        frame = frame.sort_values("最大偏离(%)", key=lambda series: pd.to_numeric(series, errors="coerce").abs(), ascending=False, na_position="last")
        return frame.reset_index(drop=True)

    def _build_multicoin_base_frame_from_monitor_frame(self, frame: pd.DataFrame) -> pd.DataFrame:
        columns = [
            "币种",
            "价格",
            "5m%",
            "30m%",
            "1h%",
            "4h%",
            "24h%",
            "24h成交额",
            "OI总额",
            "OI 1h(%)",
            "OI 4h(%)",
            "OI 24h(%)",
            "Funding(bp)",
            "L/S比",
            "Spot/OI",
            "Lead/Lag",
            "信号",
            "情绪评分",
            "置信度",
            "OI变化额",
            "主交易所",
            "主交易所键",
            "偏离交易所",
            "最大偏离(%)",
            "平均偏离(%)",
            "可比交易所",
            "联动交易所",
            "事件数",
            "事件样本额",
            "联动状态",
            "最近时间",
            "__selection",
        ]
        if frame is None or frame.empty:
            return pd.DataFrame(columns=columns)
        working = canonicalize_market_frame_columns(frame.copy())
        if "币种" not in working.columns:
            return pd.DataFrame(columns=columns)
        for numeric_column in [
            "最新价",
            "5m%",
            "30m%",
            "1h%",
            "4h%",
            "24h%",
            "24h成交额",
            "OI总额",
            "OI 1h(%)",
            "OI 4h(%)",
            "OI 24h(%)",
            "Funding(bp)",
            "5m%",
            "5m大额成交额",
            "5m大额成交笔数",
            "最近时间",
        ]:
            if numeric_column in working.columns:
                working[numeric_column] = pd.to_numeric(working[numeric_column], errors="coerce")
        rows: List[Dict[str, Any]] = []
        for coin_name, coin_frame in working.groupby("币种", sort=False):
            market_series = coin_frame["市场"].astype(str) if "市场" in coin_frame.columns else pd.Series("", index=coin_frame.index)
            perp_slice = coin_frame[market_series == "perp"].copy()
            spot_slice = coin_frame[market_series == "spot"].copy()
            dominant_slice = perp_slice if not perp_slice.empty else coin_frame
            if dominant_slice.empty:
                continue
            if "OI总额" in dominant_slice.columns:
                dominant_sort_key = pd.to_numeric(dominant_slice["OI总额"], errors="coerce").fillna(0.0)
            elif "24h成交额" in dominant_slice.columns:
                dominant_sort_key = pd.to_numeric(dominant_slice["24h成交额"], errors="coerce").fillna(0.0)
            else:
                dominant_sort_key = pd.Series(0.0, index=dominant_slice.index)
            dominant = dominant_slice.assign(_rank=dominant_sort_key).sort_values("_rank", ascending=False, na_position="last").iloc[0].to_dict()

            def weighted_perp_metric(column: str) -> Optional[float]:
                if perp_slice.empty or column not in perp_slice.columns:
                    return None
                metric_series = pd.to_numeric(perp_slice.get(column), errors="coerce")
                if metric_series.dropna().empty:
                    return None
                if float(oi_weights.sum() or 0.0) > 0:
                    return float((metric_series.fillna(0.0) * oi_weights).sum() / max(float(oi_weights.sum()), 1.0))
                return float(metric_series.dropna().mean())

            primary_exchange_key = _normalize_exchange_value(
                dominant.get("主交易所键") or dominant.get("交易所键") or dominant.get("主交易所") or dominant.get("交易所")
            )
            primary_exchange = (
                _row_exchange_name(dominant)
                or str(dominant.get("主交易所") or "").strip()
                or EXCHANGE_TITLE_MAP.get(primary_exchange_key, primary_exchange_key or "-")
            )

            volume_24h = _numeric_series_sum_or_none(coin_frame.get("24h成交额"))
            oi_total = _numeric_series_sum_or_none(perp_slice.get("OI总额")) if not perp_slice.empty else None
            oi_weights = pd.to_numeric(perp_slice.get("OI总额"), errors="coerce").fillna(0.0) if not perp_slice.empty else pd.Series(dtype=float)
            oi_1h = weighted_perp_metric("OI 1h(%)")
            oi_4h = weighted_perp_metric("OI 4h(%)")
            oi_24h = weighted_perp_metric("OI 24h(%)")
            funding_value = None
            if not perp_slice.empty:
                funding_rows: List[tuple[float, float]] = []
                for _, perp_row in perp_slice.iterrows():
                    normalized_funding_bps = _row_funding_bps(perp_row)
                    if normalized_funding_bps is None:
                        continue
                    funding_weight = max(float(_payload_float(perp_row.get("OI总额")) or 0.0), 0.0)
                    funding_rows.append((float(normalized_funding_bps), funding_weight))
                if funding_rows:
                    total_funding_weight = sum(weight for _, weight in funding_rows)
                    if total_funding_weight > 0:
                        funding_value = sum(value * weight for value, weight in funding_rows) / total_funding_weight
                    else:
                        funding_value = float(pd.Series([value for value, _ in funding_rows]).median())
            if funding_value is None:
                funding_value = _row_funding_bps(dominant)
            funding_value = _normalize_scalar(funding_value)
            signal_score_series = (
                pd.to_numeric(coin_frame.get("信号分数"), errors="coerce").fillna(0.0)
                if "信号分数" in coin_frame.columns
                else (
                    pd.to_numeric(coin_frame.get("情绪评分"), errors="coerce").fillna(0.0)
                    if "情绪评分" in coin_frame.columns
                    else pd.Series(0.0, index=coin_frame.index)
                )
            )
            confidence = min(1.0, 0.35 + 0.18 * float(len(coin_frame)) + 0.12 * float(len(perp_slice)))

            basis_rows: List[tuple[str, float]] = []
            if not perp_slice.empty and not spot_slice.empty and "交易所键" in coin_frame.columns:
                for exchange_key in sorted(set(coin_frame["交易所键"].astype(str))):
                    perp_exchange = perp_slice[perp_slice["交易所键"].astype(str) == exchange_key]
                    spot_exchange = spot_slice[spot_slice["交易所键"].astype(str) == exchange_key]
                    if perp_exchange.empty or spot_exchange.empty:
                        continue
                    perp_price = _row_last_price(perp_exchange.iloc[0])
                    spot_price = _row_last_price(spot_exchange.iloc[0])
                    if perp_price in (None, 0) or spot_price in (None, 0):
                        continue
                    basis_rows.append((exchange_key, (float(perp_price) - float(spot_price)) / float(spot_price) * 100.0))
            if basis_rows:
                max_exchange_key, max_basis_pct = max(basis_rows, key=lambda item: abs(float(item[1])))
                avg_basis_pct = float(pd.Series([item[1] for item in basis_rows]).mean())
            else:
                max_exchange_key, max_basis_pct, avg_basis_pct = None, None, None

            event_notional_series = (
                pd.to_numeric(coin_frame.get("5m大额成交额"), errors="coerce").fillna(0.0)
                if "5m大额成交额" in coin_frame.columns
                else pd.Series(0.0, index=coin_frame.index)
            )
            event_count_series = (
                pd.to_numeric(coin_frame.get("5m大额成交笔数"), errors="coerce").fillna(0.0)
                if "5m大额成交笔数" in coin_frame.columns
                else pd.Series(0.0, index=coin_frame.index)
            )
            linkage_mask = event_notional_series >= max(100_000.0, float(event_notional_series.max() or 0.0) * 0.35)
            linkage_slice = coin_frame[linkage_mask].copy() if not coin_frame.empty else pd.DataFrame()
            linkage_exchange_count = int(len(set(linkage_slice.get("交易所键", pd.Series(dtype="object")).astype(str)))) if not linkage_slice.empty else 0
            event_sample_notional = float(event_notional_series.sum()) if not event_notional_series.empty else 0.0
            event_sample_count = int(event_count_series.sum()) if not event_count_series.empty else 0
            recent_time = _best_updated_at_ms(_normalize_scalar(dominant.get("最近时间")), _frame_max_timestamp_ms(coin_frame, "最近时间"))
            linkage_state = "跨所联动" if linkage_exchange_count >= 2 else "单所异动" if event_sample_count > 0 or event_sample_notional > 0 else "等待样本"
            rows.append(
                {
                    "币种": coin_name,
                    "价格": _normalize_scalar(dominant.get("最新价")),
                    "5m%": _normalize_scalar(dominant.get("5m%")),
                    "30m%": _normalize_scalar(dominant.get("30m%")),
                    "1h%": _normalize_scalar(dominant.get("1h%")),
                    "4h%": _normalize_scalar(dominant.get("4h%")),
                    "24h%": _normalize_scalar(dominant.get("24h%")),
                    "24h成交额": _normalize_scalar(volume_24h),
                    "OI总额": _normalize_scalar(oi_total),
                    "OI 1h(%)": _normalize_scalar(oi_1h),
                    "OI 4h(%)": _normalize_scalar(oi_4h),
                    "OI 24h(%)": _normalize_scalar(oi_24h),
                    "Funding(bp)": _normalize_scalar(funding_value),
                    "L/S比": _normalize_scalar(dominant.get("L/S比")),
                    "Spot/OI": (float(volume_24h) / float(oi_total)) if volume_24h not in (None, 0) and oi_total not in (None, 0) else None,
                    "Lead/Lag": str(dominant.get("Lead/Lag") or "").strip() or "",
                    "信号": str(dominant.get("信号") or "").strip() or "-",
                    "情绪评分": float(signal_score_series.max()) if not signal_score_series.empty else 0.0,
                    "置信度": round(confidence, 2),
                    "OI变化额": _normalize_scalar(
                        _numeric_series_sum_or_none(perp_slice.get("OI变化额")) if not perp_slice.empty else dominant.get("OI变化额")
                    ),
                    "主交易所": primary_exchange or "-",
                    "主交易所键": primary_exchange_key,
                    "偏离交易所": EXCHANGE_TITLE_MAP.get(max_exchange_key or "", max_exchange_key or "-"),
                    "最大偏离(%)": _normalize_scalar(max_basis_pct),
                    "平均偏离(%)": _normalize_scalar(avg_basis_pct),
                    "可比交易所": len(basis_rows),
                    "联动交易所": linkage_exchange_count,
                    "事件数": event_sample_count,
                    "事件样本额": _normalize_scalar(event_sample_notional if event_sample_notional > 0 else None),
                    "24h爆仓样本额": _normalize_scalar(event_sample_notional if event_sample_notional > 0 else None),
                    "联动状态": linkage_state,
                    "状态": "正常" if str(dominant.get("交易所") or dominant.get("主交易所") or "").strip() else "代理",
                    "最近时间": recent_time,
                    "__selection": {"coin": coin_name, "exchange": primary_exchange_key},
                }
            )
        result = pd.DataFrame(rows, columns=columns)
        if result.empty:
            return result
        result = result.assign(_rank=pd.to_numeric(result.get("OI总额"), errors="coerce").fillna(0.0))
        result = result.sort_values(["_rank", "币种"], ascending=[False, True], na_position="last").drop(columns="_rank")
        return result.reset_index(drop=True)

    def _build_multicoin_linkage_frame_from_base(self, frame: pd.DataFrame) -> pd.DataFrame:
        columns = ["币种", "联动交易所", "最早联动时间", "事件数", "事件样本额", "联动状态", "__selection"]
        if frame is None or frame.empty:
            return pd.DataFrame(columns=columns)
        rows: List[Dict[str, Any]] = []
        for row in frame.to_dict("records"):
            rows.append(
                {
                    "币种": row.get("币种"),
                    "联动交易所": row.get("联动交易所"),
                    "最早联动时间": pd.to_datetime(int(row.get("最近时间")), unit="ms") if row.get("最近时间") not in (None, "", 0) else None,
                    "事件数": row.get("事件数"),
                    "事件样本额": row.get("事件样本额"),
                    "联动状态": row.get("联动状态"),
                    "__selection": row.get("__selection"),
                }
            )
        result = pd.DataFrame(rows, columns=columns)
        if result.empty:
            return result
        return result.sort_values(["联动交易所", "事件样本额", "事件数"], ascending=[False, False, False], na_position="last").reset_index(drop=True)

    def _build_multicoin_spot_perp_divergence_from_base(self, frame: pd.DataFrame) -> pd.DataFrame:
        columns = ["币种", "偏离交易所", "最大偏离(%)", "平均偏离(%)", "可比交易所", "__selection"]
        if frame is None or frame.empty:
            return pd.DataFrame(columns=columns)
        result = frame[[column for column in columns if column in frame.columns]].copy()
        for column in columns:
            if column not in result.columns:
                result[column] = None
        result = result[columns]
        return result.sort_values(
            "最大偏离(%)",
            key=lambda series: pd.to_numeric(series, errors="coerce").abs(),
            ascending=False,
            na_position="last",
        ).reset_index(drop=True)

    def _build_workspace_source_meta(
        self,
        *,
        source_label: str,
        working_frame: pd.DataFrame,
        detail_frame: Optional[pd.DataFrame] = None,
    ) -> Dict[str, Any]:
        return compose_workspace_source_meta(
            source_label=source_label,
            working_frame=working_frame,
            detail_frame=detail_frame,
            frame_max_timestamp_ms=_frame_max_timestamp_ms,
            best_updated_at_ms=_best_updated_at_ms,
        )

    def _resolve_watch_workspace_bundle(
        self,
        *,
        watch_group: str,
        custom_coins: Optional[List[str]] = None,
        coin_scope: str,
        exchange_keys: List[str],
        market_scope: str,
        oi_threshold_pct: float,
        sentiment_mode: str,
        large_trade_threshold: float,
        fallback_mode: str,
        sync_on_miss: bool = False,
        cache_only: bool = False,
        manager_cache_only: bool = False,
        wait_for_refresh: bool = True,
    ) -> Dict[str, Any]:
        normalized_watch_group = _normalize_watch_group(watch_group)
        normalized_custom_coins = _normalize_custom_coins(custom_coins)
        normalized_coin_scope = _normalize_coin_scope(coin_scope)
        normalized_exchange_keys = _normalize_exchange_keys(exchange_keys)
        normalized_market_scope = _normalize_market_scope(market_scope)
        normalized_oi_threshold = _normalize_oi_threshold(oi_threshold_pct)
        normalized_sentiment_mode = _normalize_sentiment_mode(sentiment_mode)
        normalized_fallback_mode = str(fallback_mode or "overview").strip().lower()

        manager_frame_cache_key = (
            f"watch-workspace-manager::{self.coin}::{normalized_watch_group}::{normalized_coin_scope}::"
            f"{','.join(normalized_exchange_keys)}::{normalized_market_scope}::{large_trade_threshold}"
        )
        manager_frame = pd.DataFrame()
        if self.manager is not None and not normalized_custom_coins:
            manager_read_only = not bool(sync_on_miss)
            if cache_only or (manager_cache_only and not sync_on_miss):
                cached_manager_frame = self._cache_peek(manager_frame_cache_key, ttl_seconds=2)
                if isinstance(cached_manager_frame, pd.DataFrame) and not cached_manager_frame.empty:
                    manager_frame = cached_manager_frame
                else:
                    stale_manager_frame = self._cache_peek(manager_frame_cache_key, ttl_seconds=None)
                    if isinstance(stale_manager_frame, pd.DataFrame) and not stale_manager_frame.empty:
                        manager_frame = stale_manager_frame
            elif sync_on_miss:
                manager_frame = self._cache_peek(manager_frame_cache_key, ttl_seconds=2)
                if not isinstance(manager_frame, pd.DataFrame) or manager_frame.empty:
                    manager_frame = self.manager.monitor_base_frame(
                        coin=self.coin,
                        watch_group=normalized_watch_group,
                        coin_scope=normalized_coin_scope,
                        exchange_keys=normalized_exchange_keys,
                        market_scope=normalized_market_scope,
                        large_trade_threshold=large_trade_threshold,
                        read_only=manager_read_only,
                        wait_for_refresh=wait_for_refresh,
                    )
                    self._cache_store(manager_frame_cache_key, manager_frame)
            else:
                manager_frame = self._cache_get_or_build(
                    manager_frame_cache_key,
                    2,
                    lambda: self.manager.monitor_base_frame(
                        coin=self.coin,
                        watch_group=normalized_watch_group,
                        coin_scope=normalized_coin_scope,
                        exchange_keys=normalized_exchange_keys,
                        market_scope=normalized_market_scope,
                        large_trade_threshold=large_trade_threshold,
                        read_only=manager_read_only,
                        wait_for_refresh=False,
                    ),
                )

        working_frame = pd.DataFrame()
        source_label = "manager monitor base cache"
        if not manager_frame.empty:
            working_frame = self._build_multicoin_base_frame_from_monitor_frame(manager_frame)
        elif normalized_fallback_mode == "legacy":
            legacy_frame_cache_key = (
                f"watch-workspace-legacy::{self.coin}::{normalized_watch_group}::{normalized_coin_scope}::"
                f"{normalized_market_scope}::{normalized_oi_threshold}::{normalized_sentiment_mode}::{large_trade_threshold}"
            )
            legacy_frame = pd.DataFrame()
            if cache_only:
                cached_legacy_frame = self._cache_peek(legacy_frame_cache_key, ttl_seconds=15)
                if isinstance(cached_legacy_frame, pd.DataFrame) and not cached_legacy_frame.empty:
                    legacy_frame = cached_legacy_frame
                else:
                    stale_legacy_frame = self._cache_peek(legacy_frame_cache_key, ttl_seconds=None)
                    if isinstance(stale_legacy_frame, pd.DataFrame) and not stale_legacy_frame.empty:
                        legacy_frame = stale_legacy_frame
            elif sync_on_miss:
                legacy_frame = self._cache_get_or_build(
                    legacy_frame_cache_key,
                    15,
                    lambda: self._build_monitor_legacy_frame(
                        watch_group=normalized_watch_group,
                        coin_scope=normalized_coin_scope,
                        market_scope=normalized_market_scope,
                        oi_threshold_pct=normalized_oi_threshold,
                        sentiment_mode=normalized_sentiment_mode,
                        large_trade_threshold=large_trade_threshold,
                    ),
                )
            else:
                legacy_frame = self._cache_peek(legacy_frame_cache_key, ttl_seconds=15)
                if legacy_frame is None:
                    legacy_frame = pd.DataFrame()
                    self._schedule_cache_warm(
                        legacy_frame_cache_key,
                        15,
                        lambda: self._build_monitor_legacy_frame(
                            watch_group=normalized_watch_group,
                            coin_scope=normalized_coin_scope,
                            market_scope=normalized_market_scope,
                            oi_threshold_pct=normalized_oi_threshold,
                            sentiment_mode=normalized_sentiment_mode,
                            large_trade_threshold=large_trade_threshold,
                        ),
                    )
            if isinstance(legacy_frame, pd.DataFrame) and not legacy_frame.empty:
                working_frame = legacy_frame.copy()
                source_label = "legacy monitor frame cache"
        if working_frame.empty and not cache_only:
            overview_frame = self._build_market_overview_frame(
                normalized_watch_group,
                custom_coins=normalized_custom_coins,
                light=True,
            )
            working_frame = self._filter_multicoin_focus_frame(
                overview_frame,
                coin_scope=normalized_coin_scope,
                oi_threshold_pct=normalized_oi_threshold,
                sentiment_mode=normalized_sentiment_mode,
            )
            source_label = "local runtime sessions + history fallback"

        if not working_frame.empty:
            try:
                working_frame = working_frame.drop_duplicates(subset=["币种", "交易所键", "市场"], keep="first").reset_index(drop=True)
            except Exception:
                working_frame = working_frame.reset_index(drop=True)
            working_frame = _filter_frame_by_exchange_keys(working_frame, normalized_exchange_keys)
            working_frame = _filter_frame_by_market_scope(working_frame, normalized_market_scope)
            if normalized_fallback_mode == "legacy":
                working_frame = self._filter_monitor_exchange_frame(
                    working_frame,
                    coin_scope=normalized_coin_scope,
                    watch_group=normalized_watch_group,
                    oi_threshold_pct=normalized_oi_threshold,
                    sentiment_mode=normalized_sentiment_mode,
                )
            else:
                working_frame = self._filter_multicoin_focus_frame(
                    working_frame,
                    coin_scope=normalized_coin_scope,
                    oi_threshold_pct=normalized_oi_threshold,
                    sentiment_mode=normalized_sentiment_mode,
                )
        if working_frame.empty:
            working_frame = pd.DataFrame(columns=["币种"])

        selected_coins = [
            str(item).upper()
            for item in working_frame.get("币种", pd.Series(dtype="object")).tolist()
            if str(item).strip()
        ]
        if not selected_coins:
            selected_coins = (normalized_custom_coins or self._monitor_watchlist_coins(normalized_watch_group, normalized_coin_scope))[
                : max(4, len(DEFAULT_MAJOR_WORKBENCH_COINS))
            ]

        source_meta = self._build_workspace_source_meta(
            source_label=source_label,
            working_frame=working_frame,
            detail_frame=manager_frame if isinstance(manager_frame, pd.DataFrame) else pd.DataFrame(),
        )

        return {
            "working_frame": working_frame,
            "detail_frame": manager_frame if isinstance(manager_frame, pd.DataFrame) else pd.DataFrame(),
            "selected_coins": selected_coins,
            "source_label": source_label,
            "source_key": str(source_meta.get("source_key") or ""),
            "data_source": str(source_meta.get("data_source") or source_label),
            "truth_level": str(source_meta.get("truth_level") or ""),
            "updated_at_ms": _best_updated_at_ms(source_meta.get("updated_at_ms")),
            "source_meta": source_meta,
            "liquidation_frame": self._build_multicoin_linkage_frame_from_base(working_frame),
            "divergence_frame": self._build_multicoin_spot_perp_divergence_from_base(working_frame),
            "reference_layers": self._build_watch_reference_layers(working_frame),
        }

    def _build_multicoin_payload(
        self,
        *,
        watch_group: str = "board",
        coin_scope: str = "majors",
        exchange_keys: Optional[List[str]] = None,
        market_scope: str = "merged",
        time_window: str = "1h",
        top_n: int = 20,
        min_notional: float = 0.0,
        oi_threshold_pct: float = 0.0,
        sentiment_mode: str = "all",
    ) -> Dict[str, Any]:
        now_ms = int(time.time() * 1000)
        normalized_watch_group = _normalize_watch_group(watch_group)
        normalized_coin_scope = _normalize_coin_scope(coin_scope)
        normalized_exchange_keys = _normalize_exchange_keys(exchange_keys)
        normalized_market_scope = _normalize_market_scope(market_scope)
        normalized_time_window = _normalize_time_window(time_window)
        normalized_top_n = _normalize_monitor_top_n(top_n)
        threshold_bundle = _effective_monitor_notional_threshold(min_notional, 0.0)
        normalized_min_notional = max(float(threshold_bundle["min_notional"]), TAPE_MIN_NOTIONAL_FLOOR)
        effective_min_notional = max(float(threshold_bundle["effective_min_notional"]), TAPE_MIN_NOTIONAL_FLOOR)
        normalized_oi_threshold = _normalize_oi_threshold(oi_threshold_pct)
        normalized_sentiment_mode = _normalize_sentiment_mode(sentiment_mode)

        workspace = self._resolve_watch_workspace_bundle(
            watch_group=normalized_watch_group,
            custom_coins=None,
            coin_scope=normalized_coin_scope,
            exchange_keys=normalized_exchange_keys,
            market_scope=normalized_market_scope,
            oi_threshold_pct=normalized_oi_threshold,
            sentiment_mode=normalized_sentiment_mode,
            large_trade_threshold=max(float(effective_min_notional or 0.0), 100_000.0),
            fallback_mode="overview",
            sync_on_miss=True,
        )
        working_frame = workspace.get("working_frame") if isinstance(workspace.get("working_frame"), pd.DataFrame) else pd.DataFrame(columns=["币种"])
        selected_coins = list(workspace.get("selected_coins") or [])
        liquidation_frame = workspace.get("liquidation_frame") if isinstance(workspace.get("liquidation_frame"), pd.DataFrame) else pd.DataFrame()
        divergence_frame = workspace.get("divergence_frame") if isinstance(workspace.get("divergence_frame"), pd.DataFrame) else pd.DataFrame()
        reference_layers = workspace.get("reference_layers") if isinstance(workspace.get("reference_layers"), dict) else {}

        cards: List[Dict[str, Any]] = []
        if normalized_market_scope != "spot" and not working_frame.empty:
            oi_leader = working_frame.loc[pd.to_numeric(working_frame["OI 1h(%)"], errors="coerce").abs().fillna(0.0).idxmax()] if "OI 1h(%)" in working_frame.columns else None
            funding_leader = working_frame.loc[pd.to_numeric(working_frame["Funding(bp)"], errors="coerce").abs().fillna(0.0).idxmax()] if "Funding(bp)" in working_frame.columns else None
            liq_leader = liquidation_frame.iloc[0] if isinstance(liquidation_frame, pd.DataFrame) and not liquidation_frame.empty else None
            cards.extend(
                [
                    {
                        "label": "OI 扩张领跑",
                        "value": str(oi_leader.get("币种") if oi_leader is not None else "-"),
                        "sub": "-" if oi_leader is None else f"OI 1h {float(oi_leader.get('OI 1h(%)') or 0.0):+.2f}%",
                    },
                    {
                        "label": "Funding 极值",
                        "value": str(funding_leader.get("币种") if funding_leader is not None else "-"),
                        "sub": "-" if funding_leader is None else _format_funding_rate_percent(funding_leader.get("Funding(bp)")),
                    },
                    {
                        "label": "多所联动先手",
                        "value": str(liq_leader.get("币种") if liq_leader is not None else "-"),
                        "sub": "-" if liq_leader is None else str(liq_leader.get("联动状态") or "-"),
                    },
                ]
            )
        if normalized_market_scope != "perp":
            divergence_leader = divergence_frame.iloc[0] if isinstance(divergence_frame, pd.DataFrame) and not divergence_frame.empty else None
            cards.append(
                {
                    "label": "Spot/Perp 偏离最大",
                    "value": str(divergence_leader.get("币种") if divergence_leader is not None else "-"),
                    "sub": "-" if divergence_leader is None else f"{float(divergence_leader.get('最大偏离(%)') or 0.0):+.3f}%",
                }
            )
        cards.append(
            {
                "label": "观察币数量",
                "value": str(len(selected_coins)),
                "sub": f"{normalized_time_window} · {normalized_market_scope}",
            }
        )

        cards.extend(self._build_watch_reference_cards(reference_layers))

        summary_signature = {
            "coins": selected_coins,
            "scope": normalized_coin_scope,
            "watch_group": normalized_watch_group,
            "market_scope": normalized_market_scope,
            "time_window": normalized_time_window,
            "exchange_keys": normalized_exchange_keys,
            "min_notional": effective_min_notional,
            "oi_threshold": normalized_oi_threshold,
            "sentiment_mode": normalized_sentiment_mode,
            "top_n": normalized_top_n,
            "updated_at_ms": now_ms,
        }
        panels: List[Dict[str, Any]] = [
            self._build_timed_frame_panel(
                "multicoin-summary",
                "多币种总控表",
                signature={**summary_signature, "panel": "summary"},
                frame_builder=lambda: working_frame,
                note="同屏比较 OI、Funding、多所联动、Spot/Perp 偏离和主导交易所。",
                limit=normalized_top_n,
                data_source="manager monitor base cache",
                updated_at_ms=now_ms,
                truth_level="proxy",
            )
        ]
        if normalized_market_scope != "spot":
            panels.extend(
                [
                    self._build_timed_figure_panel(
                        "multicoin-oi-ranking",
                        "多币种 OI 排行",
                        signature={**summary_signature, "panel": "oi-ranking", "rows": len(working_frame)},
                        figure_builder=lambda: build_multi_coin_oi_ranking_figure(working_frame, limit=normalized_top_n),
                        note="优先看谁先扩 OI、谁的 OI 总量最大。",
                        data_source="manager monitor base cache",
                        updated_at_ms=now_ms,
                        truth_level="proxy",
                    ),
                    self._build_timed_figure_panel(
                        "multicoin-oi-quadrant",
                        "多币种 OI 四象限",
                        signature={**summary_signature, "panel": "oi-quadrant", "rows": len(working_frame)},
                        figure_builder=lambda: build_multi_coin_oi_quadrant_bubble_figure(working_frame, limit=normalized_top_n),
                        note="看谁在加仓推进、谁在回补、谁只是价格动。",
                        data_source="manager monitor base cache",
                        updated_at_ms=now_ms,
                        truth_level="proxy",
                    ),
                    self._build_timed_figure_panel(
                        "multicoin-funding-heatmap",
                        "多币种 Funding 热力图",
                        signature={**summary_signature, "panel": "funding-heatmap", "rows": len(working_frame)},
                        figure_builder=lambda: build_multi_coin_funding_heatmap_figure(working_frame, limit=normalized_top_n),
                        note="Funding 极值优先，便于直接抓拥挤度。",
                        data_source="manager monitor base cache",
                        updated_at_ms=now_ms,
                        truth_level="proxy",
                    ),
                    self._build_timed_frame_panel(
                        "multicoin-liquidation-linkage",
                        "多所事件联动榜",
                        signature={**summary_signature, "panel": "liquidation-linkage", "rows": len(liquidation_frame)},
                        frame_builder=lambda: liquidation_frame,
                        note="用 5m 异动事件样本聚合跨所联动，优先看谁先扩散。",
                        limit=normalized_top_n,
                        data_source="manager monitor base cache",
                        updated_at_ms=now_ms,
                        truth_level="proxy",
                    ),
                ]
            )
        if normalized_market_scope != "perp":
            panels.append(
                self._build_timed_frame_panel(
                    "multicoin-spot-perp-divergence",
                    "Spot / Perp 偏离榜",
                    signature={**summary_signature, "panel": "spot-perp-divergence", "rows": len(divergence_frame)},
                    frame_builder=lambda: divergence_frame,
                    note="优先看哪一币的现货 / 合约偏离更大。",
                    limit=normalized_top_n,
                    data_source="manager monitor base cache",
                    updated_at_ms=now_ms,
                    truth_level="proxy",
                )
            )
        panels.extend(
            self._build_reference_panels(
                prefix="multicoin-reference",
                reference_layers=reference_layers,
                now_ms=now_ms,
                market_scope=normalized_market_scope,
                spot_title="现货参考层",
                perp_title="合约参考层",
                composite_title="综合结论层",
                spot_note="在多币种篮子里统一提取现货确认和先动币。",
                perp_note="统一比较 Funding、OI 与拥挤度，找出杠杆先动币。",
                composite_note="把现货、合约两层合并成多币种工作台的主结论。",
                spot_data_source="多币种总控表 + lead-lag",
                perp_data_source="多币种总控表 + Funding/OI",
                composite_data_source="现货参考层 + 合约参考层",
                spot_truth_level="proxy",
                perp_truth_level="proxy",
                composite_truth_level="proxy",
            )
        )
        panels = _attach_panel_meta(panels, data_source="多币种工作台", updated_at_ms=now_ms)
        payload = {
            "coin": self.coin,
            "generated_at_ms": now_ms,
            "filters": {
                "watch_group": normalized_watch_group,
                "coin_scope": normalized_coin_scope,
                "exchange_keys": normalized_exchange_keys,
                "market_scope": normalized_market_scope,
                "time_window": normalized_time_window,
                "top_n": normalized_top_n,
                "min_notional": normalized_min_notional,
                "effective_min_notional": effective_min_notional,
                "oi_threshold_pct": normalized_oi_threshold,
                "sentiment_mode": normalized_sentiment_mode,
            },
            "cards": cards,
            "rows": _frame_to_records(working_frame, limit=normalized_top_n),
            "panels": panels,
            "reference": {
                "spot": reference_layers.get("spot_metrics") or {},
                "perp": reference_layers.get("perp_metrics") or {},
                "composite": reference_layers.get("conclusion") or {},
            },
        }
        return payload

    def multicoin_payload(
        self,
        *,
        watch_group: str = "board",
        coin_scope: str = "majors",
        exchange_keys: Optional[List[str]] = None,
        market_scope: str = "merged",
        time_window: str = "1h",
        top_n: int = 20,
        min_notional: float = 0.0,
        oi_threshold_pct: float = 0.0,
        sentiment_mode: str = "all",
        _sync_on_miss: bool = False,
    ) -> Dict[str, Any]:
        self.touch()
        normalized_watch_group = _normalize_watch_group(watch_group)
        normalized_coin_scope = _normalize_coin_scope(coin_scope)
        normalized_exchange_keys = _normalize_exchange_keys(exchange_keys)
        normalized_market_scope = _normalize_market_scope(market_scope)
        normalized_time_window = _normalize_time_window(time_window)
        normalized_top_n = _normalize_monitor_top_n(top_n)
        normalized_min_notional = _normalize_notional_threshold(min_notional)
        normalized_oi_threshold = _normalize_oi_threshold(oi_threshold_pct)
        normalized_sentiment_mode = _normalize_sentiment_mode(sentiment_mode)
        now_ms = int(time.time() * 1000)
        cache_key = (
            f"payload-multicoin::{self.coin}::{normalized_watch_group}::{normalized_coin_scope}::"
            f"{','.join(normalized_exchange_keys)}::{normalized_market_scope}::{normalized_time_window}::"
            f"{normalized_top_n}::{normalized_min_notional}::{normalized_oi_threshold}::{normalized_sentiment_mode}"
        )

        def placeholder() -> Dict[str, Any]:
            return _standardize_payload_metrics({
                "coin": self.coin,
                "generated_at_ms": now_ms,
                "filters": {
                    "watch_group": normalized_watch_group,
                    "coin_scope": normalized_coin_scope,
                    "exchange_keys": normalized_exchange_keys,
                    "market_scope": normalized_market_scope,
                    "time_window": normalized_time_window,
                    "top_n": normalized_top_n,
                    "min_notional": normalized_min_notional,
                    "oi_threshold_pct": normalized_oi_threshold,
                    "sentiment_mode": normalized_sentiment_mode,
                },
                "cards": [],
                "rows": [],
                "panels": [],
                "data_meta": self._warming_data_meta("multicoin cache warming", now_ms),
            })

        builder = lambda: self._build_multicoin_payload(
            watch_group=normalized_watch_group,
            coin_scope=normalized_coin_scope,
            exchange_keys=normalized_exchange_keys,
            market_scope=normalized_market_scope,
            time_window=normalized_time_window,
            top_n=normalized_top_n,
            min_notional=normalized_min_notional,
            oi_threshold_pct=normalized_oi_threshold,
            sentiment_mode=normalized_sentiment_mode,
        )
        if _sync_on_miss:
            return self._cache_get_or_build(cache_key, 8, builder)
        return self._derived_payload_snapshot(
            cache_key=cache_key,
            ttl_seconds=8,
            builder=builder,
            placeholder_builder=placeholder,
            sync_on_miss=False,
        )

    def _load_monitor_price_action_row(self, coin: str, preferred_exchange_key: str = "") -> Dict[str, Any]:
        normalized_coin = str(coin or self.coin).upper().strip() or self.coin
        normalized_preferred_exchange = _normalize_exchange_value(preferred_exchange_key)

        def builder() -> Dict[str, Any]:
            symbol_map = default_symbols(normalized_coin)
            availability = self.catalog.get("availability", {}).get(normalized_coin, {})
            status = self.catalog.get("status", {})
            for exchange_key in EXCHANGE_ORDER:
                if str(status.get(exchange_key, {}).get("perp") or "") == "ok" and not bool(availability.get(exchange_key, {}).get("perp")):
                    symbol_map[exchange_key] = ""
            candidate_exchanges = []
            if normalized_preferred_exchange:
                candidate_exchanges.append(normalized_preferred_exchange)
            candidate_exchanges.extend([key for key in EXCHANGE_ORDER if key not in candidate_exchanges])
            selected_exchange = next((key for key in candidate_exchanges if symbol_map.get(key)), "")
            symbol = symbol_map.get(selected_exchange) or ""
            if not selected_exchange or not symbol:
                return {
                    "币种": normalized_coin,
                    "主交易所键": normalized_preferred_exchange or "",
                    "5m%": None,
                    "30m%": None,
                    "1h%": None,
                    "4h%": None,
                    "1h波动(%)": None,
                    "1m变化(%)": None,
                    "1m振幅(%)": None,
                    "闪动告警": "样本不足",
                    "闪动强度": None,
                    "最近K线时间": None,
                    "__selection": {"coin": normalized_coin, "exchange": normalized_preferred_exchange or ""},
                }
            health_lookup = _request_health_lookup()
            hard_degraded = _exchange_market_rest_hard_degraded(selected_exchange, "perp", health_lookup=health_lookup)
            history_frame = (
                self._cache_get_or_build(
                    f"price-action-history::{normalized_coin}::{selected_exchange}",
                    15,
                    lambda: self.history_store.load_market_history(
                        coin=normalized_coin,
                        exchange_keys=[selected_exchange],
                        market="perp",
                        limit=360,
                    ),
                )
                if self._history_sqlite_enabled()
                else pd.DataFrame()
            )
            if hard_degraded:
                candles_5m = []
                candles_1m = []
            else:
                try:
                    candles_5m = list(fetch_exchange_candles(selected_exchange, symbol, "5m", 60, timeout=self.timeout) or [])
                except Exception:
                    candles_5m = []
                try:
                    candles_1m = list(fetch_exchange_candles(selected_exchange, symbol, "1m", 8, timeout=self.timeout) or [])
                except Exception:
                    candles_1m = []
            move_1m = _compute_price_change_pct_by_steps(candles_1m, 1) if candles_1m else _history_change_pct(history_frame, selected_exchange, "最新价", 1)
            range_1m = _compute_last_candle_range_pct(candles_1m) if candles_1m else _history_range_pct(history_frame, selected_exchange, "最新价", 1)
            shock_score = max(abs(float(move_1m or 0.0)), float(range_1m or 0.0))
            if move_1m is not None and abs(move_1m) >= MONITOR_FLASH_MOVE_THRESHOLD_PCT:
                flash_label = "1m 暴拉" if float(move_1m) > 0 else "1m 暴跌"
            elif range_1m is not None and float(range_1m) >= MONITOR_FLASH_MOVE_THRESHOLD_PCT:
                flash_label = "1m 高波动"
            else:
                flash_label = "正常"
            updated_at_ms = _best_updated_at_ms(
                getattr(candles_1m[-1], "timestamp_ms", None) if candles_1m else None,
                getattr(candles_5m[-1], "timestamp_ms", None) if candles_5m else None,
                _frame_max_timestamp_ms(history_frame, "时间"),
            )
            return {
                "币种": normalized_coin,
                "主交易所键": selected_exchange,
                "5m%": _compute_price_change_pct_by_steps(candles_5m, MONITOR_PRICE_WINDOWS["5m"]) if candles_5m else _history_change_pct(history_frame, selected_exchange, "最新价", 5),
                "30m%": _compute_price_change_pct_by_steps(candles_5m, MONITOR_PRICE_WINDOWS["30m"]) if candles_5m else _history_change_pct(history_frame, selected_exchange, "最新价", 30),
                "1h%": _compute_price_change_pct_by_steps(candles_5m, MONITOR_PRICE_WINDOWS["1h"]) if candles_5m else _history_change_pct(history_frame, selected_exchange, "最新价", 60),
                "4h%": _compute_price_change_pct_by_steps(candles_5m, MONITOR_PRICE_WINDOWS["4h"]) if candles_5m else _history_change_pct(history_frame, selected_exchange, "最新价", 240),
                "1h波动(%)": _compute_candle_range_pct(candles_5m, MONITOR_PRICE_WINDOWS["1h"]) if candles_5m else _history_range_pct(history_frame, selected_exchange, "最新价", 60),
                "1m变化(%)": move_1m,
                "1m振幅(%)": range_1m,
                "闪动告警": flash_label,
                "闪动强度": shock_score if shock_score > 0 else None,
                "最近K线时间": updated_at_ms,
                "__selection": {"coin": normalized_coin, "exchange": selected_exchange},
            }

        cache_key = f"monitor-price-action::{normalized_coin}::{normalized_preferred_exchange or 'auto'}"
        return self._cache_get_or_build(cache_key, 20, builder)

    def _build_monitor_price_action_frame(self, frame: pd.DataFrame) -> pd.DataFrame:
        columns = [
            "币种",
            "主交易所键",
            "5m%",
            "30m%",
            "1h%",
            "4h%",
            "1h波动(%)",
            "1m变化(%)",
            "1m振幅(%)",
            "闪动告警",
            "闪动强度",
            "最近K线时间",
            "__selection",
        ]
        if frame is None or frame.empty:
            return pd.DataFrame(columns=columns)
        targets = []
        for row in frame.to_dict("records"):
            coin = str(row.get("币种") or "").upper().strip()
            if not coin:
                continue
            targets.append((coin, _normalize_exchange_value(row.get("主交易所键"))))
        rows: List[Dict[str, Any]] = []
        with ThreadPoolExecutor(max_workers=min(8, max(2, len(targets)))) as executor:
            future_map = {
                executor.submit(self._load_monitor_price_action_row, coin, exchange_key): (coin, exchange_key)
                for coin, exchange_key in targets
            }
            for future in as_completed(future_map):
                try:
                    rows.append(future.result())
                except Exception:
                    coin, exchange_key = future_map[future]
                    rows.append(
                        {
                            "币种": coin,
                            "主交易所键": exchange_key,
                            "5m%": None,
                            "30m%": None,
                            "1h%": None,
                            "4h%": None,
                            "1h波动(%)": None,
                            "1m变化(%)": None,
                            "1m振幅(%)": None,
                            "闪动告警": "加载失败",
                            "闪动强度": None,
                            "最近K线时间": None,
                            "__selection": {"coin": coin, "exchange": exchange_key},
                        }
                    )
        if not rows:
            return pd.DataFrame(columns=columns)
        return pd.DataFrame(rows, columns=columns).sort_values("币种").reset_index(drop=True)

    def _build_monitor_whale_bucket_frame(self, items: List[Dict[str, Any]]) -> pd.DataFrame:
        columns = ["阈值", "事件数", "买盘额", "卖盘额", "总额", "主导方向", "最近时间"]
        if not items:
            return pd.DataFrame(columns=columns)
        rows: List[Dict[str, Any]] = []
        for threshold in MONITOR_WHALE_BUCKETS:
            bucket_items = [item for item in items if float(abs(item.get("notional") or 0.0)) >= float(threshold)]
            if not bucket_items:
                rows.append(
                    {
                        "阈值": f">= {_fmt_compact(threshold)}",
                        "事件数": 0,
                        "买盘额": None,
                        "卖盘额": None,
                        "总额": None,
                        "主导方向": "-",
                        "最近时间": None,
                    }
                )
                continue
            buy_notional = sum(
                float(abs(item.get("notional") or 0.0))
                for item in bucket_items
                if str(item.get("side") or "").strip().lower() == "buy"
            )
            sell_notional = sum(
                float(abs(item.get("notional") or 0.0))
                for item in bucket_items
                if str(item.get("side") or "").strip().lower() == "sell"
            )
            latest_ts = _best_updated_at_ms(*[item.get("timestamp_ms") for item in bucket_items])
            dominant_side = "买盘扫单" if buy_notional >= sell_notional else "卖盘砸盘"
            rows.append(
                {
                    "阈值": f">= {_fmt_compact(threshold)}",
                    "事件数": len(bucket_items),
                    "买盘额": buy_notional or None,
                    "卖盘额": sell_notional or None,
                    "总额": buy_notional + sell_notional or None,
                    "主导方向": dominant_side,
                    "最近时间": latest_ts,
                }
            )
        return pd.DataFrame(rows, columns=columns)

    def _monitor_watchlist_coins(self, watch_group: str, coin_scope: str) -> List[str]:
        watchlist = self._watchlist_coins(watch_group)
        normalized_scope = _normalize_coin_scope(coin_scope)
        if normalized_scope == "current":
            return [self.coin]
        if normalized_scope == "majors":
            selected = [coin for coin in watchlist if coin in DEFAULT_MAJOR_WORKBENCH_COINS]
            if self.coin not in selected:
                selected.insert(0, self.coin)
            return selected
        return watchlist

    def _build_monitor_legacy_frame(
        self,
        *,
        watch_group: str,
        coin_scope: str,
        market_scope: str,
        oi_threshold_pct: float,
        sentiment_mode: str,
        large_trade_threshold: float,
    ) -> pd.DataFrame:
        overview_frame = self._build_market_overview_frame(
            watch_group,
            light=True,
        )
        overview_frame = canonicalize_market_frame_columns(overview_frame.copy()) if isinstance(overview_frame, pd.DataFrame) and not overview_frame.empty else overview_frame
        scoped_frame = self._filter_multicoin_focus_frame(
            overview_frame,
            coin_scope=coin_scope,
            oi_threshold_pct=oi_threshold_pct,
            sentiment_mode=sentiment_mode,
        )
        if scoped_frame.empty:
            scoped_frame = overview_frame.head(min(12, len(overview_frame))).reset_index(drop=True)
        price_action_frame = self._cache_get_or_build(
            (
                f"monitor-price-frame::{self.coin}::{watch_group}::{coin_scope}::"
                f"{market_scope}::{oi_threshold_pct}::{sentiment_mode}"
            ),
            20,
            lambda: self._build_monitor_price_action_frame(scoped_frame),
        )
        price_action_frame = canonicalize_market_frame_columns(price_action_frame.copy()) if isinstance(price_action_frame, pd.DataFrame) and not price_action_frame.empty else price_action_frame
        price_lookup = {
            str(row.get("币种") or "").upper(): row
            for row in price_action_frame.to_dict("records")
            if str(row.get("币种") or "").strip()
        }
        combined_rows: List[Dict[str, Any]] = []
        for row in scoped_frame.to_dict("records"):
            coin_name = str(row.get("币种") or "").upper().strip()
            merged = dict(row)
            extra = price_lookup.get(coin_name, {})
            for key, value in extra.items():
                if key in {"币种", "__selection"}:
                    continue
                merged[key] = value
            exchange_key = _row_exchange_key(row) or _normalize_exchange_value(row.get("主交易所键") or row.get("主交易所"))
            merged["交易所键"] = exchange_key
            merged["交易所"] = EXCHANGE_TITLE_MAP.get(exchange_key or "", exchange_key or _row_exchange_name(row) or row.get("主交易所") or "-")
            merged["市场"] = "合约"
            merged["__selection"] = {"coin": coin_name, "exchange": exchange_key}
            trade_metrics = {
                "5m大额成交额": None,
                "30m大额成交额": None,
                "1h大额成交额": None,
                "4h大额成交额": None,
                "5m大额买入额": None,
                "5m大额卖出额": None,
                "30m大额买入额": None,
                "30m大额卖出额": None,
                "1h大额买入额": None,
                "1h大额卖出额": None,
                "4h大额买入额": None,
                "4h大额卖出额": None,
                "5m大额成交笔数": None,
                "30m大额成交笔数": None,
                "1h大额成交笔数": None,
                "4h大额成交笔数": None,
                "5m成交量": None,
                "30m成交量": None,
                "1h成交量": None,
                "4h成交量": None,
                "最近时间": row.get("最近K线时间"),
            }
            exchange_trades = self.service.get_trade_history(exchange_key) if exchange_key else []
            if exchange_trades:
                trade_window = _compute_trade_window_totals(exchange_trades, now_ms=int(time.time() * 1000), large_trade_threshold=large_trade_threshold)
                for window in ("5m", "30m", "1h", "4h"):
                    trade_metrics[f"{window}大额成交额"] = trade_window.get(f"{window}_large_notional")
                    trade_metrics[f"{window}大额买入额"] = trade_window.get(f"{window}_large_buy_notional")
                    trade_metrics[f"{window}大额卖出额"] = trade_window.get(f"{window}_large_sell_notional")
                    trade_metrics[f"{window}大额成交笔数"] = trade_window.get(f"{window}_large_count")
                trade_metrics["最近时间"] = trade_window.get("latest_trade_at_ms") or trade_metrics["最近时间"]
            merged.update(trade_metrics)
            tags = _build_monitor_row_tags(merged)
            merged["异动标签"] = " / ".join(tags) if tags else "-"
            merged["信号分数"] = _monitor_signal_score(merged)
            merged["信号"] = _monitor_signal_label(
                tags,
                move_5m=_payload_float(merged.get("5m%")) or 0.0,
                oi_1h=_payload_float(merged.get("OI 1h(%)")) or 0.0,
                funding_bps=_payload_float(merged.get("Funding(bp)")) or 0.0,
            )
            combined_rows.append(merged)
        if not combined_rows:
            return pd.DataFrame()
        frame = pd.DataFrame(combined_rows)
        return _attach_selection_column(frame, coin=self.coin)

    def _filter_monitor_exchange_frame(
        self,
        frame: pd.DataFrame,
        *,
        coin_scope: str,
        watch_group: str,
        oi_threshold_pct: float,
        sentiment_mode: str,
    ) -> pd.DataFrame:
        if frame is None or frame.empty:
            return frame
        working = frame.copy()
        normalized_scope = _normalize_coin_scope(coin_scope)
        normalized_sentiment_mode = _normalize_sentiment_mode(sentiment_mode)
        watchlist = set(self._monitor_watchlist_coins(watch_group, coin_scope))
        if normalized_scope in {"current", "majors"}:
            working = working[working["币种"].astype(str).str.upper().isin(watchlist)].reset_index(drop=True)
        elif normalized_scope == "extreme":
            signal_series = pd.to_numeric(working.get("信号分数"), errors="coerce").fillna(0.0)
            oi_series = pd.to_numeric(working.get("OI 1h(%)"), errors="coerce").abs().fillna(0.0)
            move_series = pd.to_numeric(working.get("5m%"), errors="coerce").abs().fillna(0.0)
            funding_series = pd.to_numeric(working.get("Funding(bp)"), errors="coerce").abs().fillna(0.0)
            threshold = max(float(oi_threshold_pct or 0.0), 3.0)
            mask = (
                (signal_series >= max(6.0, signal_series.quantile(0.72) if len(signal_series) > 3 else 6.0))
                | (oi_series >= threshold)
                | (move_series >= 2.5)
                | (funding_series >= 10.0)
            )
            working = working[mask].reset_index(drop=True)
        if normalized_sentiment_mode == "bull":
            working = working[
                (pd.to_numeric(working.get("5m%"), errors="coerce").fillna(0.0) >= 0)
                | (pd.to_numeric(working.get("Funding(bp)"), errors="coerce").fillna(0.0) >= 0)
            ].reset_index(drop=True)
        elif normalized_sentiment_mode == "bear":
            working = working[
                (pd.to_numeric(working.get("5m%"), errors="coerce").fillna(0.0) <= 0)
                | (pd.to_numeric(working.get("Funding(bp)"), errors="coerce").fillna(0.0) <= 0)
            ].reset_index(drop=True)
        elif normalized_sentiment_mode == "extreme":
            working = working[
                (pd.to_numeric(working.get("Funding(bp)"), errors="coerce").abs().fillna(0.0) >= 10.0)
                | (pd.to_numeric(working.get("信号分数"), errors="coerce").fillna(0.0) >= 8.0)
            ].reset_index(drop=True)
        return working

    def _build_monitor_whale_leaderboard_frame(
        self,
        items: List[Dict[str, Any]],
        *,
        threshold: float,
        top_n: int,
    ) -> pd.DataFrame:
        columns = ["排名", "交易对", "成交金额(USDT)", "成交价格", "成交时间", "成交方向", "成交笔数", "所属交易所", "异动标签", "__selection"]
        if not items:
            return pd.DataFrame(columns=columns)
        rows: List[Dict[str, Any]] = []
        for item in items[: max(top_n * 2, top_n)]:
            selection = item.get("__selection") if isinstance(item.get("__selection"), dict) else {}
            coin = _monitor_item_coin(item, default_coin=self.coin)
            selection = {
                "coin": coin or self.coin,
                "exchange": _normalize_exchange_value(selection.get("exchange") or item.get("exchange_key") or item.get("交易所键") or item.get("exchange") or item.get("交易所")),
            }
            trade_count = int(item.get("trade_count") or 1)
            rows.append(
                {
                    "交易对": f"{coin}USDT" if coin else "-",
                    "成交金额(USDT)": float(abs(item.get("notional") or 0.0)),
                    "成交价格": _payload_float(item.get("price")),
                    "成交时间": item.get("timestamp_ms"),
                    "成交方向": _monitor_trade_direction_label(item.get("side")),
                    "成交笔数": trade_count,
                    "所属交易所": item.get("exchange") or EXCHANGE_TITLE_MAP.get(_normalize_exchange_value(item.get("exchange_key")), "-"),
                    "异动标签": (
                        "连续放量"
                        if trade_count >= 3 and float(abs(item.get("notional") or 0.0)) >= threshold * 1.2
                        else "大单扫货"
                        if str(item.get("side") or "").strip().lower() == "buy" and float(abs(item.get("notional") or 0.0)) >= max(threshold, 500_000.0)
                        else "大单砸盘"
                        if str(item.get("side") or "").strip().lower() == "sell" and float(abs(item.get("notional") or 0.0)) >= max(threshold, 500_000.0)
                        else "巨鲸成交"
                    ),
                    "__selection": selection,
                }
            )
        return pd.DataFrame(_rank_records(rows[:top_n]), columns=columns)

    def _build_monitor_mover_board(
        self,
        frame: pd.DataFrame,
        *,
        window_column: str,
        direction: str,
        top_n: int,
    ) -> pd.DataFrame:
        columns = ["排名", "交易对", "最新价格", "周期涨跌幅", "周期成交量", "所属交易所", "异动标签", "__selection"]
        if frame is None or frame.empty:
            return pd.DataFrame(columns=columns)
        frame = canonicalize_market_frame_columns(frame.copy())
        volume_column = _find_column_by_tokens(list(frame.columns), includes=[window_column.replace("%", ""), "成交量"]) or "24h成交额"
        ascending = str(direction or "up").strip().lower() == "down"
        sorted_frame = frame.sort_values([window_column, "24h成交额"], ascending=[ascending, False], na_position="last").head(top_n)
        rows: List[Dict[str, Any]] = []
        for row in sorted_frame.to_dict("records"):
            normalized_row = _with_standard_metric_aliases(dict(row))
            coin = str(row.get("币种") or "").upper().strip()
            rows.append(
                {
                    "交易对": f"{coin}USDT" if coin else "-",
                    "最新价格": _row_last_price(row),
                    "周期涨跌幅": _payload_float(row.get(window_column)),
                    "周期成交量": _payload_float(row.get(volume_column)),
                    "所属交易所": _row_exchange_name(row) or "-",
                    "异动标签": _monitor_window_anomaly_label(_with_standard_metric_aliases(dict(row)), window=window_column.replace("%", "")),
                    "__selection": row.get("__selection") or {"coin": coin, "exchange": _row_exchange_key(row)},
                }
            )
        return pd.DataFrame(_rank_records(rows), columns=columns)

    def _build_monitor_price_action_board(
        self,
        frame: pd.DataFrame,
        *,
        window_column: str,
        top_n: int,
    ) -> pd.DataFrame:
        columns = ["排名", "交易对", "当前价格", "5m涨跌幅", "30m涨跌幅", "1h涨跌幅", "4h涨跌幅", "周期成交量", "大额成交额", "所属交易所", "异动标签", "__selection"]
        if frame is None or frame.empty:
            return pd.DataFrame(columns=columns)
        frame = canonicalize_market_frame_columns(frame.copy())
        window_key = window_column.replace("%", "")
        volume_column = _find_column_by_tokens(list(frame.columns), includes=[window_key, "成交量"]) or "24h成交额"
        large_column = _find_column_by_tokens(list(frame.columns), includes=[window_key, "大额成交额"]) or "5m大额成交额"
        ranked_frame = (
            frame.assign(
                _price_action_rank=(
                    pd.to_numeric(frame[window_column], errors="coerce").abs().fillna(0.0)
                    + pd.to_numeric(frame.get("信号分数"), errors="coerce").fillna(0.0) * 0.25
                )
            )
            .sort_values(["_price_action_rank", "24h成交额"], ascending=[False, False], na_position="last")
            .head(top_n)
        )
        rows: List[Dict[str, Any]] = []
        for row in ranked_frame.to_dict("records"):
            coin = str(row.get("币种") or "").upper().strip()
            rows.append(
                {
                    "交易对": f"{coin}USDT" if coin else "-",
                    "当前价格": _row_last_price(row),
                    "5m涨跌幅": _payload_float(row.get("5m%")),
                    "30m涨跌幅": _payload_float(row.get("30m%")),
                    "1h涨跌幅": _payload_float(row.get("1h%")),
                    "4h涨跌幅": _payload_float(row.get("4h%")),
                    "周期成交量": _payload_float(row.get(volume_column)),
                    "大额成交额": _payload_float(row.get(large_column)),
                    "所属交易所": _row_exchange_name(row) or "-",
                    "异动标签": _monitor_window_anomaly_label(_with_standard_metric_aliases(dict(row)), window=window_key),
                    "__selection": row.get("__selection") or {"coin": coin, "exchange": _row_exchange_key(row)},
                }
            )
        return pd.DataFrame(_rank_records(rows), columns=columns)

